# ---- Atomic, persisted ID counters (expense refs, quote numbers). The old
# max-scan-over-all-records approach raced under concurrent ingest: two threads
# could scan the same max and issue the SAME ref. ----
_id_counter_lock = threading.Lock()
_id_counters = _load_json("id_counters.json", {}) or {}

def _next_counter(name, floor=0):
    """Monotonic counter, atomic under threads, survives restarts. `floor` seeds it
    above any historical value (from a one-time scan) so old refs never collide."""
    with _id_counter_lock:
        cur = int(_id_counters.get(name, 0) or 0)
        nxt = max(cur, int(floor or 0)) + 1
        _id_counters[name] = nxt
        _save_json("id_counters.json", _id_counters)
        return nxt

# ---------------- Hostaway ----------------
_token = {"value": None, "expires_at": 0}
_token_lock = threading.Lock()

def get_token(force=False):
    """Bearer token with PROACTIVE expiry tracking: refresh ~120s before Hostaway
    expires it, so the 401-retry path becomes a rare fallback, not the routine."""
    now = time.time()
    if _token["value"] and not force and now < _token["expires_at"] - 120:
        return _token["value"]
    with _token_lock:
        # Re-check inside the lock: another thread may have refreshed already.
        now = time.time()
        if _token["value"] and not force and now < _token["expires_at"] - 120:
            return _token["value"]
        r = requests.post(
            f"{BASE}/accessTokens",
            headers={"Content-Type": "application/x-www-form-urlencoded"},
            data={"grant_type": "client_credentials", "client_id": HOSTAWAY_ACCOUNT_ID,
                  "client_secret": HOSTAWAY_API_KEY, "scope": "general"},
            timeout=30,
        )
        r.raise_for_status()
        j = r.json()
        _token["value"] = j["access_token"]
        try:
            ttl = int(j.get("expires_in") or 0)
        except (TypeError, ValueError):
            ttl = 0
        # Hostaway tokens are long-lived; if expires_in is absent assume 12h.
        _token["expires_at"] = now + (ttl if ttl > 0 else 12 * 3600)
        return _token["value"]

# Status codes that mean "your bearer token is no longer accepted — refresh once and retry."
# Hostaway has been observed to use 403; spec says 401 — accept both to be safe.
_AUTH_RETRY_CODES = (401, 403)

def _api_request(method, path, *, params=None, body=None, _retry=0):
    """One retry policy for GET/POST/PUT: refresh-once on auth failure, EXPONENTIAL
    backoff on 429 (5s → 10s → 20s, honoring Retry-After) instead of fixed 10s×3."""
    token = get_token()
    headers = {"Authorization": f"Bearer {token}", "Cache-control": "no-cache"}
    if method != "GET":
        headers["Content-Type"] = "application/json"
    r = requests.request(method, f"{BASE}{path}", headers=headers,
                         params=params if method == "GET" else None,
                         json=body if method != "GET" else None, timeout=60)
    if r.status_code in _AUTH_RETRY_CODES and _retry == 0:   # token expired -> refresh once
        get_token(force=True)
        return _api_request(method, path, params=params, body=body, _retry=_retry + 1)
    if r.status_code == 429 and _retry < 3:                  # rate limited -> backoff
        try:
            wait = float(r.headers.get("Retry-After") or 0)
        except (TypeError, ValueError):
            wait = 0
        time.sleep(wait if wait > 0 else 5 * (2 ** _retry))
        return _api_request(method, path, params=params, body=body, _retry=_retry + 1)
    r.raise_for_status()
    return r.json()

def api_get(path, params=None, _retry=0):
    return _api_request("GET", path, params=params, _retry=_retry)

def api_post(path, body, _retry=0):
    return _api_request("POST", path, body=body, _retry=_retry)

def api_put(path, body, _retry=0):
    return _api_request("PUT", path, body=body, _retry=_retry)

_listings = {"map": {}, "ts": 0}

def get_listings_map():
    """listingMapId -> internal name (cached for 1 hour)."""
    if _listings["map"] and time.time() - _listings["ts"] < 3600:
        return _listings["map"]
    m, limit, offset = {}, 100, 0
    while True:
        data = api_get("/listings", params={"limit": limit, "offset": offset})
        batch = data.get("result", []) or []
        for l in batch:
            m[l.get("id")] = l.get("internalListingName") or l.get("name") or f"unit-{l.get('id')}"
        if len(batch) < limit:
            break
        offset += limit
    _listings["map"], _listings["ts"] = m, time.time()
    return m

async def get_listings_map_async():
    """M5: a COLD get_listings_map() paginates Hostaway synchronously (up to
    ~95s with retries), freezing every web request + the Discord heartbeat when
    called from an async handler. Async handlers must use this wrapper."""
    if _listings["map"] and time.time() - _listings["ts"] < 3600:
        return _listings["map"]                   # warm hit — no thread hop
    return await asyncio.to_thread(get_listings_map)

# ====================================================================
#  LISTINGS MASTER STORE — the single source of truth every feature reads.
#  Synced from Hostaway (NEW ✨ / CHANGED / DEACTIVATED detection, never deletes)
#  and carries dashboard-only fields Hostaway does NOT have: group/compound,
#  hard price floor, and the OujaCT (in-house cleaning team) assignment.
# ====================================================================
LISTINGS_STORE_FILE = "listings_store.json"
_ls_store = None                  # lazy-loaded; see _ls_get()
_ls_lock  = threading.Lock()
# Hostaway-owned fields refreshed on every sync (local fields below are preserved).
_LS_HA_FIELDS = ("internal_name", "public_name", "address", "city", "ha_status",
                 "active", "bedrooms", "directions_url", "directions_field")

def _ls_today_iso():
    return datetime.now(TZ).date().isoformat()

def _ls_get():
    """Load the listings store from the volume once, then keep it in memory."""
    global _ls_store
    if _ls_store is None:
        with _ls_lock:
            if _ls_store is None:
                data = _load_json(LISTINGS_STORE_FILE, None)
                if not isinstance(data, dict) or "listings" not in data:
                    data = {"listings": {}, "last_sync": None, "last_summary": {}}
                _ls_store = data
    return _ls_store

def _ls_save():
    if _ls_store is not None:
        _save_json(LISTINGS_STORE_FILE, _ls_store)

def _ls_needs_setup(rec):
    """Active listing isn't ready for pricing/cleaning until it has a group AND a floor."""
    if not rec.get("active", True):
        return False
    no_group = not str(rec.get("group") or "").strip()
    no_floor = rec.get("floor") in (None, "")
    return bool(no_group or no_floor)

def oujact_listing_ids():
    """Set of listing ids (int) currently assigned to the in-house cleaning team."""
    out = set()
    for k, rec in _ls_get()["listings"].items():
        if rec.get("oujact"):
            try:
                out.add(int(k))
            except (TypeError, ValueError):
                pass
    return out

# ===== Cleaning teams: multiple crews, each with its own apartments + unique external link =====
_cleaning_teams = {}         # team_id -> {id, name, token, created_at}
_clean_early_depart = {}     # str(lid) -> {at, reservation, note, source}  (Musaed-detected early checkout)

def _ct_now():
    return datetime.now(TZ).isoformat(timespec="seconds")

def _ct_new_id():
    import uuid
    return "team-" + uuid.uuid4().hex[:8]

def _ct_new_token():
    import secrets
    return secrets.token_urlsafe(12)

def _ct_load():
    global _cleaning_teams, _clean_early_depart
    _cleaning_teams = {str(k): v for k, v in (_load_json("cleaning_teams.json", {}) or {}).items()
                       if isinstance(v, dict) and v.get("id")}
    _clean_early_depart = _load_json("clean_early_depart.json", {}) or {}

def _ct_save():
    _save_json("cleaning_teams.json", _cleaning_teams)
    _save_json("clean_early_depart.json", _clean_early_depart)

def _ct_migrate():
    """First run: create 'Team 1' from the OujaCT-flagged apartments (its link keeps working)."""
    if _cleaning_teams:
        return 0
    tid = "team-1"
    _cleaning_teams[tid] = {"id": tid, "name": "الفريق الأول", "token": (OUJACT_ROUTE_TOKEN or _ct_new_token()),
                            "created_at": _ct_now()}
    n = 0
    for k, rec in _ls_get()["listings"].items():
        if rec.get("oujact") and not rec.get("cleaning_team"):
            rec["cleaning_team"] = tid
            n += 1
    try:
        _ls_save()
    except Exception:
        pass
    _ct_save()
    return n

def _ct_team_lids(team_id):
    out = set()
    for k, rec in _ls_get()["listings"].items():
        if str(rec.get("cleaning_team") or "") == str(team_id):
            try:
                out.add(int(k))
            except (TypeError, ValueError):
                pass
    return out

def _ct_team_by_token(token):
    if not token:
        return None
    for t in _cleaning_teams.values():
        if t.get("token") and hmac.compare_digest(str(t["token"]), str(token)):
            return t
    if OUJACT_ROUTE_TOKEN and hmac.compare_digest(str(OUJACT_ROUTE_TOKEN), str(token)):
        return _cleaning_teams.get("team-1")
    return None

def _ct_team_view(t):
    lids = _ct_team_lids(t["id"])
    return {"id": t["id"], "name": t.get("name", ""), "token": t.get("token", ""),
            "link": "/oujact-route?token=" + (t.get("token") or ""),
            "apartments": len(lids), "lids": sorted(lids)}

def _ct_team_name_for_lid(lid):
    """The cleaning-team name an apartment is assigned to ('' if none) — shown on its channel."""
    try:
        rec = _ls_get()["listings"].get(str(int(lid))) or {}
    except (TypeError, ValueError):
        return ""
    t = _cleaning_teams.get(str(rec.get("cleaning_team") or ""))
    return t.get("name", "") if t else ""

