# Track which reservations we've already system-escalated about so we don't spam
_code_escalated = set()       # reservation_ids where we already escalated "code wasn't sent"
_not_ready_escalated = set()  # reservation_ids where we already escalated "apartment not ready"

async def _post_system_escalation(title, detail, severity="high"):
    """Post a system-generated escalation card to #escalations (no guest message needed).
    Pings operations role for high severity."""
    try:
        guild = bot.get_guild(GUILD_ID)
        if guild is None:
            return
        category = await get_assistant_category(guild)
        esc_ch = await ensure_channel(guild, ESCALATION_CHANNEL, category)
        if esc_ch is None:
            return
        op_role = find_operation_role(guild)
        mention = op_role.mention if (op_role and severity == "high") else ""
        color = 0xD64545 if severity == "high" else 0xE0A22F
        embed = discord.Embed(title=f"⚠ {title}", description=detail, color=color)
        embed.set_footer(text="تصعيد آلي من النظام · يحتاج تدخّل بشري")
        await esc_ch.send(content=mention or None, embed=embed,
                          allowed_mentions=discord.AllowedMentions(roles=True))
        log_event("escalation", f"تصعيد نظام · {title}")
    except Exception as e:
        print("system escalation error:", e)

def _check_agreement_for_one(r, now):
    """Per-reservation evaluation with the new smart logic:
      1) If THIS LISTING doesn't require an agreement → skip step 2, jump to 3.
      2) If agreement required + NOT signed + check-in close → resend signing link.
      3) Either way: if check-in time has PASSED + no door-code message has been
         sent to the guest in last 24h:
            - apartment NOT ready (cleaning channel still open — an UNRELIABLE signal) →
              send the guest a NEUTRAL reassurance that never mentions cleaning/readiness,
              AND raise a system escalation telling ops to follow up.
            - apartment IS ready + still no code → raise a HIGH escalation to
              operations: "code wasn't sent, please send it now."
    Returns True if we took ANY action (so the loop logs it)."""
    res_id = r.get("id")
    if not res_id:
        return False
    if (r.get("status") or "").lower() not in CONFIRMED_STATUSES:
        return False
    arrival = _parse_date(r.get("arrivalDate"))
    if not arrival or arrival != now.date():
        return False
    hour = parse_hour(r.get("checkInTime"), 15)
    checkin_dt = datetime(arrival.year, arrival.month, arrival.day,
                          min(hour, 23), 0, tzinfo=TZ)
    hours_until = (checkin_dt - now).total_seconds() / 3600.0
    lid = r.get("listingMapId")
    listings = get_listings_map() or {}
    unit_name = listings.get(lid, f"unit-{lid}")
    guest_name = r.get("guestName") or "ضيف"
    cid = r.get("conversationId")
    action_taken = False

    # ---- Step 1+2: Agreement-not-signed reminder (only when listing requires it) ----
    needs_agreement = _unit_requires_agreement(lid)
    signed = _is_agreement_signed(r)
    if needs_agreement and not signed:
        if res_id not in _agreement_reminded \
           and 0 < hours_until <= AGREEMENT_REMINDER_LEAD_HOURS:
            link = find_agreement_url(cid)
            if link:
                is_ar = _has_arabic(guest_name) or True
                body = _reminder_message_ar(link) if is_ar else _reminder_message_en(link)
                try:
                    send_guest_message(cid, body, "email")
                    _agreement_reminded.add(res_id)
                    log_event("guest", f"تذكير توقيع العقد · {guest_name} · {unit_name} · "
                                       f"check-in بعد {hours_until:.1f}س")
                    action_taken = True
                except Exception as e:
                    print(f"agreement-reminder send error (res {res_id}):", e)
            else:
                print(f"  agreement-reminder: res {res_id} ({unit_name}) needs agreement but "
                      f"no signing URL found in conversation")

    # ---- Step 3: Check-in time has PASSED and no code arrived ----
    # Skip if the agreement IS required but NOT signed — the signing reminder above
    # is the right action; code shouldn't be released until signing.
    if needs_agreement and not signed:
        return action_taken
    # Only act once check-in has actually passed (the team should've sent the code by now).
    if hours_until > 0:
        return action_taken
    # Are they already in? Heuristic: code was sent in the last 24h.
    if _was_code_sent_recently(cid, since_hours=24):
        return action_taken
    # Is the apartment even ready?
    ready = _is_unit_ready_for_checkin(lid)
    if not ready and res_id not in _not_ready_escalated:
        # Reassure the guest a human is on it — WITHOUT claiming any cleaning/readiness status.
        # (Owner rule 2026-06-17: never tell the guest the unit is/isn't clean or ready; our
        #  open-cleaning-channel signal is unreliable. The ops escalation below handles it.)
        is_ar = _has_arabic(guest_name) or True
        msg = (
            "حياك الله 🤍\nرفعنا طلبك للفريق المختص ونتأكد من آخر التفاصيل، وكود الدخول "
            "بيوصلك منهم مباشرة خلال لحظات. شكراً لصبرك ودقايق وراح نعطيك تأكيد."
            if is_ar else
            "Hi 🤍\nWe've flagged this to our team and we're finalizing the last details — "
            "your access code will reach you directly from them shortly. Thanks for your "
            "patience, confirmation coming soon."
        )
        try:
            send_guest_message(cid, msg, "email")
            _not_ready_escalated.add(res_id)
            action_taken = True
        except Exception as e:
            print(f"not-ready guest msg error: {e}")
        # Also raise a med-severity escalation so ops can track the cleaning bottleneck
        try:
            import asyncio as _aio
            _aio.create_task(_post_system_escalation(
                title=f"🧹 شقة لم تجهز بعد · {unit_name}",
                detail=(f"الضيف **{guest_name}** موعد دخوله مرّ بـ{abs(hours_until):.1f}س "
                        f"والكود ما أُرسل لأن قناة التنظيف لـ **{unit_name}** "
                        f"لازالت مفتوحة. تابعوا التنظيف ثم أرسلوا الكود."),
                severity="med",
            ))
        except Exception as e:
            print(f"not-ready escalation post error: {e}")
        log_event("escalation", f"شقة لم تجهز · {unit_name} · {guest_name}")
        return action_taken
    if ready and res_id not in _code_escalated:
        # Apartment is ready, agreement is fine (or not required), but no code went out.
        # → operations team needs to send the code manually. The bot NEVER sends it.
        is_ar = _has_arabic(guest_name) or True
        guest_msg = (
            "حياك الله 🤍\nرفعت طلبك للفريق المختص الحين، وراح يوصلك كود الدخول "
            "خلال دقائق. آسفين على التأخير."
            if is_ar else
            "Hi 🤍\nI've flagged this to our team right now and your access code will reach "
            "you within minutes. Sorry for the delay."
        )
        try:
            send_guest_message(cid, guest_msg, "email")
        except Exception as e:
            print(f"code-not-sent guest msg error: {e}")
        try:
            import asyncio as _aio
            _aio.create_task(_post_system_escalation(
                title=f"🔑 لم يُرسَل كود الدخول · {unit_name}",
                detail=(f"الضيف **{guest_name}** ({unit_name}) — موعد دخوله مرّ بـ{abs(hours_until):.1f}س.\n"
                        f"• الشقة جاهزة (قناة التنظيف مغلقة) ✓\n"
                        f"• " + ("العقد موقّع ✓\n" if signed else "العقد غير مطلوب لهذه الشقة ✓\n") +
                        "• ما أُرسل كود الدخول للضيف خلال آخر ٢٤ ساعة ❌\n\n"
                        "⚠ **أرسلوا الكود الآن** — البوت ممنوع من إرساله ذاتياً."),
                severity="high",
            ))
            _code_escalated.add(res_id)
            action_taken = True
        except Exception as e:
            print(f"code-not-sent escalation error: {e}")
        log_event("escalation", f"كود لم يُرسَل · {unit_name} · {guest_name}")
    return action_taken

def check_agreement_reminders():
    """Top-level: pull today's reservations and run _check_agreement_for_one on each."""
    if not AGREEMENT_REMINDER_ENABLED:
        return
    today_iso = datetime.now(TZ).date().isoformat()
    try:
        data = api_get("/reservations", params={
            "arrivalStartDate": today_iso, "arrivalEndDate": today_iso,
            "limit": 200, "includeResources": 0,
        })
    except Exception as e:
        print("agreement-reminder fetch error:", e)
        return
    rows = data.get("result", []) or []
    now = datetime.now(TZ)
    n = sum(1 for r in rows if _check_agreement_for_one(r, now))
    if n:
        print(f"agreement-reminder: sent {n} nudge(s)")

# ====================================================================
# Deep-clean scheduler
# ====================================================================
def _dc_init(lid):
    if lid in _deep_clean_state:
        return
    _deep_clean_state[lid] = {
        "last_done": DEEPCLEAN_DEFAULT_LAST,
        "next_scheduled": None,
        "next_status": "unscheduled",   # unscheduled | scheduled | blocked | pushed | done
        "history": [],
        "notes": "",
    }

def _dc_calendar_day_free(lid, d_iso):
    try:
        cal = api_get(f"/listings/{lid}/calendar",
                      params={"startDate": d_iso, "endDate": d_iso})
        days = cal.get("result") or []
        if not days:
            return False
        d = days[0]
        return int(d.get("isAvailable", 0) or 0) == 1 and not d.get("reservationId")
    except Exception as e:
        print(f"deepclean cal check error ({lid}, {d_iso}):", e)
        return False

def _dc_scheduled_dates():
    return {s.get("next_scheduled") for s in _deep_clean_state.values() if s.get("next_scheduled")}

def _dc_find_next_date(lid, after_date=None):
    """Pick the earliest valid date for this unit's next deep clean.
    Constraints: weekday not in DEEPCLEAN_AVOID_WD, not already scheduled for another unit,
    within the 45-60 day window (extended to 75 if needed). Does NOT do per-date
    Hostaway lookups (too expensive) — caller verifies at confirm time."""
    if lid not in _deep_clean_state:
        _dc_init(lid)
    s = _deep_clean_state[lid]
    last = _parse_date(s.get("last_done")) or (datetime.now(TZ).date() - timedelta(days=30))
    today = datetime.now(TZ).date()
    earliest = max(last + timedelta(days=DEEPCLEAN_MIN_DAYS),
                   (after_date or today) + timedelta(days=1))
    horizon = max(last + timedelta(days=DEEPCLEAN_MAX_DAYS + 30),
                  earliest + timedelta(days=30))
    taken = _dc_scheduled_dates()
    d = earliest
    while d <= horizon:
        if d.weekday() not in DEEPCLEAN_AVOID_WD and d.isoformat() not in taken:
            return d.isoformat()
        d += timedelta(days=1)
    return None

def schedule_deep_cleans():
    """Assign next_scheduled for every non-paused unit that doesn't have one."""
    if not DEEPCLEAN_ENABLED:
        return
    listings = get_listings_map() or {}
    for lid in listings:
        if lid in _paused_units:
            continue
        if lid not in _deep_clean_state:
            _dc_init(lid)
        s = _deep_clean_state[lid]
        if s.get("next_scheduled"):
            continue
        nd = _dc_find_next_date(lid)
        if nd:
            s["next_scheduled"] = nd
            s["next_status"] = "scheduled"
            print(f"deepclean: scheduled {listings[lid]} ({lid}) for {nd}")
    return True

# ---- New scheduling primitives (insert / reset / cascade) ----
def _dc_next_valid_day(d):
    """Skip Thu/Fri forward."""
    while d.weekday() in DEEPCLEAN_AVOID_WD:
        d += timedelta(days=1)
    return d

def _dc_insert_at(lid, target_iso, _depth=0):
    """Place lid at target_iso. If someone else is already there, cascade-push them
    to the next valid day. Skips Thu/Fri. Limited recursion depth as safety."""
    if _depth > 200:
        return False
    target = _parse_date(target_iso) if isinstance(target_iso, str) else target_iso
    if not target:
        return False
    target = _dc_next_valid_day(target)
    target_iso = target.isoformat()
    # Find current occupant (excluding self)
    occupant = None
    for l, s in _deep_clean_state.items():
        if l == lid:
            continue
        if s.get("next_scheduled") == target_iso:
            occupant = l
            break
    # Assign target to lid
    if lid not in _deep_clean_state:
        _dc_init(lid)
    _deep_clean_state[lid]["next_scheduled"] = target_iso
    _deep_clean_state[lid]["next_status"] = "scheduled"
    # Cascade displaced occupant to next valid day
    if occupant is not None:
        _dc_insert_at(occupant, (target + timedelta(days=1)).isoformat(), _depth + 1)
    return True

def _dc_reset_from(start_iso, set_anchor=True):
    """Wipe all next_scheduled for non-paused units and re-lay them starting from
    start_iso, one valid-day per unit, ordered by oldest-last_done-first (most
    overdue takes the earliest slots). When set_anchor is True (the default for
    explicit user action), the start_iso is remembered as `_dc_anchor_date` so
    later pause/unpause auto-compactions stay tethered to the same start."""
    global _dc_anchor_date
    start = _parse_date(start_iso) if isinstance(start_iso, str) else start_iso
    if not start:
        return 0
    if set_anchor:
        _dc_anchor_date = start.isoformat()
    # Build priority queue: (last_done, lid) ascending so oldest = first
    pool = []
    for lid, s in _deep_clean_state.items():
        if lid in _paused_units:
            continue
        s["next_scheduled"] = None
        s["next_status"] = "unscheduled"
        last = _parse_date(s.get("last_done")) or (datetime.now(TZ).date() - timedelta(days=999))
        pool.append((last, lid))
    pool.sort()
    cur = _dc_next_valid_day(start)
    assigned = 0
    for _, lid in pool:
        cur = _dc_next_valid_day(cur)
        _deep_clean_state[lid]["next_scheduled"] = cur.isoformat()
        _deep_clean_state[lid]["next_status"] = "scheduled"
        cur += timedelta(days=1)
        assigned += 1
    return assigned

def _dc_handle_booking_conflict(blocked_lid, blocked_iso):
    """When blocked_lid was scheduled for blocked_iso but the unit got booked:
      1) Pull every later-scheduled unit BACKWARD by one valid-day to fill the gap
         (so Monday's clean becomes Sunday's, Tuesday's becomes Monday's, etc.)
      2) Find blocked_lid's checkout from Hostaway and reschedule it for the first
         valid day AFTER checkout."""
    blocked_d = _parse_date(blocked_iso)
    if not blocked_d:
        return
    # Step 1: pull others up
    others = sorted([
        (_parse_date(s["next_scheduled"]), lid)
        for lid, s in _deep_clean_state.items()
        if lid != blocked_lid and s.get("next_scheduled") and lid not in _paused_units
           and _parse_date(s["next_scheduled"]) and _parse_date(s["next_scheduled"]) > blocked_d
    ])
    cur = blocked_d
    for orig_d, lid in others:
        cur = _dc_next_valid_day(cur)
        if cur < orig_d:
            _deep_clean_state[lid]["next_scheduled"] = cur.isoformat()
            cur += timedelta(days=1)
        else:
            # caught up — no more pulling
            cur = orig_d + timedelta(days=1)
    # Step 2: push blocked_lid to first valid day after its checkout
    new_d = None
    try:
        cal = api_get(f"/listings/{blocked_lid}/calendar",
                      params={"startDate": blocked_iso, "endDate": blocked_iso})
        days = cal.get("result") or []
        res_id = days[0].get("reservationId") if days else None
        if res_id:
            res = api_get(f"/reservations/{res_id}").get("result", {})
            checkout = _parse_date(res.get("departureDate"))
            if checkout:
                new_d = checkout + timedelta(days=1)
    except Exception as e:
        print(f"booking conflict checkout lookup error ({blocked_lid}):", e)
    if new_d is None:
        new_d = blocked_d + timedelta(days=1)
    taken = _dc_scheduled_dates()
    while new_d.weekday() in DEEPCLEAN_AVOID_WD or new_d.isoformat() in taken:
        new_d += timedelta(days=1)
    _deep_clean_state[blocked_lid]["next_scheduled"] = new_d.isoformat()
    _deep_clean_state[blocked_lid]["next_status"] = "scheduled"

def confirm_tomorrow_deepcleans():
    """At 9pm: lock in tomorrow's planned deep cleans.
       - if the unit is still free → block the calendar (isAvailable=0) so the cleaner has the day
       - if a guest booked it last-minute → push to the next available slot"""
    if not DEEPCLEAN_ENABLED:
        return
    tomorrow = datetime.now(TZ).date() + timedelta(days=1)
    iso = tomorrow.isoformat()
    listings = get_listings_map() or {}
    confirmed, pushed = 0, 0
    for lid, s in list(_deep_clean_state.items()):
        if lid in _paused_units:
            continue
        if s.get("next_scheduled") != iso:
            continue
        name = listings.get(lid, str(lid))
        if not _dc_calendar_day_free(lid, iso):
            # Guest beat us to it. NEW cascade behavior: shift everyone scheduled
            # AFTER `iso` BACKWARD by one valid-day so they fill the gap, then
            # push this lid to the first valid day AFTER its checkout.
            _dc_handle_booking_conflict(lid, iso)
            pushed += 1
            new_target = _deep_clean_state.get(lid, {}).get("next_scheduled", "—")
            log_event("pricing",
                      f"تنظيف عميق · {name}: انحجزت ليوم {iso}. الباقي تقدّم يوم لتعبئة الفراغ. "
                      f"هالشقة نُقلت لتاريخ {new_target} (بعد تشيك-آوت الحجز).")
            continue
        # block the day in Hostaway
        try:
            api_put(f"/listings/{lid}/calendar",
                    {"startDate": iso, "endDate": iso,
                     "isAvailable": 0, "note": "deep-clean"})
            s["next_status"] = "blocked"
            confirmed += 1
            log_event("pricing", f"تنظيف عميق · {name}: مؤكد ومحجوز ليوم {iso}")
        except Exception as e:
            print(f"deepclean block error ({lid}, {iso}):", e)
    if confirmed or pushed:
        print(f"deepclean: confirmed={confirmed} pushed={pushed} for {iso}")

def deepclean_lookahead_check(days=7):
    """Daily early-warning sweep: live-check the next `days` of SCHEDULED deep cleans
    against Hostaway and resolve booking conflicts NOW — the old flow only discovered
    them the night before (9pm confirm), leaving no time to re-plan the crew's day.
    Tomorrow stays the confirm loop's job; this sweeps day 2..days (a handful of calls)."""
    if not DEEPCLEAN_ENABLED:
        return 0
    today = datetime.now(TZ).date()
    listings = get_listings_map() or {}
    moved = 0
    for lid, s in list(_deep_clean_state.items()):
        if lid in _paused_units:
            continue
        nd = _parse_date(s.get("next_scheduled"))
        if not nd or not (today + timedelta(days=2) <= nd <= today + timedelta(days=days)):
            continue
        iso = nd.isoformat()
        try:
            if not _dc_calendar_day_free(lid, iso):
                _dc_handle_booking_conflict(lid, iso)
                moved += 1
                name = listings.get(lid, str(lid))
                new_target = _deep_clean_state.get(lid, {}).get("next_scheduled", "—")
                log_event("pricing", f"تنظيف عميق · {name}: تعارض مبكر — يوم {iso} انحجز، "
                                     f"انتقل التنظيف إلى {new_target}")
        except Exception as e:
            print(f"deepclean lookahead error ({lid}, {iso}):", e)
    if moved:
        print(f"deepclean lookahead: resolved {moved} conflict(s) early")
    return moved

def _make_feedback_token(lid, res_id):
    """Compact opaque token combining unit + reservation. Random suffix so the
    URL can't be guessed."""
    import secrets
    return f"{int(lid)}-{int(res_id)}-{secrets.token_urlsafe(6)}"

def send_cleaning_feedback_request(reservation_row):
    """For one arrival, queue a rating-request message to the guest. Called by
    the cleaning_feedback_loop. Safe to call repeatedly — _cleaning_feedback_sent
    short-circuits duplicates."""
    if not CLEAN_FEEDBACK_ENABLED:
        return False
    r = reservation_row
    res_id = r.get("id")
    if not res_id or res_id in _cleaning_feedback_sent:
        return False
    if (r.get("status") or "").lower() not in CONFIRMED_STATUSES:
        return False
    cid = r.get("conversationId")
    if not cid:
        return False
    lid = r.get("listingMapId")
    if not lid:
        return False
    # Only ask if THIS check-in's turnover was actually cleaned (a cleaning report
    # or an OujaCT done-marker for the arrival date). The old gate (deep clean in the
    # last 30 days) silently skipped every guest arriving later than that — turnover
    # cleanliness is what the guest is rating, not deep-clean recency.
    arrival = str(r.get("arrivalDate") or "")[:10]
    if not arrival:
        return False
    cleaned = _oujact_is_done(_oc_key(int(lid), arrival))
    if not cleaned:
        rep = _cleaning_reports.get(_cleanproof_report_id(int(lid), arrival))
        cleaned = isinstance(rep, dict) and rep.get("status") not in ("", "draft")
    if not cleaned:
        return False
    token = _make_feedback_token(lid, res_id)
    unit_name = (get_listings_map() or {}).get(lid) or f"unit-{lid}"
    base_url = (os.environ.get("PUBLIC_BASE_URL") or "").rstrip("/")
    url = f"{base_url}/clean-feedback?id={token}" if base_url else f"/clean-feedback?id={token}"
    is_ar = _has_arabic(r.get("guestName") or "") or True
    body = (
        f"حياك الله 🤍\nخدمة سريعة عشانك: كيف لقيت نظافة الشقة لما دخلت؟ تقييمك يفرق معنا "
        f"وبيوصل لشركة التنظيف. ضغطة وحدة فقط:\n{url}\n\nشكراً 🤍"
        if is_ar else
        f"Hi 🤍\nQuick favor: how did you find the apartment's cleanliness on check-in? "
        f"Your rating goes straight to our cleaning team. One tap:\n{url}\n\nThank you 🤍"
    )
    try:
        send_guest_message(cid, body, "email")
        _cleaning_feedback[token] = {
            "lid": int(lid), "reservation_id": int(res_id),
            "unit": unit_name, "guest": r.get("guestName", ""),
            "ts_sent": datetime.now(TZ).isoformat(timespec="minutes"),
            "score": None, "comment": "", "ts_done": None,
            "last_clean_date": (_deep_clean_state.get(int(lid)) or {}).get("last_done"),
        }
        _cleaning_feedback_sent.add(res_id)
        log_event("guest", f"تقييم نظافة · أُرسل للضيف {r.get('guestName','')} · {unit_name}")
        return True
    except Exception as e:
        print("send_cleaning_feedback_request error:", e)
        return False

def check_cleaning_feedback_requests():
    """Walk today's arrivals; for each one whose check-in passed >= N hours ago
    and the unit was recently deep-cleaned, dispatch the feedback request once."""
    if not CLEAN_FEEDBACK_ENABLED:
        return
    today_iso = datetime.now(TZ).date().isoformat()
    yest_iso = (datetime.now(TZ).date() - timedelta(days=1)).isoformat()
    try:
        data = api_get("/reservations", params={
            "arrivalStartDate": yest_iso, "arrivalEndDate": today_iso,
            "limit": 200, "includeResources": 0,
        })
    except Exception as e:
        print("cleaning feedback fetch error:", e); return
    rows = data.get("result", []) or []
    now = datetime.now(TZ)
    sent = 0
    for r in rows:
        arr = _parse_date(r.get("arrivalDate"))
        if not arr: continue
        ci_hour = parse_hour(r.get("checkInTime"), 15)
        ci_dt = datetime(arr.year, arr.month, arr.day, min(ci_hour, 23), 0, tzinfo=TZ)
        hours_after_ci = (now - ci_dt).total_seconds() / 3600
        if hours_after_ci < CLEAN_FEEDBACK_DELAY_HOURS or hours_after_ci > 36:
            continue
        if send_cleaning_feedback_request(r):
            sent += 1
    if sent:
        print(f"cleaning-feedback: queued {sent} request(s)")

def cleaning_quality_summary():
    """Aggregate stats: avg score per unit, recent scores, distribution."""
    by_unit = defaultdict(lambda: {"name":"", "lid":None, "scores":[], "comments":[]})
    for tok, fb in _cleaning_feedback.items():
        if fb.get("score") is None:
            continue
        u = by_unit[fb["lid"]]
        u["name"] = fb["unit"]; u["lid"] = fb["lid"]
        u["scores"].append({"ts": fb.get("ts_done"), "score": fb["score"], "guest": fb.get("guest","")})
        if (fb.get("comment") or "").strip():
            u["comments"].append({"ts": fb.get("ts_done"), "comment": fb["comment"], "score": fb["score"]})
    units = []
    for lid, u in by_unit.items():
        sc = sorted(u["scores"], key=lambda x: x.get("ts") or "")
        scores = [x["score"] for x in sc]
        avg = round(sum(scores) / len(scores), 2) if scores else None
        # Item 30: trend = recent third of scores vs the earlier ones.
        trend, tdelta = "flat", 0
        if len(scores) >= 4:
            k = max(2, len(scores) // 3)
            recent, earlier = scores[-k:], scores[:-k]
            if earlier:
                tdelta = round(sum(recent) / len(recent) - sum(earlier) / len(earlier), 2)
                trend = "up" if tdelta >= 0.3 else ("down" if tdelta <= -0.3 else "flat")
        units.append({"lid": lid, "name": u["name"],
                      "avg": avg, "count": len(scores), "trend": trend, "tdelta": tdelta,
                      "recent": u["scores"][-5:], "comments": u["comments"][-5:]})
    # Item 30: declining units pinned to the top, then lowest average.
    units.sort(key=lambda x: (0 if x.get("trend") == "down" else 1,
                              x["avg"] if x["avg"] is not None else 99))
    sent = len(_cleaning_feedback)
    done = sum(1 for fb in _cleaning_feedback.values() if fb.get("score") is not None)
    overall_avg = None
    if done:
        all_scores = [fb["score"] for fb in _cleaning_feedback.values() if fb.get("score") is not None]
        overall_avg = round(sum(all_scores)/len(all_scores), 2)
    # Items 28/42: per-cleaner scores — attribute each feedback to the cleaner recorded
    # on the unit's clean record on/closest-before the feedback's clean date.
    by_cleaner = {}
    for tok, fb in _cleaning_feedback.items():
        if fb.get("score") is None:
            continue
        st = _deep_clean_state.get(fb.get("lid"))
        if not st:
            continue
        fd = (fb.get("ts_done") or "")[:10]
        best = None
        for h in st.get("history", []):
            if h.get("cleaner") and (not fd or h.get("date", "") <= fd):
                if best is None or h.get("date", "") > best.get("date", ""):
                    best = h
        if best is None:
            cands = [h for h in st.get("history", []) if h.get("cleaner")]
            best = cands[-1] if cands else None
        cleaner = best.get("cleaner") if best else None
        if not cleaner:
            continue
        by_cleaner.setdefault(cleaner, []).append(fb["score"])
    cleaners = [{"cleaner": n, "avg": round(sum(s) / len(s), 2), "count": len(s)}
                for n, s in by_cleaner.items()]
    cleaners.sort(key=lambda x: x["avg"])   # weakest first
    return {
        "units": units,
        "cleaners": cleaners,
        "stats": {"sent": sent, "responded": done,
                  "response_rate": round(done/sent*100) if sent else 0,
                  "overall_avg": overall_avg},
    }

def mark_deep_clean_done(lid, date_iso=None, notes="", cleaner=""):
    if lid not in _deep_clean_state:
        _dc_init(lid)
    s = _deep_clean_state[lid]
    done_date = date_iso or datetime.now(TZ).date().isoformat()
    cleaner = (cleaner or "").strip()[:60]
    s["history"].append({"date": done_date,
                         "ts": datetime.now(TZ).isoformat(timespec="minutes"),
                         "notes": notes, "cleaner": cleaner})   # item 28/42: who cleaned
    if cleaner:
        s["last_cleaner"] = cleaner
    s["history"] = s["history"][-20:]
    s["last_done"] = done_date
    s["next_scheduled"] = None
    s["next_status"] = "unscheduled"
    # try to free the calendar date in case we'd blocked it
    try:
        api_put(f"/listings/{lid}/calendar",
                {"startDate": done_date, "endDate": done_date, "isAvailable": 1})
    except Exception as e:
        print(f"calendar-free error (listing {lid}, {done_date}):", e)
    return True

def compute_tonight_empty():
    """For each unit empty TONIGHT, return its current price + the discount schedule the
    bot will apply if the unit stays empty. Weekends now use the normal Riyadh-time tiers
    unless DISCOUNT_WEEKEND_SKIP_TIERS=1 restores the old weekend-only rule. Also includes
    the owner-set skip status.

    Returned shape (one entry per empty unit):
      {lid, name, price, t1, t2, t3, w, weekend, skipped_until, paused_global,
       tier_times: [{label, hour, minute, pct, price}], next: {label, when_iso, price}}
    """
    today = datetime.now(TZ).date()
    today_iso = today.isoformat()
    weekend = today.weekday() in WEEKEND_DAYS
    listings = get_listings_map()
    now = datetime.now(TZ)
    paused_global = is_discount_paused()
    state = _load_discount_state()
    day_orig = state.get(today_iso, {})
    floor_ctx = _lm_floor_context(today_iso)

    items = []
    for lid, name in listings.items():
        try:
            cal = api_get(f"/listings/{lid}/calendar",
                          params={"startDate": today_iso, "endDate": today_iso})
            days = cal.get("result", []) or []
            if not days:
                continue
            d = days[0]
            available = int(d.get("isAvailable", 0) or 0) == 1
            booked = bool(d.get("reservationId"))
            price = d.get("price")
            if not available or booked or not price:
                continue
            price = float(price)
            # recover the original (anchor) so the tier prices we show match what the
            # discount loop would actually write.
            original, baseline_source = _lm_baseline(lid, today_iso, day_orig, d)
            floor = _lm_floor_for(lid, floor_ctx)

            tier_times = []
            schedule = []
            if weekend and DISCOUNT_WEEKEND_SKIP_TIERS:
                schedule.append(("Weekend", WEEKEND_DISCOUNT_HOUR, WEEKEND_DISCOUNT_MINUTE,
                                 WEEKEND_DISCOUNT_PERCENT))
            else:
                schedule.extend([
                    ("T1", DISCOUNT_TIER1_HOUR, 0, DISCOUNT_TIER1_PERCENT),
                    ("T2", DISCOUNT_TIER2_HOUR, 0, DISCOUNT_TIER2_PERCENT),
                    ("T3", DISCOUNT_TIER3_HOUR, 0, DISCOUNT_TIER3_PERCENT),
                ])
                if weekend:
                    schedule.append(("Weekend", WEEKEND_DISCOUNT_HOUR, WEEKEND_DISCOUNT_MINUTE,
                                     WEEKEND_DISCOUNT_PERCENT))
            for lab, hour, minute, pct in schedule:
                raw, final, blocked = _discount_price_from_baseline(
                    original, pct, floor.get("final_floor", 0))
                tier_times.append({"label": lab, "hour": hour, "minute": minute,
                                   "pct": int(pct), "price": int(final),
                                   "price_before_floor": int(raw),
                                   "floor_blocked": blocked})

            # which tier is "next" today (still upcoming)?
            next_tier = None
            for tt in tier_times:
                fire = now.replace(hour=tt["hour"], minute=tt["minute"], second=0, microsecond=0)
                if fire > now:
                    next_tier = {"label": tt["label"], "when_iso": fire.isoformat(timespec="minutes"),
                                 "pct": tt["pct"], "price": tt["price"]}
                    break

            items.append({
                "lid": lid, "name": name,
                "price": int(round(price)), "original": int(round(original)),
                "t1": next((x["price"] for x in tier_times if x["label"] == "T1"), None),
                "t2": next((x["price"] for x in tier_times if x["label"] == "T2"), None),
                "t3": next((x["price"] for x in tier_times if x["label"] == "T3"), None),
                "w": next((x["price"] for x in tier_times if x["label"] == "Weekend"), None),
                "weekend": weekend, "tier_times": tier_times, "next": next_tier,
                "weekend_skip_tiers": bool(DISCOUNT_WEEKEND_SKIP_TIERS),
                "baseline_source": baseline_source, "floor": floor,
                "skipped_until": unit_skip_until_iso(lid),
                "paused_global": paused_global,
            })
        except Exception as e:
            print(f"tonight-empty error for {name}: {e}")
    items.sort(key=lambda x: x["name"])
    return items

def compute_arrivals_with_status(window_hours=36):
    """For each upcoming arrival inside `window_hours`, attach the agreement
    signing status, the conversation id, and how far away check-in is. Powers
    the new home-page arrivals timeline."""
    now = datetime.now(TZ)
    cutoff = now + timedelta(hours=window_hours)
    today_iso = now.date().isoformat()
    tomorrow_iso = (now.date() + timedelta(days=1)).isoformat()
    try:
        data = api_get("/reservations", params={
            "arrivalStartDate": today_iso, "arrivalEndDate": tomorrow_iso,
            "limit": 200, "includeResources": 0,
        })
    except Exception as e:
        print("compute_arrivals_with_status fetch error:", e)
        return []
    rows = data.get("result", []) or []
    listings = get_listings_map()
    out = []
    for r in rows:
        if (r.get("status") or "").lower() not in CONFIRMED_STATUSES:
            continue
        arrival = _parse_date(r.get("arrivalDate"))
        if not arrival:
            continue
        hour = parse_hour(r.get("checkInTime"), 15)
        ci_dt = datetime(arrival.year, arrival.month, arrival.day, min(hour, 23), 0, tzinfo=TZ)
        if not (now - timedelta(hours=4) <= ci_dt <= cutoff):
            continue
        lid = r.get("listingMapId")
        unit_name = listings.get(lid) or r.get("listingName") or f"unit-{lid}"
        hrs = (ci_dt - now).total_seconds() / 3600.0
        out.append({
            "reservation_id": r.get("id"),
            "guest": r.get("guestName") or r.get("guestFirstName") or "Guest",
            "unit": unit_name, "listing_id": lid,
            "checkin_iso": ci_dt.isoformat(timespec="minutes"),
            "checkin_label": ci_dt.strftime("%a %H:%M"),
            "hours_until": round(hrs, 1),
            "nights": _res_nights(r),
            "signed": _is_agreement_signed(r),
            "conversation_id": r.get("conversationId"),
            "total_price": r.get("totalPrice"),
        })
    out.sort(key=lambda x: x["hours_until"])
    return out

def compute_urgent_now():
    """Top operational items the owner needs to see at a glance:
       - escalations open + age
       - pending replies + age
       - upcoming arrivals with unsigned agreements
       - empty units tonight (with a price-status hint)
    """
    now = time.time()
    items = []
    # ---- escalations ----
    for mid, e in _escalations.items():
        if e.get("claimed_by"):
            continue
        age_min = int((now - (e.get("last_ping") or now)) / 60)
        items.append({
            "kind": "escalation", "severity": "high",
            "id": str(mid), "title": e.get("guest", "ضيف"),
            "subtitle": e.get("unit", ""),
            "detail": (e.get("reason") or "")[:140],
            "age_min": max(0, age_min),
            "action_view": "inbox",
        })
    # ---- pending replies (>15 min counts as aging) ----
    for mid, d in _pending_replies.items():
        item = d.get("item", {})
        last_time = item.get("last_time", "")
        age_min = None
        try:
            if last_time:
                dt = _parse_msg_dt(last_time)
                if dt:
                    age_min = int((datetime.now(TZ) - dt).total_seconds() / 60)
        except Exception:
            pass
        items.append({
            "kind": "pending_reply",
            "severity": "med" if (age_min or 0) > 15 else "low",
            "id": str(mid), "title": item.get("guest", "ضيف"),
            "subtitle": item.get("unit", ""),
            "detail": (item.get("guest_text") or "")[:140],
            "age_min": age_min,
            "action_view": "inbox",
        })
    # ---- arrivals with unsigned agreements (next 24h) ----
    try:
        arrivals = compute_arrivals_with_status(window_hours=24)
        for a in arrivals:
            if a["signed"] or a["hours_until"] < 0:
                continue
            sev = "high" if a["hours_until"] <= 2 else "med"
            items.append({
                "kind": "unsigned_agreement", "severity": sev,
                "id": str(a["reservation_id"]),
                "title": a["guest"], "subtitle": a["unit"],
                "detail": f"وصول بعد {a['hours_until']} ساعة · العقد غير موقّع",
                "age_min": None, "action_view": "home",
                "checkin": a["checkin_label"],
            })
    except Exception as e:
        print("urgent arrivals error:", e)
    # ---- pricing alerts on edge days (Saudi events + low-pace weekends) ----
    try:
        for pa in compute_pricing_alerts():
            items.append({
                "kind": pa["kind"], "severity": pa["severity"],
                "id": pa["date"],
                "title": pa["title"], "subtitle": "",
                "detail": pa["detail"],
                "age_min": None,
                "action_view": pa.get("action_view", "pricing"),
                "checkin": pa["date"],
            })
    except Exception as e:
        print("pricing alerts error:", e)
    # ---- global cross-view items (item 71): must-decide things from every view ----
    try:
        for d in _design_requests.values():
            if d.get("status") == "blocked":
                items.append({"kind": "design_blocked", "severity": "med", "id": d.get("id"),
                              "title": d.get("project_name") or d.get("client_name") or "تصميم",
                              "subtitle": d.get("client_name", ""), "detail": "طلب تصميم متوقّف",
                              "age_min": None, "action_view": "design"})
            elif d.get("waiting_on") == "faisal":
                items.append({"kind": "design_wait", "severity": "med", "id": d.get("id"),
                              "title": d.get("project_name") or d.get("client_name") or "تصميم",
                              "subtitle": d.get("client_name", ""), "detail": "طلب تصميم ينتظر قرارك",
                              "age_min": None, "action_view": "design"})
        for p in _pmo_projects.values():
            if p.get("signoff"):
                items.append({"kind": "pmo_signoff", "severity": "med", "id": p.get("id"),
                              "title": (p.get("unit") or {}).get("name", "مشروع تجهيز"),
                              "subtitle": (p.get("client") or {}).get("name", ""),
                              "detail": "مشروع تجهيز يحتاج اعتمادك", "age_min": None, "action_view": "pmo"})
        for lid, s in _pricing_strategies.items():
            if s.get("active") and not any(r.get("booked") for r in (s.get("dates") or {}).values()):
                items.append({"kind": "strat_stalled", "severity": "low", "id": str(lid),
                              "title": s.get("name", str(lid)), "subtitle": "",
                              "detail": "استراتيجية تسعير ما تحرّكت — راجعها", "age_min": None, "action_view": "strat"})
    except Exception as e:
        print("urgent global error:", e)
    # severity order, then age
    sev_order = {"high": 0, "med": 1, "low": 2}
    items.sort(key=lambda x: (sev_order.get(x["severity"], 9), -(x.get("age_min") or 0)))
    return items

def get_inbox_item_detail(item_id):
    """Build a rich detail view for a pending reply or open escalation, including the
    full conversation history (refetched from Hostaway) and the booking context."""
    try:
        item_id = int(item_id)
    except Exception:
        return None
    src = None; kind = None
    if item_id in _pending_replies:
        src = _pending_replies[item_id]; kind = "reply"
    elif item_id in _escalations:
        src = _escalations[item_id]; kind = "escalation"
    if not src:
        return None

    if kind == "reply":
        item = src.get("item", {})
        cid = item.get("conversation_id")
        guest = item.get("guest"); unit = item.get("unit"); lid = item.get("listing_id")
        res_id = item.get("reservation_id")
        checkin = item.get("checkin"); checkout = item.get("checkout")
        draft = src.get("draft", ""); confirmed = src.get("confirmed", False)
        reason = ""; intent = src.get("intent", ""); conf = src.get("confidence")
        sentiment = src.get("sentiment", "")
    else:   # escalation
        cid = src.get("conversation_id")
        guest = src.get("guest"); unit = src.get("unit"); lid = None
        res_id = None; checkin = None; checkout = None
        draft = ""; confirmed = False
        reason = src.get("reason", ""); intent = ""; conf = None; sentiment = ""

    # refetch the live thread so the dashboard shows the latest
    thread = []
    if cid:
        try:
            data = api_get(f"/conversations/{cid}/messages")
            msgs = sorted((data.get("result") or []), key=_msg_sort_key)
            for m in msgs[-30:]:
                thread.append({
                    "from": "guest" if _msg_is_inbound(m) else "host",
                    "text": (m.get("body") or "").strip(),
                    "ts": _msg_time(m),
                    "automated": (not _msg_is_inbound(m)) and _looks_automated(m.get("body") or ""),
                })
        except Exception as e:
            print(f"detail fetch thread error ({cid}):", e)

    # booking context
    nights = None; total = None; status = ""
    if res_id:
        try:
            data = api_get(f"/reservations/{res_id}")
            r = data.get("result") or {}
            nights = _res_nights(r) or None
            total = r.get("totalPrice") or None
            status = (r.get("status") or "").lower()
            checkin = checkin or r.get("arrivalDate")
            checkout = checkout or r.get("departureDate")
        except Exception as e:
            print(f"detail fetch reservation error ({res_id}):", e)

    return {
        "kind": kind, "id": item_id, "guest": guest or "", "unit": unit or "",
        "listing_id": lid, "conversation_id": cid, "reservation_id": res_id,
        "status": status, "confirmed": confirmed,
        "checkin": checkin, "checkout": checkout, "nights": nights, "total_price": total,
        "draft": draft, "reason": reason, "intent": intent, "confidence": conf,
        "sentiment": sentiment, "thread": thread,
    }

def compute_headsup():
    """List units still empty for TOMORROW night, with the discount they'll actually get."""
    f1 = (100.0 - DISCOUNT_TIER1_PERCENT) / 100.0
    f2 = (100.0 - DISCOUNT_TIER2_PERCENT) / 100.0
    f3 = (100.0 - DISCOUNT_TIER3_PERCENT) / 100.0
    fw = (100.0 - WEEKEND_DISCOUNT_PERCENT) / 100.0
    tomorrow_date = datetime.now(TZ).date() + timedelta(days=1)
    tomorrow = tomorrow_date.isoformat()
    weekend = tomorrow_date.weekday() in WEEKEND_DAYS
    listings = get_listings_map()
    items = []
    for lid, name in listings.items():
        try:
            cal = api_get(f"/listings/{lid}/calendar",
                          params={"startDate": tomorrow, "endDate": tomorrow})
            days = cal.get("result", []) or []
            if not days:
                continue
            d = days[0]
            available = int(d.get("isAvailable", 0) or 0) == 1
            booked = bool(d.get("reservationId"))
            price = d.get("price")
            if not available or booked or not price:
                continue
            price = float(price)
            items.append({"name": name, "price": int(price),
                          "t1": int(round(price * f1)), "t2": int(round(price * f2)),
                          "t3": int(round(price * f3)), "w": int(round(price * fw))})
        except Exception as e:
            print(f"headsup error for {name}: {e}")
    return items, tomorrow, weekend

# ---------------- handled-set persistence ----------------
# Atomic via _save_json/_load_json: a crash mid-write must never truncate the file
# (a truncated handled-set re-spams every cleaning channel after reboot).
def load_handled():
    return set(_load_json("handled.json", []))

def save_handled(s):
    _save_json("handled.json", list(s))

