class CleaningDoneView(discord.ui.View):
    def __init__(self):
        super().__init__(timeout=None)   # persistent across restarts

    @discord.ui.button(label="📷 Submit for Review", style=discord.ButtonStyle.success,
                       custom_id="ouja_cleaning_done")
    async def done(self, interaction: discord.Interaction, button: discord.ui.Button):
        await interaction.response.defer(ephemeral=False, thinking=True)
        ch = interaction.channel
        topic = getattr(ch, "topic", "") or ""
        key = parse_topic_oujact_key(topic)
        try:
            if not key:
                await interaction.followup.send(
                    "ما قدرت أعرف الشقة واليوم من هذا الروم. افتح رابط الفريق وارفع الصور من هناك، بعدها أرسل للمراجعة.",
                    ephemeral=False)
                return
            lid_raw, date_iso = key.split(":", 1)
            try:
                lid = int(lid_raw)
            except Exception:
                await interaction.followup.send(
                    "ما قدرت أقرأ رقم الشقة من هذا الروم. افتح رابط الفريق وارفع الصور من هناك.",
                    ephemeral=False)
                return
            report = await asyncio.to_thread(
                _cleanproof_get_or_create_report,
                lid,
                date_iso,
                str(interaction.user),
                "discord",
            )
            _cleanproof_recount(report)
            # Allow submit even if some required photos are missing — just FLAG it so the
            # manager sees it's incomplete and decides. (Was: blocked until complete.)
            missing = _cleanproof_missing_required_labels(report, "ar")
            report["photos_incomplete"] = bool(missing)
            report["missing_required"] = missing
            if missing:
                _cleanproof_audit(
                    report["report_id"], "submitted_incomplete_photos", str(interaction.user),
                    report.get("status"), report.get("status"), ", ".join(missing))
            prev = report.get("status")
            if prev not in ("manager_approved", "manager_rejected", "needs_reshoot"):
                report["status"] = "issue_found" if report.get("issue_found") else "pending_manager_review"
                report["updated_at"] = _cleanproof_now()
                _cleanproof_audit(
                    report["report_id"], "report_submitted_from_discord", str(interaction.user),
                    prev, report.get("status"),
                    (("صور ناقصة: " + ", ".join(missing)) if missing else "Discord channel submit button"))
            _cleaning_reports[report["report_id"]] = report
            _save_json("cleaning_reports.json", _cleaning_reports)
            ok, err = await _cleanproof_send_discord_review(report["report_id"], target_channel=ch)
            if not ok:
                await interaction.followup.send(
                    "الصور مكتملة والتقرير محفوظ، بس ما قدرت أرسل كرت المراجعة في Discord. "
                    f"السبب: {err or 'غير معروف'}",
                    ephemeral=False)
                return
            _oujact_log_status(lid, date_iso, "done",
                               "Submitted photo report for manager review",
                               str(interaction.user))
            # Close the dispatch loop for this unit/day only after the real
            # photo report is complete and has been sent for manager review.
            _oujact_mark_done(key)
        except Exception as e:
            print("submit-review error:", e)
            await interaction.followup.send(f"صار خطأ أثناء إرسال تقرير الصور للمراجعة: {e}", ephemeral=False)
            return
        try:
            if "cleaning-review:1" not in topic:
                await ch.edit(topic=(topic + " cleaning-review:1").strip()[:1024])
        except Exception as e:
            print("submit-review topic error:", e)
        _flag = ""
        try:
            if report.get("photos_incomplete"):
                _mt = "، ".join((report.get("missing_required") or [])[:6])
                _flag = f"\n⚠️ مُرسل مع تنبيه: فيه صور ناقصة ({_mt}). المدير يقرر."
        except Exception:
            pass
        await interaction.followup.send(
            f"📷 تم إرسال تقرير الصور للمراجعة بواسطة {interaction.user.mention}. "
            "كرت المراجعة تم نشره هنا في نفس الروم — الاعتماد أو الرفض من أزرار الكرت، "
            "والداشبورد يعرض نفس الحالة." + _flag,
            ephemeral=False)

def channel_name(internal_name):
    # Discord channel names must be lowercase, no spaces/symbols.
    # "Ouja | B209" -> "ouja-b209". The full name is shown inside the channel.
    return re.sub(r"[^a-z0-9]+", "-", internal_name.lower()).strip("-")[:90] or "unit"

# ---- responsible-person lookup (from assignments.json built off the Excel) ----
# Lives on the volume (STATE_DIR) so dashboard edits survive redeploys; the repo
# copy only seeds it once (one-time migration on first boot with a volume).
def _load_assignments():
    vol = _load_json("assignments.json", None)
    if isinstance(vol, dict) and vol.get("by_day") is not None:
        return vol
    try:
        repo = json.load(open("assignments.json", encoding="utf-8"))
        _save_json("assignments.json", repo)     # migrate the repo copy to the volume
        print("assignments.json migrated from repo to STATE_DIR")
        return repo
    except Exception as e:
        print("Could not load assignments.json:", e)
        return {"by_day": {}, "discord_ids": {}}

ASSIGNMENTS = _load_assignments()

# Python weekday(): Mon=0 ... Sun=6
ARABIC_DAYS = ["الاثنين", "الثلاثاء", "الأربعاء", "الخميس", "الجمعة", "السبت", "الأحد"]

def norm_unit(s):
    s = str(s).strip().lower().replace("ouja", "").replace("|", "")
    return re.sub(r"[\s\-_]+", " ", s).strip()

def _clip(s, n=18):
    """Trim a unit name so the table columns stay aligned."""
    s = str(s).strip()
    return s if len(s) <= n else s[:n - 1] + "…"

def _fmt_hour(h):
    """24h int -> friendly label, e.g. 0->'12 AM', 12->'12 PM', 18->'6 PM'."""
    suffix = "AM" if h < 12 else "PM"
    return f"{h % 12 or 12} {suffix}"

def parse_topic_res(topic):
    """Reservation id stored in a turnover channel's topic."""
    m = re.search(r"hostaway-res:(\d+)", topic or "")
    return m.group(1) if m else None

def parse_topic_oujact_key(topic):
    """Stable per-cleaning key 'lid:YYYY-MM-DD' stored in an OujaCT channel topic. THIS is the
    de-dup identity — it survives Hostaway reservation-id changes when a guest modifies a
    booking (the reservation-id-based dedup was the cause of duplicate channels)."""
    m = re.search(r"oujact-key:(\d+:\d{4}-\d{2}-\d{2})", topic or "")
    return m.group(1) if m else None

def _oujact_mark_done(key):
    """Record that this unit+day's cleaning is finished/closed so the sync loop never re-opens
    its channel (was the cause of channels 'popping back' after cleaner submit)."""
    if not key:
        return
    _oujact_done[str(key)] = datetime.now(TZ).date().isoformat()
    try:
        _save_json("oujact_done.json", _oujact_done)
    except Exception:
        pass

def _oujact_is_done(key):
    return str(key) in _oujact_done

# We ALSO remember every unit+day we've opened a channel for — once. The automatic sync
# (poll loop + the startup tick discord.py fires the moment .start() runs) must never
# RE-open a channel that was already opened and then closed/deleted (the cause of cleaned
# channels "popping back" on every Railway deploy). A channel closed without a photo report
# is never marked done, so the done-marker alone wasn't enough; this makes creation idempotent
# per turnover. An explicit dashboard rebuild (day='today'/'tomorrow') bypasses this guard.
def _oujact_mark_opened(key):
    if not key or str(key) in _oujact_opened:
        return                                  # only write when it's genuinely new (no churn)
    _oujact_opened[str(key)] = datetime.now(TZ).date().isoformat()
    try:
        _save_json("oujact_opened.json", _oujact_opened)
    except Exception:
        pass

def _oujact_was_opened(key):
    return str(key) in _oujact_opened

def _oujact_prune_opened(days=3):
    cutoff = (datetime.now(TZ).date() - timedelta(days=days)).isoformat()
    stale = [k for k, d in list(_oujact_opened.items()) if str(d) < cutoff]
    if stale:
        for k in stale:
            _oujact_opened.pop(k, None)
        try:
            _save_json("oujact_opened.json", _oujact_opened)
        except Exception:
            pass

def _oujact_prune_done(days=3):
    """Purge done-markers older than `days`. Keyed `lid:date`, so without expiry the
    SAME unit+date next year would collide and its channel would silently never open.
    Called from the channel sweep AND the daily loop (so it runs even if Discord is down)."""
    cutoff = (datetime.now(TZ).date() - timedelta(days=days)).isoformat()
    stale = [k for k, d in list(_oujact_done.items()) if str(d) < cutoff]
    if stale:
        for k in stale:
            _oujact_done.pop(k, None)
        try:
            _save_json("oujact_done.json", _oujact_done)
        except Exception:
            pass
    # The latest-status index is keyed lid:date too — drop entries older than 30 days.
    idx_cutoff = (datetime.now(TZ).date() - timedelta(days=30)).isoformat()
    for k, e in list(_oujact_status_last.items()):
        if str((e or {}).get("date") or "") < idx_cutoff:
            _oujact_status_last.pop(k, None)
    return len(stale)

def parse_topic_did(topic):
    """Responsible cleaner's Discord id stored in the topic (None if unassigned)."""
    m = re.search(r"did:(\d+)", topic or "")
    return m.group(1) if m else None

def find_operation_role(guild):
    """The role to ping when a unit has no assigned cleaner."""
    if OPERATION_ROLE_ID.isdigit():
        r = guild.get_role(int(OPERATION_ROLE_ID))
        if r:
            return r
    name = OPERATION_ROLE_NAME.lower()
    for r in guild.roles:
        if r.name.lower() == name:
            return r
    return None

def responsible_for(internal_name, checkout_dt):
    """Returns (employee_name, discord_id, arabic_day). Any may be None if no match."""
    day = ARABIC_DAYS[checkout_dt.weekday()]
    emp = ASSIGNMENTS.get("by_day", {}).get(day, {}).get(norm_unit(internal_name))
    did = ASSIGNMENTS.get("discord_ids", {}).get(emp) if emp else None
    return emp, did, day

async def get_category(guild):
    for cat in guild.categories:
        if cat.name == CATEGORY_NAME:
            return cat
    return await guild.create_category(CATEGORY_NAME)

async def get_assistant_category(guild):
    """Category for guest-assistant + escalations. Reuses your existing Operations category."""
    want = ASSISTANT_CATEGORY.lower()
    for cat in guild.categories:
        if cat.name.lower() == want:
            return cat
    return await guild.create_category(ASSISTANT_CATEGORY)

async def ensure_channel(guild, name, category=None):
    """Find a text channel by name (create it if missing) and keep it under `category`."""
    ch = discord.utils.get(guild.text_channels, name=name)
    if ch is None:
        try:
            ch = await guild.create_text_channel(name, category=category)
        except Exception as e:
            print(f"channel create error ({name}):", e)
            return None
    elif category is not None and ch.category_id != category.id:
        try:
            await ch.edit(category=category)      # move existing channel under the category
        except Exception as e:
            print(f"channel move error ({name}):", e)
    return ch

def _category_family(guild, category):
    """The category plus its overflow twins («<name> ٢» …). Turnover channels
    spill there when Discord's 50-channel cap fills the category (M6 — same
    fix as the cb779d3 ticket flow), so every existence scan must cover them."""
    fam = [category]
    for suf in _TK_OVERFLOW_SUFFIXES:
        oname = f"{category.name} {suf}"
        cat = next((c for c in guild.categories
                    if _tk_cat_norm(c.name) == _tk_cat_norm(oname)), None)
        if cat is not None:
            fam.append(cat)
    return fam

async def _make_channel_spill(guild, category, name, topic=None):
    """guild.create_text_channel that survives the 50-channel category cap by
    spilling into overflow categories («<name> ٢» …). Any other Discord error
    bubbles up so the caller can surface the REAL reason (M6)."""
    try:
        return await guild.create_text_channel(name, category=category, topic=topic)
    except discord.HTTPException as e:
        if not _tk_category_full(e):
            raise
    for suf in _TK_OVERFLOW_SUFFIXES:
        oname = f"{category.name} {suf}"
        cat = next((c for c in guild.categories
                    if _tk_cat_norm(c.name) == _tk_cat_norm(oname)), None)
        if cat is None:
            cat = await guild.create_category(oname)
        try:
            return await guild.create_text_channel(name, category=cat, topic=topic)
        except discord.HTTPException as e:
            if _tk_category_full(e):
                continue          # this overflow is full too — try the next one
            raise
    # every overflow category is also full — last resort: guild root (no category)
    return await guild.create_text_channel(name, topic=topic)

async def _turnover_create_failed_alert(guild, unit, err):
    """M6: a cleaner who never gets their channel is INVISIBLE if we only
    print. Shout once (per unit, 6h) in the escalations channel with the real,
    actionable reason."""
    try:
        if not _once_claim(f"turnover-open-fail:{unit}"):
            return
        cat = await get_assistant_category(guild)
        ch = await ensure_channel(guild, ESCALATION_CHANNEL, cat)
        if ch:
            await ch.send("🚨 **ما قدرنا نفتح روم تنظيف** — الوحدة: **%s**\n%s"
                          % (unit, _tk_open_error_msg(err, "خطأ غير متوقع من ديسكورد")))
    except Exception as e2:
        print("turnover alert error:", e2)

async def sync_checkouts():
    guild = bot.get_guild(GUILD_ID)
    if guild is None:
        print("Guild not found — check DISCORD_GUILD_ID and that the bot was invited.")
        return
    category = await get_category(guild)

    # reservation ids that already have a live channel (incl. overflow categories — M6)
    existing = set()
    for cat in _category_family(guild, category):
        for ch in cat.text_channels:
            rid = parse_topic_res(ch.topic)
            if rid:
                existing.add(rid)
    handled.update(existing)

    items = await asyncio.to_thread(fetch_upcoming_checkouts)
    oujact_ids = oujact_listing_ids()   # these go through the dedicated OujaCT flow instead
    for it in items:
        if it["res_id"] in handled or it["res_id"] in existing:
            continue
        if it.get("lid") in oujact_ids:   # OujaCT-assigned -> handled by sync_oujact_turnovers
            continue
        try:
            emp, did, day = responsible_for(it["listing"], it["checkout"])
            # topic carries the reservation id + responsible discord id (for reminders)
            # + the stable oujact-key so the photo-proof Submit button works on LEGACY
            # channels too (parse_topic_oujact_key needs lid:date — without it the
            # cleaner's submit errored out on every non-OujaCT unit).
            topic = f"hostaway-res:{it['res_id']} did:{did or ''}"
            try:
                if it.get("lid"):
                    topic += f" oujact-key:{int(it['lid'])}:{it['checkout'].date().isoformat()}"
            except (TypeError, ValueError, AttributeError):
                pass
            ch = await _make_channel_spill(
                guild, category, channel_name(it["listing"]), topic=topic)
            embed = discord.Embed(title="🧹 Turnover Ready", color=GOLD)
            embed.add_field(name="Unit", value=it["listing"], inline=False)
            embed.add_field(name="Guest", value=it["guest"], inline=True)
            embed.add_field(name="Checkout",
                            value=it["checkout"].strftime("%a %d %b · %I:%M %p"), inline=True)

            if emp:
                embed.add_field(name="مسؤول التنظيف",
                                value=(f"<@{did}> ({emp})" if did else emp), inline=False)
            embed.set_footer(text="Tap the button below when photos/work are ready for manager review.")

            content = f"<@{did}> 🧹 وحدة جاهزة للتنظيف" if did else None
            await ch.send(content=content, embed=embed, view=CleaningDoneView(),
                          allowed_mentions=discord.AllowedMentions(users=True, roles=True))
            handled.add(it["res_id"])
            save_handled(handled)
            note = f" -> {emp}" if emp else " (no responsible match — check unit name)"
            print(f"Opened channel for {it['listing']} (res {it['res_id']}){note}")
        except Exception as e:
            print("create error:", e)
            await _turnover_create_failed_alert(guild, it["listing"], e)   # M6: never fail silently

# ---- OujaCT (in-house cleaning team) turnover channels + daily schedule ----
def _schedule_hostaway_listings():
    """All Hostaway listings for the Employee-Schedule picker: [{id, name, active, oujact}].
    OujaCT-assigned units sort first. Best-effort; returns [] if Hostaway is unreachable."""
    try:
        store = _ls_get()["listings"]
        out = []
        for lid, nm in get_listings_map().items():
            rec = store.get(str(lid)) or {}
            out.append({"id": int(lid), "name": rec.get("internal_name") or nm,
                        "active": bool(rec.get("active", True)), "oujact": bool(rec.get("oujact"))})
        out.sort(key=lambda x: (not x["oujact"], x["name"] or ""))
        return out
    except Exception as e:
        print("schedule hostaway-listings provider error:", e)
        return []

def _oujact_cover_info(listing_name, date_iso, lid=None):
    """{name, emoji, ...} of the employee responsible for cleaning this apartment on `date_iso`,
    looked up via the Employee Schedule. Tries the EXACT Hostaway-listing-id link first (reliable),
    then falls back to a best-effort name match for apartments not yet linked. Returns None when
    nothing matches. Never raises — channel creation must not break on a schedule miss."""
    if not (_HAS_SCHEDULE and _schedule):
        return None
    try:
        info = None
        if lid is not None:
            info = _schedule.coverage.cover_for_listing_id(lid, date_iso)
        if info is None:
            info = _schedule.coverage.cover_for_listing(listing_name, date_iso)
        return info
    except Exception as e:
        print("OujaCT cover lookup failed:", e)
        return None

def _oujact_channel(internal_name, checkin_today, team_name="", cover_emoji=""):
    """Discord-safe cleaning-channel name = unit + TEAM name + the responsible-employee EMOJI at the
    END, e.g. '103-nrjs-oujact🟢' / '12b-stayclean-checkin🟢'. The emoji (whoever covers the unit
    that day, from the Employee Schedule) sits at the very end so the owner spots who's in charge at
    a glance. The team name is what the owner sees; the 'oujact:1' marker lives in the TOPIC (for
    dedup/cleanup), never the visible name."""
    base = channel_name(internal_name)[:50]
    team = channel_name(team_name) if team_name else ""
    if not team or team == "unit":
        team = "clean"
    suffix = "-checkin" if checkin_today else ""
    em = (cover_emoji or "").strip()
    return (base + "-" + team[:24] + suffix)[:100 - len(em)] + em

def _oujact_topic(it, team_name=""):
    """Channel topic carrying the STABLE dedup key (lid:date) + reservation id + check-in flag
    + team name. Dedup is by the stable key, NOT the reservation id."""
    tm = (" team:" + str(team_name).replace(" ", "_")) if team_name else ""
    return ("oujact:1 oujact-key:{lid}:{date} hostaway-res:{rid} checkin:{ci}{tm}".format(
            lid=it["lid"], date=it["checkout_date"], rid=it["res_id"],
            ci=(1 if it["checkin_today"] else 0), tm=tm))

def _oujact_card_embed(it, team_name="", cover=None):
    """English turnover card for the in-house team. Reuses the submit-for-review button.
    `cover` (optional) = {name, emoji} of the employee responsible for this unit today, shown so
    the team can see who's in charge at a glance."""
    e = discord.Embed(title="🧹 Turnover — Ready to Clean", color=GOLD)
    e.add_field(name="Unit", value=it["listing"], inline=False)
    if cover and (cover.get("name") or cover.get("emoji")):
        e.add_field(name="Responsible",
                    value=((cover.get("emoji") or "") + " " + (cover.get("name") or "")).strip(),
                    inline=True)
    if team_name:
        e.add_field(name="Cleaning Team", value=team_name, inline=True)
    e.add_field(name="Checkout",
                value=it["checkout"].strftime("%a %d %b · %I:%M %p"), inline=True)
    if it["checkin_today"]:
        cin = it.get("checkin_dt")
        when = (" · " + cin.strftime("%I:%M %p")) if cin else ""
        e.add_field(name="Status", value=f"🔴 CHECK-IN TODAY{when}", inline=True)
    link = it.get("directions_url")
    e.add_field(name="Directions", value=(link if link else "No link"), inline=False)
    e.set_footer(text="Tap 📷 Submit for Review when photos/work are ready for manager review.")
    return e

async def sync_oujact_turnovers(day=None):
    """Open the OujaCT turnover channel for each apartment — one channel per apartment per
    checkout day. De-dup is by the STABLE key (lid:date), so a booking modification (new
    reservation id) never spawns a second channel. The channel name + card show the cleaning
    team. Stale/duplicate channels are pruned first. Returns a change log.
    `day`: None (automatic) → only checkouts within HOURS_AHEAD (~12h before); 'today' → ALL of
    today's checkouts; 'tomorrow' → ALL of tomorrow's checkouts (lets the owner build ahead)."""
    guild = bot.get_guild(GUILD_ID)
    if guild is None or not oujact_listing_ids():
        return []
    force = day is not None              # an explicit dashboard rebuild may re-open; the auto path never does
    pruned = await _oujact_cleanup_channels(guild)          # clear the backlog/dupes first
    category = await get_category(guild)
    now = datetime.now(TZ)
    today_iso = now.date().isoformat()
    tomorrow_iso = (now.date() + timedelta(days=1)).isoformat()
    items = await asyncio.to_thread(fetch_oujact_turnovers)
    if day == "today":
        items = [it for it in items if it["checkout_date"] == today_iso]
    elif day == "tomorrow":
        items = [it for it in items if it["checkout_date"] == tomorrow_iso]
    else:                                                   # automatic: ~12h before checkout
        items = [it for it in items if it["checkout"] <= now + timedelta(hours=HOURS_AHEAD)]
    # index existing OujaCT channels by the STABLE key; keep a reservation-id fallback for legacy
    # (incl. overflow categories — M6: a spilled channel that isn't scanned gets duplicated)
    by_key, by_res = {}, {}
    for cat in _category_family(guild, category):
        for ch in cat.text_channels:
            topic = ch.topic or ""
            if "oujact:1" not in topic:
                continue
            k = parse_topic_oujact_key(topic)
            if k:
                by_key[k] = ch
            rid = parse_topic_res(topic)
            if rid:
                by_res[rid] = ch
    changed = []
    for it in items:
        key = "{}:{}".format(it["lid"], it["checkout_date"])
        if _oujact_is_done(key):
            continue                                       # cleaning closed for this unit+day — never re-open
        team_name = _ct_team_name_for_lid(it["lid"])
        topic = _oujact_topic(it, team_name)
        ch = by_key.get(key) or by_res.get(str(it["res_id"]))
        if ch is None and not force and _oujact_was_opened(key):
            continue                                       # opened once already & since closed → don't auto-reopen (restart/poll)
        try:
            if ch is None:
                cover = _oujact_cover_info(it["listing"], it["checkout_date"], it["lid"])
                cover_emoji = (cover.get("emoji") if cover else "") or "⚪"
                want = _oujact_channel(it["listing"], it["checkin_today"], team_name, cover_emoji)
                ch = await _make_channel_spill(guild, category, want, topic=topic)
                await ch.send(embed=_oujact_card_embed(it, team_name, cover), view=CleaningDoneView())
                by_key[key] = ch
                changed.append({"unit": it["listing"], "channel": want,
                                "action": "created", "checkin": it["checkin_today"]})
                print(f"OujaCT: opened {want} ({key})")
            else:
                # already open — only touch the topic if it lacks the stable key (legacy upgrade)
                # or the check-in flag flipped; never rename (avoids Discord rate-limit churn).
                had_checkin = "checkin:1" in (ch.topic or "")
                if parse_topic_oujact_key(ch.topic or "") != key or had_checkin != it["checkin_today"]:
                    await ch.edit(topic=topic)
                if it["checkin_today"] and not had_checkin:
                    await ch.send("🔴 **CHECK-IN TODAY** — same-day arrival, prioritize this turnover.")
                    changed.append({"unit": it["listing"], "channel": ch.name,
                                    "action": "checkin_flagged", "checkin": True})
        except Exception as e:
            print("OujaCT channel error:", e)
            if ch is None:                  # creation failed → the cleaner has NO room; shout (M6)
                await _turnover_create_failed_alert(guild, it["listing"], e)
        if ch is not None:
            _oujact_mark_opened(key)        # remember it exists so we never auto-reopen it once closed
    if pruned:
        changed.append({"action": "pruned", "count": pruned})
    return changed

async def _oujact_cleanup_channels(guild=None):
    """Safely delete ONLY the OujaCT channels the bot created (topic carries 'oujact:1'):
    duplicates of the same stable key, channels whose checkout day is 2+ days past, and legacy
    keyless channels older than 3 days. Never touches any other channel. Returns #deleted."""
    guild = guild or (bot.get_guild(GUILD_ID) if GUILD_ID else None)
    if guild is None:
        return 0
    try:
        category = await get_category(guild)
    except Exception:
        return 0
    today = datetime.now(TZ).date()
    _oujact_prune_done()
    _oujact_prune_opened()
    seen, deleted = set(), 0
    _fam_channels = [ch for cat in _category_family(guild, category) for ch in cat.text_channels]
    for ch in list(_fam_channels):
        topic = ch.topic or ""
        if "oujact:1" not in topic:
            continue
        key = parse_topic_oujact_key(topic)
        drop = False
        if key:
            if key in seen:                       # duplicate of an apartment+day we already kept
                drop = True
            else:
                seen.add(key)
                try:
                    d = datetime.strptime(key.split(":")[1], "%Y-%m-%d").date()
                    if (today - d).days >= 2:     # checkout day well past — cleaning is long done
                        drop = True
                except Exception:
                    pass
        else:
            # legacy channel with no stable key: drop if it's been around 3+ days
            try:
                age_days = (datetime.now(TZ) - ch.created_at.astimezone(TZ)).days
                if age_days >= 3:
                    drop = True
            except Exception:
                pass
        if drop:
            try:
                await ch.delete(reason="OujaCT cleanup: stale/duplicate channel")
                deleted += 1
            except Exception as e:
                print("OujaCT cleanup delete error:", e)
    if deleted:
        print(f"OujaCT cleanup: removed {deleted} stale/duplicate channels")
    return deleted

async def _oujact_find_turnover_channel(guild, lid, date_iso):
    """The apartment's own OujaCT turnover channel for a given checkout day (by stable key)."""
    if guild is None:
        return None
    try:
        category = await get_category(guild)
    except Exception:
        return None
    key = "{}:{}".format(lid, str(date_iso)[:10])
    for ch in category.text_channels:
        if "oujact:1" in (ch.topic or "") and parse_topic_oujact_key(ch.topic) == key:
            return ch
    return None

async def post_oujact_schedule():
    """Daily English schedule of OujaCT turnovers (today + tomorrow), priority-ordered:
    check-ins first, then earliest check-in time. Each line: internal name · flag · directions."""
    guild = bot.get_guild(GUILD_ID)
    if guild is None or not oujact_listing_ids():
        return
    items = await asyncio.to_thread(fetch_oujact_turnovers)
    category = await get_category(guild)
    ch = await ensure_channel(guild, OUJACT_SCHEDULE_CHANNEL, category)
    if ch is None:
        return
    today_iso = datetime.now(TZ).date().isoformat()
    lines = []
    for it in items:
        flag = "  🔴 CHECK-IN TODAY" if it["checkin_today"] else ""
        when = "today" if it["checkout_date"] == today_iso else "tomorrow"
        link = it.get("directions_url") or "No link"
        lines.append(f"**{it['listing']}** · checkout {when}{flag}\n  Directions: {link}")
    desc = "\n\n".join(lines) if lines else "No OujaCT turnovers for today or tomorrow."
    embed = discord.Embed(title="🧹 OujaCT — Today & Tomorrow's Turnovers",
                          description=desc[:4000], color=GOLD)
    embed.set_footer(text="Order: check-ins first, then earliest check-in time.")
    await ch.send(embed=embed)
    print(f"OujaCT: posted daily schedule ({len(items)} turnovers)")

# ============================================================================
#  OUJACT DISPATCH CENTER — priority plan, checkout state, route token, ETA
#  (reuses fetch_oujact_turnovers + the listings store + the public-page token
#   pattern. Never fakes Airbnb detection or ETA; priority always beats distance.)
# ============================================================================
def _extract_latlng(url):
    """Safely pull (lat, lng) from a Google Maps URL. Returns None if not confidently found."""
    if not url:
        return None
    raw = str(url).strip()
    coord = r"(-?\d{1,3}\.\d+),\s*(-?\d{1,3}\.\d+)"

    # Browser geolocation sends the route start as plain "lat,lng".
    m = re.fullmatch(r"\s*" + coord + r"\s*", raw)
    if m:
        try:
            lat, lng = float(m.group(1)), float(m.group(2))
            if -90 <= lat <= 90 and -180 <= lng <= 180:
                return (lat, lng)
        except (TypeError, ValueError):
            pass

    # Some place links encode destination as longitude then latitude. Prefer this
    # over /dir/ path coordinates because those can be the origin.
    for pat in (r"!1d(-?\d{1,3}\.\d+)!2d(-?\d{1,3}\.\d+)",):
        m = re.search(pat, raw)
        if m:
            try:
                lng, lat = float(m.group(1)), float(m.group(2))
                if -90 <= lat <= 90 and -180 <= lng <= 180:
                    return (lat, lng)
            except (TypeError, ValueError):
                pass

    for pat in (r"!3d(-?\d{1,3}\.\d+)!4d(-?\d{1,3}\.\d+)",):
        m = re.search(pat, raw)
        if m:
            try:
                lat, lng = float(m.group(1)), float(m.group(2))
                if -90 <= lat <= 90 and -180 <= lng <= 180:
                    return (lat, lng)
            except (TypeError, ValueError):
                pass

    # Directions links often have both route endpoints before "/@", then a map-center
    # coordinate after "/@". Prefer the last explicit endpoint over the viewport center.
    before_center = raw.split("/@", 1)[0]
    path_coords = list(re.finditer(r"/" + coord + r"(?=/|$)", before_center))
    if path_coords:
        m = path_coords[-1]
        try:
            lat, lng = float(m.group(1)), float(m.group(2))
            if -90 <= lat <= 90 and -180 <= lng <= 180:
                return (lat, lng)
        except (TypeError, ValueError):
            pass

    for pat in (r"[?&](?:q|ll|destination|center)=" + coord,
                r"@(-?\d{1,3}\.\d+),(-?\d{1,3}\.\d+)"):              # map center fallback
        m = re.search(pat, raw)
        if m:
            try:
                lat, lng = float(m.group(1)), float(m.group(2))
                if -90 <= lat <= 90 and -180 <= lng <= 180:
                    return (lat, lng)
            except (TypeError, ValueError):
                pass
    return None

# --- small append-safe state stores (existing _load_json/_save_json persistence) ---
_oujact_checkout = _load_json("oujact_checkout.json", {}) or {}    # "lid|date" -> {state, by, ts}
_oujact_status   = _load_json("oujact_status.json", []) or []      # append-only status actions
# O(1) latest-status lookup: {key -> last event}. Rebuilt once at load, kept fresh by
# _oujact_log_status — replaces an O(5000) scan per unit per dashboard load.
_oujact_status_last = {e.get("key"): e for e in _oujact_status if isinstance(e, dict) and e.get("key")}
_oujact_route_audit = _load_json("oujact_route_audit.json", []) or []
_oujact_dispatch_log = _load_json("oujact_dispatch_log.json", {}) or {}  # "lid|date" -> {flags}
_clean_tasks = _load_json("cleaning_tasks.json", {}) or {}         # task_id -> manual cleaning task
_oujact_done = _load_json("oujact_done.json", {}) or {}            # "lid:date" -> date marked done (don't reopen the channel)
_oujact_opened = _load_json("oujact_opened.json", {}) or {}        # "lid:date" -> date a channel was first opened (don't auto-reopen after it's closed)
_cleaning_photo_templates = _load_json("cleaning_photo_templates.json", {}) or {}
_cleaning_reports = _load_json("cleaning_reports.json", {}) or {}
_cleaning_report_photos = _load_json("cleaning_report_photos.json", {}) or {}
# Guards report read-modify-writes: decisions come from Discord buttons AND the dashboard,
# and photo uploads mutate reports from to_thread workers — a threading lock covers both
# (an asyncio.Lock can't, since the writers are real threads).
_cleanproof_lock = threading.RLock()
_cleaning_report_audit = _load_json("cleaning_report_audit.json", []) or []
_cleaning_drive_service = None

CLEANING_REPORT_STATUSES = (
    "draft", "uploading", "submitted_for_review", "pending_manager_review",
    "manager_approved", "manager_rejected", "needs_reshoot", "issue_found")

DEFAULT_CLEANING_PHOTO_SLOTS = [
    ("living_room", "غرفة المعيشة", "Living room"),
    ("dining_table", "طاولة الطعام", "Dining table"),
    ("tv_remote", "ريموت التلفزيون", "TV remote"),
    ("bedroom", "غرفة النوم", "Bedroom"),
    ("bathroom", "الحمام", "Bathroom"),
    ("kitchen", "المطبخ", "Kitchen"),
    ("entrance", "المدخل", "Entrance"),
    ("supplies", "المستلزمات", "Supplies"),
    ("damage_check", "فحص الأضرار", "Damage check"),
]

OUJACT_CHECKOUT_STATES = ("unknown", "guest_confirmed", "checkout_button", "airbnb_confirmed",
                          "late_checkout", "inside", "checkout_passed")
def _oc_key(lid, date_iso):
    return f"{lid}|{str(date_iso)[:10]}"
def _oujact_checkout_state(lid, date_iso):
    return (_oujact_checkout.get(_oc_key(lid, date_iso)) or {}).get("state", "unknown")
def _oujact_set_checkout_state(lid, date_iso, state, by=""):
    if state not in OUJACT_CHECKOUT_STATES:
        return False
    _oujact_checkout[_oc_key(lid, date_iso)] = {
        "state": state, "by": (by or "")[:60],
        "ts": datetime.now(TZ).isoformat(timespec="seconds")}
    _save_json("oujact_checkout.json", _oujact_checkout)
    return True
def _oujact_latest_status(lid, date_iso):
    return _oujact_status_last.get(_oc_key(lid, date_iso))
def _oujact_log_status(lid, date_iso, action, note="", by=""):
    e = {"key": _oc_key(lid, date_iso), "lid": lid, "date": str(date_iso)[:10],
         "action": action, "note": (note or "")[:300], "by": (by or "")[:60],
         "prev": (_oujact_latest_status(lid, date_iso) or {}).get("action"),
         "ts": datetime.now(TZ).isoformat(timespec="seconds")}
    _oujact_status.append(e)
    _oujact_status_last[e["key"]] = e
    if len(_oujact_status) > 5000:
        del _oujact_status[:len(_oujact_status) - 5000]
    _save_json("oujact_status.json", _oujact_status)
    return e

def _cleanproof_now():
    return datetime.now(TZ).isoformat(timespec="seconds")

def _cleanproof_template_id(scope, value=""):
    value = str(value or "default").strip() or "default"
    return f"cpt-{scope}-{value}".replace("|", "-").replace(" ", "-")

def _cleanproof_default_template():
    now = _cleanproof_now()
    return {
        "template_id": "cpt-default",
        "scope": "default",
        "apartment_id": "",
        "apartment_type": "",
        "template_name": "Default cleaning photo checklist",
        "active": True,
        "created_at": now,
        "updated_at": now,
        "updated_by": "system",
        "slots": [
            {
                "slot_id": sid, "label_ar": ar, "label_en": en,
                "instructions_ar": "صوّر بوضوح بعد التنظيف.",
                "instructions_en": "Take a clear photo after cleaning.",
                "required": True, "allow_multiple": False,
                "display_order": i + 1, "active": True,
            }
            for i, (sid, ar, en) in enumerate(DEFAULT_CLEANING_PHOTO_SLOTS)
        ],
    }

def _cleanproof_ensure_default_template():
    t = _cleaning_photo_templates.get("cpt-default")
    if not isinstance(t, dict):
        t = _cleanproof_default_template()
        _cleaning_photo_templates["cpt-default"] = t
        _save_json("cleaning_photo_templates.json", _cleaning_photo_templates)
    return t

def _cleanproof_template_for(lid=None):
    _cleanproof_ensure_default_template()
    if lid is not None:
        tid = _cleanproof_template_id("apartment", lid)
        t = _cleaning_photo_templates.get(tid)
        if isinstance(t, dict) and t.get("active"):
            return t
    return _cleaning_photo_templates["cpt-default"]

def _cleanproof_snapshot_template(tpl):
    snap = json.loads(json.dumps(tpl, ensure_ascii=False))
    snap["snapshot_at"] = _cleanproof_now()
    return snap

def _cleanproof_code(name, lid):
    s = (name or "").split("|")[-1].strip() or str(lid)
    s = re.sub(r"[^A-Za-z0-9\u0600-\u06FF_-]+", "-", s).strip("-")
    return s[:30] or str(lid)

def _cleanproof_listing_name(lid):
    """Resolve a listing name without a live Hostaway call; photo proof must work offline."""
    try:
        rec = (_ls_get().get("listings") or {}).get(str(int(lid))) or {}
        nm = rec.get("internal_name") or rec.get("public_name") or ""
        if nm:
            return nm
    except Exception:
        pass
    try:
        return (_listings.get("map") or {}).get(int(lid)) or str(lid)
    except Exception:
        return str(lid)

def _cleanproof_report_id(lid, date_iso):
    code = _cleanproof_code(_cleanproof_listing_name(lid), lid)
    raw = f"{date_iso}-{lid}-{code}".encode("utf-8")
    return f"CLR-{str(date_iso).replace('-', '')}-{code}-{hashlib.sha1(raw).hexdigest()[:6]}"

def _cleanproof_audit(report_id, action, actor="", prev="", new="", detail="", extra=None):
    rep = _cleaning_reports.get(report_id) or {}
    row = {
        "timestamp": _cleanproof_now(),
        "report_id": report_id,
        "apartment": rep.get("apartment_name") or "",
        "action": action,
        "actor": (actor or "")[:80],
        "previous_status": prev or "",
        "new_status": new or "",
        "detail": (detail or "")[:500],
    }
    if isinstance(extra, dict):
        row.update({k: v for k, v in extra.items() if k not in ("token", "secret", "api_key")})
    _cleaning_report_audit.append(row)
    if len(_cleaning_report_audit) > 5000:
        del _cleaning_report_audit[:len(_cleaning_report_audit) - 5000]
    _save_json("cleaning_report_audit.json", _cleaning_report_audit)
    return row

def _cleanproof_report_photos(report_id):
    return [p for p in _cleaning_report_photos.values()
            if isinstance(p, dict) and p.get("report_id") == report_id and p.get("status") != "removed"]

def _cleanproof_recount(report):
    slots = [s for s in (report.get("checklist_snapshot") or {}).get("slots", []) if s.get("active")]
    required = [s for s in slots if s.get("required")]
    uploaded_slots = {p.get("slot_id") for p in _cleanproof_report_photos(report.get("report_id")) if p.get("status") == "uploaded"}
    report["required_slots_count"] = len(required)
    report["uploaded_required_slots_count"] = sum(1 for s in required if s.get("slot_id") in uploaded_slots)
    report["all_required_complete"] = report["uploaded_required_slots_count"] >= report["required_slots_count"]
    return report

def _cleanproof_fmt_clock(iso):
    """Local 'HH:MM' from an ISO timestamp; '—' if it can't be parsed."""
    try:
        return datetime.fromisoformat(iso).astimezone(TZ).strftime("%H:%M")
    except Exception:
        return "—"

def _cleanproof_fmt_duration(minutes):
    """Bilingual duration label from a minute count; '—' when unknown."""
    if minutes is None:
        return "—"
    if minutes < 60:
        return f"{minutes} دقيقة / {minutes} min"
    h, m = divmod(minutes, 60)
    return f"{h} س {m} د / {h}h {m}m"

def _cleanproof_timing(report):
    """Best-effort timing for one cleaning report:
    (started_iso, ended_iso, minutes, photo_count).
    started = first photo upload (fallback: report created_at);
    ended   = submit time (fallback: last photo upload, then updated_at);
    minutes = None when it can't be computed. Works on old reports too — it leans on the
    photo `uploaded_at` stamps that have always been recorded."""
    photos = [p for p in _cleanproof_report_photos(report.get("report_id"))
              if p.get("status") == "uploaded"]
    ups = sorted(p.get("uploaded_at") for p in photos if p.get("uploaded_at"))
    started = (ups[0] if ups else "") or report.get("created_at") or ""
    ended = report.get("submitted_at") or (ups[-1] if ups else "") or report.get("updated_at") or ""
    minutes = None
    try:
        if started and ended:
            delta = (datetime.fromisoformat(ended) - datetime.fromisoformat(started)).total_seconds() / 60.0
            if delta >= 0:
                minutes = int(round(delta))
    except Exception:
        minutes = None
    return started, ended, minutes, len(photos)

def _cleanproof_missing_required_labels(report, lang="ar"):
    """Manager/team-safe names for required photo slots that are still missing."""
    key = "label_en" if lang == "en" else "label_ar"
    uploaded = {
        p.get("slot_id")
        for p in _cleanproof_report_photos(report.get("report_id"))
        if p.get("status") == "uploaded"
    }
    missing = []
    for slot in (report.get("checklist_snapshot") or {}).get("slots", []):
        if not slot.get("active") or not slot.get("required"):
            continue
        sid = slot.get("slot_id")
        if sid not in uploaded:
            missing.append(slot.get(key) or slot.get("label_ar") or slot.get("label_en") or sid or "photo")
    return missing

def _cleanproof_get_or_create_report(lid, date_iso, actor="", route_id=""):
    with _cleanproof_lock:
        return _cleanproof_get_or_create_report_locked(lid, date_iso, actor, route_id)

def _cleanproof_get_or_create_report_locked(lid, date_iso, actor="", route_id=""):
    lid = int(lid)
    date_iso = str(date_iso or datetime.now(TZ).date().isoformat())[:10]
    rid = _cleanproof_report_id(lid, date_iso)
    report = _cleaning_reports.get(rid)
    if isinstance(report, dict):
        return _cleanproof_recount(report)
    name = _cleanproof_listing_name(lid)
    tpl = _cleanproof_template_for(lid)
    now = _cleanproof_now()
    report = {
        "report_id": rid, "date": date_iso, "route_id": route_id,
        "dispatch_item_id": _oc_key(lid, date_iso), "apartment_id": lid,
        "apartment_name": name, "apartment_code": _cleanproof_code(name, lid),
        "listing_id": lid, "cleaner_id": "", "cleaner_name": actor or "",
        "checklist_template_id": tpl.get("template_id"),
        "checklist_snapshot": _cleanproof_snapshot_template(tpl),
        "status": "draft", "required_slots_count": 0,
        "uploaded_required_slots_count": 0, "all_required_complete": False,
        "drive_folder_id": "", "drive_folder_url": "",
        "storage_provider": "google_drive" if _cleanproof_drive_configured() else "local_fallback",
        "storage_warning": "" if _cleanproof_drive_configured() else "Google Drive is not configured. Files are saved under STATE_DIR local storage.",
        "discord_review_channel_id": "", "discord_review_message_id": "",
        "manager_decision": "", "manager_notes": "",
        "approved_by": "", "approved_at": "", "rejected_by": "", "rejected_at": "",
        "reshoot_requested_by": "", "reshoot_requested_at": "",
        "issue_found": False, "issue_notes": "",
        "created_at": now, "updated_at": now,
    }
    _cleanproof_recount(report)
    _cleaning_reports[rid] = report
    _save_json("cleaning_reports.json", _cleaning_reports)
    _cleanproof_audit(rid, "report_created", actor, "", "draft")
    return report

def _cleanproof_safe_filename(slot_id, code, report_id, original_name):
    ext = os.path.splitext(original_name or "")[1].lower()
    if ext not in (".jpg", ".jpeg", ".png", ".webp", ".heic"):
        ext = ".jpg"
    stamp = datetime.now(TZ).strftime("%Y%m%d_%H%M%S")
    base = f"{slot_id}_{code}_{stamp}_{report_id}".replace("/", "-")
    return re.sub(r"[^A-Za-z0-9_.\-\u0600-\u06FF]+", "-", base)[:160] + ext

def _cleanproof_save_local(report, slot_id, filename, data, mime_type):
    root = os.path.join(STATE_DIR, "cleaning_photos", report["date"], report["report_id"])
    os.makedirs(root, exist_ok=True)
    path = os.path.join(root, filename)
    with open(path, "wb") as f:
        f.write(data)
    return {"provider": "local_fallback", "path": path, "url": ""}

def _cleanproof_purge_local_photos(retention_days=None):
    """Delete local cleaning-photo date-folders older than the retention window so the volume
    can't slowly fill (this is what filled /data and broke the whole bot on 2026-06-23). Photos
    are stored as STATE_DIR/cleaning_photos/<YYYY-MM-DD>/<report_id>/..., so we only ever remove
    whole date-folders whose NAME is a real calendar date older than the cutoff — non-date entries
    are never touched. Safe + idempotent; returns (folders_deleted, mb_reclaimed)."""
    days = CLEANING_PHOTO_RETENTION_DAYS if retention_days is None else retention_days
    base = os.path.join(STATE_DIR, "cleaning_photos")
    if days is None or days < 1 or not os.path.isdir(base):
        return (0, 0.0)
    cutoff = datetime.now(TZ).date() - timedelta(days=days)
    deleted, freed = 0, 0
    for name in os.listdir(base):
        folder = os.path.join(base, name)
        if not os.path.isdir(folder):
            continue
        try:
            folder_date = datetime.strptime(name, "%Y-%m-%d").date()
        except ValueError:
            continue                       # not a date-named folder → leave it alone
        if folder_date >= cutoff:
            continue
        try:
            for r, _d, files in os.walk(folder):
                for f in files:
                    try:
                        freed += os.path.getsize(os.path.join(r, f))
                    except OSError:
                        pass
            shutil.rmtree(folder)
            deleted += 1
        except Exception as e:
            print("cleaning-photo purge: could not remove", folder, "-", e)
    if deleted:
        print("cleaning photos: purged %d folder(s) older than %d days, reclaimed %.1f MB"
              % (deleted, days, freed / 1e6))
    return (deleted, round(freed / 1e6, 1))

def _cleanproof_drive_configured():
    return bool(CLEANING_DRIVE_ROOT_FOLDER_ID and
                (CLEANING_DRIVE_SERVICE_ACCOUNT_JSON or CLEANING_DRIVE_SERVICE_ACCOUNT_FILE or
                 CLEANING_DRIVE_OAUTH_TOKEN_JSON or CLEANING_DRIVE_OAUTH_TOKEN_FILE))

def _cleanproof_drive_url(file_id):
    return f"https://drive.google.com/file/d/{file_id}/view" if file_id else ""

def _cleanproof_drive_folder_url(folder_id):
    return f"https://drive.google.com/drive/folders/{folder_id}" if folder_id else ""

def _cleanproof_drive_escape(s):
    return str(s or "").replace("\\", "\\\\").replace("'", "\\'")

def _cleanproof_drive_creds_info():
    raw = CLEANING_DRIVE_SERVICE_ACCOUNT_JSON
    if not raw:
        return None
    try:
        if raw.startswith("{"):
            return json.loads(raw)
        return json.loads(base64.b64decode(raw).decode("utf-8"))
    except Exception as e:
        raise RuntimeError(f"invalid CLEANING_DRIVE_SERVICE_ACCOUNT_JSON: {e}")

def _cleanproof_drive_oauth_token_info():
    raw = CLEANING_DRIVE_OAUTH_TOKEN_JSON
    if not raw and CLEANING_DRIVE_OAUTH_TOKEN_FILE:
        with open(CLEANING_DRIVE_OAUTH_TOKEN_FILE, "r", encoding="utf-8") as f:
            raw = f.read().strip()
    if not raw:
        return None
    try:
        if raw.startswith("{"):
            return json.loads(raw)
        return json.loads(base64.b64decode(raw).decode("utf-8"))
    except Exception as e:
        raise RuntimeError(f"invalid CLEANING_DRIVE_OAUTH_TOKEN_JSON: {e}")

def _cleanproof_storage_error_message(err):
    raw = str(err or "")
    low = raw.lower()
    if "storage quota" in low or "storagequotaexceeded" in low:
        return ("Google Drive refused the upload because the service account has no personal storage. "
                "Use a Shared Drive folder as CLEANING_DRIVE_ROOT_FOLDER_ID and add the service account as Content manager.")
    if "file not found" in low or "not found" in low:
        return ("Google Drive cannot see the root folder. Check CLEANING_DRIVE_ROOT_FOLDER_ID and share that folder "
                "with the service account email as Content manager.")
    if "insufficient" in low or "forbidden" in low or "permission" in low or "403" in low:
        return ("Google Drive permission problem. Share the Drive folder with the service account email as Content manager, "
                "then restart Railway.")
    if "broken pipe" in low or "connection reset" in low:
        return ("Upload connection was interrupted while sending to Google Drive. Try one smaller photo; if it repeats, "
                "restart Railway and check the Drive folder permission.")
    if "invalid cleaning_drive_service_account_json" in low:
        return "The Railway service account JSON is invalid. Paste the full JSON key into CLEANING_DRIVE_SERVICE_ACCOUNT_JSON."
    if "invalid cleaning_drive_oauth_token_json" in low or "refresh token" in low:
        return "The Google Drive OAuth token is invalid or expired. Regenerate CLEANING_DRIVE_OAUTH_TOKEN_JSON."
    return raw[:300] or "Storage upload failed"

def _cleanproof_get_drive_service():
    global _cleaning_drive_service
    if _cleaning_drive_service is not None:
        return _cleaning_drive_service
    if not _cleanproof_drive_configured():
        return None
    try:
        from google.oauth2 import service_account
        from google.oauth2.credentials import Credentials
        from googleapiclient.discovery import build
    except Exception as e:
        raise RuntimeError(f"Google Drive libraries missing: {e}")
    scopes = ["https://www.googleapis.com/auth/drive"]
    token_info = _cleanproof_drive_oauth_token_info()
    if token_info:
        creds = Credentials.from_authorized_user_info(token_info, scopes=scopes)
    else:
        info = _cleanproof_drive_creds_info()
        if info:
            creds = service_account.Credentials.from_service_account_info(info, scopes=scopes)
        else:
            creds = service_account.Credentials.from_service_account_file(
                CLEANING_DRIVE_SERVICE_ACCOUNT_FILE, scopes=scopes)
    _cleaning_drive_service = build("drive", "v3", credentials=creds, cache_discovery=False)
    return _cleaning_drive_service

def _cleanproof_drive_find_or_create_folder(service, parent_id, name):
    safe_name = _cleanproof_drive_escape(name)
    safe_parent = _cleanproof_drive_escape(parent_id)
    q = ("mimeType='application/vnd.google-apps.folder' and trashed=false "
         f"and name='{safe_name}' and '{safe_parent}' in parents")
    found = service.files().list(q=q, fields="files(id,name)", pageSize=1,
                                 supportsAllDrives=True, includeItemsFromAllDrives=True).execute()
    files = found.get("files") or []
    if files:
        return files[0]["id"]
    body = {"name": name, "mimeType": "application/vnd.google-apps.folder", "parents": [parent_id]}
    created = service.files().create(body=body, fields="id", supportsAllDrives=True).execute()
    return created["id"]

def _cleanproof_report_drive_folder(report):
    if report.get("drive_folder_id"):
        return report["drive_folder_id"]
    service = _cleanproof_get_drive_service()
    if service is None:
        return ""
    date_folder = str(report.get("date") or datetime.now(TZ).date().isoformat())
    apt = (report.get("apartment_name") or report.get("apartment_code") or str(report.get("apartment_id"))).strip()
    rid = report.get("report_id") or "report"
    root = CLEANING_DRIVE_ROOT_FOLDER_ID
    yid = _cleanproof_drive_find_or_create_folder(service, root, "Oujact Cleaning Reports")
    did = _cleanproof_drive_find_or_create_folder(service, yid, date_folder)
    aid = _cleanproof_drive_find_or_create_folder(service, did, apt[:120] or "Apartment")
    fid = _cleanproof_drive_find_or_create_folder(service, aid, rid[:120])
    report["drive_folder_id"] = fid
    report["drive_folder_url"] = _cleanproof_drive_folder_url(fid)
    report["storage_provider"] = "google_drive"
    report["storage_warning"] = ""
    report["updated_at"] = _cleanproof_now()
    _cleaning_reports[report["report_id"]] = report
    _save_json("cleaning_reports.json", _cleaning_reports)
    _cleanproof_audit(report["report_id"], "drive_folder_created", "bot",
                      report.get("status"), report.get("status"), fid)
    return fid

def _cleanproof_save_drive(report, slot_id, filename, data, mime_type):
    from googleapiclient.http import MediaIoBaseUpload
    service = _cleanproof_get_drive_service()
    folder_id = _cleanproof_report_drive_folder(report)
    if service is None or not folder_id:
        raise RuntimeError("Google Drive is not configured")
    media = MediaIoBaseUpload(io.BytesIO(data), mimetype=mime_type or "image/jpeg", resumable=True)
    body = {"name": filename, "parents": [folder_id],
            "description": f"Oujact cleaning proof {report.get('report_id')} {slot_id}"}
    created = service.files().create(body=body, media_body=media,
                                     fields="id,webViewLink", supportsAllDrives=True).execute()
    file_id = created.get("id", "")
    return {"provider": "google_drive", "path": "", "url": created.get("webViewLink") or _cleanproof_drive_url(file_id),
            "file_id": file_id, "folder_id": folder_id, "folder_url": report.get("drive_folder_url") or _cleanproof_drive_folder_url(folder_id)}

def _cleanproof_drive_invalidate():
    """Drop the cached Drive client so a rotated Google key works without a restart."""
    global _cleaning_drive_service
    _cleaning_drive_service = None

def _cleanproof_save_photo(report, slot_id, filename, data, mime_type):
    if _cleanproof_drive_configured():
        try:
            return _cleanproof_save_drive(report, slot_id, filename, data, mime_type)
        except Exception as e:
            # Auth errors (rotated/revoked key) -> invalidate the cached client + retry
            # once with fresh credentials before deciding.
            status = getattr(getattr(e, "resp", None), "status", None)
            if status in (401, 403) or "invalid_grant" in str(e).lower():
                print("drive auth error — invalidating cached client and retrying:", e)
                _cleanproof_drive_invalidate()
                try:
                    return _cleanproof_save_drive(report, slot_id, filename, data, mime_type)
                except Exception as e2:
                    e = e2
            # Drive is configured but the upload still failed — most often a service account
            # with no My-Drive quota (storageQuotaExceeded) or a folder/permission problem.
            # NEVER block the cleaner on a storage misconfig: save the photo on the volume so
            # the upload always succeeds, and flag the report so the owner can fix the Drive
            # (Shared Drive) config later. Photos are served + attached to the Discord review
            # card from the local copy either way (_cleanproof_photo_bytes reads local first).
            print("drive upload failed — saving photo locally instead:", e)
            try:
                report["storage_provider"] = "local_fallback"
                report["storage_warning"] = _cleanproof_storage_error_message(e)
                _cleanproof_audit(report.get("report_id"), "drive_upload_fallback_local", "bot",
                                  report.get("status"), report.get("status"),
                                  _cleanproof_storage_error_message(e), {"raw_error": str(e)[:300]})
            except Exception:
                pass
            return _cleanproof_save_local(report, slot_id, filename, data, mime_type)
    return _cleanproof_save_local(report, slot_id, filename, data, mime_type)

def _cleanproof_photo_view(photo):
    return {
        "photo_id": photo.get("photo_id"), "report_id": photo.get("report_id"),
        "slot_id": photo.get("slot_id"), "file_name": photo.get("file_name"),
        "mime_type": photo.get("mime_type"), "file_size": photo.get("file_size"),
        "uploaded_at": photo.get("uploaded_at"), "uploaded_by": photo.get("uploaded_by"),
        "drive_file_id": photo.get("drive_file_id"), "drive_file_url": photo.get("drive_file_url"),
        "thumbnail_url": photo.get("thumbnail_url"), "storage_url": photo.get("storage_url"),
        "status": photo.get("status"), "error_message": photo.get("error_message"),
    }

def _cleanproof_report_view(report, include_photos=True):
    r = _cleanproof_recount(report)
    out = {k: v for k, v in r.items() if k != "checklist_snapshot"}
    out["checklist"] = r.get("checklist_snapshot") or {}
    if include_photos:
        out["photos"] = [_cleanproof_photo_view(p) for p in _cleanproof_report_photos(r.get("report_id"))]
    out["audit"] = [a for a in _cleaning_report_audit if a.get("report_id") == r.get("report_id")][-80:]
    return out

# Feature 5 — priority tiers (lower = first). Operational urgency ALWAYS beats distance;
# ETA only reorders within the same tier.
_OUJACT_REASON = {
    "guest_confirmed": ("الضيف أكد الخروج", "Guest confirmed checkout"),
    "checkin_today":   ("فيه دخول اليوم", "Check-in today"),
    "checkout_passed": ("وقت الخروج عدى", "Checkout passed"),
    "missing_report":  ("التقرير ناقص", "Missing report"),
    "urgent":          ("بلاغ عاجل", "Urgent issue"),
    "late_checkout":   ("خروج متأخر معتمد", "Late checkout approved"),
    "inside":          ("الضيف باقي داخل", "Guest still inside"),
    "flexible":        ("مرن", "Flexible"),
}
def _oujact_priority(it, cstate, done, now):
    """Returns (tier, reason_code). Lower tier = dispatched first."""
    passed = it["checkout"] <= now
    if cstate == "inside":
        return (95, "inside")                       # blocker — last
    if cstate == "late_checkout":
        return (80, "late_checkout")
    if cstate in ("guest_confirmed", "checkout_button", "airbnb_confirmed"):
        return (0 if it["checkin_today"] else 1, "guest_confirmed")
    if it["checkin_today"]:
        return (1, "checkin_today")                 # same-day check-in — near the top regardless of distance
    if passed and not done:
        return (2, "missing_report")
    if passed:
        return (3, "checkout_passed")
    return (6, "flexible")

def _oujact_dispatch_plan(today_only=True, assigned=None):
    """Today's prioritized Oujact dispatch plan (priority tier first; within-tier by check-in
    time then checkout). Includes config, checkout state, status, reason chips, missing-map flag.
    Pass `assigned` (a set of listing ids) to scope the plan to ONE cleaning team."""
    items = fetch_oujact_turnovers(assigned=assigned)
    today = datetime.now(TZ).date().isoformat()
    if today_only:
        items = [it for it in items if it["checkout_date"] == today]
    now = datetime.now(TZ)
    store = _ls_get()["listings"]
    plan = []
    for it in items:
        lid, d = it["lid"], it["checkout_date"]
        cfg = store.get(str(lid)) or {}
        cstate = _oujact_checkout_state(lid, d)
        if cstate == "unknown" and it["checkout"] <= now:
            cstate = "checkout_passed"              # official time passed (not a guest signal)
        last = _oujact_latest_status(lid, d)
        done = (last or {}).get("action") in ("done",)
        tier, rc = _oujact_priority(it, _oujact_checkout_state(lid, d), done, now)
        maps = (cfg.get("maps_link") or "").strip()
        parsed_ll = _extract_latlng(maps)
        lat, lng = parsed_ll if parsed_ll else (cfg.get("lat"), cfg.get("lng"))
        plan.append({
            "lid": lid, "name": it["listing"], "date": d,
            "district": cfg.get("group") or cfg.get("address") or "",
            "checkout_time": it["checkout"].strftime("%H:%M"),
            "checkout_passed": it["checkout"] <= now,
            "checkin_today": it["checkin_today"],
            "checkin_time": (it["checkin_dt"].strftime("%H:%M") if it.get("checkin_dt") else None),
            "checkout_state": cstate, "status": (last or {}).get("action"),
            "tier": tier, "reason_code": rc,
            "reason_ar": _OUJACT_REASON.get(rc, ("", ""))[0],
            "reason_en": _OUJACT_REASON.get(rc, ("", ""))[1],
            "maps_link": maps, "directions_url": cfg.get("directions_url"),
            "lat": lat, "lng": lng, "missing_maps": not maps,
            "clean_min": cfg.get("clean_min") or OUJACT_CLEAN_MIN,
            "clean_max": cfg.get("clean_max") or OUJACT_CLEAN_MAX,
            "park_buffer": cfg.get("park_buffer") if cfg.get("park_buffer") is not None else OUJACT_PARK_BUFFER,
            "access_notes": cfg.get("access_notes") or "", "parking_notes": cfg.get("parking_notes") or "",
            "discord_channel": cfg.get("discord_channel") or "",
        })
    # Merge manager-added MANUAL cleaning tasks for the same day (so the cleaning team's route
    # page + the dashboard both surface them). A manual task on a unit that already checks out
    # today just annotates that turnover with the chosen cleaning type/note.
    have = {p["lid"]: p for p in plan}
    lmap = get_listings_map() or {}
    for tk in _clean_tasks_for(today, assigned):
        lid = tk["lid"]
        if lid in have:
            have[lid]["manual_type"] = tk["ctype"]
            have[lid]["manual_note"] = tk.get("note") or ""
            have[lid]["task_id"] = tk["id"]
            continue
        cfg = store.get(str(lid)) or {}
        maps = (cfg.get("maps_link") or "").strip()
        parsed_ll = _extract_latlng(maps)
        lat, lng = parsed_ll if parsed_ll else (cfg.get("lat"), cfg.get("lng"))
        last = _oujact_latest_status(lid, today)
        item = {
            "lid": lid, "name": lmap.get(lid) or cfg.get("internal_name") or f"unit-{lid}", "date": today,
            "district": cfg.get("group") or cfg.get("address") or "",
            "checkout_time": "—", "checkout_passed": True,
            "checkin_today": False, "checkin_time": None,
            "checkout_state": "manual", "status": (last or {}).get("action"),
            "tier": 2, "reason_code": "manual",
            "reason_ar": _clean_type_label(tk["ctype"], "ar"),
            "reason_en": _clean_type_label(tk["ctype"], "en"),
            "maps_link": maps, "directions_url": cfg.get("directions_url"),
            "lat": lat, "lng": lng, "missing_maps": not maps,
            "clean_min": cfg.get("clean_min") or OUJACT_CLEAN_MIN,
            "clean_max": cfg.get("clean_max") or OUJACT_CLEAN_MAX,
            "park_buffer": cfg.get("park_buffer") if cfg.get("park_buffer") is not None else OUJACT_PARK_BUFFER,
            "access_notes": cfg.get("access_notes") or "", "parking_notes": cfg.get("parking_notes") or "",
            "discord_channel": cfg.get("discord_channel") or "",
            "manual": True, "manual_type": tk["ctype"], "manual_note": tk.get("note") or "", "task_id": tk["id"],
        }
        plan.append(item)
        have[lid] = item                 # a 2nd manual task for the same unit annotates, never duplicates
    # Defensive: exactly one row per apartment (collapse any same-lid duplicates that slipped through).
    seen_lid, uniq = set(), []
    for p in plan:
        if p["lid"] in seen_lid:
            continue
        seen_lid.add(p["lid"])
        uniq.append(p)
    plan = uniq
    plan.sort(key=lambda p: (p["tier"], p.get("checkin_time") or "99:99", p["checkout_time"]))
    for i, p in enumerate(plan):
        p["rank"] = i + 1
    return plan

def _clean_ops_snapshot(team_lids):
    """Per-unit cleaning STAGE for today across a set of listing ids (reuses the dispatch plan,
    which already merges manual tasks). Stage ∈ to_clean | in_progress | review | approved | redo.
    Drives the Cleaning-Teams operations view + the 3-step pipeline counts."""
    today = datetime.now(TZ).date().isoformat()
    plan = _oujact_dispatch_plan(True, team_lids)
    units = []
    counts = {"to_clean": 0, "in_progress": 0, "review": 0, "approved": 0, "redo": 0, "urgent": 0, "total": 0}
    for p in plan:
        lid = p["lid"]
        rep = _cleaning_reports.get(_cleanproof_report_id(lid, today))
        rep_status = (rep or {}).get("status") or ""
        action = (_oujact_latest_status(lid, today) or {}).get("action") or ""
        if rep_status == "manager_approved":
            stage = "approved"
        elif rep_status in ("manager_rejected", "needs_reshoot"):
            stage = "redo"
        elif rep_status in ("pending_manager_review", "submitted_for_review", "issue_found"):
            stage = "review"
        elif action in ("started", "arrived"):
            stage = "in_progress"
        elif action == "done":
            stage = "in_progress"
        else:
            stage = "to_clean"
        counts[stage] = counts.get(stage, 0) + 1
        counts["total"] += 1
        if p.get("checkin_today"):
            counts["urgent"] += 1
        units.append({
            "lid": lid, "name": p["name"], "stage": stage,
            "checkout_time": p.get("checkout_time"), "checkout_passed": p.get("checkout_passed"),
            "checkin_today": p.get("checkin_today"), "checkin_time": p.get("checkin_time"),
            "early": _clean_early_departure_active(lid),
            "manual": bool(p.get("manual")), "manual_type": p.get("manual_type") or "",
            "task_id": p.get("task_id") or "",
            "reason_ar": p.get("reason_ar"), "reason_en": p.get("reason_en"),
            "status": action,
            "report_id": (rep or {}).get("report_id") or "",
            "report_status": rep_status,
            "photos_done": (rep or {}).get("uploaded_required_slots_count") or 0,
            "photos_req": (rep or {}).get("required_slots_count") or 0,
            "tier": p.get("tier"),
        })
    return {"date": today, "units": units, "counts": counts}

def _clean_center_setup_missing(lid, plan_item=None):
    """Manager-facing setup gaps for cleaning ops. Keep this small: daily screens only
    need to know whether the apartment is operationally ready for team routing."""
    try:
        lid = int(lid)
    except (TypeError, ValueError):
        return ["missing_apartment"]
    rec = (_ls_get().get("listings") or {}).get(str(lid)) or {}
    p = plan_item or {}
    missing = []
    if not rec.get("cleaning_team"):
        missing.append("team")
    maps = (rec.get("maps_link") or p.get("maps_link") or "").strip()
    if not maps:
        missing.append("map")
    if not (rec.get("access_notes") or p.get("access_notes") or "").strip():
        missing.append("access")
    if not (rec.get("parking_notes") or p.get("parking_notes") or "").strip():
        missing.append("parking")
    parsed_ll = _extract_latlng(maps)
    if not parsed_ll and not (rec.get("lat") and rec.get("lng")) and not (p.get("lat") and p.get("lng")):
        missing.append("coords")
    return missing

def _clean_center_next_action(stage, report_id=""):
    if stage == "to_clean":
        return "open_team_link"
    if stage == "in_progress":
        return "track_progress"
    if stage == "review":
        return "review_photos" if report_id else "details"
    if stage == "approved":
        return "view_report" if report_id else "details"
    if stage == "redo":
        return "follow_reshoot"
    return "details"

def _clean_center_issue_type(unit, latest, report):
    action = (latest or {}).get("action") or ""
    if action == "guest_inside":
        return "guest_inside"
    if action == "issue":
        note = ((latest or {}).get("note") or "").lower()
        if "access" in note or "دخول" in note or "مفتاح" in note:
            return "no_access"
        if "damage" in note or "ضرر" in note or "كسر" in note:
            return "damage"
        if "supply" in note or "مستلزم" in note or "ناقص" in note:
            return "supplies"
        if "map" in note or "location" in note or "عنوان" in note:
            return "cannot_find"
        return "other"
    if report and report.get("issue_found"):
        return "damage" if report.get("issue_notes") else "other"
    if unit.get("stage") == "redo":
        return "reshoot"
    return ""

def _clean_center_snapshot():
    """Cleaning Command Center V2.
    Dashboard remains source of truth: route actions + cleaning reports are reconciled
    into one daily manager workflow without changing pricing, finance, or Hostaway data."""
    today = datetime.now(TZ).date().isoformat()
    now_iso = datetime.now(TZ).isoformat(timespec="seconds")
    all_lids = oujact_listing_ids()
    plan = _oujact_dispatch_plan(True, all_lids)
    plan_by_lid = {p.get("lid"): p for p in plan}
    snap = _clean_ops_snapshot(all_lids)
    teams = []
    team_by_lid = {}
    for t in sorted(_cleaning_teams.values(), key=lambda x: (x.get("name") or "", x.get("created_at") or "")):
        tv = _ct_team_view(t)
        team_snap = _clean_ops_snapshot(set(tv.get("lids") or []))
        tv["counts"] = team_snap.get("counts") or {}
        teams.append(tv)
        for lid in tv.get("lids") or []:
            team_by_lid[int(lid)] = {"id": tv["id"], "name": tv.get("name") or "", "link": tv.get("link") or ""}

    jobs = []
    setup_health = []
    for u in snap.get("units") or []:
        lid = u.get("lid")
        p = plan_by_lid.get(lid) or {}
        latest = _oujact_latest_status(lid, today) or {}
        report = _cleaning_reports.get(u.get("report_id") or _cleanproof_report_id(lid, today)) or {}
        team = team_by_lid.get(int(lid)) if lid is not None and str(lid).isdigit() else {}
        missing = _clean_center_setup_missing(lid, p)
        if missing:
            setup_health.append({"lid": lid, "name": u.get("name") or p.get("name") or str(lid),
                                 "missing": missing, "team": team.get("name") or ""})
        issue_type = _clean_center_issue_type(u, latest, report)
        stage = u.get("stage") or "to_clean"
        late = bool((stage in ("to_clean", "in_progress") and p.get("checkout_passed")) or stage == "redo")
        urgent = bool(u.get("checkin_today") or u.get("early") or issue_type or late)
        reason_keys = []
        if u.get("early"):
            reason_keys.append("early_departure")
        if u.get("checkin_today"):
            reason_keys.append("same_day")
        if late:
            reason_keys.append("late")
        if issue_type:
            reason_keys.append("issue")
        if missing:
            reason_keys.append("missing_setup")
        jobs.append({
            "lid": lid, "name": u.get("name") or p.get("name") or str(lid),
            "date": today, "stage": stage, "team": team,
            "checkout_time": u.get("checkout_time") or p.get("checkout_time"),
            "checkout_passed": bool(p.get("checkout_passed")),
            "checkin_today": bool(u.get("checkin_today")),
            "checkin_time": u.get("checkin_time") or p.get("checkin_time"),
            "early": bool(u.get("early")), "manual": bool(u.get("manual")),
            "manual_type": u.get("manual_type") or p.get("manual_type") or "",
            "priority_reason_ar": u.get("reason_ar") or p.get("reason_ar") or "",
            "priority_reason_en": u.get("reason_en") or p.get("reason_en") or "",
            "reason_keys": reason_keys, "urgent": urgent, "late": late,
            "setup_missing": missing, "issue_type": issue_type,
            "issue_note": (latest.get("note") or report.get("issue_notes") or "")[:240],
            "last_action": latest.get("action") or "",
            "last_action_at": latest.get("ts") or report.get("updated_at") or "",
            "report_id": u.get("report_id") or report.get("report_id") or "",
            "report_status": u.get("report_status") or report.get("status") or "",
            "photos_done": int(u.get("photos_done") or report.get("uploaded_required_slots_count") or 0),
            "photos_req": int(u.get("photos_req") or report.get("required_slots_count") or 0),
            "next_action": _clean_center_next_action(stage, u.get("report_id") or report.get("report_id") or ""),
            "maps_link": p.get("maps_link") or "", "directions_url": p.get("directions_url") or "",
        })

    jobs.sort(key=lambda j: (
        0 if j.get("urgent") else 1,
        {"redo": 0, "review": 1, "to_clean": 2, "in_progress": 3, "approved": 4}.get(j.get("stage"), 5),
        j.get("checkin_time") or "99:99",
        j.get("checkout_time") or "99:99",
    ))
    summary = {
        "total": len(jobs),
        "same_day": sum(1 for j in jobs if j.get("checkin_today")),
        "needs_cleaning": sum(1 for j in jobs if j.get("stage") == "to_clean"),
        "in_progress": sum(1 for j in jobs if j.get("stage") == "in_progress"),
        "pending_review": sum(1 for j in jobs if j.get("stage") == "review"),
        "approved": sum(1 for j in jobs if j.get("stage") == "approved"),
        "needs_reshoot": sum(1 for j in jobs if j.get("stage") == "redo"),
        "late_risk": sum(1 for j in jobs if j.get("late") or j.get("urgent")),
        "missing_setup": len(set(str(s.get("lid")) for s in setup_health)),
        "issues": sum(1 for j in jobs if j.get("issue_type")),
    }
    return {
        "ok": True, "date": today, "generated_at": now_iso,
        "summary": summary, "jobs": jobs,
        "reviews": [j for j in jobs if j.get("stage") == "review"],
        "issues": [j for j in jobs if j.get("issue_type") or j.get("stage") == "redo"],
        "teams": teams, "setup_health": setup_health[:200],
        "storage": {"provider": "google_drive" if _cleanproof_drive_configured() else "local_fallback",
                    "drive_configured": _cleanproof_drive_configured()},
    }

def _oujact_route_eta(start, plan):
    """Leg-by-leg ETA (minutes) in plan order, traffic-aware, ONLY when a Google key + the
    start coords + each destination's coords are available. Never fabricates — returns
    {available, reason, legs:[min|None], total_drive_min} and the page falls back gracefully."""
    if not GOOGLE_MAPS_API_KEY:
        return {"available": False, "reason": "no_api_key", "legs": [], "total_drive_min": None}
    s = _extract_latlng(start) if isinstance(start, str) else start
    if not s:
        return {"available": False, "reason": "no_start_coords", "legs": [], "total_drive_min": None}
    legs, total, ok_any = [], 0, False
    origin = s
    try:
        for p in plan:
            if p.get("lat") is None or p.get("lng") is None:
                legs.append(None); continue
            body = {"origins": [{"waypoint": {"location": {"latLng": {"latitude": origin[0], "longitude": origin[1]}}}}],
                    "destinations": [{"waypoint": {"location": {"latLng": {"latitude": p["lat"], "longitude": p["lng"]}}}}],
                    "travelMode": "DRIVE", "routingPreference": "TRAFFIC_AWARE"}
            r = requests.post("https://routes.googleapis.com/distanceMatrix/v2:computeRouteMatrix",
                              headers={"X-Goog-Api-Key": GOOGLE_MAPS_API_KEY,
                                       "X-Goog-FieldMask": "originIndex,destinationIndex,duration,condition",
                                       "Content-Type": "application/json"}, json=body, timeout=20)
            r.raise_for_status()
            rows = r.json() if isinstance(r.json(), list) else [r.json()]
            dur = None
            for row in rows:
                ds = str(row.get("duration") or "").rstrip("s")
                if ds.isdigit():
                    dur = round(int(ds) / 60)
            legs.append(dur)
            if dur is not None:
                total += dur; ok_any = True
            origin = (p["lat"], p["lng"])
        return {"available": ok_any, "reason": ("ok" if ok_any else "no_legs"),
                "legs": legs, "total_drive_min": (total if ok_any else None)}
    except requests.HTTPError as e:
        resp = getattr(e, "response", None)
        status = getattr(resp, "status_code", None)
        reason = "api_error"
        if status in (401, 403):
            reason = "api_key_rejected"
        elif status == 429:
            reason = "api_rate_limited"
        elif status and status >= 500:
            reason = "api_temporary_error"
        body = ""
        try:
            body = (resp.text or "")[:220] if resp is not None else ""
        except Exception:
            body = ""
        print("oujact ETA error:", status or "", body or e)
        return {"available": False, "reason": reason, "legs": [], "total_drive_min": None}
    except Exception as e:
        print("oujact ETA error:", e)
        return {"available": False, "reason": "api_error", "legs": [], "total_drive_min": None}

@tasks.loop(minutes=POLL_MINUTES)
async def poll_loop():
    try:
        await sync_checkouts()
    except Exception as e:
        print("poll error:", e)
    try:
        await sync_oujact_turnovers()      # keep OujaCT channels current between daily runs
    except Exception as e:
        print("oujact poll error:", e)

