def _exp_has_real_hostaway_ref(exp):
    ref = exp.get("hostaway_ref") or exp.get("hostaway_expense_id")
    return bool(ref) and str(ref) not in ("DRYRUN", "ok", "existing", "None", "none", "FILE")

def _exp_posted_to_hostaway(exp):
    """True when an expense is genuinely recorded in Hostaway and must therefore appear
    on the owner statement. 'verified' (hostaway_verified) is the gold signal — but an
    expense the owner already exported, that carries a REAL Hostaway expense id, is just
    as real money on the unit. The secondary 'verify' re-fetch is fragile (the Hostaway
    expense list is paginated/capped and may not echo our reference, plus read-after-write
    lag), so its failure must NOT silently hide a posted expense from the owner — that was
    the 'المصاريف 0' bug. Dry-run / the legacy 'ok' sentinel / failed / not-yet-sent
    never count."""
    if exp.get("hostaway_verified"):
        return True
    if not _exp_has_real_hostaway_ref(exp):
        return False
    return _exp_canonical_status(exp) in ("verified", "sent_unverified", "stale_pending")

def _exp_hostaway_item_id(item):
    if not isinstance(item, dict):
        return None
    for k in ("id", "expenseId", "expense_id"):
        v = item.get(k)
        if v not in (None, ""):
            return str(v)
    return None

def _exp_hostaway_item_amount(item):
    try:
        return round(abs(float((item or {}).get("amount"))), 2)
    except Exception:
        return None

def _exp_hostaway_item_date(item):
    return str((item or {}).get("expenseDate") or (item or {}).get("date") or "")[:10]

def _exp_hostaway_item_lid(item):
    return (item or {}).get("listingMapId") or (item or {}).get("listingId") or (item or {}).get("listing_id")

def _exp_fetch_hostaway_one(hostaway_ref):
    """Best-effort direct lookup by Hostaway expense id. Returns (item, ok, error).
    This is intentionally optional because some Hostaway deployments only support
    list endpoints for expenses; callers fall back to the bulk fetch."""
    hid = str(hostaway_ref or "").strip()
    if not hid or hid in ("DRYRUN", "ok", "existing", "None", "none"):
        return None, False, "no_real_hostaway_ref"
    try:
        data = api_get(f"{EXPENSE_HOSTAWAY_PATH}/{hid}")
        if isinstance(data, dict):
            res = data.get("result")
            if isinstance(res, dict):
                return res, True, None
            if isinstance(res, list) and res:
                return res[0], True, None
            return data, True, None
        if isinstance(data, list) and data:
            return data[0], True, None
        return None, True, "empty_response"
    except Exception as e:
        return None, False, str(e)[:300]

def _exp_match_hostaway_item(exp, hostaway_items=None, direct_item=None):
    """Conservative Hostaway matcher for V2 reconciliation.
    High-confidence verification needs a direct id/ref match plus amount, or a
    stored Hostaway id found in the list. Key-only matches are duplicate evidence."""
    items = hostaway_items or []
    ref = str(exp.get("ref") or "")
    ha_ref = str(exp.get("hostaway_ref") or exp.get("hostaway_expense_id") or "")
    want_amt = None
    try:
        want_amt = round(abs(float(exp.get("amount") or 0)), 2)
    except Exception:
        pass
    key = _exp_ha_key(exp.get("listing_id"), exp.get("amount"), exp.get("expense_date"))

    def amount_ok(item):
        got = _exp_hostaway_item_amount(item)
        return got is not None and want_amt is not None and abs(got - want_amt) < 1

    def pack(item, method, confidence, reason=""):
        return {
            "present": True,
            "item": item,
            "id": _exp_hostaway_item_id(item),
            "method": method,
            "confidence": confidence,
            "reason": reason,
        }

    if isinstance(direct_item, dict) and amount_ok(direct_item):
        return pack(direct_item, "hostaway_id", 0.97)
    if isinstance(direct_item, dict):
        return pack(direct_item, "hostaway_id", 0.55, "amount_mismatch")

    for item in items:
        try:
            raw = json.dumps(item, ensure_ascii=False)
        except Exception:
            raw = str(item)
        if ref and ref in raw:
            if amount_ok(item):
                return pack(item, "reference", 0.98)
            return pack(item, "reference", 0.55, "amount_mismatch")

    for item in items:
        item_id = _exp_hostaway_item_id(item)
        if ha_ref and item_id and item_id == ha_ref and amount_ok(item):
            return pack(item, "hostaway_id", 0.96)

    for item in items:
        lid = _exp_hostaway_item_lid(item)
        item_key = _exp_ha_key(lid, item.get("amount"), _exp_hostaway_item_date(item))
        if key and item_key == key:
            return pack(item, "property_amount_date", 0.82)

    return {"present": False, "item": None, "id": None, "method": "", "confidence": 0.0, "reason": "not_found"}

def _exp_v2_validation_errors(exp):
    errors = []
    if not (exp.get("apartment") or "").strip():
        errors.append("missing_apartment")
    if exp.get("listing_id") is None:
        errors.append("missing_hostaway_property")
    try:
        amt = float(exp.get("amount"))
        if amt <= 0:
            errors.append("missing_amount")
    except Exception:
        errors.append("missing_amount")
    if not (exp.get("expense_date") or "").strip():
        errors.append("missing_date")
    if not (exp.get("category") or "").strip():
        errors.append("missing_category")
    if exp.get("primary_reason") == "duplicate" or exp.get("discrepancy") == "duplicate":
        errors.append("duplicate_suspected")
    if exp.get("split_error"):
        errors.append(exp.get("split_error"))
    return list(dict.fromkeys(errors))

def _exp_v2_source_state(exp, match):
    sub_id = str(exp.get("submission_id") or "")
    return {
        "sheet_state": {
            "present_in_sheet": sub_id.startswith("gs-"),
            "sheet_row_id": sub_id if sub_id.startswith("gs-") else "",
            "sheet_last_seen_at": exp.get("submitted_at") or exp.get("created_at") or "",
            "parsed_ok": not bool(_exp_v2_validation_errors(exp)),
            "parse_errors": _exp_v2_validation_errors(exp),
            "sheet_raw_data": {
                "apartment": exp.get("apartment"),
                "amount": exp.get("amount"),
                "date": exp.get("expense_date"),
                "submitter": exp.get("submitter"),
            } if sub_id.startswith("gs-") else {},
        },
        "dashboard_state": {
            "present_in_dashboard": True,
            "local_reference": exp.get("ref") or "",
            "local_status": _exp_canonical_status(exp),
            "local_last_updated": exp.get("updated_at") or exp.get("created_at") or "",
            "local_attempt_count": int(exp.get("retry_count") or 0),
            "local_error": exp.get("error") or exp.get("status_reason") or "",
            "local_parent_id": exp.get("split_parent_id") or "",
            "local_child_ids": exp.get("split_child_ids") or [],
        },
        "hostaway_state": {
            "present_in_hostaway": bool(match.get("present") and match.get("confidence", 0) >= 0.82),
            "hostaway_expense_id": match.get("id") or "",
            "hostaway_last_checked_at": _exp_now().isoformat(timespec="seconds"),
            "hostaway_match_method": match.get("method") or "",
            "match_method": match.get("method") or "",
            "hostaway_match_confidence": match.get("confidence") or 0.0,
            "match_confidence": match.get("confidence") or 0.0,
            "hostaway_payload_or_response_summary": _exp_safe_hostaway_summary(match.get("item")),
            "hostaway_error": match.get("reason") if match.get("reason") not in ("not_found", "") else "",
        },
    }

def _exp_safe_hostaway_summary(item):
    if not isinstance(item, dict):
        return {}
    keep = ("id", "expenseId", "listingMapId", "listingId", "amount", "expenseDate",
            "date", "categoryName", "concept", "name", "reference", "description")
    return {k: item.get(k) for k in keep if k in item}

def _exp_v2_status_for_exp(exp, match):
    canon = _exp_canonical_status(exp)
    real_ref = _exp_has_real_hostaway_ref(exp)
    validation_errors = _exp_v2_validation_errors(exp)
    matched = bool(match.get("present") and match.get("confidence", 0) >= 0.82)
    high_conf = bool(match.get("present") and match.get("confidence", 0) >= 0.95)

    if exp.get("split_role") == "parent" or exp.get("status") == "split_parent":
        return "split_parent", "split_parent", "none", False, "archive_parent"
    if canon == "archived":
        return "archived", "archived", "none", False, "none"
    if matched and (high_conf or real_ref):
        return "verified", "hostaway_verified", "archive_if_done", False, "mark_verified"
    if matched:
        return "duplicate", "duplicate_suspected", "skip_duplicate", False, "skip_duplicate"
    if real_ref:
        return "sent_not_verified", "hostaway_id_not_found", "verify_hostaway_id", False, "manual_verify"
    if canon in ("queued", "sending"):
        return "in_progress", canon, "wait_or_open_log", False, "wait"
    if canon == "stale_pending":
        if exp.get("previous_status") in ("queued", "sending"):
            return "failed", "queue_stuck", "retry_temporary_failure", False, "retry_temporary"
        return "sent_not_verified", "sent_pending_verify", "verify_sent", False, "verify_sent"
    if canon == "failed":
        return "failed", exp.get("error_class") or "export_failed", "retry_temporary_failure", False, "retry_temporary"
    if validation_errors:
        return "needs_review", validation_errors[0], "fix_required_fields", False, "move_to_review"
    if canon == "duplicate":
        return "duplicate", "duplicate_suspected", "skip_duplicate", False, "skip_duplicate"
    return "ready", "hostaway_missing", "export_ready", True, "export_safe_missing"

def _exp_v2_row_for_exp(exp, hostaway_items):
    match = _exp_match_hostaway_item(exp, hostaway_items)
    v2_status, reason, recommended, can_export, repair_action = _exp_v2_status_for_exp(exp, match)
    states = _exp_v2_source_state(exp, match)
    label = EXPENSE_V2_STATUS_LABELS.get(v2_status, (v2_status, v2_status))
    reason_label = EXPENSE_V2_REASON_LABELS.get(reason, (reason, reason))
    return {
        "id": exp.get("id"),
        "ref": exp.get("ref") or "",
        "source_kind": "dashboard",
        "date": exp.get("expense_date") or "",
        "apartment": exp.get("apartment") or "",
        "listing_id": exp.get("listing_id"),
        "category": exp.get("category") or "",
        "description": exp.get("note") or exp.get("maintenance_type") or exp.get("vendor") or "",
        "vendor": exp.get("vendor") or "",
        "amount": round(abs(float(exp.get("amount") or 0)), 2),
        "source": "sheet" if states["sheet_state"]["present_in_sheet"] else "manual",
        "raw_status": exp.get("status") or "",
        "local_status": _exp_canonical_status(exp),
        "v2_status": v2_status,
        "v2_status_label": {"ar": label[0], "en": label[1]},
        "reason": reason,
        "reason_label": {"ar": reason_label[0], "en": reason_label[1]},
        "recommended_action": recommended,
        "repair_action": repair_action,
        "can_export": bool(can_export),
        "can_verify": v2_status in ("sent_not_verified", "in_progress"),
        "attempts": int(exp.get("retry_count") or 0),
        "last_attempt_at": exp.get("last_attempt_at") or exp.get("sending_at") or exp.get("sent_at") or "",
        "events": (exp.get("events") or [])[-20:],
        "export_attempts": (exp.get("export_attempts") or [])[-20:],
        **states,
    }

def _exp_v2_orphan_row(item):
    hid = _exp_hostaway_item_id(item) or ""
    amount = _exp_hostaway_item_amount(item) or 0
    date = _exp_hostaway_item_date(item)
    desc = item.get("concept") or item.get("name") or item.get("description") or ""
    return {
        "id": "ha_" + hid,
        "ref": "",
        "source_kind": "hostaway_only",
        "date": date,
        "apartment": str(_exp_hostaway_item_lid(item) or ""),
        "listing_id": _exp_hostaway_item_lid(item),
        "category": item.get("categoryName") or "",
        "description": desc,
        "vendor": "",
        "amount": amount,
        "source": "hostaway",
        "raw_status": "hostaway_only",
        "local_status": "",
        "v2_status": "duplicate",
        "v2_status_label": {"ar": EXPENSE_V2_STATUS_LABELS["duplicate"][0], "en": EXPENSE_V2_STATUS_LABELS["duplicate"][1]},
        "reason": "duplicate_suspected",
        "reason_label": {"ar": EXPENSE_V2_REASON_LABELS["duplicate_suspected"][0], "en": EXPENSE_V2_REASON_LABELS["duplicate_suspected"][1]},
        "recommended_action": "review_hostaway_only",
        "repair_action": "skip_duplicate",
        "can_export": False,
        "can_verify": False,
        "attempts": 0,
        "last_attempt_at": "",
        "events": [],
        "export_attempts": [],
        "sheet_state": {"present_in_sheet": False, "sheet_row_id": "", "sheet_last_seen_at": "", "parsed_ok": False, "parse_errors": ["missing_sheet"], "sheet_raw_data": {}},
        "dashboard_state": {"present_in_dashboard": False, "local_reference": "", "local_status": "", "local_last_updated": "", "local_attempt_count": 0, "local_error": "", "local_parent_id": "", "local_child_ids": []},
        "hostaway_state": {
            "present_in_hostaway": True,
            "hostaway_expense_id": hid,
            "hostaway_last_checked_at": _exp_now().isoformat(timespec="seconds"),
            "hostaway_match_method": "orphan",
            "match_method": "orphan",
            "hostaway_match_confidence": 1.0,
            "match_confidence": 1.0,
            "hostaway_payload_or_response_summary": _exp_safe_hostaway_summary(item),
            "hostaway_error": "",
        },
    }

def _exp_v2_reconcile_items(hostaway_items=None, include_hostaway_orphans=True):
    if hostaway_items is None:
        hostaway_items, ha_ok, ha_err = _exp_fetch_hostaway()
    else:
        ha_ok, ha_err = True, None
    rows = []
    matched_ids = set()
    for exp in _expenses.values():
        if exp.get("status") == "discarded":
            pass
        row = _exp_v2_row_for_exp(exp, hostaway_items or [])
        rows.append(row)
        hid = row["hostaway_state"].get("hostaway_expense_id")
        if hid:
            matched_ids.add(str(hid))
    if include_hostaway_orphans:
        for item in hostaway_items or []:
            hid = _exp_hostaway_item_id(item)
            if hid and str(hid) in matched_ids:
                continue
            rows.append(_exp_v2_orphan_row(item))
    totals = {}
    sar = {}
    for r in rows:
        st = r["v2_status"]
        totals[st] = totals.get(st, 0) + 1
        sar[st] = round(sar.get(st, 0.0) + abs(float(r.get("amount") or 0)), 2)
    diagnostics = defaultdict(lambda: {"count": 0, "examples": []})
    for r in rows:
        reason = r.get("reason") or "unknown"
        g = diagnostics[reason]
        g["count"] += 1
        if len(g["examples"]) < 5:
            g["examples"].append({"id": r.get("id"), "ref": r.get("ref"), "amount": r.get("amount"), "apartment": r.get("apartment")})
    return {
        "ok": True,
        "hostaway_ok": ha_ok,
        "hostaway_error": ha_err,
        "generated_at": _exp_now().isoformat(timespec="seconds"),
        "rows": rows,
        "totals": totals,
        "sar_totals": sar,
        "health": {
            "sheet": dict(_exp_sheet_diag or {}),
            "dashboard": {
                "local_records": len(_expenses),
                "ready": totals.get("ready", 0),
                "failed": totals.get("failed", 0),
                "split_parents": totals.get("split_parent", 0),
            },
            "hostaway": {
                "connected": bool(ha_ok),
                "last_fetch": _exp_now().isoformat(timespec="seconds"),
                "verified_matches": totals.get("verified", 0),
                "api_error": ha_err,
                "fetched": len(hostaway_items or []),
            },
        },
        "diagnostics": dict(diagnostics),
    }

def _exp_v2_repair_plan(hostaway_items=None):
    snap = _exp_v2_reconcile_items(hostaway_items=hostaway_items, include_hostaway_orphans=True)
    actions = {
        "mark_matched_verified": [],
        "move_unsafe_to_review": [],
        "export_safe_missing": [],
        "retry_temporary": [],
        "manual_verify": [],
        "skip_duplicate": [],
    }
    for r in snap["rows"]:
        action = r.get("repair_action")
        if action == "mark_verified":
            actions["mark_matched_verified"].append(r)
        elif action == "move_to_review":
            actions["move_unsafe_to_review"].append(r)
        elif action == "export_safe_missing":
            actions["export_safe_missing"].append(r)
        elif action == "retry_temporary":
            actions["retry_temporary"].append(r)
        elif action in ("manual_verify", "verify_sent"):
            # BUGFIX: 'verify_sent' (stale sent expenses) had NO bucket, so the
            # "Verify Sent" button silently skipped them. Both just re-check Hostaway.
            actions["manual_verify"].append(r)
        elif action == "skip_duplicate":
            actions["skip_duplicate"].append(r)
    return {
        "ok": True,
        "dry_run": True,
        "counts": {k: len(v) for k, v in actions.items()},
        "actions": actions,
        "summary": {
            "already_verified": len(actions["mark_matched_verified"]),
            "missing_from_hostaway": len(actions["export_safe_missing"]),
            "duplicates": len(actions["skip_duplicate"]),
            "unsafe_to_export": len(actions["move_unsafe_to_review"]),
            "temporary_failures": len(actions["retry_temporary"]),
            "manual_review": len(actions["manual_verify"]),
        },
        "snapshot": snap,
    }

def _exp_v2_child_ref(parent_ref, idx):
    return f"{parent_ref}-{chr(ord('A') + idx)}"

def _exp_v2_split_preview(parent_id, mode, rows):
    parent = _expenses.get(str(parent_id))
    if not parent:
        return {"ok": False, "error": "not_found"}
    mode = (mode or "").strip()
    if mode not in ("percentage", "amount"):
        return {"ok": False, "error": "bad_split_mode"}
    try:
        total = round(abs(float(parent.get("amount") or 0)), 2)
    except Exception:
        return {"ok": False, "error": "missing_amount"}
    if total <= 0:
        return {"ok": False, "error": "missing_amount"}
    if not isinstance(rows, list) or len(rows) < 2:
        return {"ok": False, "error": "need_two_or_more_children"}
    children = []
    running = 0.0
    for i, row in enumerate(rows):
        try:
            value = float(row.get("value"))
        except Exception:
            return {"ok": False, "error": "invalid_split_value"}
        if value < 0:
            return {"ok": False, "error": "invalid_split_value"}
        if mode == "percentage":
            amount = round(total * value / 100.0, 2)
            pct = round(value, 4)
        else:
            amount = round(value, 2)
            pct = round((amount / total) * 100.0, 4) if total else 0
        if i == len(rows) - 1:
            amount = round(total - running, 2) if mode == "percentage" else amount
        running = round(running + amount, 2)
        children.append({
            "ref": _exp_v2_child_ref(parent.get("ref") or "OJ-EXP", i),
            "amount": amount,
            "percentage": pct,
            "apartment": (row.get("apartment") or "").strip(),
            "listing_id": row.get("listing_id"),
        })
    if mode == "percentage":
        pct_total = round(sum(float(r.get("value") or 0) for r in rows), 4)
        if abs(pct_total - 100.0) > 0.01:
            return {"ok": False, "error": "split_not_balanced", "remaining_amount": round(total - running, 2)}
    if abs(running - total) > 0.01:
        return {"ok": False, "error": "split_not_balanced", "remaining_amount": round(total - running, 2)}
    return {"ok": True, "parent": {"id": parent.get("id"), "ref": parent.get("ref"), "amount": total},
            "mode": mode, "children": children, "remaining_amount": 0.0}

def _exp_v2_split_confirm(parent_id, mode, rows, by=""):
    preview = _exp_v2_split_preview(parent_id, mode, rows)
    if not preview.get("ok"):
        return preview
    parent = _expenses.get(str(parent_id))
    child_ids = []
    for child in preview["children"]:
        eid = _new_expense_id()
        exp = dict(parent)
        exp.update({
            "id": eid,
            "ref": child["ref"],
            "amount": child["amount"],
            "apartment": child["apartment"] or parent.get("apartment"),
            "listing_id": child["listing_id"],
            "status": "ready",
            "hostaway_ref": None,
            "hostaway_expense_id": None,
            "hostaway_verified": False,
            "split_role": "child",
            "split_parent_id": parent.get("id"),
            "split_percentage": child["percentage"],
            "events": [],
            "export_attempts": [],
            "note": ((parent.get("note") or parent.get("maintenance_type") or "") + f" · split from {parent.get('ref')}").strip(" ·"),
            "created_at": _exp_now().isoformat(timespec="seconds"),
            "updated_at": _exp_now().isoformat(timespec="seconds"),
        })
        _expenses[eid] = exp
        _exp_log_event(exp, "split_child_created", by=by, detail=parent.get("ref") or "")
        _exp_validate(exp)
        child_ids.append(eid)
    parent["split_role"] = "parent"
    parent["split_child_ids"] = child_ids
    _exp_set_status(parent, "split_parent", reason="split_confirmed", by=by, detail=str(len(child_ids)))
    _exp_log_event(parent, "split_parent_created", by=by, detail="children " + ",".join(child_ids))
    return {"ok": True, "parent_id": parent.get("id"), "child_ids": child_ids,
            "children": [_exp_view(_expenses[cid]) for cid in child_ids]}

def _exp_reconcile(apply=False):
    """Pull every sheet row, compare against expenses already in Hostaway, and
    report (and optionally post) the clean ones that are missing from Hostaway.
    Held/incomplete/unmatched expenses are never auto-posted — they stay in the
    review queue. Respects EXPENSE_POST_DRYRUN. Returns a summary dict."""
    pulled = _exp_poll_sheet()
    # Re-run validation on every not-yet-posted expense so the latest apartment
    # matching (e.g. the bracketed listing-id rule) re-resolves old held items.
    revalidated = 0
    for e in list(_expenses.values()):
        if e.get("status") == "discarded":
            continue
        if e.get("hostaway_ref") and e["hostaway_ref"] not in ("DRYRUN", "existing", "ok", None):
            continue
        before = e.get("status")
        _exp_validate(e)
        if e.get("status") != before:
            revalidated += 1
    ha_items, ha_ok, ha_err = _exp_fetch_hostaway()
    ha_keys = set()
    for x in ha_items:
        lid = x.get("listingMapId") or x.get("listingId") or x.get("listing_id")
        k = _exp_ha_key(lid, x.get("amount"), x.get("expenseDate") or x.get("date"))
        if k:
            ha_keys.add(k)

    total = len(_expenses)
    counts = {"held": 0, "already_ours": 0, "already_in_hostaway": 0,
              "missing": 0, "posted_now": 0, "post_failed": 0, "unmatched": 0}
    missing_preview = []
    for e in _expenses.values():
        st = e.get("status")
        if st == "discarded":
            continue
        # already truly posted by us (real Hostaway ref, not a DRYRUN placeholder)
        if e.get("hostaway_ref") and e["hostaway_ref"] not in ("DRYRUN", "existing", "ok", None):
            counts["already_ours"] += 1
            continue
        # only clean/ready expenses are eligible to post; held ones wait for review
        ready = (st == "ready") or (st == "posted" and e.get("hostaway_ref") in ("DRYRUN", "ok", "existing", None))
        if not ready:
            counts["held"] += 1
            continue
        lid = e.get("listing_id")
        if lid is None:
            counts["unmatched"] += 1
            continue
        k = _exp_ha_key(lid, e.get("amount"), e.get("expense_date"))
        if ha_ok and k and k in ha_keys:
            # Hostaway already has an equivalent expense → mark as reconciled, don't repost
            e["status"] = "posted"
            if not e.get("hostaway_ref") or e["hostaway_ref"] == "DRYRUN":
                e["hostaway_ref"] = "existing"
            counts["already_in_hostaway"] += 1
            continue
        # missing from Hostaway
        counts["missing"] += 1
        missing_preview.append({"ref": e.get("ref"), "apartment": e.get("apartment"),
                                "amount": e.get("amount"), "date": e.get("expense_date"),
                                "type": e.get("maintenance_type")})
        if apply:
            ok = _exp_post_to_hostaway(e)
            counts["posted_now" if ok else "post_failed"] += 1
    persist_state()
    summary = {"pulled_from_sheet": pulled, "total_expenses": total,
               "revalidated": revalidated,
               "hostaway_fetch_ok": ha_ok, "hostaway_error": ha_err,
               "hostaway_existing": len(ha_keys), "dryrun": EXPENSE_POST_DRYRUN,
               "applied": bool(apply), **counts,
               "missing_sample": missing_preview[:50],
               "sheet_debug": dict(_exp_sheet_diag)}
    log_event("ops", f"مطابقة المصاريف · سحب {pulled} · ناقص {counts['missing']} · "
                     f"{'رُحّل ' + str(counts['posted_now']) if apply else 'معاينة'}")
    return summary

# ============ Expense traceability: timeline · verify · pipeline · reconciliation ============
def _exp_log_event(exp, event, by="", detail=""):
    """Append one append-only timeline entry to an expense (who + when + what)."""
    exp.setdefault("events", []).append({
        "ts": datetime.now(TZ).isoformat(timespec="seconds"),
        "event": event, "by": (by or "")[:60], "detail": (detail or "")[:200]})
    if len(exp["events"]) > 100:
        del exp["events"][:len(exp["events"]) - 100]

def _exp_last_actor(exp):
    """The last human who touched this expense (for the sync-status 'who' column)."""
    for ev in reversed(exp.get("events", [])):
        if ev.get("by"):
            return ev["by"]
    return exp.get("approved_by") or exp.get("submitter") or ""

def _exp_verify_in_hostaway(exp):
    """Re-query Hostaway and CONFIRM this expense is really there WITH a matching amount —
    by our reference (OJ-EXP-…) first, else by (listing, amount, date). This is the ONLY
    place that promotes an expense to 'posted'. Never fakes: DRY-RUN and an unreachable
    Hostaway both leave it unverified (still 'in_transit'). A ref found but with a different
    amount is flagged 'amount_mismatch' (conflict), NOT posted."""
    if EXPENSE_POST_DRYRUN:
        exp["hostaway_verified"] = False
        exp["verify_note"] = "dryrun"
        exp["error_class"] = "dryrun"
        return None
    ref = (exp.get("ref") or "")
    if _exp_has_real_hostaway_ref(exp):
        direct, direct_ok, _direct_err = _exp_fetch_hostaway_one(exp.get("hostaway_ref") or exp.get("hostaway_expense_id"))
        if direct_ok and isinstance(direct, dict):
            direct_match = _exp_match_hostaway_item(exp, [], direct_item=direct)
            if direct_match.get("present") and direct_match.get("confidence", 0) >= 0.95:
                exp["hostaway_verified"] = True
                exp["verify_note"] = "found:hostaway_id"
                exp["verification_method"] = "hostaway_id"
                exp["verified_at"] = datetime.now(TZ).isoformat(timespec="seconds")
                hid = _exp_hostaway_item_id(direct)
                if hid:
                    exp["hostaway_expense_id"] = hid
                    exp["hostaway_ref"] = hid
                _exp_set_status(exp, "verified", reason="hostaway_match", detail="matched by hostaway_id")
                exp["error"] = None
                exp["error_class"] = ""
                if not exp.get("posted_at"):
                    exp["posted_at"] = exp["verified_at"]
                if not any(e.get("event") == "verified" for e in exp.get("events", [])):
                    _exp_log_event(exp, "verified", detail="matched by hostaway_id")
                return True
            if direct_match.get("reason") == "amount_mismatch":
                exp["hostaway_verified"] = False
                exp["verify_note"] = "amount_conflict"
                exp["discrepancy"] = "amount_mismatch"
                exp["error_class"] = "verification"
                return False
    items, ok, err = _exp_fetch_hostaway()
    if not ok:
        exp["verify_note"] = "hostaway_unreachable"
        return None
    want_amt = round(abs(float(exp.get("amount") or 0)), 2)
    key = _exp_ha_key(exp.get("listing_id"), exp.get("amount"), exp.get("expense_date"))
    found_by = None
    found_item = None
    ref_seen = False
    for x in items:
        try:
            x_amt = round(abs(float(x.get("amount"))), 2)
        except (TypeError, ValueError):
            x_amt = None
        if ref and ref in json.dumps(x, ensure_ascii=False):
            ref_seen = True
            if x_amt is not None and abs(x_amt - want_amt) < 1:    # amount must match
                found_by = "ref"; found_item = x; break
        lid = x.get("listingMapId") or x.get("listingId") or x.get("listing_id")
        if key and _exp_ha_key(lid, x.get("amount"), x.get("expenseDate") or x.get("date")) == key:
            found_by = "key"; found_item = x; break
    if found_by:
        exp["hostaway_verified"] = True
        exp["verify_note"] = "found:" + found_by
        exp["verification_method"] = found_by
        exp["verified_at"] = datetime.now(TZ).isoformat(timespec="seconds")
        if isinstance(found_item, dict):
            hid = found_item.get("id") or found_item.get("expenseId") or found_item.get("expense_id")
            if hid is not None:
                exp["hostaway_expense_id"] = str(hid)
                if not exp.get("hostaway_ref") or exp.get("hostaway_ref") in ("ok", "existing"):
                    exp["hostaway_ref"] = str(hid)
        _exp_set_status(exp, "verified", reason="hostaway_match", detail=("matched by " + found_by))
        if exp.get("discrepancy") == "amount_mismatch":
            exp["discrepancy"] = None
        exp["error"] = None
        exp["error_class"] = ""
        if not exp.get("posted_at"):
            exp["posted_at"] = exp["verified_at"]
        if not any(e.get("event") == "verified" for e in exp.get("events", [])):
            _exp_log_event(exp, "verified", detail=("matched by " + found_by))
        return True
    exp["hostaway_verified"] = False
    # LEGACY 'ok' sentinel (pre-verification era): it WAS posted once — we just can't
    # match it in the current fetch window. NEVER demote it to 'ready': that path
    # re-exports and double-posts in Hostaway. It stays legacy-verified, flagged only.
    if str(exp.get("hostaway_ref") or "") == "ok":
        exp["verify_note"] = "legacy_ok_unconfirmed"
        return None
    # Backfill / truth-keeping: an optimistic 'posted' that Hostaway can't confirm is NOT
    # posted — demote it to in_transit (or to ready when there is no real ref to repost).
    if _exp_canonical_status(exp) == "verified" or exp.get("status") == "posted":
        has_real_ref = exp.get("hostaway_ref") and exp["hostaway_ref"] not in ("DRYRUN", "ok", "existing", None)
        _exp_set_status(exp, "sent_unverified" if has_real_ref else "ready",
                        reason="verify_failed", detail="not found in Hostaway")
        _exp_log_event(exp, "verify_failed", detail="not found in Hostaway — re-queued")
    if ref_seen:                                  # our ref is in Hostaway but the amount differs
        exp["verify_note"] = "amount_conflict"
        exp["discrepancy"] = "amount_mismatch"
        exp["error_class"] = "verification"
    else:
        exp["verify_note"] = "not_found"
    return False

# ============================================================================
#  EXPENSES — DIAGNOSIS-FIRST RUNNER (read-only; proves WHY an expense is stuck)
#  Reuses the existing status/verify/mapping/dup helpers. Sends NOTHING to Hostaway.
# ============================================================================
def _exp_build_payload(exp):
    """Build the EXACT Hostaway expense payload WITHOUT sending — mirrors the live poster
    (_exp_post_to_hostaway). Returns (payload, missing_required_fields). Read-only."""
    s = _exp_settings()
    cat = (s.get("category_map") or {}).get(exp.get("category") or "", exp.get("category") or "Other")
    ref = exp.get("ref") or ""
    name = (exp.get("maintenance_type") or "Expense")
    if (exp.get("note") or "").strip():
        name = f"{name} — {exp['note'].strip()}"
    if ref:
        name = f"[{ref}] {name}"
    desc_bits = []
    if ref:                          desc_bits.append(f"Ref: {ref}")
    if exp.get("vendor"):            desc_bits.append(f"Vendor: {exp['vendor']}")
    if exp.get("payment_method"):    desc_bits.append(f"Paid: {exp['payment_method']}")
    if exp.get("submitter"):         desc_bits.append(f"By: {exp['submitter']}")
    if exp.get("receipt_link"):      desc_bits.append(f"Receipt: {exp['receipt_link']}")
    if exp.get("no_receipt_reason"): desc_bits.append(f"No receipt: {exp['no_receipt_reason']}")
    missing = []
    if exp.get("listing_id") is None:                 missing.append("listing_id (Hostaway property)")
    if exp.get("amount") in (None, ""):               missing.append("amount")
    if not (exp.get("expense_date") or "").strip():   missing.append("expense_date")
    if not (exp.get("category") or "").strip():       missing.append("category")
    try:
        amt = -abs(float(exp["amount"])) if exp.get("amount") not in (None, "") else None
    except (TypeError, ValueError):
        amt = None; missing.append("amount (not a number)")
    payload = {
        "listingMapId": (int(exp["listing_id"]) if exp.get("listing_id") is not None else None),
        "amount": amt, "expenseDate": exp.get("expense_date"), "date": exp.get("expense_date"),
        "categoryName": cat, "concept": name[:120], "name": name[:120],
        "reference": ref, "description": " · ".join(desc_bits)[:900], "currency": "SAR"}
    return payload, missing

def _exp_diagnose(exp):
    """Full per-expense diagnosis answering: did we actually call Hostaway, what did it return,
    is mapping/payload/dup/verification the problem? Read-only — sends nothing."""
    canon = _exp_canonical_status(exp)
    payload, missing = _exp_build_payload(exp)
    ref = exp.get("ref") or ""
    hr = exp.get("hostaway_ref")
    dry = (hr == "DRYRUN") or bool(exp.get("dry"))
    real_ref = bool(hr) and hr not in ("DRYRUN", "ok", "existing", None)
    # was a REAL Hostaway API call attempted? (a 'sent' event, or a real ref) vs dry/never
    evs = exp.get("events", [])
    sent_evs = [e for e in evs if e.get("event") in ("sent", "post_failed")]
    dry_evs = [e for e in evs if e.get("event") == "dry_send"]
    called = bool(sent_evs) or real_ref
    last_attempt = exp.get("sent_at") or (sent_evs[-1]["ts"] if sent_evs else (dry_evs[-1]["ts"] if dry_evs else None))
    lid_match, cands = _exp_match_apartment(exp.get("apartment"))
    twin = _exp_find_duplicate(exp)
    # ---- root-cause classification (priority order) ----
    if canon == "verified":
        code, ar, en = "verified", "متحقق في Hostaway ✓", "Verified in Hostaway."
    elif exp.get("listing_id") is None:
        code, ar, en = "no_mapping", "الشقة غير مربوطة برقم Hostaway — ما نقدر نرحّله.", "Apartment is not mapped to a Hostaway property id — cannot export."
    elif missing:
        code, ar, en = "missing_fields", "البيانات ناقصة: " + ", ".join(missing), "Payload missing required fields: " + ", ".join(missing)
    elif dry:
        code, ar, en = "dryrun", "وضع التجربة (EXPENSE_POST_DRYRUN=1) — ما انكتب فعليًا في Hostaway.", "DRY-RUN (EXPENSE_POST_DRYRUN=1) — never actually written to Hostaway."
    elif canon == "failed":
        ecl = exp.get("error_class") or _exp_error_class(exp.get("error"))
        code, en = "failed_" + (ecl or "unknown"), "Hostaway/export failed (" + (ecl or "unknown") + "): " + (exp.get("error") or "")[:160]
        ar = "فشل الترحيل (" + (ecl or "غير معروف") + "): " + (exp.get("error") or "")[:160]
    elif exp.get("discrepancy") == "amount_mismatch":
        code, ar, en = "amount_conflict", "المرجع موجود في Hostaway لكن المبلغ مختلف.", "Reference exists in Hostaway but the amount differs."
    elif canon == "duplicate" or twin:
        code, ar, en = "duplicate", "احتمال تكرار — موجود مسبقًا.", "Duplicate suspected — a matching record exists."
    elif canon == "stale_pending":
        code, ar, en = "stale", "علق في الطابور/الإرسال أطول من الحد.", "Stuck in queue/sending past the threshold."
    elif canon == "sent_unverified":
        code = "sent_unverified"
        ar = "تم الإرسال لكن ما تحققنا: ما لقينا " + ref + " بعد تحديث Hostaway." if not called and not real_ref else "تم الإرسال لـHostaway لكن إعادة الجلب ما لقت " + ref + "."
        en = "Sent but not verified: re-fetch did not find " + ref + " in Hostaway."
    elif canon in ("inbox", "draft", "captured"):
        code, ar, en = "awaiting_review", "ينتظر المراجعة في الوارد — ما طُلب ترحيله بعد.", "Waiting in the inbox — not requested for export yet."
    elif canon == "ready":
        code, ar, en = "approved_not_exported", "معتمد وجاهز — لكن ما طُلب ترحيله بعد.", "Approved/ready — but export has not been requested yet."
    else:
        code, ar, en = "needs_review", _exp_status_reason(exp) or "يحتاج مراجعة", "Needs review."
    rec_ar, rec_en = _EXP_DIAG_REC.get(code, ("راجع البطاقة", "Review the card"))
    return {
        "ref": ref, "id": exp.get("id"), "apartment": exp.get("apartment"),
        "amount": exp.get("amount"), "date": exp.get("expense_date"), "category": exp.get("category"),
        "canonical_status": canon, "legacy_status": exp.get("status"),
        "source": {"submission_id": exp.get("submission_id"), "submitter": exp.get("submitter"),
                   "vendor": exp.get("vendor"), "receipt_link": exp.get("receipt_link"),
                   "note": exp.get("note"), "submitted_at": exp.get("submitted_at")},
        "validation_missing": missing,
        "apartment_mapping": {"stored_listing_id": exp.get("listing_id"),
                              "rematch_listing_id": lid_match,
                              "candidates": [c.get("name") for c in (cands or [])][:5],
                              "hostaway_property_id": exp.get("listing_id")},
        "payload_preview": payload,
        "reference_in_payload": bool(ref) and ("[" + ref + "]") in (payload.get("name") or "") and payload.get("reference") == ref,
        "hostaway_called": called, "dry_run_only": dry,
        "hostaway_ref": hr, "hostaway_expense_id": exp.get("hostaway_expense_id"),
        "real_hostaway_ref": real_ref, "last_attempt_at": last_attempt,
        "last_error": exp.get("error"), "error_class": exp.get("error_class") or _exp_error_class(exp.get("error")),
        "verify_note": exp.get("verify_note"), "verification_method": exp.get("verification_method"),
        "hostaway_verified": bool(exp.get("hostaway_verified")), "verified_at": exp.get("verified_at"),
        "verify_query": {"by": "reference→hostaway_id→(listing,amount,date)",
                         "reference": ref, "listing_id": exp.get("listing_id"),
                         "amount": exp.get("amount"), "date": exp.get("expense_date")},
        "duplicate_match": ({"ref": twin.get("ref"), "id": twin.get("id"),
                             "amount": twin.get("amount"), "date": twin.get("expense_date")} if twin else None),
        "queue_state": exp.get("queue_reason") or exp.get("status_reason") or "",
        "diagnosis_code": code, "diagnosis_ar": ar, "diagnosis_en": en,
        "recommended_ar": rec_ar, "recommended_en": rec_en,
        "events": (exp.get("events") or [])[-15:],
    }

_EXP_DIAG_REC = {
    "verified":              ("لا إجراء — متحقق.", "No action — verified."),
    "no_mapping":            ("اربط الشقة برقم Hostaway من «ربط بشقة مختلفة».", "Map the apartment to a Hostaway property id."),
    "missing_fields":        ("عدّل المصروف وكمّل الحقول الناقصة ثم اعتمده.", "Edit the expense, fill the missing fields, then approve."),
    "dryrun":                ("اضبط EXPENSE_POST_DRYRUN=0 في Railway ثم رحّل المعتمد.", "Set EXPENSE_POST_DRYRUN=0 in Railway, then export approved."),
    "amount_conflict":       ("راجع المبلغ في Hostaway أو عدّل المصروف ثم أعد التحقق.", "Reconcile the amount in Hostaway or edit it, then re-verify."),
    "duplicate":             ("لو مو مكرر اضغط «مو مكرر» ثم رحّله، وإلا اتركه.", "If not a duplicate mark it so, else leave it."),
    "stale":                 ("أعد المحاولة (مؤقت فقط) من «مطابقة وإصلاح».", "Retry (temporary only) via Reconcile & Repair."),
    "sent_unverified":       ("حدّث Hostaway وتحقّق؛ لو ما ظهر تأكد من فلتر الشهر/الشقة.", "Refresh Hostaway + verify; if still missing, check the month/property filter."),
    "awaiting_review":       ("اعتمده من الوارد عشان يجهز للترحيل.", "Approve it in the Inbox to make it export-ready."),
    "approved_not_exported": ("اضغط «ترحيل المعتمد».", "Click Export Approved."),
    "failed_auth":           ("مفتاح/توكن Hostaway — تأكد من HOSTAWAY_API_KEY.", "Hostaway auth — check HOSTAWAY_API_KEY."),
    "failed_validation":     ("عدّل البيانات الناقصة ثم أعد الترحيل.", "Fix the invalid/missing fields, then re-export."),
    "failed_network":        ("مؤقت — أعد المحاولة بعد قليل.", "Temporary — retry shortly."),
}

def _exp_diagnose_sample(limit=8):
    """Pick the most-stuck expenses (failed / stale / sent-unverified / dry-run / duplicate /
    no-mapping) and diagnose each. Read-only."""
    stuck = []
    for e in _expenses.values():
        canon = _exp_canonical_status(e)
        if (canon in ("failed", "stale_pending", "sent_unverified", "duplicate", "needs_review")
                or e.get("hostaway_ref") == "DRYRUN" or e.get("listing_id") is None):
            stuck.append(e)
    stuck.sort(key=lambda e: (e.get("updated_at") or e.get("created_at") or ""), reverse=True)
    return [_exp_diagnose(e) for e in stuck[:max(5, limit)]]

def _exp_diag_overview():
    """Counts by canonical status + by diagnosis code, so the panel can say WHERE the problem is.
    Also reports the Hostaway-endpoint TRUTH (can we actually read expenses back? which path? error?)
    — this is the real question once DRY-RUN is off."""
    by_status, by_code = {}, {}
    dry = 0
    for e in _expenses.values():
        c = _exp_canonical_status(e)
        by_status[c] = by_status.get(c, 0) + 1
        if e.get("hostaway_ref") == "DRYRUN":
            dry += 1
    for d in _exp_diagnose_sample(limit=200):
        by_code[d["diagnosis_code"]] = by_code.get(d["diagnosis_code"], 0) + 1
    # Hostaway read-back truth (cached ~45s; ONE pull). Confirms the endpoint actually responds.
    try:
        ha_items, ha_ok, ha_err = _exp_fetch_hostaway(force=False)
    except Exception as e:
        ha_items, ha_ok, ha_err = [], False, str(e)[:200]
    return {"by_status": by_status, "by_diagnosis": by_code, "dryrun_count": dry,
            "total": len(_expenses), "dryrun_on": EXPENSE_POST_DRYRUN,
            "dryrun_raw": os.environ.get("EXPENSE_POST_DRYRUN", "1"),
            "hostaway_endpoint": {"path": EXPENSE_HOSTAWAY_PATH, "readable": bool(ha_ok),
                                  "count": len(ha_items), "error": ha_err}}

def _exp_pipeline(e):
    """The 3-step pipeline state for one expense (Sheet → Dashboard → Hostaway) + overall
    colour (max 4: green / amber / red / gray). Hostaway is 'done' ONLY when verified."""
    st = _exp_canonical_status(e)
    sheet = "done"                                            # it's in our system (sheet or manual)
    dash = ("done" if st in ("ready", "queued", "sending", "sent_unverified", "verified") else
            "skip" if st == "archived" else "active")         # active = needs review / in progress
    if st == "failed":
        ha = "failed"
    elif st == "verified" and e.get("hostaway_verified"):
        ha = "done"                                           # verified present in Hostaway ✓
    elif st in ("queued", "sending", "sent_unverified", "stale_pending"):
        ha = "dry" if (e.get("dry") or e.get("hostaway_ref") == "DRYRUN") else "active"  # جاري التحقق
    else:
        ha = "pending"
    color = ("red" if (st == "failed" or e.get("discrepancy")) else
             "green" if ha == "done" else
             "amber" if (ha in ("active", "dry") or dash == "active") else "gray")
    return {"sheet": sheet, "dashboard": dash, "hostaway": ha,
            "color": color, "discrepancy": e.get("discrepancy"),
            "verified": bool(e.get("hostaway_verified"))}

def _exp_discrepancies():
    """Reconciliation engine — flag mismatches across Sheet/Dashboard/Hostaway:
    in-sheet-not-Hostaway, in-Hostaway-not-sheet (orphans), amount mismatch, and duplicates.
    Tags each of OUR expenses with e['discrepancy']; returns a summary (+ orphan sample)."""
    ha_items, ha_ok, ha_err = _exp_fetch_hostaway()
    ha_keys = set()
    ha_by_listing_date = {}
    for x in ha_items:
        lid = x.get("listingMapId") or x.get("listingId") or x.get("listing_id")
        dt = str(x.get("expenseDate") or x.get("date") or "")[:10]
        k = _exp_ha_key(lid, x.get("amount"), dt)
        if k:
            ha_keys.add(k)
            try:
                ha_by_listing_date.setdefault((int(lid), dt), []).append(round(abs(float(x.get("amount"))), 2))
            except Exception:
                pass
    live = [e for e in _expenses.values() if e.get("status") != "discarded"]
    for e in live:
        e["discrepancy"] = None
    sheet_not_ha, amount_mismatch, dups = [], [], []
    seen = {}
    for e in live:
        lid, amt, dt = e.get("listing_id"), e.get("amount"), str(e.get("expense_date") or "")[:10]
        if lid is None or not isinstance(amt, (int, float)):
            continue
        k = _exp_ha_key(lid, amt, dt)
        if k in seen:                                         # duplicate among OUR records
            e["discrepancy"] = "duplicate"; dups.append(e.get("ref"))
        else:
            seen[k] = e.get("ref")
        if e.get("status") in ("ready", "posted") and ha_ok:
            if k not in ha_keys:
                ha_amts = ha_by_listing_date.get((int(lid), dt), []) if dt else []
                if ha_amts and round(abs(float(amt)), 2) not in ha_amts:
                    e["discrepancy"] = e.get("discrepancy") or "amount_mismatch"; amount_mismatch.append(e.get("ref"))
                elif e.get("status") == "ready" or not e.get("hostaway_verified"):
                    e["discrepancy"] = e.get("discrepancy") or "sheet_not_hostaway"; sheet_not_ha.append(e.get("ref"))
    our_keys = {_exp_ha_key(e.get("listing_id"), e.get("amount"), e.get("expense_date")) for e in live}
    orphans = []
    if ha_ok:
        for x in ha_items:
            lid = x.get("listingMapId") or x.get("listingId") or x.get("listing_id")
            dt = str(x.get("expenseDate") or x.get("date") or "")[:10]
            k = _exp_ha_key(lid, x.get("amount"), dt)
            if k and k not in our_keys:
                orphans.append({"listing": k[0], "amount": k[1], "date": k[2]})
    persist_state()
    return {"hostaway_ok": ha_ok, "hostaway_error": ha_err,
            "sheet_not_hostaway": len(sheet_not_ha), "hostaway_not_sheet": len(orphans),
            "amount_mismatch": len(amount_mismatch), "duplicates": len(dups),
            "orphans_sample": orphans[:50],
            "refs": {"sheet_not_hostaway": sheet_not_ha[:50],
                     "amount_mismatch": amount_mismatch[:50], "duplicates": dups[:50]}}

def _exp_export_eligible(exp, *, retry=False):
    canon = _exp_canonical_status(exp)
    if canon in ("ready", "failed", "stale_pending"):
        return True
    if retry and canon in ("sent_unverified", "queued", "sending"):
        return True
    return False

def _exp_queue_for_export(exp, *, by="", reason="manual", retry=False):
    """Put one expense in the durable-ish in-process export queue.
    The queue state is persisted on the expense, so a restart can repair stale
    queued/sending rows safely instead of silently losing them."""
    if not exp:
        return False, "not_found"
    if _exp4_approval_status(exp) != "approved":     # V4 approval gate: export ONLY approved expenses
        return False, "needs_approval"
    if _exp_canonical_status(exp) in ("needs_review", "duplicate", "archived", "verified"):
        return False, _exp_canonical_status(exp)
    if not _exp_export_eligible(exp, retry=retry):
        return False, _exp_canonical_status(exp)
    if exp.get("id") not in _expense_export_queue and exp.get("id") not in _expense_export_running:
        _expense_export_queue.append(exp.get("id"))
    exp["queued_at"] = _exp_now().isoformat(timespec="seconds")
    exp["queue_reason"] = reason
    exp["queued_by"] = by[:60]
    _exp_set_status(exp, "queued", reason=reason, by=by, detail=reason)
    _exp_export_attempt(exp, "export_queued", detail=reason)
    return True, "queued"

def _exp_repair_preview_rows():
    now = _exp_now()
    rows = []
    for e in _expenses.values():
        _exp_apply_stale_state(e, now=now)
        canon = _exp_canonical_status(e, now=now)
        if canon in ("stale_pending", "failed", "sent_unverified", "queued", "sending"):
            rows.append({
                "id": e.get("id"), "ref": e.get("ref"), "status": canon,
                "raw_status": e.get("status"), "reason": _exp_status_reason(e, canon),
                "hostaway_ref": e.get("hostaway_ref"),
                "amount": e.get("amount"), "apartment": e.get("apartment"),
                "date": e.get("expense_date"), "retry_count": int(e.get("retry_count") or 0),
                "safe_action": "verify_first" if e.get("hostaway_ref") else ("retry_export" if canon == "failed" else "review"),
            })
    rows.sort(key=lambda r: (r.get("status") or "", r.get("ref") or ""))
    return rows

async def _exp_export_one(exp_id):
    exp = _expenses.get(exp_id)
    if not exp:
        return False
    _expense_export_running.add(exp_id)
    try:
        _exp_apply_stale_state(exp)
        canon = _exp_canonical_status(exp)
        if canon in ("archived", "verified", "needs_review", "duplicate"):
            _exp_export_attempt(exp, "export_skipped", detail=canon, ok=False)
            return False

        # If anything was already sent, verify first and never blindly duplicate it.
        if exp.get("hostaway_ref") and canon in ("sent_unverified", "stale_pending", "queued", "sending"):
            _exp_export_attempt(exp, "verify_before_retry", detail=str(exp.get("hostaway_ref")))
            ok = await asyncio.to_thread(_exp_verify_in_hostaway, exp)
            if ok:
                _exp_export_attempt(exp, "export_verified", detail=exp.get("verify_note", ""), ok=True)
                return True
            if exp.get("hostaway_ref") not in ("DRYRUN", "ok", "existing", None):
                _exp_set_status(exp, "stale_pending", reason="sent_not_verified", detail=exp.get("verify_note") or "not_found")
                _exp_export_attempt(exp, "retry_blocked_sent_unverified", detail="real Hostaway ref exists; manual review required", ok=False)
                return False

        await asyncio.to_thread(_exp_validate, exp)
        if exp.get("status") != "ready":
            _exp_set_status(exp, "needs_review", reason=exp.get("primary_reason") or "validation")
            _exp_export_attempt(exp, "export_blocked", detail=exp.get("primary_reason") or "validation", ok=False)
            return False

        exp["retry_count"] = int(exp.get("retry_count") or 0) + 1
        exp["sending_at"] = _exp_now().isoformat(timespec="seconds")
        _exp_set_status(exp, "sending", reason="worker", detail=f"attempt {exp['retry_count']}")
        _exp_export_attempt(exp, "export_sending", detail=f"attempt {exp['retry_count']}")
        ok = await asyncio.to_thread(_exp_post_to_hostaway, exp)
        if not ok:
            _exp_export_attempt(exp, "export_failed", detail=exp.get("error") or "", ok=False)
            return False
        _exp_export_attempt(exp, "export_sent", detail=exp.get("hostaway_ref") or "", ok=True)
        verified = await asyncio.to_thread(_exp_verify_in_hostaway, exp)
        _exp_export_attempt(exp, "export_verified" if verified else "export_unverified",
                            detail=exp.get("verify_note") or "", ok=bool(verified))
        return bool(verified)
    finally:
        _expense_export_running.discard(exp_id)
        await asyncio.to_thread(persist_state)

async def _exp_export_worker():
    global _expense_export_worker_task
    try:
        while _expense_export_queue:
            batch = []
            while _expense_export_queue and len(batch) < EXPENSE_EXPORT_WORKERS:
                eid = _expense_export_queue.popleft()
                if eid in _expense_export_running:
                    continue
                batch.append(eid)
            if not batch:
                await asyncio.sleep(0.1)
                continue
            await asyncio.gather(*[_exp_export_one(eid) for eid in batch])
            await asyncio.sleep(0.1)
    finally:
        _expense_export_worker_task = None

def _exp_ensure_export_worker():
    global _expense_export_worker_task
    try:
        loop = asyncio.get_running_loop()
    except RuntimeError:
        return False
    if _expense_export_worker_task is None or _expense_export_worker_task.done():
        _expense_export_worker_task = loop.create_task(_exp_export_worker())
    return True

# ============================================================================
#  EXPENSES V4 — Expense Approval Center (the canonical workflow)
#  Google Sheet = intake only · Dashboard = approval only · Hostaway = export only.
#  Rebuilt clean on the existing durable ledger (_expenses / expenses.json).
#  Reuses ONLY low-level primitives (api_post/api_get, sheet fetch, persistence,
#  i18n, theme). The old _exp_* / V2 logic stays in the file but is unlinked from
#  the UI + poll loop. NEVER fakes a Hostaway confirmation; never auto-exports.
# ============================================================================
EXP4_APPROVAL = ("pending_approval", "approved", "rejected", "needs_edit")
EXP4_EXPORT = ("not_exported", "export_requested", "exporting",
               "exported_not_verified", "verified", "failed", "duplicate_found")

def _exp4_missing_required(exp):
    """Minimum fields an expense needs before it can be approved/exported."""
    miss = []
    amt = exp.get("amount")
    try:
        bad_amt = amt in (None, "") or float(amt) == 0
    except (TypeError, ValueError):
        bad_amt = True
    if bad_amt:
        miss.append("amount")
    if not str(exp.get("expense_date") or "").strip():
        miss.append("expense_date")
    if not str(exp.get("apartment") or "").strip() and exp.get("listing_id") is None:
        miss.append("apartment")
    if not str(exp.get("category") or "").strip():
        miss.append("category")
    return miss

def _exp4_export_status(exp):
    """Single source of truth for the export lane, derived from the canonical status +
    verification flag. NEVER returns 'verified' unless Hostaway actually confirmed it."""
    if exp.get("hostaway_verified"):
        return "verified"
    canon = _exp_canonical_status(exp)
    if canon == "verified":            # canonical says verified but the flag is missing → stay honest
        return "exported_not_verified"
    if canon == "duplicate":
        return "duplicate_found"
    if canon == "failed":
        return "failed"
    if canon == "queued":
        return "exporting" if exp.get("id") in _expense_export_running else "export_requested"
    if canon == "sending":
        return "exporting"
    if canon in ("sent_unverified", "stale_pending"):
        return "exported_not_verified" if (exp.get("hostaway_ref") or _exp_has_real_hostaway_ref(exp)) else "failed"
    return "not_exported"

def _exp4_approval_status(exp):
    """Stored approval lane (set by migration / intake / approve / reject / edit)."""
    a = exp.get("approval_status")
    if a in EXP4_APPROVAL:
        return a
    canon = _exp_canonical_status(exp)                 # fallback derive (pre-migration safety)
    if canon in ("verified", "sent_unverified", "queued", "sending", "stale_pending", "failed"):
        return "approved"
    if canon == "archived":
        return "rejected"
    return "pending_approval"

def _exp4_tab(exp):
    """Which of the 5 lifecycle tabs this expense belongs to (or 'archived')."""
    if exp.get("archived"):
        return "archived"
    es = _exp4_export_status(exp)
    aps = _exp4_approval_status(exp)
    if es == "verified":
        return "verified"
    if es in ("export_requested", "exporting", "exported_not_verified"):
        return "exported"
    if es in ("failed", "duplicate_found") or aps in ("needs_edit", "rejected") or exp.get("is_split_parent"):
        return "needs_action"
    if aps == "approved":
        return "approved"
    return "pending"

_EXP4_REC = {     # (ar, en) recommended next action by situation key
    "fix_fields":   ("كمّل الحقول الناقصة ثم اعتمد", "Fill the missing fields, then approve"),
    "approve":      ("راجع المصروف واعتمده", "Review and approve"),
    "export":       ("اضغط «تصدير إلى Hostaway»", "Click Export to Hostaway"),
    "wait_export":  ("قيد التصدير — انتظر قليلاً", "Exporting — please wait"),
    "recheck":      ("تحقق ثم أعد التصدير", "Check then re-export"),
    "view_match":   ("اعرض مطابقة Hostaway", "View the Hostaway match"),
    "verified":     ("لا إجراء — متحقق في Hostaway", "No action — verified in Hostaway"),
    "dedupe":       ("راجع التكرار في Hostaway", "Review the duplicate in Hostaway"),
    "rejected":     ("مرفوض — عدّله لإعادة فتحه", "Rejected — edit to reopen it"),
    "split_parent": ("مصروف مقسّم — أدر الأبناء", "Split parent — manage its children"),
}

def _exp4_recommended(exp):
    es = _exp4_export_status(exp); aps = _exp4_approval_status(exp)
    if exp.get("is_split_parent"): key = "split_parent"
    elif es == "verified": key = "verified"
    elif es == "duplicate_found": key = "dedupe"
    elif es == "failed": key = "recheck"
    elif es == "exported_not_verified": key = "view_match"
    elif es in ("export_requested", "exporting"): key = "wait_export"
    elif aps == "rejected": key = "rejected"
    elif aps == "needs_edit": key = "fix_fields"
    elif aps == "approved": key = "export"
    else: key = "approve"
    return key, _EXP4_REC.get(key, ("", ""))

def _exp4_view(exp):
    """Full V4 record for the API/UI. Derives the lanes; stores nothing."""
    miss = _exp4_missing_required(exp)
    rec_key, (rec_ar, rec_en) = _exp4_recommended(exp)
    sub_id = str(exp.get("submission_id") or "")
    return {
        "expense_id": exp.get("id"),
        "ouja_reference": exp.get("ref") or "",
        "source": "split" if exp.get("split_parent_id") else ("google_sheet" if sub_id.startswith("gs-") else ("bank" if sub_id.startswith("bank-") else "manual")),
        "source_row_id": sub_id,
        "submitted_at": exp.get("submitted_at") or exp.get("created_at") or "",
        "imported_at": exp.get("created_at") or "",
        "submitter": exp.get("submitter") or "",
        "apartment": exp.get("apartment") or "",
        "listing_id": exp.get("listing_id"),
        "amount_sar": round(abs(float(exp.get("amount") or 0)), 2),
        "expense_date": exp.get("expense_date") or "",
        "category": exp.get("category") or "",
        "concept": exp.get("maintenance_type") or exp.get("category") or "",
        "description": exp.get("note") or "",
        "vendor": exp.get("vendor") or "",
        "receipt_url": exp.get("receipt_link") or "",
        "kind": exp.get("kind") or "expense",                 # expense (negative) | extra (positive)
        "owner_email": exp.get("owner_email") or "",
        "approval_status": _exp4_approval_status(exp),
        "export_status": _exp4_export_status(exp),
        "tab": _exp4_tab(exp),
        "hostaway_expense_id": exp.get("hostaway_expense_id") or (exp.get("hostaway_ref") if _exp_has_real_hostaway_ref(exp) else ""),
        "hostaway_verified": bool(exp.get("hostaway_verified")),
        "hostaway_last_checked_at": exp.get("verified_at") or exp.get("hostaway_last_checked_at") or "",
        "last_export_attempt_at": exp.get("sending_at") or exp.get("last_attempt_at") or "",
        "retry_count": int(exp.get("retry_count") or 0),
        "last_error_code": exp.get("error_class") or "",
        "last_error_message": exp.get("error") or "",
        "missing_fields": miss,
        "recommended_key": rec_key, "recommended_ar": rec_ar, "recommended_en": rec_en,
        "rejection_reason": exp.get("rejection_reason") or "",
        "approved_by": exp.get("approved_by") or "", "approved_at": exp.get("approved_at") or "",
        "is_split_parent": bool(exp.get("is_split_parent")),
        "split_parent_id": exp.get("split_parent_id") or "",
        "split_child_ids": exp.get("split_child_ids") or [],
        "archived": bool(exp.get("archived")),
        "created_at": exp.get("created_at") or "", "updated_at": exp.get("updated_at") or "",
    }

def _exp4_log(exp, action, *, actor="", prev="", new="", detail="",
              payload_summary=None, response_summary=None, error_code="", error_message="", recommended=""):
    """Append-only V4 audit entry (no secrets). Mirrors into the legacy timeline too."""
    row = {
        "ts": _exp_now().isoformat(timespec="seconds"),
        "ref": exp.get("ref") or exp.get("id"),
        "actor": (actor or "")[:60], "action": action,
        "prev_status": prev, "new_status": new, "detail": (detail or "")[:240],
        "error_code": (error_code or "")[:60], "error_message": (error_message or "")[:240],
        "recommended_action": (recommended or "")[:120],
    }
    if payload_summary is not None: row["payload_summary"] = payload_summary
    if response_summary is not None: row["response_summary"] = response_summary
    exp.setdefault("audit", []).append(row)
    if len(exp["audit"]) > 200:
        del exp["audit"][:len(exp["audit"]) - 200]
    try:
        _exp_log_event(exp, "v4:" + action, by=actor, detail=detail or new or "")
    except Exception:
        pass
    return row

def _exp4_migrate_all():
    """One-time, idempotent backfill: give every existing expense an approval_status.
    Owner rule: anything NOT yet sent to Hostaway → pending_approval (NO auto-approve);
    already-exported/verified keep their state. Never overwrites an existing approval_status,
    never deletes, never fakes verification."""
    migrated = 0
    for e in _expenses.values():
        if e.get("approval_status") in EXP4_APPROVAL:
            continue
        canon = _exp_canonical_status(e)
        if canon in ("verified", "sent_unverified", "queued", "sending", "stale_pending", "failed"):
            e["approval_status"] = "approved"             # already exported/in-flight → implicitly approved
        elif canon == "archived":
            e["approval_status"] = "rejected"; e["archived"] = True
        elif canon == "split_parent":
            e["approval_status"] = "approved"; e["is_split_parent"] = True
        else:                                             # ready/draft/captured/needs_review/duplicate → not yet sent
            e["approval_status"] = "needs_edit" if _exp4_missing_required(e) else "pending_approval"
        _exp4_log(e, "migrated_v4", prev=canon, new=e["approval_status"], detail="mapped into V4 lifecycle")
        migrated += 1
    if migrated:
        persist_state()
    return migrated

def _exp4_approve(exp, by=""):
    """Pending/Needs-Edit → Approved. HONEST: refuses no-ops. _exp4_tab gives export-status
    precedence, so 'approving' an already-verified/exported/failed/duplicate/split expense
    would flip approval_status yet never move the row — a silent no-op the UI reports as
    success (root cause of the 'press اعتماد → returns to متحققة' bug). Refuse with a reason
    instead, so the frontend can show it as blocked rather than fake a move."""
    if exp.get("hostaway_verified"):
        _exp4_log(exp, "approve_blocked", actor=by, detail="already_verified")
        return False, "already_verified"
    es = _exp4_export_status(exp)
    if es in ("export_requested", "exporting", "exported_not_verified"):
        _exp4_log(exp, "approve_blocked", actor=by, detail="already_exported")
        return False, "already_exported"
    if es in ("failed", "duplicate_found"):
        _exp4_log(exp, "approve_blocked", actor=by, detail=es)
        return False, "needs_recheck" if es == "failed" else "duplicate"
    if exp.get("is_split_parent"):
        _exp4_log(exp, "approve_blocked", actor=by, detail="split_parent")
        return False, "split_parent"
    miss = _exp4_missing_required(exp)
    if miss:
        exp["approval_status"] = "needs_edit"
        _exp4_log(exp, "approve_blocked", actor=by, new="needs_edit", detail="missing: " + ",".join(miss))
        return False, "needs_edit:" + ",".join(miss)
    prev = _exp4_approval_status(exp)
    exp["approval_status"] = "approved"
    exp["approved_by"] = (by or "")[:60]
    exp["approved_at"] = _exp_now().isoformat(timespec="seconds")
    exp["updated_at"] = exp["approved_at"]
    _exp4_log(exp, "approved", actor=by, prev=prev, new="approved")
    return True, "approved"

def _exp4_reject(exp, by="", reason=""):
    prev = _exp4_approval_status(exp)
    exp["approval_status"] = "rejected"
    exp["rejected_by"] = (by or "")[:60]
    exp["rejected_at"] = _exp_now().isoformat(timespec="seconds")
    exp["rejection_reason"] = (reason or "")[:240]
    exp["updated_at"] = exp["rejected_at"]
    _exp4_log(exp, "rejected", actor=by, prev=prev, new="rejected", detail=reason)
    return True, "rejected"

_EXP4_EDITABLE = ("apartment", "category", "maintenance_type", "amount", "expense_date",
                  "vendor", "note", "receipt_link", "payment_method", "owner_email")

def _exp4_edit(exp, fields, by=""):
    """Edit editable fields, re-match the apartment, and re-evaluate the approval lane."""
    changed = []
    if "kind" in fields and str(fields["kind"]) in ("expense", "extra"):
        if exp.get("kind") != fields["kind"]:
            exp["kind"] = fields["kind"]; changed.append("kind")
    for k in _EXP4_EDITABLE:
        if k not in fields:
            continue
        v = fields[k]
        if k == "amount":
            try:
                v = round(float(str(v).replace(",", "").strip()), 2)
            except (TypeError, ValueError):
                continue
        else:
            v = str(v).strip()[:600]
        if exp.get(k) != v:
            exp[k] = v; changed.append(k)
    if "apartment" in changed:
        lid, _c = _exp_match_apartment(exp.get("apartment"))
        if lid is not None:
            exp["listing_id"] = lid
    if _exp4_approval_status(exp) in ("needs_edit", "rejected"):
        exp["approval_status"] = "needs_edit" if _exp4_missing_required(exp) else "pending_approval"
    exp["updated_at"] = _exp_now().isoformat(timespec="seconds")
    _exp4_log(exp, "edited", actor=by, detail=",".join(changed) or "no change")
    return True, changed

# ---- V4 export worker / state machine (rebuilt; reuses only low-level Hostaway I/O) ----
_exp4_queue = deque()
_exp4_running = set()
_exp4_worker_task = None
EXP4_MAX_ATTEMPTS = max(1, int(os.environ.get("EXP4_MAX_ATTEMPTS", "4") or "4"))
EXP4_JOB_STATES = ("export_requested", "validating", "checking_hostaway",
                   "creating_hostaway_expense", "verifying_hostaway", "verified",
                   "exported_not_verified", "failed", "duplicate_found")

def _exp4_job(exp):
    return exp.setdefault("export_job", {"state": "", "attempts": 0, "started_at": "",
                                         "updated_at": "", "last_error": ""})

def _exp4_set_job(exp, state, *, error=""):
    j = _exp4_job(exp)
    if state == "export_requested":
        j["started_at"] = _exp_now().isoformat(timespec="seconds")
    j["state"] = state
    j["updated_at"] = _exp_now().isoformat(timespec="seconds")
    if error:
        j["last_error"] = error[:240]
    return j

def _exp4_build_payload(exp):
    """Exact Hostaway expense payload. Amount is NEGATIVE (Hostaway treats expenses as
    negative; extras are positive). The stable Ouja reference is embedded in the concept so
    we can match it back later — without clobbering the human description."""
    s = _exp_settings()
    cat = (s.get("category_map") or {}).get(exp.get("category") or "", exp.get("category") or "Other")
    ref = exp.get("ref") or ""
    apt = (exp.get("apartment") or "").replace("Ouja |", "").strip()
    base = (exp.get("maintenance_type") or exp.get("category") or "Expense")
    concept = " | ".join([p for p in (ref, base, apt) if p])[:200]
    try:
        amt = -abs(round(float(exp.get("amount")), 2))
    except (TypeError, ValueError):
        amt = None
    desc_bits = [b for b in (
        ("Ref: " + ref) if ref else "",
        ("Vendor: " + exp["vendor"]) if exp.get("vendor") else "",
        ("By: " + exp["submitter"]) if exp.get("submitter") else "",
        ("Note: " + exp["note"]) if exp.get("note") else "",
        ("Receipt: " + exp["receipt_link"]) if exp.get("receipt_link") else "",
    ) if b]
    return {
        "listingMapId": (int(exp["listing_id"]) if exp.get("listing_id") is not None else None),
        "amount": amt, "expenseDate": exp.get("expense_date"), "date": exp.get("expense_date"),
        "categoryName": cat, "concept": concept, "name": concept,
        "reference": ref, "description": " · ".join(desc_bits)[:900], "currency": "SAR",
    }

def _exp4_safe_summary(d, keep):
    if not isinstance(d, dict):
        return {}
    return {k: d.get(k) for k in keep if k in d}

def _exp4_find_in_hostaway(exp, items=None):
    """'Does this exact expense already exist in Hostaway?' Reuses the conservative matcher.
    Read-only; returns a match dict (present / confidence / id / method)."""
    if items is None:
        items, ok, _err = _exp_fetch_hostaway(force=True)
        if not ok:
            return {"present": False, "confidence": 0.0, "reason": "hostaway_unreachable", "id": None, "item": None}
    return _exp_match_hostaway_item(exp, items)

async def _exp4_verify(exp):
    """Re-fetch Hostaway and confirm the EXACT expense exists. Only a high-confidence match
    flips it to verified. DRY-RUN / unreachable never verify (honest)."""
    exp["hostaway_last_checked_at"] = _exp_now().isoformat(timespec="seconds")
    if EXPENSE_POST_DRYRUN:
        exp["verify_note"] = "dryrun"
        return False
    match = None
    # Strongest proof first: a direct GET of the exact Hostaway expense id. This is
    # independent of the expense LIST size — a freshly-created expense can sit beyond the
    # paginated list window and never appear there, so the list alone misses it. (Mirrors
    # _exp_verify_in_hostaway, which already checks by id first.)
    if _exp_has_real_hostaway_ref(exp):
        direct, direct_ok, _de = await asyncio.to_thread(
            _exp_fetch_hostaway_one, exp.get("hostaway_ref") or exp.get("hostaway_expense_id"))
        if direct_ok and isinstance(direct, dict):
            dm = _exp_match_hostaway_item(exp, [], direct_item=direct)
            if dm.get("present") and dm.get("confidence", 0) >= 0.95:
                match = dm
    if match is None:
        match = await asyncio.to_thread(_exp4_find_in_hostaway, exp)
    if match.get("present") and match.get("confidence", 0) >= 0.95:
        exp["hostaway_verified"] = True
        exp["hostaway_expense_id"] = match.get("id") or exp.get("hostaway_expense_id")
        if match.get("id"):
            exp["hostaway_ref"] = str(match.get("id"))
        exp["hostaway_match_snapshot"] = _exp4_safe_summary(match.get("item") or {},
            ("id", "listingMapId", "amount", "expenseDate", "date", "categoryName", "concept", "reference"))
        exp["verified_at"] = exp["hostaway_last_checked_at"]
        exp["verify_note"] = "match:" + (match.get("method") or "")
        _exp_set_status(exp, "verified", reason="hostaway_match", detail=match.get("method") or "")
        return True
    exp["verify_note"] = match.get("reason") or "not_found"
    return False

async def _exp4_export_one(eid):
    """The export state machine for ONE expense: validating → checking_hostaway →
    creating_hostaway_expense → verifying_hostaway → verified/exported_not_verified/failed/
    duplicate_found. Idempotent (lock + check-Hostaway-first), audited at every step."""
    exp = _expenses.get(eid)
    if not exp or eid in _exp4_running:
        return
    _exp4_running.add(eid)
    try:
        if _exp4_approval_status(exp) != "approved" or exp.get("is_split_parent"):
            _exp4_set_job(exp, "failed", error="not_approved_or_split")
            _exp4_log(exp, "export_rejected", new="failed", detail="not approved / split parent")
            return
        # 1) validating
        _exp4_set_job(exp, "validating")
        miss = _exp4_missing_required(exp)
        if miss:
            exp["approval_status"] = "needs_edit"
            _exp_set_status(exp, "needs_review", reason="validation", detail=",".join(miss))
            _exp4_set_job(exp, "failed", error="missing:" + ",".join(miss))
            _exp4_log(exp, "validate_failed", new="failed", error_code="validation",
                      error_message=",".join(miss), recommended="fill missing fields")
            return
        # 2) checking_hostaway FIRST — never blind-duplicate
        _exp4_set_job(exp, "checking_hostaway")
        match = await asyncio.to_thread(_exp4_find_in_hostaway, exp)
        if match.get("present") and match.get("confidence", 0) >= 0.95:
            await _exp4_verify(exp)
            _exp4_set_job(exp, "verified")
            _exp4_log(exp, "already_in_hostaway", new="verified", detail=match.get("method") or "",
                      response_summary=_exp4_safe_summary(match.get("item") or {}, ("id", "amount", "concept")))
            return
        if match.get("present") and match.get("confidence", 0) >= 0.82:
            exp["primary_reason"] = "duplicate"
            _exp_set_status(exp, "duplicate", reason="duplicate_suspected")
            _exp4_set_job(exp, "duplicate_found")
            _exp4_log(exp, "duplicate_found", new="duplicate_found", detail=match.get("method") or "",
                      recommended="review the duplicate in Hostaway")
            return
        # 3) creating_hostaway_expense
        exp["retry_count"] = int(exp.get("retry_count") or 0) + 1
        exp["sending_at"] = _exp_now().isoformat(timespec="seconds")
        _exp_set_status(exp, "sending", reason="v4_worker", detail="attempt %d" % exp["retry_count"])
        _exp4_set_job(exp, "creating_hostaway_expense")
        payload = _exp4_build_payload(exp)
        _exp4_log(exp, "create_attempt", new="creating_hostaway_expense",
                  payload_summary=_exp4_safe_summary(payload, ("listingMapId", "amount", "expenseDate", "categoryName", "concept", "reference", "currency")))
        if EXPENSE_POST_DRYRUN:
            exp["hostaway_ref"] = "DRYRUN"; exp["dry"] = True; exp["hostaway_verified"] = False
            _exp_set_status(exp, "sent_unverified", reason="dryrun", detail="DRY-RUN — not written")
            _exp4_set_job(exp, "exported_not_verified", error="dryrun")
            _exp4_log(exp, "dry_run", new="exported_not_verified",
                      detail="DRY-RUN (EXPENSE_POST_DRYRUN=1) — nothing written to Hostaway")
            return
        try:
            res = await asyncio.to_thread(api_post, EXPENSE_HOSTAWAY_PATH, payload)
        except Exception as e:
            msg = str(e)[:240]; cls = _exp_error_class(msg)
            exp["error"] = msg; exp["error_class"] = cls
            if cls == "network" and exp["retry_count"] < EXP4_MAX_ATTEMPTS:
                _exp_set_status(exp, "queued", reason="retry_backoff")
                _exp4_set_job(exp, "export_requested", error=msg)
                _exp4_log(exp, "create_error_retry", new="export_requested", error_code=cls, error_message=msg)
                _exp4_queue.append(eid)
            else:
                _exp_set_status(exp, "failed", reason=cls, detail=msg)
                _exp4_set_job(exp, "failed", error=msg)
                _exp4_log(exp, "create_failed", new="failed", error_code=cls, error_message=msg,
                          recommended="check then re-export")
            return
        ha_id = None
        if isinstance(res, dict):
            ha_id = (res.get("result") or {}).get("id") if isinstance(res.get("result"), dict) else res.get("id")
        exp["hostaway_ref"] = str(ha_id) if ha_id is not None else "ok"
        exp["hostaway_expense_id"] = exp["hostaway_ref"]
        exp["dry"] = False; exp["error"] = None; exp["error_class"] = ""
        _exp_set_status(exp, "sent_unverified", reason="created")
        _exp4_log(exp, "created", new="verifying_hostaway",
                  response_summary={"id": ha_id} if ha_id is not None else {"result": "ok"})
        # 4) verifying_hostaway
        _exp4_set_job(exp, "verifying_hostaway")
        if await _exp4_verify(exp):
            _exp4_set_job(exp, "verified")
            _exp4_log(exp, "verified", new="verified", detail=exp.get("verify_note") or "")
        else:
            _exp_set_status(exp, "sent_unverified", reason="exported_not_verified", detail=exp.get("verify_note") or "")
            _exp4_set_job(exp, "exported_not_verified", error=exp.get("verify_note") or "not_found")
            _exp4_log(exp, "exported_not_verified", new="exported_not_verified",
                      detail="searched ref→listing+amount+date; not confirmed yet",
                      recommended="view match / check again")
    finally:
        _exp4_running.discard(eid)
        await asyncio.to_thread(persist_state)

async def _exp4_worker():
    global _exp4_worker_task
    try:
        while _exp4_queue:
            batch = []
            while _exp4_queue and len(batch) < EXPENSE_EXPORT_WORKERS:
                e = _exp4_queue.popleft()
                if e not in _exp4_running:
                    batch.append(e)
            if not batch:
                await asyncio.sleep(0.1); continue
            await asyncio.gather(*[_exp4_export_one(e) for e in batch])
            await asyncio.sleep(0.1)
    finally:
        _exp4_worker_task = None

def _exp4_ensure_worker():
    global _exp4_worker_task
    try:
        loop = asyncio.get_running_loop()
    except RuntimeError:
        return False
    if _exp4_worker_task is None or _exp4_worker_task.done():
        _exp4_worker_task = loop.create_task(_exp4_worker())
    return True

def _exp4_request_export(exp, by=""):
    """Gated export request. Only an APPROVED, non-split expense is enqueued. The worker
    checks Hostaway first (duplicate-safe), creates, then verifies."""
    if not exp:
        return False, "not_found"
    if exp.get("is_split_parent"):
        return False, "split_parent_not_exportable"
    if _exp4_approval_status(exp) != "approved":
        return False, "needs_approval"
    if exp.get("hostaway_verified"):
        return False, "already_verified"
    eid = exp.get("id")
    if eid not in _exp4_queue and eid not in _exp4_running:
        _exp4_queue.append(eid)
    exp["queued_at"] = _exp_now().isoformat(timespec="seconds")
    _exp_set_status(exp, "queued", reason="v4_export", by=by)
    _exp4_set_job(exp, "export_requested")
    _exp4_log(exp, "export_requested", actor=by, new="export_requested")
    _exp4_ensure_worker()
    return True, "export_requested"

def _exp4_check_then_reexport(exp, by=""):
    """Duplicate-safe retry. Identical to requesting an export: the worker's step-2 check
    confirms Hostaway FIRST and verifies/dedupes instead of creating a second copy."""
    return _exp4_request_export(exp, by=by)

def _exp4_recover_stuck():
    """On restart, expenses left mid-export (no worker alive) are recovered, never left
    'exporting' forever: approved+unverified rows are re-queued (the worker re-checks
    Hostaway first, so this can't duplicate)."""
    n = 0
    for e in _expenses.values():
        j = e.get("export_job") or {}
        if j.get("state") in ("export_requested", "validating", "checking_hostaway",
                               "creating_hostaway_expense", "verifying_hostaway"):
            if (_exp4_approval_status(e) == "approved" and not e.get("hostaway_verified")
                    and not e.get("is_split_parent")):
                _exp4_set_job(e, "export_requested", error="recovered_after_restart")
                if e.get("id") not in _exp4_queue and e.get("id") not in _exp4_running:
                    _exp4_queue.append(e.get("id"))
                n += 1
    return n

# ---- V4 split expenses (one paid receipt → 2-5 apartments) ----
def _exp4_child_ref(parent_ref, idx):
    return "%s-%s" % (parent_ref or "OJ-EXP", chr(ord("A") + idx))

def _exp4_split_compute(parent_amount, mode, rows):
    """Return (child_amounts, errors). rows = [{apartment, value}]; mode = percent|sar.
    Rounds to 2dp and pushes any rounding remainder onto the LAST child so children sum
    EXACTLY to the parent total."""
    errors = []
    try:
        total = round(abs(float(parent_amount)), 2)
    except (TypeError, ValueError):
        return [], ["parent amount is invalid"]
    clean = [r for r in rows if str(r.get("apartment") or "").strip()]
    if len(clean) < 2:
        errors.append("need at least 2 apartments")
    vals = []
    for r in clean:
        try:
            vals.append(float(str(r.get("value")).replace(",", "").strip()))
        except (TypeError, ValueError):
            vals.append(None)
    if any(v is None for v in vals):
        return [], errors + ["every row needs a number"]
    if any(v <= 0 for v in vals):
        errors.append("no zero or negative amounts")
    if mode == "percent":
        if abs(sum(vals) - 100.0) > 0.1:
            errors.append("percentages must total 100%% (got %.1f%%)" % sum(vals))
        amounts = [round(total * v / 100.0, 2) for v in vals]
    else:
        if abs(sum(vals) - total) > 0.01:
            errors.append("amounts must total %.2f (got %.2f)" % (total, sum(vals)))
        amounts = [round(v, 2) for v in vals]
    if amounts and not errors:
        amounts[-1] = round(amounts[-1] + round(total - sum(amounts), 2), 2)
        if any(a <= 0 for a in amounts):
            errors.append("a child amount rounded to zero — adjust the split")
    return amounts, errors

def _exp4_split_preview(parent_id, mode, rows):
    parent = _expenses.get(str(parent_id))
    if not parent:
        return {"ok": False, "errors": ["parent_not_found"]}
    amounts, errors = _exp4_split_compute(parent.get("amount"), mode, rows)
    clean = [r for r in rows if str(r.get("apartment") or "").strip()]
    children = ([{"apartment": clean[i].get("apartment"), "amount": amounts[i],
                  "ref": _exp4_child_ref(parent.get("ref"), i)} for i in range(len(amounts))]
                if amounts else [])
    total = round(abs(float(parent.get("amount") or 0)), 2)
    allocated = round(sum(amounts), 2) if amounts else 0.0
    return {"ok": not errors, "errors": errors, "parent_amount": total,
            "allocated": allocated, "remaining": round(total - allocated, 2), "children": children}

def _exp4_split_apply(parent_id, mode, rows, by=""):
    """Create the child expenses and mark the parent a (non-exportable) Split Parent.
    No Hostaway calls — split is local until each child is approved + exported separately."""
    parent = _expenses.get(str(parent_id))
    if not parent:
        return False, "parent_not_found", []
    if parent.get("is_split_parent"):
        return False, "already_split", []
    if parent.get("hostaway_verified") or _exp_has_real_hostaway_ref(parent):
        return False, "already_in_hostaway", []          # never split something already booked
    prev = _exp4_split_preview(parent_id, mode, rows)
    if not prev.get("ok"):
        return False, ";".join(prev.get("errors") or ["invalid"]), []
    child_ids = []
    n = len(prev["children"])
    for i, ch in enumerate(prev["children"]):
        cid = _new_expense_id()
        lid, _c = _exp_match_apartment(ch["apartment"])
        child = {
            "id": cid, "ref": ch["ref"], "submission_id": cid,
            "submitter": parent.get("submitter") or "", "apartment": ch["apartment"], "listing_id": lid,
            "maintenance_type": parent.get("maintenance_type") or "", "category": parent.get("category") or "",
            "amount": ch["amount"], "expense_date": parent.get("expense_date") or "",
            "receipt_link": parent.get("receipt_link") or "", "vendor": parent.get("vendor") or "",
            "payment_method": parent.get("payment_method") or "",
            "note": (parent.get("note") or "") + (" — split %d/%d of %s" % (i + 1, n, parent.get("ref") or "")),
            "submitted_at": parent.get("submitted_at") or _exp_now().isoformat(timespec="seconds"),
            "status": "captured", "hold_reasons": [], "primary_reason": None, "candidates": [],
            "hostaway_ref": None, "hostaway_verified": False, "verify_note": None,
            "discrepancy": None, "events": [], "audit": [],
            "created_at": _exp_now().isoformat(timespec="seconds"), "split_parent_id": parent.get("id"),
        }
        child["approval_status"] = "needs_edit" if _exp4_missing_required(child) else "pending_approval"
        _expenses[cid] = child
        _exp4_log(child, "split_child_created", actor=by, new=child["approval_status"],
                  detail="from %s · %s SAR" % (parent.get("ref"), ch["amount"]))
        child_ids.append(cid)
    parent["is_split_parent"] = True
    parent["split_child_ids"] = child_ids
    parent["approval_status"] = "approved"               # parent is settled via its children; un-exportable
    _exp_set_status(parent, "split_parent", reason="split_confirmed", by=by, detail=str(len(child_ids)))
    _exp4_log(parent, "split_parent_created", actor=by, new="split_parent",
              detail="%d children: %s" % (len(child_ids), ",".join(child_ids)))
    persist_state()
    return True, "split", child_ids

# ---- V4 three-source reconciliation (Advanced drawer — diagnostics, not the main flow) ----
def _exp4_reconcile():
    """Compare the Internal Ledger vs Hostaway (+ a sheet-origin flag), reference-first with
    a conservative fallback. NEVER marks verified on a weak match. Read-only."""
    items, ok, err = _exp_fetch_hostaway(force=True)
    buckets = {"ledger_only": [], "verified_in_all": [], "exported_not_verified": [],
               "duplicate_suspected": [], "hostaway_only": []}
    matched_ha = set()
    for e in _expenses.values():
        if e.get("archived"):
            continue
        v = _exp4_view(e)
        m = _exp_match_hostaway_item(e, items) if ok else {"present": False, "confidence": 0.0}
        if m.get("id"):
            matched_ha.add(str(m.get("id")))
        row = {"ref": v["ouja_reference"], "apartment": v["apartment"], "amount": v["amount_sar"],
               "date": v["expense_date"], "approval_status": v["approval_status"],
               "export_status": v["export_status"], "in_sheet": v["source"] == "google_sheet",
               "confidence": round(m.get("confidence", 0), 2), "match_method": m.get("method", "")}
        if v["export_status"] == "verified":
            buckets["verified_in_all"].append(row)
        elif m.get("present") and m.get("confidence", 0) >= 0.82 and not v["hostaway_verified"]:
            buckets["duplicate_suspected"].append(row)
        elif v["export_status"] == "exported_not_verified":
            buckets["exported_not_verified"].append(row)
        else:
            buckets["ledger_only"].append(row)
    for it in (items or []):
        hid = str(_exp_hostaway_item_id(it) or "")
        if hid and hid not in matched_ha:
            buckets["hostaway_only"].append(_exp4_safe_summary(it, ("id", "amount", "expenseDate", "date", "concept", "categoryName")))
    return {"ok": ok, "error": err, "hostaway_count": len(items or []),
            "counts": {k: len(v) for k, v in buckets.items()}, "buckets": buckets}

# ---- V4 bulk EXPORT via Hostaway's import file (.xlsx) — no API create, dup-safe ----
# Hostaway has NO bulk/import API (verified against their docs); the .xlsx is uploaded by
# hand in Hostaway's web import. So we BUILD the exact-format file, after a live duplicate
# check, and verification still re-fetches Hostaway. Expense=negative, Extra=positive.
EXP4_IMPORT_COLS = ["name", "description", "category", "date", "reservationId",
                    "listingId", "unitId", "owner", "amount"]

def _exp4_import_date(s):
    try:
        y, m, d = str(s)[:10].split("-")
        return datetime(int(y), int(m), int(d))      # template cells are datetimes; matches Hostaway
    except Exception:
        return str(s or "")

def _exp4_import_row(exp):
    """One Hostaway import-template row from a ledger expense. Embeds the OJ-EXP ref in the
    name so we can verify it back. Expense → negative amount, Extra → positive."""
    s = _exp_settings()
    cat = (s.get("category_map") or {}).get(exp.get("category") or "", exp.get("category") or "")
    ref = exp.get("ref") or ""
    apt = (exp.get("apartment") or "").replace("Ouja |", "").strip()
    base = (exp.get("maintenance_type") or exp.get("category") or "Expense")
    name = " | ".join([p for p in (ref, base, apt) if p])[:200]
    desc_bits = [b for b in (
        ("Vendor: " + exp["vendor"]) if exp.get("vendor") else "",
        ("By: " + exp["submitter"]) if exp.get("submitter") else "",
        ("Note: " + exp["note"]) if exp.get("note") else "",
        ("Receipt: " + exp["receipt_link"]) if exp.get("receipt_link") else "",
    ) if b]
    try:
        amt = round(abs(float(exp.get("amount"))), 2)
    except (TypeError, ValueError):
        amt = 0.0
    if (exp.get("kind") or "expense") == "expense":
        amt = -amt                                      # expense negative; extra stays positive
    return {"name": name, "description": " · ".join(desc_bits)[:900], "category": cat,
            "date": (exp.get("expense_date") or "")[:10], "reservationId": exp.get("reservation_id") or "",
            "listingId": (int(exp["listing_id"]) if exp.get("listing_id") is not None else ""),
            "unitId": "", "owner": exp.get("owner_email") or "", "amount": amt}

def _exp4_xlsx_bytes(rows):
    """Build a Hostaway import .xlsx (exact template columns) from row dicts. openpyxl is a
    declared dependency (requirements.txt)."""
    import openpyxl, io
    wb = openpyxl.Workbook()
    ws = wb.active
    ws.title = "Expenes and extras import templ"          # match Hostaway's template sheet name
    ws.append(EXP4_IMPORT_COLS)
    for r in rows:
        ws.append([r.get(c, "") for c in EXP4_IMPORT_COLS])
    buf = io.BytesIO()
    wb.save(buf)
    return buf.getvalue()

def _exp4_csv_bytes(rows):
    """Build a Hostaway import CSV (exact template columns), UTF-8 with a BOM so Excel and
    Arabic text render correctly. Proper quoting via the csv module."""
    import csv as _csv, io as _io
    sio = _io.StringIO()
    w = _csv.writer(sio)
    w.writerow(EXP4_IMPORT_COLS)
    for r in rows:
        w.writerow([r.get(c, "") for c in EXP4_IMPORT_COLS])
    return ("﻿" + sio.getvalue()).encode("utf-8")

def _exp4_file_eligible(exp):
    """A row may go into the import file only if approved, non-split, valid, AND mapped to a
    Hostaway listing id (the import needs the numeric listingId, not just a text apartment)."""
    if not exp or exp.get("is_split_parent"):
        return False, "split_parent"
    if _exp4_approval_status(exp) != "approved":
        return False, "not_approved"
    miss = _exp4_missing_required(exp)
    if miss:
        return False, "missing:" + ",".join(miss)
    if exp.get("listing_id") is None:
        return False, "no_hostaway_listing"
    return True, "ok"

def _exp4_prepare_check(ids):
    """LIVE pre-download duplicate check: for a batch of approved expenses, ask Hostaway
    'is each already there?' and classify ready / already_in_hostaway / blocked. Read-only —
    builds NOTHING and changes NOTHING yet."""
    items, ok, err = _exp_fetch_hostaway(force=True)
    ready, already, blocked = [], [], []
    for i in ids:
        e = _expenses.get(str(i))
        if not e:
            continue
        base = {"id": e.get("id"), "ref": e.get("ref"), "apartment": e.get("apartment"),
                "amount": round(abs(float(e.get("amount") or 0)), 2), "date": e.get("expense_date"),
                "kind": e.get("kind") or "expense"}
        elig, why = _exp4_file_eligible(e)
        if not elig:
            base["reason"] = why; blocked.append(base); continue
        m = _exp_match_hostaway_item(e, items) if ok else {"present": False, "confidence": 0}
        if m.get("present") and m.get("confidence", 0) >= 0.82:
            base["confidence"] = round(m.get("confidence", 0), 2)
            base["match_method"] = m.get("method", "")
            base["hostaway_id"] = m.get("id") or ""
            already.append(base)
        else:
            ready.append(base)
    return {"ok": ok, "error": err, "hostaway_count": len(items or []),
            "ready": ready, "already": already, "blocked": blocked}

def _exp4_new_batch_id():
    n = 0
    for k in _exp4_batches:
        try:
            n = max(n, int(str(k).split("-")[-1]))
        except (ValueError, IndexError):
            pass
    return "OJ-IMP-%04d" % (n + 1)

def _exp4_build_file(ids, by=""):
    """Build the import CSV for the FINAL included ids, mark each 'in import file, awaiting
    verification', and RECORD a downloadable batch in the files log. Returns
    (csv_bytes, marked_ids, skipped, batch_id). Skips ineligible rows."""
    rows, marked, skipped, meta = [], [], [], []
    for i in ids:
        e = _expenses.get(str(i))
        elig, why = _exp4_file_eligible(e) if e else (False, "not_found")
        if not elig:
            skipped.append({"id": str(i), "reason": why}); continue
        rows.append(_exp4_import_row(e))
        meta.append({"expense_id": e.get("id"), "ref": e.get("ref"), "apartment": e.get("apartment"),
                     "amount": round(abs(float(e.get("amount") or 0)), 2), "kind": e.get("kind") or "expense",
                     "date": e.get("expense_date"), "listing_id": e.get("listing_id"), "category": e.get("category")})
        e["hostaway_ref"] = "FILE"                          # placeholder (not a real id; excluded by _exp_has_real_hostaway_ref)
        e["dry"] = False
        e["import_batch_at"] = _exp_now().isoformat(timespec="seconds")
        _exp_set_status(e, "sent_unverified", reason="import_file", detail="in Hostaway import file")
        _exp4_set_job(e, "exported_not_verified", error="awaiting_import")
        marked.append(e.get("id"))
    csv_bytes = _exp4_csv_bytes(rows)
    batch_id = ""
    if marked:
        import base64
        batch_id = _exp4_new_batch_id()
        _exp4_batches[batch_id] = {
            "batch_id": batch_id, "created_at": _exp_now().isoformat(timespec="seconds"),
            "by": (by or "")[:60], "filename": "ouja-hostaway-import-" + batch_id + ".csv",
            "count": len(meta), "total_sar": round(sum(r["amount"] for r in meta), 2),
            "rows": meta, "csv_b64": base64.b64encode(csv_bytes).decode("ascii"),
        }
        for e_id in marked:
            e = _expenses.get(e_id)
            if e:
                e["import_batch_id"] = batch_id
                _exp4_log(e, "import_file_prepared", actor=by, new="exported_not_verified",
                          detail="in import batch " + batch_id, recommended="upload in Hostaway, then verify")
    persist_state()
    return csv_bytes, marked, skipped, batch_id

def _exp4_batch_status(b):
    """Live tracking for a batch: how many of its expenses are now verified in Hostaway."""
    v = 0
    for r in b.get("rows", []):
        e = _expenses.get(r.get("expense_id"))
        if e and _exp4_export_status(e) == "verified":
            v += 1
    total = len(b.get("rows", []))
    return {"verified": v, "pending": total - v, "total": total}

def _exp4_batches_list(q=""):
    """The files log (newest first), searchable by batch id / OJ-EXP ref / apartment / amount."""
    ql = (q or "").strip().lower()
    out = []
    for b in _exp4_batches.values():
        if ql:
            hay = (b.get("batch_id", "") + " " + " ".join(
                str(r.get("ref", "")) + " " + str(r.get("apartment", "")) + " " + str(r.get("amount", ""))
                for r in b.get("rows", []))).lower()
            if ql not in hay:
                continue
        out.append({"batch_id": b["batch_id"], "created_at": b.get("created_at"), "by": b.get("by", ""),
                    "filename": b.get("filename"), "count": b.get("count"), "total_sar": b.get("total_sar"),
                    "status": _exp4_batch_status(b), "rows": b.get("rows", [])})
    out.sort(key=lambda x: (x.get("created_at") or ""), reverse=True)
    return out

async def _exp4_verify_now(exp):
    """Re-fetch Hostaway and verify this one expense (no API create). Used after a file import
    and for the 'Verify now' action. Green check only on a real match."""
    if not exp or exp.get("is_split_parent"):
        return False, "split_parent"
    ok = await _exp4_verify(exp)
    if ok:
        _exp4_set_job(exp, "verified")
        _exp4_log(exp, "verified_recheck", new="verified", detail=exp.get("verify_note") or "")
    else:
        _exp4_log(exp, "verify_recheck_miss", detail=exp.get("verify_note") or "not_found")
    return ok, ("verified" if ok else (exp.get("verify_note") or "not_found"))

_EXP4_RESET_CLEAR = ("hostaway_ref", "hostaway_expense_id", "hostaway_match_snapshot",
                     "verified_at", "verify_note", "dry", "discrepancy", "primary_reason",
                     "sending_at", "queued_at", "import_batch_at", "error", "error_class", "export_job")

def _exp4_reset_unverified(by=""):
    """Admin 'restart' (one Hostaway pull, then local matching): for every NON-verified
    expense, re-check Hostaway — the ones actually there become Verified; everything else is
    cleaned back to Pending Approval (clears fake exported/FILE/duplicate traces) so the owner
    can re-approve and build a fresh import file. Never deletes; keeps the audit trail."""
    items, ok, err = _exp_fetch_hostaway(force=True)
    reverified = reset = kept = 0
    for e in _expenses.values():
        if e.get("archived") or e.get("is_split_parent"):
            continue
        if _exp4_export_status(e) == "verified":
            kept += 1
            continue
        m = _exp_match_hostaway_item(e, items) if ok else {"present": False, "confidence": 0}
        if ok and m.get("present") and m.get("confidence", 0) >= 0.95:
            e["hostaway_verified"] = True
            e["hostaway_expense_id"] = m.get("id") or e.get("hostaway_expense_id")
            if m.get("id"):
                e["hostaway_ref"] = str(m.get("id"))
            e["hostaway_match_snapshot"] = _exp4_safe_summary(m.get("item") or {},
                ("id", "listingMapId", "amount", "expenseDate", "date", "categoryName", "concept", "reference"))
            e["verified_at"] = _exp_now().isoformat(timespec="seconds")
            e["verify_note"] = "match:" + (m.get("method") or "")
            e["approval_status"] = "approved"
            _exp_set_status(e, "verified", reason="reset_match", detail=m.get("method") or "")
            _exp4_set_job(e, "verified")
            _exp4_log(e, "reset_verified", actor=by, new="verified", detail="found in Hostaway on reset")
            reverified += 1
        else:
            for k in _EXP4_RESET_CLEAR:
                e.pop(k, None)
            e["hostaway_verified"] = False
            e["retry_count"] = 0
            e["approval_status"] = "needs_edit" if _exp4_missing_required(e) else "pending_approval"
            _exp_set_status(e, "captured", reason="reset_unverified", by=by, detail="not in Hostaway — back to pending")
            _exp4_log(e, "reset_unverified", actor=by, new=e["approval_status"], detail="not found in Hostaway; reset to pending")
            reset += 1
    # also drain any leftover in-process queue so nothing re-fires
    try:
        _exp4_queue.clear()
    except Exception:
        pass
    persist_state()
    return {"ok": ok, "error": err, "hostaway_count": len(items or []),
            "reverified": reverified, "reset_to_pending": reset, "kept_verified": kept}

def _exp4_demote_verified(exp, by=""):
    """Un-verify an expense that is no longer in Hostaway: clear the verified/Hostaway link and
    send it back to its real lane (Pending / Needs-Edit). NEVER deletes; fully logged + reversible.
    This is the missing other half of verification — the flag used to be a one-way latch."""
    for k in ("hostaway_ref", "hostaway_expense_id", "hostaway_match_snapshot", "verified_at",
              "verify_note", "export_job", "sending_at", "queued_at"):
        exp.pop(k, None)
    exp["hostaway_verified"] = False
    exp["retry_count"] = 0
    exp["approval_status"] = "needs_edit" if _exp4_missing_required(exp) else "pending_approval"
    _exp_set_status(exp, "captured", reason="reverify_absent", by=by, detail="no longer in Hostaway")
    exp["updated_at"] = _exp_now().isoformat(timespec="seconds")
    _exp4_log(exp, "demoted_unverified", actor=by, new=exp["approval_status"],
              detail="re-check: not found in Hostaway")

def _lid_eq(a, b):
    try:
        return int(a) == int(b)
    except (TypeError, ValueError):
        return False

async def _exp4_reverify_verified(apply=False, by=""):
    """Re-check every VERIFIED expense against live Hostaway. Two findings:
      - ABSENT: nothing in Hostaway resembles it -> un-verify (demote back to Pending). Closes the
        one-way-latch bug where an expense deleted in Hostaway stayed متحققة forever.
      - listing_diff: it IS in Hostaway but filed under a DIFFERENT listing than ours -> kept, but
        reported (the 'verified yet not under this apartment' case the owner caught).

    SAFE BY CONSTRUCTION. An expense is found 'present' if ANY of: its real id is in the live list,
    a direct id-GET resolves it, our reference is embedded in a Hostaway expense, or a Hostaway
    expense shares its amount+date. It is demoted ONLY when NONE of those hold AND the Hostaway
    list came back COMPLETE (we did not hit the page cap — list-miss on a capped list never demotes,
    the 'المصاريف 0' trap). Unreachable Hostaway changes nothing. apply=False is a dry-run."""
    items, ok, err = await asyncio.to_thread(_exp_fetch_hostaway, None, True)
    if not ok:
        return {"ok": False, "error": err or "hostaway_unreachable", "checked": 0, "present": 0,
                "absent": 0, "inconclusive": 0, "listing_ok": 0, "listing_diff": 0,
                "mismatches": [], "demoted": [], "applied": False, "direct_works": False, "complete": False}
    present_items = {}
    for it in items:
        iid = _exp_hostaway_item_id(it)
        if iid:
            present_items[str(iid)] = it
    complete = len(items) < EXPENSE_HA_MAX_PAGES * 100      # didn't hit the page cap → the full list
    # Does this deployment support direct id-GET? Probe a known-present id; if not, we lean on the list.
    direct_works = False
    if present_items:
        probe = next(iter(present_items))
        pit, pok, _pe = await asyncio.to_thread(_exp_fetch_hostaway_one, probe)
        direct_works = bool(pok and str(_exp_hostaway_item_id(pit) or "") == probe)

    def amount_date_anywhere(e):
        try:
            want_amt = round(abs(float(e.get("amount") or 0)), 2)
        except (TypeError, ValueError):
            return None
        want_date = str(e.get("expense_date") or "")[:10]
        if not want_date:
            return None
        for it in items:
            if _exp_hostaway_item_amount(it) == want_amt and _exp_hostaway_item_date(it) == want_date:
                return it
        return None

    verified = [e for e in _expenses.values()
                if not e.get("archived") and not e.get("is_split_parent")
                and _exp4_export_status(e) == "verified"]
    present = inconclusive = listing_ok = listing_diff = 0
    gone, mismatches = [], []
    for e in verified:
        rid = (str(e.get("hostaway_expense_id") or e.get("hostaway_ref") or "")
               if _exp_has_real_hostaway_ref(e) else "")
        ha_item = None
        if rid and rid in present_items:
            ha_item = present_items[rid]                    # its id is in the live Hostaway list
        elif rid and direct_works:
            dit, dok, _de = await asyncio.to_thread(_exp_fetch_hostaway_one, rid)
            if dok and str(_exp_hostaway_item_id(dit) or "") == rid:
                ha_item = dit                               # beyond the list window, but really there
        if ha_item is None:                                 # no id hit → try reference / amount+date match
            m = _exp_match_hostaway_item(e, items)
            if m.get("present") and m.get("confidence", 0) >= 0.80:
                ha_item = m.get("item")
            else:
                ha_item = amount_date_anywhere(e)
        if ha_item is not None:
            present += 1
            our_lid, ha_lid = e.get("listing_id"), _exp_hostaway_item_lid(ha_item)
            if our_lid is not None and ha_lid is not None and not _lid_eq(our_lid, ha_lid):
                listing_diff += 1
                if len(mismatches) < 80:
                    mismatches.append({"ref": e.get("ref") or e.get("id"), "apartment": e.get("apartment") or "",
                                       "our_listing": our_lid, "ha_listing": ha_lid,
                                       "amount": round(abs(float(e.get("amount") or 0)), 2),
                                       "date": str(e.get("expense_date") or "")[:10]})
            else:
                listing_ok += 1
        elif complete:
            gone.append(e)                                  # nothing in the COMPLETE Hostaway list resembles it
        else:
            inconclusive += 1                               # list may be capped → can't be sure
    demoted_refs = []
    for e in gone:
        demoted_refs.append(e.get("ref") or e.get("id"))
        if apply:
            _exp4_demote_verified(e, by=by)
    if apply and demoted_refs:
        _owner_cache_bust()                                 # statements changed → bust the cache
        await asyncio.to_thread(persist_state)
    return {"ok": True, "checked": len(verified), "present": present, "absent": len(gone),
            "inconclusive": inconclusive, "listing_ok": listing_ok, "listing_diff": listing_diff,
            "mismatches": mismatches, "demoted": demoted_refs, "applied": bool(apply),
            "direct_works": direct_works, "complete": complete}

def _exp4_approve_all_pending(by=""):
    """Approve every Pending expense that passes validation (bulk). Invalid ones stay
    Needs-Edit. Returns counts."""
    approved = skipped = 0
    for e in _expenses.values():
        if _exp4_tab(e) != "pending":
            continue
        if _exp4_missing_required(e):
            e["approval_status"] = "needs_edit"; skipped += 1; continue
        ok, _why = _exp4_approve(e, by=by)
        if ok:
            approved += 1
    persist_state()
    return {"ok": True, "approved": approved, "skipped": skipped}

