# ---- Stage 6: per-month apply (preview -> confirm -> apply -> real result) ----
def _month_apply_plan(month_str):
    """Every (unit, date) in `month_str` (YYYY-MM) whose FINAL price differs from the current
    Hostaway price — the exact set the 'Apply [month]' button would write. Preview = plan."""
    recs = _pe_get_recs().get("recs") or []
    plan = []
    for r in recs:
        if not pricing_activated(r.get("lid")):
            continue                                   # opt-in: never plan writes for non-activated units
        d = r.get("date") or ""
        if not d.startswith(month_str):
            continue
        final = r.get("final")
        cur = r.get("current")
        if final is None:
            continue
        if cur is not None and int(final) == int(cur):
            continue                                   # already at the final price — skip
        plan.append({"lid": r["lid"], "unit": r.get("unit"), "date": d,
                     "current": cur, "final": int(final), "color": r.get("final_color"),
                     "source": r.get("final_source", "engine")})
    plan.sort(key=lambda x: ((x["unit"] or ""), x["date"]))
    return plan

async def _api_pricing_month_preview(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    month = (request.query.get("month") or "")[:7]
    if not re.match(r"^\d{4}-\d{2}$", month):
        return _json({"error": "bad month"}, 400)
    plan = await asyncio.to_thread(_month_apply_plan, month)
    raises = sum(1 for p in plan if p["current"] is not None and p["final"] > p["current"])
    drops = sum(1 for p in plan if p["current"] is not None and p["final"] < p["current"])
    return _json({"month": month, "plan": plan, "count": len(plan),
                  "raises": raises, "drops": drops, "dry_run": PRICE_APPLY_DRYRUN})

async def _api_pricing_apply_month(request):
    """Apply every planned price for the month — each through _pe_apply_night (logged via the
    central audit log, DRYRUN-honoring), returning the REAL per-date result. Never faked."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    month = str(b.get("month") or "")[:7]                 # str(): a numeric month in the body must not crash the slice
    if not re.match(r"^\d{4}-\d{2}$", month):
        return _json({"error": "bad month"}, 400)
    plan = await asyncio.to_thread(_month_apply_plan, month)
    results = []
    for p in plan:
        res = await asyncio.to_thread(_pe_apply_night, p["lid"], p["date"], p["final"],
                                      "monthly", f"تطبيق شهري {month}", p["current"])
        results.append({"lid": p["lid"], "unit": p["unit"], "date": p["date"],
                        "final": p["final"], "current": p["current"], "ok": res.get("ok"),
                        "dry": res.get("dry_run"), "confirmed": res.get("confirmed"),
                        "error": res.get("error")})
    applied = sum(1 for r in results if r["ok"])
    failed = sum(1 for r in results if not r["ok"])
    log_event("pricing", f"تطبيق شهري {month} · {applied} نجح · {failed} فشل"
                         + (" · تجربة" if PRICE_APPLY_DRYRUN else ""))
    return _json({"month": month, "results": results, "applied": applied,
                  "failed": failed, "dry_run": PRICE_APPLY_DRYRUN})

# ---- Pricing analytics header + per-apartment apply (redesign; reuses the engine) ----
def _pricing_analytics():
    """Header numbers for the Pricing page — all from existing data (recs, toggles, the
    central change log, revenue, the learning log). Also returns per-unit toggle states."""
    recs = _pe_get_recs().get("recs") or []
    units = sorted({r["lid"] for r in recs if r.get("lid") is not None})
    activated_count = sum(1 for lid in units if pricing_activated(lid))
    strat_counts = {k: sum(1 for lid in units if strategy_enabled(k, lid)) for k in STRATEGY_KEYS}
    unit_toggles = {str(lid): {k: strategy_enabled(k, lid) for k in STRATEGY_KEYS} for lid in units}
    uplift = opp = 0
    for r in recs:
        if not pricing_activated(r.get("lid")):
            continue                                   # uplift/opps reflect ACTIVATED units only
        f, c = r.get("final"), r.get("current")
        if f is not None and c is not None and int(f) != int(c):
            opp += 1
            if f > c:
                uplift += (f - c)
    cur_month = datetime.now(TZ).strftime("%Y-%m")
    # §9: count CONFIRMED Hostaway writes only — never background recomputes/dry entries
    changed = disc = 0
    for entries in _price_log.values():
        for e in entries:
            if (e.get("ts") or "")[:7] == cur_month and e.get("confirmed") is True and not e.get("dry"):
                changed += 1
                if e.get("old") is not None and e.get("new") is not None and e["new"] < e["old"]:
                    disc += 1
    spark, mom = [], None
    try:
        rv = _compute_revenue()
        spark = [{"m": x.get("m"), "rev": x.get("rev", 0)} for x in (rv.get("monthly") or [])][-6:]
        if len(spark) >= 2 and spark[-2]["rev"]:
            mom = round(100.0 * (spark[-1]["rev"] - spark[-2]["rev"]) / spark[-2]["rev"])
    except Exception as e:
        print("pricing analytics revenue:", e)
    ls = _pe_learning_summary()
    ar = ls.get("applied_real", 0)
    bk = ls.get("applied_then_booked", 0)
    hit = {"have": ar > 0, "applied": ar, "booked": bk,
           "rate": (round(100.0 * bk / ar) if ar else None)}
    return {"units": len(units), "activated_count": activated_count,
            "strat_counts": strat_counts, "unit_toggles": unit_toggles,
            "opp": opp, "uplift": int(uplift), "changed_this_month": changed,
            "discount_changes_this_month": disc, "month": cur_month,
            "spark": spark, "mom": mom, "hit_rate": hit, "dry_run": PRICE_APPLY_DRYRUN}

