async def _handle_invest(request):
    # Gated: the shareable investor token (?token=) or an authenticated dashboard session.
    tok = request.query.get("token") or ""
    cur = _invest_token_get()
    ok = bool(tok) and hmac.compare_digest(str(tok), str(cur))
    if not ok and not _dash_auth(request):
        return web.Response(text=_INVEST_DENIED_HTML, content_type="text/html", status=403)
    return web.Response(text=_render_invest_html(), content_type="text/html")

async def _api_invest_link(request):
    """The investor link. GET → current URL + meta (any logged-in dashboard session —
    the home-page deck button and the Users card both read it). POST regenerate →
    ADMIN ONLY, server-side. The owner copies the link from here — never hand-builds URLs."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    if request.method == "POST":
        # regeneration kills every previously shared link — admin only, enforced here
        if not _user_can(request, "users", "write"):
            return _json({"error": "forbidden — admin only"}, 403)
        b = await _read_body(request)
        if (b.get("action") or "") == "regenerate":
            _invest_token_regenerate(_req_actor(request))
        else:
            return _json({"error": "bad action"}, 400)
    tok = _invest_token_get()
    return _json({"ok": True, "url": "/invest?token=" + tok,
                  "source": _invest_link.get("source"),
                  "created_at": _invest_link.get("created_at"),
                  "regens": len(_invest_link.get("regen_log") or []),
                  "can_regenerate": _user_can(request, "users", "write")})

async def _api_pricing_detail(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    try:
        lid = int(request.query.get("lid"))
    except Exception:
        return _json({"error": "bad lid"}, 400)
    return _json(_last_price_detail.get(lid) or {"rows": []})

def _strategy_price(base, d, factors):
    """Best-number price for one night: demand target × Saudi-event boost,
    stepped down as the night nears while empty."""
    mi = factors["month_index"].get(d.month, 1)
    di = factors["dom_index"].get(d.day, 1)
    wi = factors["dow_index"].get(d.weekday(), 1)
    ev = event_boost_for_date(d)           # 1.4-1.6 on Eid / National Day, 0.75 during Ramadan
    target = max(0.6 * base, min(2.2 * base, base * mi * di * wi * ev))
    lead = (d - datetime.now(TZ).date()).days
    f = 0.80 if lead <= 2 else 0.86 if lead <= 5 else 0.92 if lead <= 10 else 0.97 if lead <= 20 else 1.0
    return int(round(max(0.6 * base, target * f)))

def activate_strategy(lid, applied=0):
    """Start (or refresh) an active pricing strategy for a unit from its latest detail rows."""
    det = _last_price_detail.get(lid)
    if not det or not det.get("rows"):
        return False
    dates = {}
    for r in det["rows"]:
        p = r["proposed"]
        dates[r["date"]] = {"start": p, "cur": p, "booked": False, "changes": 0,
                            "last": datetime.now(TZ).isoformat(timespec="minutes")}
    prev = _pricing_strategies.get(lid, {})
    _pricing_strategies[lid] = {"name": det.get("name", str(lid)), "base": det.get("base", 0),
                                "started": prev.get("started") or datetime.now(TZ).isoformat(timespec="minutes"),
                                "updated": time.time(), "active": True, "dates": dates,
                                "applied_start": applied, "changes_total": prev.get("changes_total", 0),
                                "dry_at_start": PRICE_APPLY_DRYRUN}
    return True

async def _kick_strategy(lid):
    """Run a single optimization pass for one unit immediately (called right after Apply)."""
    try:
        strat = _pricing_strategies.get(lid)
        if not strat:
            return
        factors = await asyncio.to_thread(lambda: compute_demand_factors(get_reservations_cached()))
        await asyncio.to_thread(_run_strategy_unit, lid, strat, factors, datetime.now(TZ).date())
    except Exception as e:
        print(f"kick strategy {lid}:", e)

@tasks.loop(minutes=PRICING_STRATEGY_MIN)
async def pricing_strategy_loop():
    """Keep re-optimizing every active unit's open nights toward the best numbers."""
    if not (PRICING_STRATEGY_ENABLED and any(s.get("active") for s in _pricing_strategies.values())):
        return
    try:
        factors = await asyncio.to_thread(lambda: compute_demand_factors(get_reservations_cached()))
    except Exception as e:
        print("strategy factors error:", e)
        return
    today = datetime.now(TZ).date()
    for lid, strat in list(_pricing_strategies.items()):
        if not strat.get("active"):
            continue
        try:
            await asyncio.to_thread(_run_strategy_unit, lid, strat, factors, today)
        except Exception as e:
            print(f"strategy unit {lid} error:", e)

def _run_strategy_unit(lid, strat, factors, today):
    if not strategy_enabled("strategy", lid):
        return                                  # dynamic strategy disabled (globally or for this unit)
    dates = strat["dates"]
    future = [d for d in dates if (_parse_date(d) or today) >= today]
    if not future:
        strat["active"] = False
        return
    ds = sorted(_parse_date(d) for d in future)
    booked_now, note_now, price_now = {}, {}, {}
    try:
        cal = api_get(f"/listings/{lid}/calendar",
                      params={"startDate": ds[0].isoformat(), "endDate": ds[-1].isoformat()})
        for day in (cal.get("result") or []):
            booked_now[day.get("date")] = (int(day.get("isAvailable", 0) or 0) != 1
                                           or bool(day.get("reservationId")))
            note_now[day.get("date")] = day.get("note")       # for preserving the TRUE ouja-orig
            price_now[day.get("date")] = day.get("price")      # live price BEFORE this write
    except Exception as e:
        print("strategy calendar error:", e)
        return
    base = strat.get("base") or factors["overall_adr"]
    for dstr in future:
        d = _parse_date(dstr)
        if d < today:
            continue
        rec = dates[dstr]
        if booked_now.get(dstr):                       # it sold — success, stop managing it
            if not rec["booked"]:
                rec["booked"] = True
                rec["last"] = datetime.now(TZ).isoformat(timespec="minutes")
                log_event("pricing", f"استراتيجية · انحجزت ليلة {dstr} · {strat['name']} ✅")
            continue
        want = _strategy_price(base, d, factors)
        cur = rec.get("cur") or want
        # M1: never write 0/negative or below the hard floors. base can resolve
        # to 0 when the reservations cache is cold → _strategy_price returns 0,
        # and the old raw api_put would have PUT a 0-SAR night to Hostaway.
        floor = max(int(round(DISCOUNT_FLOOR or 0)), int(_pe_floor_overrides.get(lid, 0) or 0))
        if want <= 0 or (floor and want < floor):
            print(f"strategy skip {lid} {dstr}: want={want} below floor {floor} or non-positive")
            continue
        if cur and abs(want - cur) / cur >= 0.03:       # only meaningful moves
            # preserve the TRUE original: existing ouja-orig note → else the live price BEFORE this write
            _orig = _lm_orig_from_note(note_now.get(dstr)) or _coerce_price(price_now.get(dstr)) or cur or want
            # M1: write through _pe_apply_night — floor/zero guards, dry-run,
            # read-back confirm and audit logging live THERE, not here.
            res = _pe_apply_night(lid, dstr, want, source="strategy",
                                  reason="إعادة تحسين ديناميكية (تقترب الليلة وفاضية)",
                                  old=(int(cur) if cur else None),
                                  note="ouja-orig:%d" % int(_orig))
            if not (res or {}).get("ok"):
                print(f"strategy put {lid} {dstr}:", (res or {}).get("error"))
                continue
            rec["cur"] = want
            rec["changes"] = rec.get("changes", 0) + 1
            rec["last"] = datetime.now(TZ).isoformat(timespec="minutes")
            strat["changes_total"] = strat.get("changes_total", 0) + 1
    strat["updated"] = time.time()
    if all(rec["booked"] or (_parse_date(d) and _parse_date(d) < today) for d, rec in dates.items()):
        strat["active"] = False

def _strategy_view(lid):
    """Strategy detail with per-night before/after + the 'why' (month/dom/dow factors +
    lead-time discount) so the dashboard can elaborate each price decision."""
    s = _pricing_strategies.get(lid)
    if not s:
        return {"active": False, "dates": []}
    # compute factors once so we can attach per-night reasoning to the rows
    try:
        factors = compute_demand_factors(get_reservations_cached())
    except Exception:
        factors = {"month_index": {}, "dom_index": {}, "dow_index": {}, "overall_adr": 0}
    today = datetime.now(TZ).date()
    _WD_AR = ["الاثنين", "الثلاثاء", "الأربعاء", "الخميس", "الجمعة", "السبت", "الأحد"]
    _WD_EN = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"]
    rows = []
    for d_str, r in s["dates"].items():
        d = _parse_date(d_str)
        if not d:
            continue
        lead = (d - today).days
        mi = round(factors["month_index"].get(d.month, 1), 2) if d else 1
        di = round(factors["dom_index"].get(d.day, 1), 2) if d else 1
        wi = round(factors["dow_index"].get(d.weekday(), 1), 2) if d else 1
        lead_factor = (0.80 if lead <= 2 else 0.86 if lead <= 5 else
                       0.92 if lead <= 10 else 0.97 if lead <= 20 else 1.0)
        rows.append({
            "date": d_str, "wd_ar": _WD_AR[d.weekday()], "wd_en": _WD_EN[d.weekday()],
            "lead": lead, "start": r["start"], "cur": r["cur"],
            "booked": r["booked"], "changes": r.get("changes", 0),
            "last": r.get("last", ""),
            "mi": mi, "di": di, "wi": wi, "lead_factor": lead_factor,
        })
    rows.sort(key=lambda x: x["date"])
    booked = sum(1 for r in rows if r["booked"])
    return {"name": s.get("name"), "base": s.get("base"), "active": s.get("active", False),
            "started": s.get("started"), "updated": s.get("updated", 0),
            "interval": PRICING_STRATEGY_MIN, "dry_run": PRICE_APPLY_DRYRUN,
            "applied_start": s.get("applied_start", 0), "changes_total": s.get("changes_total", 0),
            "total": len(rows), "booked": booked, "open": len(rows) - booked, "dates": rows}

def _strategies_list():
    """Summary of every strategy (active + finished) for the standing Strategies page."""
    out = []
    for lid, s in _pricing_strategies.items():
        dates = s.get("dates", {})
        booked = sum(1 for r in dates.values() if r.get("booked"))
        # Item 21: revenue captured since the strategy started = sum of the prices on
        # the nights that actually booked while it ran (an estimate, labelled as such).
        rev_captured = round(sum((r.get("cur") or 0) for r in dates.values() if r.get("booked")))
        active = s.get("active", False)
        # Item 22: working (booking nights) vs stalled (active but nothing moved) vs done.
        flag = "done" if not active else ("working" if booked > 0 else "stalled")
        out.append({"lid": lid, "name": s.get("name", str(lid)), "base": s.get("base", 0),
                    "active": active, "started": s.get("started"),
                    "updated": s.get("updated", 0), "total": len(dates), "booked": booked,
                    "rev_captured": rev_captured, "flag": flag,
                    "open": len(dates) - booked, "applied_start": s.get("applied_start", 0),
                    "changes_total": s.get("changes_total", 0),
                    "dry": s.get("dry_at_start", PRICE_APPLY_DRYRUN)})
    # Item 23: active first; within active, STALLED (no bookings) pinned above working
    # so a strategy producing zero movement surfaces at the top to be fixed.
    out.sort(key=lambda x: (not x["active"], x["booked"] > 0, -(x["updated"] or 0)))
    return out

# ============ §3/§4 metric engine — captured / due-hit / 5-state nights (never fabricate) ============
def _strat_night_state(repriced, base, final, booked, passed):
    """The 5 night-states (§4). repriced = ≥1 confirmed non-dry change on this night."""
    if not repriced:
        if final is not None and base is not None and int(final) != int(base):
            return "suggested"            # preview (final≠baseline), not applied
        return "baseline"                 # untouched
    if booked:
        return "booked"                   # applied + the night booked (win)
    if passed:
        return "empty"                    # applied + date passed + never booked (miss)
    return "applied"                      # applied + still future/open (live)

def _strat_booked_index(lid):
    """{date: {booked_price, booked_at}} for nights of `lid` that REALLY booked (from the
    learning log, populated by _pe_backfill_outcomes against confirmed reservations)."""
    idx = {}
    for e in _pe_reco_log:
        if e.get("lid") == lid and e.get("booked") and e.get("date"):
            idx[e["date"]] = {"booked_price": e.get("booked_price"), "booked_at": e.get("booked_at")}
    return idx

def _strat_night_confirmed(lid, date_iso):
    """Confirmed, non-dry price-change entries for one (lid, date)."""
    return [x for x in price_change_log(lid, date_iso)
            if x.get("confirmed") is True and not x.get("dry")]

def _strat_unit_metrics(lid, recs_by_date, today_iso):
    """Per-activated-unit §3 metrics. Considers the UNION of rec dates (future) + every date
    with a confirmed change (catches past repriced nights). captured/due-hit count only
    DUE nights (passed or booked); future-open repriced nights are EXCLUDED."""
    import statistics as _st
    booked_idx = _strat_booked_index(lid)
    dates = set(d for d in recs_by_date.keys() if d)
    for key in _price_log:
        p = key.split("|")
        if len(p) == 2 and p[0] == str(lid):
            dates.add(p[1])
    nights = []
    captured = 0
    n_repriced = n_booked = n_empty = due = 0
    base_booked, after_booked = [], []
    for date_iso in sorted(dates):
        r = recs_by_date.get(date_iso) or {}
        base = r.get("baseline")
        if base is None:
            base = pricing_baseline(lid, date_iso)
        final = r.get("final")
        cur = r.get("current")
        repriced = len(_strat_night_confirmed(lid, date_iso)) > 0
        bk = booked_idx.get(date_iso)
        passed = date_iso < today_iso
        state = _strat_night_state(repriced, base, final, bool(bk), passed)
        if repriced:
            n_repriced += 1
        is_due = repriced and (passed or bool(bk))
        if is_due:
            due += 1
        cap = None
        if state == "booked" and base is not None and bk and bk.get("booked_price") is not None:
            cap = round(bk["booked_price"] - base)
            captured += cap; n_booked += 1
            base_booked.append(base); after_booked.append(bk["booked_price"])
        elif state == "empty":
            n_empty += 1
        nights.append({"date": date_iso, "state": state, "baseline": base, "final": final,
                       "current": cur, "color": r.get("final_color"), "source": r.get("final_source"),
                       "badges": r.get("badges") or [],
                       "booked_price": (bk.get("booked_price") if bk else None),
                       "booked_at": (bk.get("booked_at") if bk else None),
                       "captured": cap, "due": is_due,
                       "moved": (final is not None and base is not None and int(final) != int(base))})
    return {"nights": nights, "captured": int(captured), "n_repriced": n_repriced,
            "n_booked": n_booked, "n_empty": n_empty, "due_nights": due,
            "due_hit": {"booked": n_booked, "due": due,
                        "rate": (round(100.0 * n_booked / due) if due else None)},
            "adr_before": (round(_st.median(base_booked)) if base_booked else None),
            "adr_after": (round(_st.median(after_booked)) if after_booked else None),
            "revpar_before": (round(sum(base_booked) / due) if due else None),
            "revpar_after": (round(sum(after_booked) / due) if due else None),
            "base_sum_booked": int(sum(base_booked))}

def _strat_verdict(m):
    """Najdi + EN one-line verdict per unit (§3)."""
    n, mm, x, k = m["n_repriced"], m["n_booked"], m["captured"], m["n_empty"]
    ar = f"رفعنا {n} ليلة، انحجزت {mm}، كسبنا +{x:,} ر.س فوق الأساسي، و{k} فاتت فاضية."
    en = f"Repriced {n} nights · {mm} booked · +{x:,} SAR over baseline · {k} went empty."
    return ar, en

def _confirmed_changes_month(lids=None):
    """Count CONFIRMED, non-dry Hostaway writes this month (optionally restricted to `lids`)."""
    cur = datetime.now(TZ).strftime("%Y-%m")
    n = 0
    for key, entries in _price_log.items():
        if lids is not None:
            p = key.split("|")
            try:
                if int(p[0]) not in lids:
                    continue
            except (ValueError, IndexError):
                continue
        for e in entries:
            if e.get("confirmed") is True and not e.get("dry") and (e.get("ts") or "")[:7] == cur:
                n += 1
    return n

def _strat_attention(unit_metrics, today):
    """Exception-based attention queue (§6). unit_metrics: [{lid,name,...,_recs}]."""
    out = []
    horizon48 = today + timedelta(days=2)
    for u in unit_metrics:
        nm = u["name"]
        # 1. last-minute risk: applied future nights < 48h out, still open
        risk = [n for n in u["nights"] if n["state"] == "applied"
                and n["date"] and _parse_date(n["date"]) and today <= _parse_date(n["date"]) < horizon48]
        if risk:
            out.append({"kind": "lastminute", "lid": u["lid"],
                        "ar": f"{nm}: {len(risk)} ليالي باقي أقل من ٤٨ ساعة وفاضية — خصم اللحظة الأخيرة شغّال.",
                        "en": f"{nm}: {len(risk)} nights <48h out still open — last-minute step-down active."})
        # 2. un-applied opportunity: suggested nights (final≠baseline, not pushed)
        opp = [n for n in u["nights"] if n["state"] == "suggested" and n["final"] is not None and n["baseline"] is not None]
        gain = sum(max(0, n["final"] - n["baseline"]) for n in opp)
        if opp and gain >= 50:
            out.append({"kind": "unapplied", "lid": u["lid"],
                        "ar": f"{nm}: فرصة +{gain:,} ر.س على {len(opp)} ليلة ما طُبّقت.",
                        "en": f"{nm}: +{gain:,} SAR opportunity on {len(opp)} un-applied nights."})
        # 4. activated but silent: 0 confirmed changes
        if u.get("last_change") is None and u.get("activated_days", 0) >= 2:
            out.append({"kind": "silent", "lid": u["lid"],
                        "ar": f"{nm}: مفعّلة من {u['activated_days']} أيام · ٠ تغييرات — تحتاج إعداد أو بيانات.",
                        "en": f"{nm}: activated {u['activated_days']}d · 0 changes — needs setup or data."})
    return out

def _strategies_deep():
    """The deep Strategies command center — everything happening to the ACTIVATED units, built
    from the central price-change audit log + live recs + real booking outcomes. Per unit:
    every change (old→new · source · confirmed/dry · when), per-night before→after, the active
    strategies, open uplift, and the full timeline. Portfolio totals + per-source breakdown."""
    recs = _pe_get_recs().get("recs") or []
    by_lid = {}
    for r in recs:
        by_lid.setdefault(r.get("lid"), []).append(r)
    listings = get_listings_map() or {}
    today = datetime.now(TZ).date().isoformat()
    # index the append-only change log by listing
    log_by_lid = {}
    for key, entries in _price_log.items():
        parts = key.split("|")
        try:
            lid = int(parts[0])
        except (ValueError, IndexError):
            continue
        dte = parts[1] if len(parts) > 1 else ""
        for e in entries:
            log_by_lid.setdefault(lid, []).append(dict(e, date=dte))
    src_counts, units = {}, []
    total_changes = real_changes = dry_changes = open_uplift = 0
    captured_total = base_sum_total = booked_total = due_total = 0
    for lid, urecs in by_lid.items():
        if not pricing_activated(lid):
            continue
        ulog = sorted(log_by_lid.get(lid, []), key=lambda e: e.get("ts") or "")
        changes = [e for e in ulog if e.get("old") is not None and e.get("new") is not None and e["old"] != e["new"]]
        for e in changes:
            src_counts[e.get("source")] = src_counts.get(e.get("source"), 0) + 1
        u_real = sum(1 for e in changes if not e.get("dry"))
        total_changes += len(changes); real_changes += u_real; dry_changes += (len(changes) - u_real)
        # future-open uplift (for the scoreboard); §3 metrics come from _strat_unit_metrics
        u_uplift = 0
        for r in urecs:
            if (r.get("date") or "") < today:
                continue
            base, fin = r.get("baseline"), r.get("final")
            if base is not None and fin is not None and fin > base:
                u_uplift += (fin - base)
        open_uplift += u_uplift
        m = _strat_unit_metrics(lid, {r.get("date"): r for r in urecs if r.get("date")}, today)
        var, ven = _strat_verdict(m)
        captured_total += m["captured"]; base_sum_total += m["base_sum_booked"]
        booked_total += m["n_booked"]; due_total += m["due_nights"]
        units.append({
            "lid": lid, "name": listings.get(lid) or (urecs[0].get("unit") if urecs else str(lid)),
            "compound": (urecs[0].get("compound") if urecs else ""),
            "changes": len(changes), "real_changes": u_real, "dry_changes": len(changes) - u_real,
            "open_uplift": int(u_uplift), "moved_nights": sum(1 for n in m["nights"] if n["moved"]),
            "active_strategies": [k for k in STRATEGY_KEYS if strategy_enabled(k, lid)],
            "last_change": (ulog[-1]["ts"] if ulog else None),
            "activated_days": 2,    # placeholder; activation timestamp not tracked yet
            "captured": m["captured"], "due_hit": m["due_hit"],
            "n_repriced": m["n_repriced"], "n_booked": m["n_booked"], "n_empty": m["n_empty"],
            "adr_before": m["adr_before"], "adr_after": m["adr_after"],
            "revpar_before": m["revpar_before"], "revpar_after": m["revpar_after"],
            "verdict_ar": var, "verdict_en": ven,
            "nights": m["nights"][:90],
            "log": [dict(e, source_ar=PRICE_SOURCE_LABEL.get(e.get("source"), {}).get("ar", e.get("source")),
                         source_en=PRICE_SOURCE_LABEL.get(e.get("source"), {}).get("en", e.get("source")),
                         source_icon=PRICE_SOURCE_LABEL.get(e.get("source"), {}).get("icon", "•"))
                    for e in sorted(ulog, key=lambda e: e.get("ts") or "", reverse=True)[:50]],
        })
    units.sort(key=lambda u: -u["captured"] if u["captured"] else -u["open_uplift"])
    ls = _pe_learning_summary()
    ar_n, bk = ls.get("applied_real", 0), ls.get("applied_then_booked", 0)
    src_break = [{"source": s, "count": c,
                  "label_ar": PRICE_SOURCE_LABEL.get(s, {}).get("ar", s),
                  "label_en": PRICE_SOURCE_LABEL.get(s, {}).get("en", s),
                  "icon": PRICE_SOURCE_LABEL.get(s, {}).get("icon", "•")}
                 for s, c in sorted(src_counts.items(), key=lambda kv: -kv[1])]
    spark, mom = [], None
    try:
        rv = _compute_revenue()
        spark = [{"m": x.get("m"), "rev": x.get("rev", 0)} for x in (rv.get("monthly") or [])][-6:]
        if len(spark) >= 2 and spark[-2]["rev"]:
            mom = round(100.0 * (spark[-1]["rev"] - spark[-2]["rev"]) / spark[-2]["rev"])
    except Exception as e:
        print("strategies deep revenue:", e)
    activated_lids = set(u["lid"] for u in units)
    today_d = datetime.now(TZ).date()
    attention = _strat_attention(units, today_d)
    # HERO — captured SAR over BOOKED repriced nights only (future-open excluded → no 2/348 lie)
    captured_pct = (round(100.0 * captured_total / base_sum_total) if base_sum_total else None)
    hero = {"captured": int(captured_total),
            "captured_pct": captured_pct,
            "have_outcome": booked_total > 0,
            "booked": booked_total, "due": due_total,
            "due_hit": {"booked": booked_total, "due": due_total,
                        "rate": (round(100.0 * booked_total / due_total) if due_total else None)}}
    return {"activated": len(units), "total_units": len(by_lid),
            "total_changes": total_changes, "real_changes": real_changes, "dry_changes": dry_changes,
            "confirmed_changes_month": _confirmed_changes_month(activated_lids),
            "open_uplift": int(open_uplift), "source_breakdown": src_break,
            "hero": hero, "attention": attention,
            "hit_rate": {"have": ar_n > 0, "applied": ar_n, "booked": bk,
                         "rate": (round(100.0 * bk / ar_n) if ar_n else None)},
            "spark": spark, "mom": mom, "month": today[:7], "dry_run": PRICE_APPLY_DRYRUN, "units": units}

