async def _api_cleaning_import_csv(request):
    """POST multipart-form with field 'file' = a CSV with two columns: name,date.
    Header row optional. Date format: YYYY-MM-DD (or DD/MM/YYYY also accepted).
    Names are matched against listings by normalized comparison
    (strip 'Ouja|', lower-case, collapse whitespace)."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    try:
        reader = await request.multipart()
        field = await reader.next()
        if not field or field.name != "file":
            return _json({"error": "expected 'file' multipart field"}, 400)
        raw = (await field.read()).decode("utf-8-sig", errors="ignore")
    except Exception as e:
        return _json({"error": f"upload error: {e}"}, 400)

    import csv as _csv, io as _io
    listings = (await get_listings_map_async()) or {}
    norm_to_lid = {norm_unit(name): lid for lid, name in listings.items()}
    rows = list(_csv.reader(_io.StringIO(raw)))
    if not rows:
        return _json({"error": "empty CSV"}, 400)
    # Skip the header row if first row's "date" cell doesn't parse as a date
    start = 0
    if rows[0]:
        test_date = (rows[0][-1] or "").strip()
        if not _parse_any_date(test_date):
            start = 1

    matched, unmatched, no_date = [], [], []
    for r in rows[start:]:
        if not r or len(r) < 2:
            continue
        raw_name = (r[0] or "").strip()
        raw_date = (r[-1] or "").strip()
        if not raw_name:
            continue
        d = _parse_any_date(raw_date)
        if not d:
            no_date.append({"name": raw_name, "raw_date": raw_date})
            continue
        n = norm_unit(raw_name)
        lid = norm_to_lid.get(n)
        if not lid:
            # fuzzy fallback: contains-match
            for k, v in norm_to_lid.items():
                if n and (n in k or k in n) and len(n) >= 3:
                    lid = v
                    break
        if not lid:
            unmatched.append({"name": raw_name})
            continue
        if lid not in _deep_clean_state:
            _dc_init(lid)
        _deep_clean_state[lid]["last_done"] = d.isoformat()
        _deep_clean_state[lid]["next_scheduled"] = None
        _deep_clean_state[lid]["next_status"] = "unscheduled"
        matched.append({"lid": lid, "name": listings[lid], "date": d.isoformat()})
    await asyncio.to_thread(persist_state)
    # rerun scheduler so the new dates flow into next_scheduled
    await asyncio.to_thread(schedule_deep_cleans)
    log_event("pricing", f"تنظيف عميق · استورد {len(matched)} وحدة من CSV "
                          f"(غير مطابقة: {len(unmatched)}, بدون تاريخ: {len(no_date)})")
    return _json({"ok": True, "matched": matched, "unmatched": unmatched, "no_date": no_date})

def _parse_any_date(s):
    """Tolerant date parser: accepts YYYY-MM-DD, DD/MM/YYYY, DD-MM-YYYY, MM/DD/YYYY."""
    s = (s or "").strip()
    if not s:
        return None
    for fmt in ("%Y-%m-%d", "%d/%m/%Y", "%d-%m-%Y", "%m/%d/%Y", "%Y/%m/%d"):
        try:
            return datetime.strptime(s[:10], fmt).date()
        except Exception:
            pass
    return None

# ---- Smart Arabic free-form date parser (for the cleaning-baseline import) ----
_AR_NUM_MAP = str.maketrans("٠١٢٣٤٥٦٧٨٩", "0123456789")
_AR_MONTHS = {
    "يناير": 1, "كانون الثاني": 1,
    "فبراير": 2, "شباط": 2,
    "مارس": 3, "آذار": 3, "اذار": 3,
    "أبريل": 4, "ابريل": 4, "نيسان": 4,
    "مايو": 5, "أيار": 5, "ايار": 5,
    "يونيو": 6, "حزيران": 6,
    "يوليو": 7, "تموز": 7,
    "أغسطس": 8, "اغسطس": 8, "آب": 8,
    "سبتمبر": 9, "أيلول": 9, "ايلول": 9,
    "أكتوبر": 10, "اكتوبر": 10, "تشرين الأول": 10,
    "نوفمبر": 11, "تشرين الثاني": 11,
    "ديسمبر": 12, "كانون الأول": 12,
}
# Phrases that mean "we don't know" / "never done". Caller treats these as the
# unit being maximally overdue (forces immediate scheduling).
_AR_UNKNOWN_PHRASES = ("مدري", "ماسوينا", "ما سوينا", "ما تم", "?", "n/a", "—")

def parse_ar_freeform_date(s, today=None):
    """Returns (date | None, was_unknown:bool). Handles ISO, DD/MM/YYYY,
    "قبل X يوم/اسبوع/شهر[ ونص]", Arabic month names with Arabic or western
    numerals, and uncertainty phrases like "مدري"/"ماسوينا" → returns (None, True)."""
    if s is None:
        return None, False
    today = today or datetime.now(TZ).date()
    if isinstance(s, datetime):
        return s.date(), False
    if isinstance(s, date) and not isinstance(s, datetime):
        return s, False
    raw = str(s).strip()
    if not raw:
        return None, False
    s = raw.translate(_AR_NUM_MAP).lower().strip()
    if any(s == u or s.startswith(u) for u in _AR_UNKNOWN_PHRASES if u):
        return None, True
    d = _parse_any_date(s)
    if d:
        return d, False
    # relative day phrases
    m = re.search(r"قبل\s*(\d+)\s*(?:يوم|ايام|أيام)", s)
    if m: return today - timedelta(days=int(m.group(1))), False
    if "قبل اسبوعين" in s or "قبل أسبوعين" in s: return today - timedelta(days=14), False
    if "قبل اسبوع" in s or "قبل أسبوع" in s: return today - timedelta(days=7), False
    m = re.search(r"قبل\s*(\d+)\s*(?:اسابيع|أسابيع)", s)
    if m: return today - timedelta(weeks=int(m.group(1))), False
    if "قبل شهرين ونص" in s or "قبل شهرين ونصف" in s: return today - timedelta(days=75), False
    if "قبل شهر ونص" in s or "قبل شهر ونصف" in s: return today - timedelta(days=45), False
    if "قبل شهرين" in s: return today - timedelta(days=60), False
    if "قبل شهر" in s: return today - timedelta(days=30), False
    m = re.search(r"قبل\s*(\d+)\s*(?:اشهر|أشهر|شهور)", s)
    if m: return today - timedelta(days=30 * int(m.group(1))), False
    # Arabic month name with day number
    for name, num in _AR_MONTHS.items():
        if name in s:
            digs = re.findall(r"\d+", s)
            if digs:
                day_n = int(digs[0])
                if 1 <= day_n <= 31:
                    try:
                        d = date(today.year, num, day_n)
                        if (d - today).days > 180:
                            d = date(today.year - 1, num, day_n)
                        return d, False
                    except ValueError:
                        pass
    return None, False

# Add a 'date' alias at module level since we use it in the helper above
from datetime import date  # noqa: E402

async def _api_cleaning_import_xlsx(request):
    """POST multipart 'file' = .xlsx with one row per apartment.
    Auto-detects which columns hold the apartment name and the last-clean date
    (any cell in a row that parses as an Arabic-or-ISO date counts as the date,
    any cell that matches a catalog name as the name). 'مدري' / 'ماسوينا' / blank
    are treated as 'overdue from day one' so the scheduler picks them first."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    try:
        import openpyxl as _xl, io as _io
    except Exception:
        return _json({"error": "openpyxl not installed"}, 500)
    try:
        reader = await request.multipart()
        field = await reader.next()
        if not field or field.name != "file":
            return _json({"error": "expected 'file' multipart field"}, 400)
        blob = await field.read()
    except Exception as e:
        return _json({"error": f"upload error: {e}"}, 400)
    try:
        wb = _xl.load_workbook(_io.BytesIO(blob), data_only=True)
    except Exception as e:
        return _json({"error": f"not a valid xlsx: {e}"}, 400)

    listings = (await get_listings_map_async()) or {}
    norm_to_lid = {norm_unit(n): lid for lid, n in listings.items()}
    today = datetime.now(TZ).date()
    # treat "unknown" as 90 days ago so the scheduler picks them immediately
    UNKNOWN_FALLBACK = today - timedelta(days=90)

    matched, unmatched, unknown_dates = [], [], []
    for sheet in wb.sheetnames:
        ws = wb[sheet]
        for row in ws.iter_rows(values_only=True):
            # Find name-cell + date-cell heuristically
            name_cell, date_cell, parsed_date, was_unknown = None, None, None, False
            for cell in row:
                if isinstance(cell, str) and len(cell.strip()) >= 2:
                    norm = norm_unit(cell)
                    if norm in norm_to_lid:
                        name_cell = cell; continue
                d, unk = parse_ar_freeform_date(cell, today=today)
                if d:
                    date_cell = cell; parsed_date = d
                if unk:
                    was_unknown = True; date_cell = cell
            # Fallback: if no exact match, try fuzzy contains on string cells
            if not name_cell:
                for cell in row:
                    if isinstance(cell, str) and len(cell.strip()) >= 2:
                        norm = norm_unit(cell)
                        for k in norm_to_lid:
                            if norm and (norm in k or k in norm) and abs(len(norm) - len(k)) <= 6:
                                name_cell = cell
                                break
                        if name_cell:
                            break
            if not name_cell:
                continue
            lid = norm_to_lid.get(norm_unit(name_cell))
            if not lid:
                for k, v in norm_to_lid.items():
                    n = norm_unit(name_cell)
                    if n and (n in k or k in n) and abs(len(n) - len(k)) <= 6:
                        lid = v; break
            if not lid:
                unmatched.append({"name": name_cell, "raw_date": str(date_cell or "")})
                continue
            if lid not in _deep_clean_state:
                _dc_init(lid)
            if parsed_date:
                _deep_clean_state[lid]["last_done"] = parsed_date.isoformat()
                _deep_clean_state[lid]["next_scheduled"] = None
                _deep_clean_state[lid]["next_status"] = "unscheduled"
                matched.append({"lid": lid, "name": listings[lid],
                                "raw_date": str(date_cell), "parsed": parsed_date.isoformat()})
            elif was_unknown:
                _deep_clean_state[lid]["last_done"] = UNKNOWN_FALLBACK.isoformat()
                _deep_clean_state[lid]["next_scheduled"] = None
                _deep_clean_state[lid]["next_status"] = "unscheduled"
                _deep_clean_state[lid]["notes"] = (
                    "تاريخ آخر تنظيف غير معروف (مدري/ماسوينا) — تمت معاملته كأنه قبل ٩٠ يوم لضمان جدولة فورية."
                )
                unknown_dates.append({"lid": lid, "name": listings[lid],
                                      "raw_date": str(date_cell)})
    # Re-run the scheduler so the freshly-imported dates yield real next dates
    await asyncio.to_thread(persist_state)
    await asyncio.to_thread(schedule_deep_cleans)
    log_event("pricing",
              f"تنظيف عميق · استيراد XLSX: {len(matched)} تاريخ + "
              f"{len(unknown_dates)} غير معروف · {len(unmatched)} غير مطابق")
    return _json({"ok": True, "matched": matched, "unknown": unknown_dates,
                  "unmatched": unmatched})

async def _api_cleaning_set_last(request):
    """POST {lid, date} — set last_done (used to import the April 27 baseline file)."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    try:
        lid = int(b.get("lid"))
    except Exception:
        return _json({"error": "bad lid"}, 400)
    date = b.get("date")
    if not _parse_date(date):
        return _json({"error": "bad date"}, 400)
    if lid not in _deep_clean_state:
        _dc_init(lid)
    _deep_clean_state[lid]["last_done"] = date
    _deep_clean_state[lid]["next_scheduled"] = None
    _deep_clean_state[lid]["next_status"] = "unscheduled"
    await asyncio.to_thread(persist_state)
    return _json({"ok": True})

def _dc_effective_anchor():
    """Resolve the start date for an auto-compaction.
       - If owner set an anchor via reschedule-from, use max(anchor, tomorrow-valid).
       - Otherwise default to tomorrow's next valid day."""
    tomorrow = datetime.now(TZ).date() + timedelta(days=1)
    tomorrow_v = _dc_next_valid_day(tomorrow)
    anchor = _parse_date(_dc_anchor_date) if _dc_anchor_date else None
    if anchor and anchor > tomorrow_v:
        return _dc_next_valid_day(anchor).isoformat()
    return tomorrow_v.isoformat()

async def _api_cleaning_pause(request):
    """POST {lid} — pause a unit. After the pause we auto-compact the queue
    forward so we don't waste days: the remaining units are re-laid starting from
    the owner's anchor date (or tomorrow if no anchor)."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    try:
        lid = int(b.get("lid"))
    except Exception:
        return _json({"error": "bad lid"}, 400)
    _paused_units.add(lid)
    if lid in _deep_clean_state:
        _deep_clean_state[lid]["next_scheduled"] = None
        _deep_clean_state[lid]["next_status"] = "paused"
    # Auto-compact: pull the remaining queue forward so the gap left behind
    # gets filled instead of every other unit drifting later.
    start_iso = _dc_effective_anchor()
    _dc_reset_from(start_iso, set_anchor=False)
    await asyncio.to_thread(persist_state)
    name = next((u["name"] for u in _catalog_units if u.get("id") == lid), str(lid))
    log_event("pricing", f"تنظيف عميق · {name}: تم الإيقاف ⏸ · تم ضغط الطابور من {start_iso}")
    return _json({"ok": True, "rebased_from": start_iso})

async def _api_cleaning_unpause(request):
    """POST {lid} — unpause a unit. Re-compacts the whole queue from the anchor
    so the just-unpaused unit gets slotted in by last_done priority (oldest first)
    instead of pinned to the very end."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    try:
        lid = int(b.get("lid"))
    except Exception:
        return _json({"error": "bad lid"}, 400)
    _paused_units.discard(lid)
    if lid in _deep_clean_state and _deep_clean_state[lid].get("next_status") == "paused":
        _deep_clean_state[lid]["next_status"] = "unscheduled"
    # Re-compact from the anchor so this unit takes its priority slot.
    start_iso = _dc_effective_anchor()
    _dc_reset_from(start_iso, set_anchor=False)
    await asyncio.to_thread(persist_state)
    name = next((u["name"] for u in _catalog_units if u.get("id") == lid), str(lid))
    log_event("pricing", f"تنظيف عميق · {name}: تم تشغيله ▶ · تم إعادة الترتيب من {start_iso}")
    return _json({"ok": True, "rebased_from": start_iso})

async def _api_cleaning_insert(request):
    """POST {lid, date} — insert a deep-clean for lid at date (e.g. after finishing).
    If date is occupied, the occupant is cascade-pushed forward."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    try:
        lid = int(b.get("lid"))
    except Exception:
        return _json({"error": "bad lid"}, 400)
    date = b.get("date")
    if not _parse_date(date):
        return _json({"error": "bad date"}, 400)
    # Un-pause if it was paused
    _paused_units.discard(lid)
    if lid not in _deep_clean_state:
        _dc_init(lid)
    _dc_insert_at(lid, date)
    await asyncio.to_thread(persist_state)
    name = next((u["name"] for u in _catalog_units if u.get("id") == lid), str(lid))
    final_date = _deep_clean_state.get(lid, {}).get("next_scheduled", date)
    log_event("pricing", f"تنظيف عميق · {name}: إضافة في {final_date} ➕")
    return _json({"ok": True, "scheduled_for": final_date})

async def _api_cleaning_reschedule_from(request):
    """POST {date} — wipe all non-paused next_scheduled and re-lay the queue
    starting from `date`, oldest-last_done first."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    date = b.get("date")
    if not _parse_date(date):
        return _json({"error": "bad date"}, 400)
    n = _dc_reset_from(date)
    await asyncio.to_thread(persist_state)
    log_event("pricing", f"تنظيف عميق · إعادة جدولة من {date} · {n} شقة 🔄")
    return _json({"ok": True, "rescheduled": n})

# ===================== MAINTENANCE TICKETS API =====================
def _ticket_view(t):
    """Dashboard-friendly view of a ticket (no sensitive internals)."""
    open_age = None
    try:
        if t.get("created_at") and t.get("status") in ("open", "in_progress"):
            ca = datetime.fromisoformat(t["created_at"])
            open_age = (datetime.now(TZ) - ca).days
    except Exception:
        open_age = None
    overdue = False
    try:
        if t.get("due_date") and t.get("status") in ("open", "in_progress"):
            d = datetime.strptime(t["due_date"], "%Y-%m-%d").date()
            overdue = d < datetime.now(TZ).date()
    except Exception:
        overdue = False
    # Item 32: SLA status from due date / age.
    sla = "none"
    if t.get("status") in ("open", "in_progress"):
        if overdue:
            sla = "overdue"
        elif t.get("due_date"):
            try:
                dd = (datetime.strptime(t["due_date"], "%Y-%m-%d").date() - datetime.now(TZ).date()).days
                sla = "due_soon" if dd <= 2 else "ok"
            except Exception:
                sla = "ok"
        elif open_age is not None and open_age >= 7:
            sla = "aging"
        else:
            sla = "ok"
    # Item 34: recurring = same problem category seen before in the same unit.
    recurring = False
    _lid, _cat = t.get("lid"), t.get("category")
    if _lid is not None and _cat:
        recurring = sum(1 for o in _tickets
                        if o.get("lid") == _lid and o.get("category") == _cat
                        and o.get("id") != t.get("id")) > 0
    return {
        "sla": sla, "recurring": recurring,
        "id": t["id"], "title": t.get("title", ""),
        "description": t.get("description", ""),
        "status": t.get("status", "open"),
        "priority": t.get("priority", "med"),
        "category": t.get("category", "صيانة"),
        "lid": t.get("lid"), "unit_name": t.get("unit_name"),
        "assignee": t.get("assignee"),
        "due_date": t.get("due_date"),
        "cost": t.get("cost"),
        "vendor": t.get("vendor"), "vendor_phone": t.get("vendor_phone"),
        "source": t.get("source", "manual"),
        "source_ref": t.get("source_ref"),
        "guest": t.get("guest"),
        "created_at": t.get("created_at"),
        "created_by": t.get("created_by", "bot"),
        "log": t.get("log", [])[-10:],
        "open_age_days": open_age,
        "overdue": overdue,
    }

_tickets_ctx_cache = {"ts": 0, "hot_lids": set(), "next_arr": {}}

def _tickets_context(today):
    """Occupied-now + arriving-soon context for ticket impact sorting, cached 5 min
    (fetch_inhouse is a live Hostaway query — once per tab-load was wasteful)."""
    now = time.time()
    if now - _tickets_ctx_cache["ts"] < 300:
        return _tickets_ctx_cache["hot_lids"], _tickets_ctx_cache["next_arr"]
    hot_lids, next_arr = set(), {}
    try:
        for r in fetch_inhouse(today):
            a, d = _parse_date(r.get("arrivalDate")), _parse_date(r.get("departureDate"))
            if a and d and a <= today < d:
                hot_lids.add(r.get("listingMapId"))
        for r in get_reservations_cached():
            if not _res_realized(r):
                continue
            a = _parse_date(r.get("arrivalDate")); lid = r.get("listingMapId")
            if a and a >= today:
                if (lid not in next_arr) or (a.isoformat() < next_arr[lid]):
                    next_arr[lid] = a.isoformat()
                if 0 <= (a - today).days <= 2:
                    hot_lids.add(lid)
        _tickets_ctx_cache.update({"ts": now, "hot_lids": hot_lids, "next_arr": next_arr})
    except Exception as e:
        print("tickets context error:", e)
    return hot_lids, next_arr

async def _api_tickets_list(request):
    """GET /api/tickets/list?status=&priority=&category=&q=&lid="""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    q  = (request.query.get("q", "") or "").lower().strip()
    st = (request.query.get("status", "") or "").strip()
    pr = (request.query.get("priority", "") or "").strip()
    cat = (request.query.get("category", "") or "").strip()
    try:
        lid_f = int(request.query.get("lid")) if request.query.get("lid") else None
    except Exception:
        lid_f = None
    # Items 31/33: which units are occupied now or arriving soon. Cached 5 min and
    # computed off the event loop — this was a LIVE Hostaway call on every tab load.
    today = datetime.now(TZ).date()
    hot_lids, next_arr = await asyncio.to_thread(_tickets_context, today)
    items = []
    for t in _tickets:
        if st and t.get("status") != st: continue
        if pr and t.get("priority") != pr: continue
        if cat and t.get("category") != cat: continue
        if lid_f is not None and t.get("lid") != lid_f: continue
        if q:
            blob = " ".join(str(t.get(k, "")) for k in
                            ("title", "description", "unit_name", "vendor",
                             "assignee", "guest")).lower()
            if q not in blob: continue
        v = _ticket_view(t)
        v["impact_hot"] = v.get("lid") in hot_lids
        v["next_arrival"] = next_arr.get(v.get("lid"))
        items.append(v)
    # Item 31: tickets on occupied / about-to-be-occupied units first, then overdue,
    # then priority, then oldest.
    rank = {"urgent": 3, "high": 2, "med": 1, "low": 0}
    items.sort(key=lambda x: (0 if x.get("impact_hot") else 1,
                              0 if x["overdue"] else 1,
                              -(rank.get(x["priority"], 1)),
                              x.get("created_at") or ""), reverse=False)
    # Counts — single pass over _tickets (was 4 separate full scans per load)
    counts = {"total": len(_tickets), "open": 0, "in_progress": 0, "fixed": 0,
              "overdue": sum(1 for v in items if v["overdue"]), "urgent": 0}
    for t in _tickets:
        st_t = t.get("status")
        if st_t in counts and st_t in ("open", "in_progress", "fixed"):
            counts[st_t] += 1
        if t.get("priority") == "urgent" and st_t in ("open", "in_progress"):
            counts["urgent"] += 1
    return _json({
        "items": items, "counts": counts,
        "categories": _TICKET_CATS,
        "today": datetime.now(TZ).date().isoformat(),
    })

async def _api_tickets_create(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    title = (b.get("title") or "").strip()
    if not title:
        return _json({"error": "title required"}, 400)
    t = _ticket_create(
        title=title,
        description=(b.get("description") or "").strip(),
        lid=b.get("lid"),
        priority=(b.get("priority") or "med"),
        category=(b.get("category") or "صيانة"),
        assignee=(b.get("assignee") or None),
        due_date=(b.get("due_date") or None),
        cost=b.get("cost"),
        vendor=(b.get("vendor") or None),
        vendor_phone=(b.get("vendor_phone") or None),
        source="manual",
        created_by=(b.get("created_by") or "owner"),
    )
    await asyncio.to_thread(persist_state)
    return _json({"ok": True, "ticket": _ticket_view(t)})

def _find_ticket(tid):
    for t in _tickets:
        if t.get("id") == tid:
            return t
    return None

async def _api_tickets_update(request):
    """POST {id, status?, priority?, category?, assignee?, due_date?, cost?,
       vendor?, vendor_phone?, title?, description?, note?}"""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    tid = (b.get("id") or "").strip()
    t = _find_ticket(tid)
    if not t:
        return _json({"error": "not found"}, 404)
    who = (b.get("by") or "owner").strip() or "owner"
    changed = []
    field_map_ar = {
        "status":   "الحالة",
        "priority": "الأولوية",
        "category": "التصنيف",
        "assignee": "المسؤول",
        "due_date": "تاريخ الاستحقاق",
        "cost":     "التكلفة",
        "vendor":   "المورّد",
        "vendor_phone": "هاتف المورّد",
        "title":    "العنوان",
        "description": "الوصف",
    }
    for k in ("status", "priority", "category", "assignee", "due_date",
              "cost", "vendor", "vendor_phone", "title", "description"):
        if k not in b:
            continue
        v = b.get(k)
        if k == "status" and v and v not in _TICKET_STATUSES:
            continue
        if k == "priority" and v and v not in _TICKET_PRIORITY:
            continue
        if k == "category" and v and v not in _TICKET_CATS:
            continue
        old = t.get(k)
        if old == v:
            continue
        t[k] = v
        changed.append(f"{field_map_ar.get(k, k)}: {old or '—'} → {v or '—'}")
    note = (b.get("note") or "").strip()
    if note:
        _ticket_log(t, who, f"تعليق: {note[:200]}")
    if changed:
        _ticket_log(t, who, " · ".join(changed)[:280])
    await asyncio.to_thread(persist_state)
    return _json({"ok": True, "ticket": _ticket_view(t)})

async def _api_tickets_delete(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    tid = (b.get("id") or "").strip()
    for i, t in enumerate(_tickets):
        if t.get("id") == tid:
            del _tickets[i]
            await asyncio.to_thread(persist_state)
            return _json({"ok": True})
    return _json({"error": "not found"}, 404)

# ===================== REVIEWS API =====================
def _review_urgency(rating, has_text):
    """Map a rating + content to an urgency band used by the UI cards."""
    if rating and rating <= 2:
        return "urgent"
    if rating and rating <= 3:
        return "warning"
    if not has_text:
        return "normal"
    return "normal"

def _review_view(rev_id, rev):
    ai = _review_ai_cache.get(rev_id) or {}
    state = _review_states.get(rev_id) or {}
    tr = _review_translations.get(rev_id) or {}
    listings = get_listings_map() or {}
    unit_name = listings.get(rev.get("listing_id"), str(rev.get("listing_id") or ""))
    return {
        "id": rev_id,
        "listing_id": rev.get("listing_id"),
        "unit_name": unit_name,
        "guest_name": rev.get("guest_name") or "",
        "rating": rev.get("rating") or 0,
        "rating_raw": rev.get("rating_raw") or 0,
        "channel": rev.get("channel") or "",
        "date": rev.get("date") or "",
        "public_review": rev.get("public_review") or "",
        "public_review_en": tr.get("en") or "",
        "private_review": rev.get("private_review") or "",
        "urgency": _review_urgency(rev.get("rating") or 0,
                                   bool(rev.get("public_review"))),
        "analyzed": bool(ai),
        "is_positive": bool(ai.get("is_positive")) if ai else (
            True if (rev.get("rating") or 0) >= 4 else False),
        "ai": {
            "removability":           ai.get("removability"),
            "removability_reason_ar": ai.get("removability_reason_ar"),
            "policy_reference":       ai.get("policy_reference"),
            "dispute_angle_ar":       ai.get("dispute_angle_ar"),
            "dispute_message_en":     ai.get("dispute_message_en"),
            "public_response_ar":     ai.get("public_response_ar"),
            "public_response_en":     ai.get("public_response_en"),
            "is_positive":            ai.get("is_positive"),
            "generated_at":           ai.get("generated_at"),
        } if ai else None,
        "state": {
            "fixed":        bool(state.get("fixed")),
            "assignee":     state.get("assignee"),
            "notes":        state.get("notes") or "",
            "ticket_id":    state.get("ticket_id"),
            "last_edit_by": state.get("last_edit_by"),
            "last_edit_at": state.get("last_edit_at"),
        },
    }

def _review_in_window(rev, days):
    """True if the review's date is within the last `days` days. days=0 → all."""
    if not days:
        return True
    d = (rev or {}).get("date") or ""
    if not d:
        return False
    try:
        rd = datetime.strptime(d[:10], "%Y-%m-%d").date()
    except Exception:
        return False
    today = datetime.now(TZ).date()
    return (today - rd).days <= days

async def _api_reviews_list(request):
    """GET /api/reviews/list?lid=&urgency=&fixed=&q=&days=&sentiment="""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    try:
        lid_f = int(request.query.get("lid")) if request.query.get("lid") else None
    except Exception:
        lid_f = None
    urg = (request.query.get("urgency") or "").strip()
    fixed = request.query.get("fixed", "")
    q = (request.query.get("q") or "").lower().strip()
    try:
        days = int(request.query.get("days") or 0)
    except Exception:
        days = 0
    sentiment = (request.query.get("sentiment") or "").strip()  # "" | "positive" | "negative"

    rows = []
    for rid, rev in _reviews.items():
        if not _review_in_window(rev, days):
            continue
        v = _review_view(rid, rev)
        if lid_f is not None and v["listing_id"] != lid_f: continue
        if urg and v["urgency"] != urg: continue
        if fixed == "1" and not v["state"]["fixed"]: continue
        if fixed == "0" and v["state"]["fixed"]: continue
        if sentiment == "positive" and not v["is_positive"]: continue
        if sentiment == "negative" and v["is_positive"]: continue
        if q:
            blob = (v["public_review"] + " " + v["public_review_en"] + " "
                    + v["guest_name"] + " " + v["unit_name"]).lower()
            if q not in blob: continue
        rows.append(v)
    # newest first, urgent first
    rank = {"urgent": 3, "warning": 2, "normal": 1}
    rows.sort(key=lambda x: (rank.get(x["urgency"], 0),
                             x.get("date") or ""), reverse=True)

    # Group by apartment for the UI
    by_unit = {}
    for v in rows:
        lid = v["listing_id"]
        key = str(lid) if lid is not None else "_"
        by_unit.setdefault(key, {
            "listing_id": lid, "unit_name": v["unit_name"],
            "reviews": [], "count": 0, "avg": 0.0,
            "urgency": "normal", "unfixed_negatives": 0,
        })
        by_unit[key]["reviews"].append(v)
    for grp in by_unit.values():
        ratings = [r["rating"] for r in grp["reviews"] if r["rating"]]
        grp["count"] = len(grp["reviews"])
        grp["avg"] = round(sum(ratings) / len(ratings), 2) if ratings else 0
        urgs = [r["urgency"] for r in grp["reviews"]]
        if "urgent" in urgs: grp["urgency"] = "urgent"
        elif "warning" in urgs: grp["urgency"] = "warning"
        grp["unfixed_negatives"] = sum(
            1 for r in grp["reviews"]
            if r["urgency"] in ("urgent", "warning") and not r["state"]["fixed"])
    units = sorted(by_unit.values(),
                   key=lambda g: (-{"urgent":2,"warning":1,"normal":0}[g["urgency"]],
                                  -g["unfixed_negatives"],
                                  g["avg"]))
    # Per-window counters so the UI's time-filter buttons can show counts
    def _count_window(d):
        return sum(1 for r in _reviews.values() if _review_in_window(r, d))
    windows = {"all": _count_window(0), "7d": _count_window(7),
               "14d": _count_window(14), "30d": _count_window(30),
               "90d": _count_window(90), "180d": _count_window(180),
               "365d": _count_window(365)}
    counts = {
        "total":    len(_reviews),
        "shown":    len(rows),
        "urgent":   sum(1 for v in rows if v["urgency"] == "urgent"),
        "warning":  sum(1 for v in rows if v["urgency"] == "warning"),
        "positive": sum(1 for v in rows if v["is_positive"]),
        "unfixed":  sum(1 for v in rows if v["urgency"] in ("urgent","warning") and not v["state"]["fixed"]),
        "analyzed": sum(1 for v in rows if v["analyzed"]),
        "translated": sum(1 for v in rows if v["public_review_en"]),
        "windows":  windows,
    }
    return _json({
        "units": units,
        "counts": counts,
        "filter": {"days": days, "sentiment": sentiment, "urgency": urg, "fixed": fixed, "q": q},
        "last_fetch_iso": (datetime.fromtimestamp(_reviews_last_fetch, TZ).isoformat(timespec="minutes")
                           if _reviews_last_fetch else None),
    })

async def _api_reviews_insights(request):
    """GET → per-apartment review scorecards + common issues.
    Historical category breakdown (cleanliness, value, …) comes from the shipped
    export (reviews_insights.json); live counts/averages are overlaid from the
    reviews currently pulled from Hostaway so the numbers stay current."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    seed = _reviews_insights or {}
    seed_apts = seed.get("apartments", {}) or {}
    listings = await get_listings_map_async()
    live = {}
    for rev in _reviews.values():
        lid = rev.get("listing_id")
        if lid is None:
            continue
        key = str(lid)
        g = live.setdefault(key, {"count": 0, "sum": 0.0, "n": 0, "recent90": 0})
        g["count"] += 1
        try:
            rr = float(rev.get("rating_raw") or 0)
        except Exception:
            rr = 0
        if rr > 0:
            g["sum"] += rr
            g["n"] += 1
        if _review_in_window(rev, 90):
            g["recent90"] += 1
    cards = []
    seen = set()
    for name, s in seed_apts.items():
        lid = s.get("listing_id")
        key = str(lid) if lid is not None else None
        lv = live.get(key, {}) if key else {}
        if key:
            seen.add(key)
        cur_name = listings.get(int(lid)) if (lid and str(lid).isdigit()) else None
        cards.append({
            "name": cur_name or name, "hist_name": name, "listing_id": lid,
            "hist_count": s.get("count", 0), "hist_avg": s.get("avg"),
            "cats": s.get("cats", {}), "low": s.get("low", 0), "issues": s.get("issues", []),
            "live_count": lv.get("count", 0),
            "live_avg": round(lv["sum"] / lv["n"], 2) if lv.get("n") else None,
            "recent90": lv.get("recent90", 0),
        })
    for key, lv in live.items():
        if key in seen:
            continue
        lid = int(key) if key.isdigit() else key
        cards.append({
            "name": listings.get(lid) or ("unit-" + key), "hist_name": None, "listing_id": lid,
            "hist_count": 0, "hist_avg": None, "cats": {}, "low": 0, "issues": [],
            "live_count": lv.get("count", 0),
            "live_avg": round(lv["sum"] / lv["n"], 2) if lv.get("n") else None,
            "recent90": lv.get("recent90", 0),
        })
    cards.sort(key=lambda c: (c["hist_count"] + c["live_count"]), reverse=True)
    return _json({
        "overall": seed.get("overall", {}), "issues": seed.get("issues", []),
        "issues_all": seed.get("issues_all", []), "generated": seed.get("generated"),
        "apartments": cards, "live_total": len(_reviews),
    })

