def _wr_is_resolved(apt):
    """True if this apartment row is fully resolved (so it should NOT carry over)."""
    res = (apt.get("resolved") or "").strip().lower()
    return res in ("نعم", "yes", "تم الحل", "resolved")

def _wr_open_issues(apt):
    """Structured issues on an apartment row that are still open (resolved != True)."""
    return [it for it in (apt.get("issues") or [])
            if isinstance(it, dict) and not it.get("resolved")]

def _wr_latest_prior(before_date):
    """The most recent saved report strictly before `before_date` (ISO yyyy-mm-dd)."""
    cands = [r for r in _weekly_reports.values()
             if (r.get("date") or "") and (r.get("date") or "") < (before_date or "9999")]
    cands.sort(key=lambda r: (r.get("date") or "", r.get("created_at") or ""), reverse=True)
    return cands[0] if cands else None

def _wr_summary(apts):
    """Auto-computed report header counts (§Part 2 'auto summary')."""
    apts = apts or []
    total = len(apts)
    with_issue = sum(1 for a in apts if _wr_open_issues(a)
                     or any(v == "issue" for v in (a.get("checks") or {}).values())
                     or any(r not in ("لا يوجد خطر", "No risk") for r in (a.get("risks") or [])))
    resolved = sum(1 for a in apts if _wr_is_resolved(a))
    carried = sum(1 for a in apts for it in _wr_open_issues(a) if (it.get("weeks") or 1) > 1)
    high = sum(1 for a in apts for it in _wr_open_issues(a) if (it.get("severity") == "high"))
    occupied = sum(1 for a in apts if a.get("occupied"))
    return {"total": total, "with_issue": with_issue, "resolved": resolved,
            "unresolved": max(0, with_issue - resolved), "carried": carried,
            "high": high, "occupied": occupied}

async def _api_weekly_template(request):
    """GET → all apartments pre-listed, each auto-enriched with: most-common review
    issues, NEW reviews in the last 7 days, currently-open maintenance tickets,
    current occupancy, and any unresolved issues carried over from the previous
    week's report (with a week counter). Lets the employee just tick the checklist
    and review what the system already knows instead of starting from a blank page."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    seed = _reviews_insights or {}
    seed_apts = seed.get("apartments", {}) or {}
    try:
        listings = await asyncio.to_thread(get_listings_map)
    except Exception:
        listings = {}
    # --- current occupancy (one targeted in-house query) ---
    today = datetime.now(TZ).date()
    occ_lids = set()
    try:
        rows = await asyncio.to_thread(fetch_inhouse, today)
        for r in rows:
            a, d = _parse_date(r.get("arrivalDate")), _parse_date(r.get("departureDate"))
            if a and d and a <= today < d:
                occ_lids.add(str(r.get("listingMapId")))
    except Exception:
        pass
    # --- new reviews in the last 7 days, per listing ---
    wk_ago = (today - timedelta(days=7)).isoformat()
    new_rev = {}
    for rv in _reviews.values():
        lid = rv.get("listing_id")
        if lid is None:
            continue
        if (rv.get("date") or "") >= wk_ago:
            new_rev[str(lid)] = new_rev.get(str(lid), 0) + 1
    # --- open tickets per listing ---
    open_tk = {}
    for t in _tickets:
        if t.get("status") in ("open", "in_progress") and t.get("lid") is not None:
            open_tk.setdefault(str(t["lid"]), []).append(
                {"title": t.get("title") or "", "priority": t.get("priority") or "med",
                 "status": t.get("status")})
    # --- carry-over from the previous report ---
    prior = _wr_latest_prior(today.isoformat())
    carry_by_lid, carry_by_name = {}, {}
    if prior:
        for a in (prior.get("apartments") or []):
            opens = _wr_open_issues(a)
            if not opens:
                continue
            carried = []
            for it in opens:
                c = dict(it)
                c["weeks"] = int(c.get("weeks") or 1) + 1
                c["carried"] = True
                carried.append(c)
            if a.get("listing_id") is not None:
                carry_by_lid[str(a["listing_id"])] = carried
            if a.get("name"):
                carry_by_name[a["name"]] = carried

    def enrich(name, lid):
        k = str(lid) if lid is not None else None
        carried = (carry_by_lid.get(k) if k else None) or carry_by_name.get(name) or []
        return {
            "new_reviews": (new_rev.get(k, 0) if k else 0),
            "open_tickets": (open_tk.get(k, []) if k else []),
            "occupied": (k in occ_lids) if k else False,
            "issues": [dict(c) for c in carried],
        }

    apts, seen = [], set()
    for nm, s in sorted(seed_apts.items(), key=lambda kv: kv[0]):
        lid = s.get("listing_id")
        cur = listings.get(int(lid)) if (lid and str(lid).isdigit()) else None
        name = cur or nm
        e = enrich(name, lid)
        apts.append({
            "name": name, "listing_id": lid,
            "common_issues": [it.get("tag") for it in (s.get("issues") or []) if it.get("tag")][:6],
            **e,
        })
        if lid is not None:
            seen.add(str(lid))
    for lid, name in sorted(listings.items(), key=lambda kv: str(kv[1])):
        if str(lid) in seen:
            continue
        apts.append({"name": name, "listing_id": lid, "common_issues": [], **enrich(name, lid)})
    return _json({"apartments": apts, "count": len(apts),
                  "carried_from": (prior or {}).get("date")})

async def _api_weekly_save(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    rid = (b.get("id") or "").strip()
    is_new = not rid or rid not in _weekly_reports
    if is_new:
        rid = rid or _new_report_id()
        r = {"id": rid, "created_at": datetime.now(TZ).isoformat(timespec="seconds")}
        _weekly_reports[rid] = r
    else:
        r = _weekly_reports[rid]
    for k in ("employee", "date"):
        if k in b: r[k] = (b[k] or "").strip()
    # Report-level free-text fields (§Part 2)
    if "highlights" in b: r["highlights"] = (b.get("highlights") or "").strip()[:2000]
    if "unusual" in b:    r["unusual"]    = (b.get("unusual") or "").strip()[:2000]
    if isinstance(b.get("apartments"), list):
        cleaned = []
        for apt in b["apartments"]:
            if not isinstance(apt, dict): continue
            checks = {}
            if isinstance(apt.get("checks"), dict):
                for k, v in list(apt["checks"].items())[:40]:
                    checks[str(k)[:60]] = str(v)[:10]
            # Structured, trackable issues (severity / assignee / follow-up / week count)
            issues = []
            for it in (apt.get("issues") or [])[:30]:
                if not isinstance(it, dict): continue
                txt = (it.get("text") or "").strip()[:200]
                if not txt: continue
                sev = (it.get("severity") or "med")
                issues.append({
                    "text":     txt,
                    "severity": sev if sev in ("low", "med", "high") else "med",
                    "assignee": (it.get("assignee") or "").strip()[:60],
                    "followup": (it.get("followup") or "").strip()[:10],
                    "weeks":    int(it.get("weeks") or 1),
                    "carried":  bool(it.get("carried")),
                    "resolved": bool(it.get("resolved")),
                })
            cleaned.append({
                "name":      (apt.get("name") or "").strip()[:80],
                "listing_id": apt.get("listing_id"),
                "status":    (apt.get("status") or "").strip()[:40],
                "risks":     [str(x)[:120] for x in (apt.get("risks") or [])][:20],
                "updates":   [str(x)[:160] for x in (apt.get("updates") or [])][:20],
                "challenges":[str(x)[:120] for x in (apt.get("challenges") or [])][:20],
                "plan":      [str(x)[:200] for x in (apt.get("plan") or [])][:20],
                "supervisor":[str(x)[:160] for x in (apt.get("supervisor") or [])][:20],
                "resolved":  (apt.get("resolved") or "").strip()[:40],
                "risks_other":      (apt.get("risks_other") or "").strip()[:200],
                "updates_other":    (apt.get("updates_other") or "").strip()[:200],
                "plan_other":       (apt.get("plan_other") or "").strip()[:200],
                "supervisor_other": (apt.get("supervisor_other") or "").strip()[:200],
                "comments":  [str(x)[:200] for x in (apt.get("comments") or [])][:20],
                "common_issues": [str(x)[:60] for x in (apt.get("common_issues") or [])][:10],
                "issues":    issues,
                "new_reviews": int(apt.get("new_reviews") or 0),
                "open_tickets": [
                    {"title": str(t.get("title", ""))[:120],
                     "priority": str(t.get("priority", "med"))[:10],
                     "status": str(t.get("status", ""))[:20]}
                    for t in (apt.get("open_tickets") or []) if isinstance(t, dict)][:20],
                "occupied":  bool(apt.get("occupied")),
                "checks":    checks,
            })
        r["apartments"] = cleaned
        r["summary"] = _wr_summary(cleaned)
    r["updated_at"] = datetime.now(TZ).isoformat(timespec="seconds")
    await asyncio.to_thread(persist_state)
    if is_new:
        log_event("ops", f"تقرير أسبوعي · {r.get('employee','?')} · "
                         f"{len(r.get('apartments') or [])} شقة")
    return _json({"ok": True, "report": r, "is_new": is_new})

