# ===================== FIELD EXPENSES API =====================
def _exp_view(e):
    """Expense dict + the 3-step pipeline + the suspected-twin summary (for side-by-side UI)."""
    v = dict(e)
    raw_status = e.get("status") or "captured"
    canon = _exp_canonical_status(e)
    v["raw_status"] = raw_status
    v["status"] = canon
    v["status_label"] = {
        "ar": EXPENSE_STATUS_LABELS.get(canon, (canon, canon))[0],
        "en": EXPENSE_STATUS_LABELS.get(canon, (canon, canon))[1],
    }
    v["status_reason"] = _exp_status_reason(e, canon)
    v["retry_count"] = int(e.get("retry_count") or 0)
    v["attempt_count"] = len(e.get("export_attempts") or [])
    v["last_attempt_at"] = e.get("last_attempt_at") or e.get("sending_at") or e.get("sent_at")
    v["hostaway_expense_id"] = e.get("hostaway_expense_id") or e.get("hostaway_ref")
    v["can_export"] = _exp_can_export(e)
    v["can_verify"] = _exp_can_verify(e)
    if canon == "failed":
        ec = e.get("error_class") or _exp_error_class(e.get("error")) or "unknown"
        v["error_class"] = ec
        v["error_label"] = {
            "ar": EXPENSE_ERROR_LABELS.get(ec, EXPENSE_ERROR_LABELS["unknown"])[0],
            "en": EXPENSE_ERROR_LABELS.get(ec, EXPENSE_ERROR_LABELS["unknown"])[1],
        }
    v["pipeline"] = _exp_pipeline(e)
    v["sync_state"] = _exp_sync_state(e)
    if e.get("dup_of") and e["dup_of"] in _expenses:
        t = _expenses[e["dup_of"]]
        v["dup_twin"] = {
            "id": t.get("id"), "ref": t.get("ref"), "amount": t.get("amount"),
            "expense_date": t.get("expense_date"), "apartment": t.get("apartment"),
            "category": t.get("category"), "status": t.get("status"),
        }
    return v

async def _api_expenses_ingest(request):
    """Public webhook for the Google Apps Script. Authenticated by a shared
    secret (header X-Ingest-Secret or ?secret=). Idempotent by submission_id.
    Accepts one submission or a {submissions:[...]} batch."""
    if not EXPENSE_INGEST_SECRET:
        # No shared secret configured -> the endpoint is closed (no anonymous ingest).
        return _json({"error": "ingest disabled: EXPENSE_INGEST_SECRET not set"}, 503)
    secret = request.headers.get("X-Ingest-Secret") or request.query.get("secret") or ""
    ok_secret = hmac.compare_digest(secret, EXPENSE_INGEST_SECRET)
    if not ok_secret and not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    subs = b.get("submissions") if isinstance(b.get("submissions"), list) else [b]
    out = []
    created_any = False
    for sub in subs:
        if not isinstance(sub, dict):
            continue
        exp, created = await asyncio.to_thread(_exp_ingest, sub)
        created_any = created_any or created
        out.append({"id": exp.get("id"), "ref": exp.get("ref"),
                    "status": exp.get("status"), "created": created,
                    "primary_reason": exp.get("primary_reason")})
        if created and exp.get("status") in ("held", "failed"):
            lbl = EXPENSE_HOLD_LABELS.get(exp.get("primary_reason") or "", ("مصروف", ""))[0]
            log_event("ops", f"مصروف يحتاج مراجعة [{exp.get('ref')}] · {lbl} · "
                             f"{exp.get('apartment') or '—'} · {exp.get('amount') or 0} ر.س")
        elif created and _exp_canonical_status(exp) in ("queued", "sending", "sent_unverified", "verified"):
            _exp_ensure_export_worker()
            log_event("ops", f"مصروف في طابور التصدير [{exp.get('ref')}] · "
                             f"{exp.get('apartment') or '—'} · {exp.get('amount') or 0} ر.س")
    if created_any:
        await asyncio.to_thread(persist_state)
    return _json({"ok": True, "results": out})

def _exp_in_period(e, dfrom, dto):
    d = (e.get("expense_date") or "")[:10]
    if dfrom and d < dfrom: return False
    if dto and d > dto:     return False
    return True

async def _api_expenses_list(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    q = request.query
    status = q.get("status", "")
    dfrom, dto = q.get("from", ""), q.get("to", "")
    apt = q.get("apartment", "")
    emp = q.get("employee", "")
    cat = q.get("category", "")
    mt  = q.get("maintenance_type", "")
    search = (q.get("q", "") or "").lower().strip()
    items = []
    for e in _expenses.values():
        _exp_apply_stale_state(e)
        canon = _exp_canonical_status(e)
        if status and canon != status: continue
        if not _exp_in_period(e, dfrom, dto): continue
        if apt and e.get("apartment") != apt: continue
        if emp and e.get("submitter") != emp: continue
        if cat and e.get("category") != cat: continue
        if mt and e.get("maintenance_type") != mt: continue
        if search and search not in (
            (e.get("apartment", "") + e.get("submitter", "") + e.get("note", "") +
             e.get("vendor", "") + e.get("ref", "") + e.get("maintenance_type", "")).lower()):
            continue
        items.append(_exp_view(e))
    items.sort(key=lambda e: (e.get("submitted_at") or e.get("created_at") or ""), reverse=True)
    # Pagination instead of a silent 500-row cliff: ?offset=&limit= (limit ≤ 500).
    try:
        offset = max(0, int(q.get("offset", "0")))
    except (TypeError, ValueError):
        offset = 0
    try:
        limit = min(500, max(1, int(q.get("limit", "500"))))
    except (TypeError, ValueError):
        limit = 500
    page = items[offset:offset + limit]
    return _json({"expenses": page, "count": len(items),
                  "offset": offset, "limit": limit,
                  "has_more": offset + limit < len(items)})

async def _api_expenses_queue(request):
    """The review queue: Held + Failed + Ready-but-not-yet-posted, newest first, PLUS the
    most-recently-posted few so a successful post visibly MOVES the card into the مُرحّل
    group (instead of vanishing). The posted tail is capped so it never grows unbounded."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    for e in _expenses.values():
        _exp_apply_stale_state(e)
    queue_states = {"needs_review", "duplicate", "failed", "ready", "queued", "sending",
                    "sent_unverified", "stale_pending"}
    items = [_exp_view(e) for e in _expenses.values()
             if _exp_canonical_status(e) in queue_states]
    items.sort(key=lambda e: (e.get("submitted_at") or e.get("created_at") or ""), reverse=True)
    # recently-posted tail (newest first, capped) — the "it worked, here it is" confirmation
    posted = [e for e in _expenses.values() if _exp_canonical_status(e) == "verified" and e.get("posted_at")]
    posted.sort(key=lambda e: e.get("posted_at") or "", reverse=True)
    items += [_exp_view(e) for e in posted[:8]]
    return _json({"expenses": items, "count": len(items)})

async def _api_expenses_summary(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    q = request.query
    dfrom, dto = q.get("from", ""), q.get("to", "")
    posted_sar = held = posted_n = failed = 0
    week_sar = 0.0
    wk_from = (datetime.now(TZ).date() - timedelta(days=7)).isoformat()
    in_transit_n = 0
    in_transit_sar = 0.0
    ready_n = queued_n = sending_n = stale_n = archived_n = duplicate_n = 0
    total_sar = 0.0
    by_apt, by_emp = {}, {}
    for e in _expenses.values():
        _exp_apply_stale_state(e)
        st = _exp_canonical_status(e)
        verified = (st == "verified")
        in_transit = st in ("queued", "sending", "sent_unverified")
        if st in ("needs_review",): held += 1
        if st in ("duplicate",): duplicate_n += 1
        if st in ("failed",): failed += 1
        if st in ("ready",): ready_n += 1
        if st in ("queued",): queued_n += 1
        if st in ("sending",): sending_n += 1
        if st in ("stale_pending",): stale_n += 1
        if st in ("archived",): archived_n += 1
        if in_transit: in_transit_n += 1
        if not _exp_in_period(e, dfrom, dto): continue
        amt = abs(float(e.get("amount") or 0))
        total_sar += amt
        if in_transit: in_transit_sar += amt
        if verified:
            posted_sar += amt; posted_n += 1
            if (e.get("expense_date") or "") >= wk_from:
                week_sar += amt
        a = e.get("apartment") or "—"; m = e.get("submitter") or "—"
        ba = by_apt.setdefault(a, {"apartment": a, "total": 0.0, "count": 0})
        be = by_emp.setdefault(m, {"employee": m, "total": 0.0, "count": 0,
                                   "posted": 0, "held": 0, "discarded": 0})
        if verified:
            ba["total"] += amt; ba["count"] += 1
            be["total"] += amt; be["posted"] += 1
        be["count"] += 1
        if st in ("needs_review", "duplicate"): be["held"] += 1
        if st == "archived": be["discarded"] += 1
    return _json({
        "posted_sar": round(posted_sar, 2), "held": held, "posted_n": posted_n,
        "in_transit_n": in_transit_n, "in_transit_sar": round(in_transit_sar, 2),
        "ready": ready_n, "queued": queued_n, "sending": sending_n,
        # honest label: ONLY expenses actually sent-but-not-verified (the old value
        # lumped queued+sending in, overstating what reached Hostaway)
        "sent_unverified": max(0, in_transit_n - queued_n - sending_n),
        "stale_pending": stale_n,
        "duplicates": duplicate_n, "archived": archived_n,
        "failed": failed, "week_sar": round(week_sar, 2),
        "total_sar": round(total_sar, 2),
        "needs_review": held,
        "verified": posted_n,
        "queue": held + duplicate_n + failed + in_transit_n + ready_n + stale_n,
        "export_queue": _exp_queue_snapshot(),
        "by_apartment": sorted(by_apt.values(), key=lambda x: -x["total"]),
        "by_employee": sorted(by_emp.values(), key=lambda x: -x["total"]),
        "owners": dict(_unit_owners),   # item 60: apartment -> owner map
        "dryrun": EXPENSE_POST_DRYRUN,
        "sheet_configured": bool(EXPENSE_SHEET_CSV_URL),
        "sheet_last_sync": _exp_sheet_last_sync,
        "hostaway_ok": bool(_token.get("value")),     # a cached token = Hostaway auth is live
    })

async def _api_expenses_set_owner(request):
    """POST {apartment, owner} — assign a unit to an owner for per-owner P&L (item 60)."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    apt = (b.get("apartment") or "").strip()
    if not apt:
        return _json({"error": "no apartment"}, 400)
    owner = (b.get("owner") or "").strip()[:80]
    if owner:
        _unit_owners[apt] = owner
    else:
        _unit_owners.pop(apt, None)
    await asyncio.to_thread(persist_state)
    return _json({"ok": True})

# ===================== FINANCE / ACCOUNTING API (Stage 3) =====================
def _finance_key(lid, owner):
    return ("owner:" + owner) if owner else ("lid:" + str(lid))

async def _api_finance_units(request):
    """Apartments for the report picker (lid, name, owner, saved mgmt%)."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    out = []
    for u in (_catalog_units or []):
        if not u.get("id"):
            continue
        info = _owner_info(u.get("name"))
        owner = (info.get("owner") if info else None) or _unit_owners.get(u.get("name"), "")
        dft = _finance_defaults.get(_finance_key(u["id"], owner), {})
        mgmt = dft.get("mgmt_pct")
        if mgmt is None and info:
            mgmt = info.get("mgmt_pct")
        out.append({"lid": u["id"], "name": u.get("name"), "owner": owner, "mgmt_pct": mgmt,
                    "cleaning": (info.get("cleaning") if info else None)})
    out.sort(key=lambda x: x["name"] or "")
    return _json({"units": out, "last_import": dict(_finance_last_import)})

async def _api_finance_pdf(request):
    """Server-rendered owner-statement PDF(s) with proper Arabic. POST {mode, lids|owners,
    start, end} → a single PDF (1 item) or a ZIP of named PDFs (many). Binary download."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    start = _parse_date(b.get("start", "")); end = _parse_date(b.get("end", ""))
    if not start or not end or end < start:
        return _json({"error": "bad date range"}, 400)
    mode = "owner" if b.get("mode") == "owner" else "apartment"
    items = await asyncio.to_thread(_finance_collect_items, mode, b.get("lids") or [], b.get("owners") or [], start, end)
    if not items:
        return _json({"error": "no items"}, 400)
    try:
        data, fn, ct = await asyncio.to_thread(_finance_pdf_payload, items)
    except PdfFontError as e:
        # Loud failure path: the owner must never receive broken-Arabic statements.
        print("finance pdf FONT FAILURE:", e)
        try:
            await _post_system_escalation("⚠️ كشوفات PDF متوقفة — خط العربي غير متوفر",
                                          "تعذّر تحميل خط العربي للـ PDF (الريبو/الفولت/الشبكة). "
                                          "ما راح نصدر كشف مكسور — أصلح الخط أول.", severity="high")
        except Exception as ex:
            print("pdf font alert error:", ex)
        return _json({"error": "pdf_font_unavailable",
                      "message": "خط العربي غير متوفر — لن نُصدر كشفًا بحروف مكسورة. حاول بعد دقائق أو تأكد من اتصال الخادم."}, 503)
    except Exception as e:
        print("finance pdf error:", e)
        return _json({"error": "pdf_failed: " + str(e)[:160]}, 500)
    ascii_fn = "ouja-statements.zip" if ct == "application/zip" else "ouja-statement.pdf"
    return web.Response(body=data, content_type=ct,
                        headers={"Content-Disposition": "attachment; filename=" + ascii_fn})

async def _api_finance_import_expenses(request):
    """Import the expenses list from Hostaway into the ledger (so statements reflect everything
    in Hostaway). Read-from-Hostaway only; never writes back; never duplicates."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    return _json(await asyncio.to_thread(_finance_import_hostaway_expenses))

async def _api_finance_owners(request):
    """GET → the owner+cleaning-fee registry (editable table; ?q= search).
    POST {apartment, owner, mgmt_pct, cleaning:{type,amount}} → upsert; {apartment, delete:true} → remove."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    if request.method == "GET":
        ql = (request.query.get("q") or "").strip().lower()
        listings = (await get_listings_map_async()) or {}
        rows = []
        for rec in _owner_registry.values():
            if ql and ql not in (str(rec.get("apartment", "")) + " " + str(rec.get("owner", ""))).lower():
                continue
            lid = _owner_resolve_lid(rec, listings)
            r2 = dict(rec)
            r2["matched_lid"] = lid
            r2["matched_listing"] = listings.get(lid) if lid is not None else ""
            rows.append(r2)
        rows.sort(key=lambda r: (r.get("owner") or "", r.get("apartment") or ""))
        owners = sorted({r.get("owner") for r in _owner_registry.values() if r.get("owner")})
        return _json({"ok": True, "rows": rows, "owners": owners, "total": len(rows),
                      "listings": [{"lid": k, "name": v} for k, v in sorted(listings.items(), key=lambda x: x[1] or "")]})
    b = await _read_body(request)
    apt = (b.get("apartment") or "").strip()
    if not apt:
        return _json({"error": "apartment required"}, 400)
    k = _owner_key(apt)
    if b.get("delete"):
        _owner_registry.pop(k, None)
        _owner_cache_bust()      # v2.2 slice 0: registry change — every owner aggregate may shift
        await asyncio.to_thread(persist_state)
        return _json({"ok": True, "deleted": apt})
    cl = b.get("cleaning") or {}
    ctype = "owner" if cl.get("type") == "owner" else "ours"
    try:
        camt = round(float(cl.get("amount") or 0), 2)
    except (TypeError, ValueError):
        camt = 0.0
    try:
        mgmt = round(float(b.get("mgmt_pct")), 2) if b.get("mgmt_pct") not in (None, "") else None
    except (TypeError, ValueError):
        mgmt = None
    lid = None
    if b.get("lid") not in (None, ""):
        try:
            lid = int(b.get("lid"))
        except (TypeError, ValueError):
            lid = None
    _owner_registry[k] = {"apartment": apt, "owner": (b.get("owner") or "").strip(),
                          "mgmt_pct": mgmt, "lid": lid,
                          "cleaning": {"type": ctype, "amount": camt if ctype == "owner" else 0}}
    _owner_cache_bust()          # v2.2 slice 0: unit may have moved owners — bust both sides
    await asyncio.to_thread(persist_state)
    return _json({"ok": True, "row": _owner_registry[k]})

async def _api_finance_report(request):
    """Stage 3: the owner report for an apartment + date range. Real data only — never estimates."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    q = request.query
    try:
        lid = int(q.get("lid")) if q.get("lid") else None
    except Exception:
        lid = None
    start = _parse_date(q.get("start", "")); end = _parse_date(q.get("end", ""))
    if not start or not end or end < start:
        return _json({"error": "bad date range"}, 400)
    try:
        mgmt = float(q.get("mgmt", "0") or 0)
    except Exception:
        mgmt = 0.0
    settings = {}
    if q.get("rounding"):
        try:
            settings["rounding"] = int(q.get("rounding"))
        except Exception:
            pass
    if q.get("vat_pct"):
        # Explicit owner choice (was a buried [CONFIRM] constant): VAT % applied per
        # the report math; default 0 = all figures net, the historical behavior.
        try:
            settings["vat_pct"] = max(0.0, float(q.get("vat_pct")))
        except Exception:
            pass
    if q.get("basis") in ("checkin", "checkout"):
        settings["period_basis"] = q.get("basis")
    cleaning = None
    if q.get("clean_type") in ("ours", "owner"):
        try:
            ca = round(float(q.get("clean_amount") or 0), 2)
        except (TypeError, ValueError):
            ca = 0.0
        cleaning = {"type": q.get("clean_type"), "amount": ca}
    rep = await asyncio.to_thread(build_owner_report, lid, start, end, mgmt, settings, None, cleaning)
    return _json(rep)

def _finance_aggregate(reps, owner, start, end):
    """Combine several apartment reports into ONE owner statement (sum the money, keep a
    per-apartment breakdown). Used for the per-owner bulk PDF."""
    R = lambda x: round(float(x or 0), 2)
    tot = lambda k: R(sum(float(r.get(k) or 0) for r in reps))
    parts = [{"apartment": r.get("apartment"), "lid": r.get("lid"),
              "total_income": r.get("total_income"),
              "ouja_fee": r.get("ouja_fee"), "expenses": r.get("expenses"),
              "cleaning": (r.get("cleaning") or {}).get("total", 0), "owner_net": r.get("owner_net")}
             for r in reps]
    cleaning_total = R(sum((r.get("cleaning") or {}).get("total", 0) for r in reps))
    balanced = all((r.get("reconciliation") or {}).get("balanced") for r in reps) if reps else True
    ti = tot("total_income"); fee = tot("ouja_fee")
    blended = round(fee / ti * 100, 1) if ti else None     # owners can differ per apartment → blended effective %
    mil = []
    for r in reps:
        mil.extend(r.get("manual_income_lines") or [])
    # OR2 owner portal: carry the LINES through (each already names its apartment), so the
    # tokenized page renders one table across all the owner's units from this same object.
    all_lines = []; all_exp = []; all_unpaid = []; all_refunded = []
    flagged = {"missing_payout_ids": [], "needs_channel_rule_ids": [], "needs_base_ids": []}
    for r in reps:
        all_lines.extend(r.get("resv_lines") or [])
        all_exp.extend(r.get("exp_lines") or [])
        all_unpaid.extend(r.get("unpaid_lines") or [])
        all_refunded.extend(r.get("refunded_lines") or [])
        rc = r.get("reconciliation") or {}
        for k in flagged:
            flagged[k].extend(rc.get(k) or [])
    all_lines.sort(key=lambda l: l.get("checkin") or "")
    all_exp.sort(key=lambda e: e.get("date") or "")
    # excluded-money rollup (0b): sums of the per-unit summaries, never recomputed
    exsum = {"needs_review": 0, "needs_review_reference": 0.0, "unpaid": 0,
             "unpaid_expected": 0.0, "refunded": 0, "reasons": {}}
    for r in reps:
        es = r.get("excluded_summary") or {}
        for k in ("needs_review", "unpaid", "refunded"):
            exsum[k] += int(es.get(k) or 0)
        for k in ("needs_review_reference", "unpaid_expected"):
            exsum[k] = R(exsum[k] + float(es.get(k) or 0))
        for k, v in (es.get("reasons") or {}).items():
            exsum["reasons"][k] = exsum["reasons"].get(k, 0) + v
    return {"currency": "SAR", "owner": owner, "management_pct": blended,
            "excluded_summary": exsum,
            "period": {"start": start.isoformat(), "end": end.isoformat(), "basis": "checkin"},
            "income_airbnb": tot("income_airbnb"), "income_direct": tot("income_direct"),
            "extras": tot("extras"), "manual_income": tot("manual_income"), "manual_income_lines": mil,
            "total_income": tot("total_income"), "ouja_fee": tot("ouja_fee"),
            "expenses": tot("expenses"), "cleaning": {"type": "mixed", "total": cleaning_total, "cleans": None, "amount": None},
            "owner_net": tot("owner_net"), "apartments": parts,
            "resv_lines": all_lines, "exp_lines": all_exp,
            "unpaid_lines": all_unpaid, "refunded_lines": all_refunded,
            "reconciliation": {"balanced": balanced, **flagged}, "n_apartments": len(reps)}

async def _api_finance_adjust(request):
    """GET ?lid&start&end → saved statement edits; POST {lid,start,end,adjust} → save / clear."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    if request.method == "GET":
        k = _finance_adjust_key(request.query.get("lid") or "all", request.query.get("start", ""), request.query.get("end", ""))
        return _json({"ok": True, "adjust": _finance_adjust.get(k, {})})
    b = await _read_body(request)
    k = _finance_adjust_key(b.get("lid") if b.get("lid") not in (None, "") else "all",
                            b.get("start", ""), b.get("end", ""))
    adj = b.get("adjust") or {}
    existing = _finance_adjust.get(k) or {}
    # preserve per-line overrides (saved via the line editor) when the Edit-Statement drawer saves
    line_overrides = adj["line_overrides"] if isinstance(adj.get("line_overrides"), dict) else (existing.get("line_overrides") or {})
    has = bool(adj.get("expense_overrides") or adj.get("extra_lines") or line_overrides or (adj.get("comment") or "").strip())
    if has:
        _finance_adjust[k] = {"expense_overrides": adj.get("expense_overrides") or {},
                              "extra_lines": [x for x in (adj.get("extra_lines") or []) if isinstance(x, dict)][:50],
                              "line_overrides": line_overrides,
                              "comment": (adj.get("comment") or "")[:1000]}
    else:
        _finance_adjust.pop(k, None)
    # v2.2 slice 0: saved adjusts feed the owner portal through build_owner_report —
    # the memoized owner-month reports are stale the moment one is saved.
    _adj_mk = _exp_mkey(b.get("start"))
    _owner_cache_bust(lid=b.get("lid"),
                      mkey=(_adj_mk if _adj_mk and _adj_mk == _exp_mkey(b.get("end")) else None))
    await asyncio.to_thread(persist_state)
    return _json({"ok": True})

async def _api_finance_line_edit(request):
    """Per-line override for a READY report line (reservation or expense). Stores a DISPLAY
    override (amount/date/description/investor_note/category) without ever touching raw Hostaway
    data, with an audit entry. {lid,start,end,kind:'resv'|'exp',id, amount?,date?,description?,
    investor_note?,category?,edit_reason?,edited_by?,clear?}. Amount edits require a reason."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    kind = (b.get("kind") or "").strip()
    if kind not in ("resv", "exp"):
        return _json({"error": "bad kind"}, 400)
    line_id = str(b.get("id") or "").strip()
    if not line_id:
        return _json({"error": "missing id"}, 400)
    k = _finance_adjust_key(b.get("lid") if b.get("lid") not in (None, "") else "all",
                            b.get("start", ""), b.get("end", ""))
    rec = dict(_finance_adjust.get(k) or {})
    lov = dict(rec.get("line_overrides") or {})
    ovkey = kind + ":" + line_id
    actor = (b.get("edited_by") or "").strip()[:80] or _req_actor(request)
    if b.get("clear"):
        lov.pop(ovkey, None)
        _finance_audit_add(k, ovkey, "clear", actor, {})
    else:
        ov = {}
        amount_changed = False
        if b.get("amount") not in (None, ""):
            try:
                ov["amount"] = round(float(b.get("amount")), 2); amount_changed = True
            except (TypeError, ValueError):
                return _json({"error": "bad amount"}, 400)
        for f in ("date", "description", "investor_note", "category"):
            if b.get(f) not in (None, ""):
                ov[f] = str(b.get(f))[:500]
        reason = (b.get("edit_reason") or "").strip()
        if amount_changed and not reason:
            return _json({"error": "reason_required"}, 400)     # amount edit needs a reason
        if reason:
            ov["edit_reason"] = reason[:300]
        if not ov:
            return _json({"error": "nothing to edit"}, 400)
        ov["edited_by"] = actor
        ov["edited_at"] = datetime.now(TZ).isoformat(timespec="seconds")
        prev = dict(lov.get(ovkey) or {})
        prev.update(ov)
        lov[ovkey] = prev
        _finance_audit_add(k, ovkey, "edit", actor, ov)
    rec["line_overrides"] = lov
    rec.setdefault("expense_overrides", {})
    rec.setdefault("extra_lines", [])
    rec.setdefault("comment", "")
    if not (rec.get("expense_overrides") or rec.get("extra_lines") or rec.get("line_overrides") or (rec.get("comment") or "").strip()):
        _finance_adjust.pop(k, None)
    else:
        _finance_adjust[k] = rec
    _le_mk = _exp_mkey(b.get("start"))      # v2.2 slice 0: line edits must show on the owner page now
    _owner_cache_bust(lid=b.get("lid"),
                      mkey=(_le_mk if _le_mk and _le_mk == _exp_mkey(b.get("end")) else None))
    await asyncio.to_thread(persist_state)
    return _json({"ok": True, "line_overrides": lov})

async def _api_finance_audit(request):
    """GET ?lid&start&end → the line-edit audit trail for this report (newest first)."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    k = _finance_adjust_key(request.query.get("lid") or "all", request.query.get("start", ""), request.query.get("end", ""))
    rows = [a for a in _finance_audit if a.get("report") == k]
    rows = list(reversed(rows))[:200]
    return _json({"ok": True, "audit": rows})

