async def _api_expenses_repair_apply(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    ids = b.get("ids") if isinstance(b.get("ids"), list) else []
    by = (b.get("by") or "")[:60]
    if not ids:
        ids = [r["id"] for r in _exp_repair_preview_rows()
               if r.get("safe_action") in ("verify_first", "retry_export")]
    # Safe repair first verifies sent/stale rows. It queues retries only for failed rows
    # or records without any Hostaway ref.
    verified = []
    queued = []
    skipped = []
    _exp_fetch_hostaway(force=True)
    for eid in ids:
        e = _expenses.get(str(eid))
        if not e:
            skipped.append({"id": str(eid), "reason": "not_found"})
            continue
        if e.get("hostaway_ref"):
            ok = await asyncio.to_thread(_exp_verify_in_hostaway, e)
            verified.append({"id": eid, "verified": bool(ok), "note": e.get("verify_note")})
            if ok:
                continue
            if _exp_has_real_hostaway_ref(e):
                _exp_set_status(e, "sent_unverified", reason="hostaway_id_not_found",
                                detail="real Hostaway ref exists; verify manually before export")
                skipped.append({"id": str(eid), "reason": "manual_verify_required"})
                continue
        ok, why = _exp_queue_for_export(e, by=by, reason="repair_apply", retry=True)
        (queued if ok else skipped).append({"id": str(eid), "reason": why})
    if queued:
        _exp_ensure_export_worker()
    await asyncio.to_thread(persist_state)
    return _json({"ok": True, "verified": verified, "queued": queued, "skipped": skipped,
                  "queue": _exp_queue_snapshot()})

async def _api_expenses_approve(request):
    """Manager approves a SOFT gate (no_receipt / high_amount / bad_date) so the expense
    can post — sets the approval flag + re-validates. This is the mechanism that was
    missing (the old 'Approve & post' just re-validated and re-blocked)."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    e = _expenses.get((b.get("id") or "").strip())
    if not e:
        return _json({"error": "not found"}, 404)
    flag = {"no_receipt": "no_receipt_approved", "high_amount": "amount_approved",
            "bad_date": "date_approved"}.get(b.get("gate", ""))
    if not flag:
        return _json({"error": "bad gate"}, 400)
    e[flag] = True
    e["approved_by"] = (b.get("by") or "")[:60]
    _exp_log_event(e, "approved", by=e["approved_by"], detail=b.get("gate", ""))
    await asyncio.to_thread(_exp_validate, e)
    await asyncio.to_thread(persist_state)
    return _json({"ok": True, "expense": _exp_view(e)})

async def _api_expenses_resolve_apartment(request):
    """Manager picked the right listing for an ambiguous/not-found expense."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    e = _expenses.get((b.get("id") or "").strip())
    if not e:
        return _json({"error": "not found"}, 404)
    lid = b.get("listing_id")
    try:
        lid = int(lid)
    except Exception:
        return _json({"error": "bad listing_id"}, 400)
    name = ((await get_listings_map_async()) or {}).get(lid)
    if name:
        e["apartment"] = name
    old_lid = e.get("listing_id")
    e["listing_id"] = lid
    e["candidates"] = []
    e["apartment_locked"] = lid       # remember the manual choice
    _exp_log_event(e, "apartment_confirmed", by=(b.get("by") or "")[:60], detail=(name or str(lid)))
    await asyncio.to_thread(_exp_process, e, allow_post=True)
    _ra_mk = _exp_mkey(e.get("expense_date"))       # v2.2 slice 0: the unit changed
    _owner_cache_bust(lid=old_lid, mkey=_ra_mk)
    _owner_cache_bust(lid=lid, mkey=_ra_mk)
    await asyncio.to_thread(persist_state)
    return _json({"ok": True, "expense": _exp_view(e)})

