# ---- Stage 6: alert the team about a stuck/failed post (with a retry hint) ----
async def _exp_alert_failure(exp):
    try:
        guild = bot.get_guild(GUILD_ID)
        if guild is None:
            return
        ch = await ensure_channel(guild, EXPENSE_ALERT_CHANNEL, await get_assistant_category(guild))
        if ch is None:
            return
        op_role = find_operation_role(guild)
        mention = op_role.mention if op_role else ""
        emb = discord.Embed(title="⚠️ فشل ترحيل مصروف لـ Hostaway", color=0xE5484D)
        emb.add_field(name="المرجع", value=str(exp.get("ref") or "—"), inline=True)
        emb.add_field(name="الشقة", value=str(exp.get("apartment") or "—"), inline=True)
        emb.add_field(name="المبلغ", value=f"{exp.get('amount') or '—'} ر.س", inline=True)
        emb.add_field(name="السبب", value=str(exp.get("error") or "—")[:400], inline=False)
        emb.set_footer(text="افتح لوحة المصاريف → «إعادة المحاولة» على البطاقة")
        await ch.send(content=mention or None, embed=emb,
                      allowed_mentions=discord.AllowedMentions(roles=True))
        log_event("ops", f"تنبيه فشل ترحيل مصروف [{exp.get('ref')}] · {exp.get('error','')[:80]}")
    except Exception as ex:
        print("exp alert error:", ex)

async def _api_expenses_verify(request):
    """Re-check ONE expense against live Hostaway (the ✓ only turns green here)."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    e = _expenses.get((b.get("id") or "").strip())
    if not e:
        return _json({"error": "not found"}, 404)
    await asyncio.to_thread(_exp_verify_in_hostaway, e)
    await asyncio.to_thread(persist_state)
    return _json({"ok": True, "verified": bool(e.get("hostaway_verified")),
                  "note": e.get("verify_note"), "expense": _exp_view(e)})

_EXP_STATE_LABELS = {
    "verified": ("مؤكّد في Hostaway", "Verified in Hostaway"),
    "in_transit": ("جاري التحقق", "In transit"),
    "failed": ("فشل الترحيل", "Failed"),
    "discrepancy": ("تعارض", "Discrepancy"),
    "ready": ("جاهز للترحيل", "Ready to post"),
    "held": ("بانتظار المراجعة", "Needs review"),
}

def _exp_sync_state(e):
    st = _exp_canonical_status(e)
    if st == "failed":
        return "failed"
    if e.get("discrepancy"):
        return "discrepancy"
    if st == "verified":
        return "verified"
    if st in ("queued", "sending", "sent_unverified", "stale_pending"):
        return "in_transit"
    if st == "ready":
        return "ready"
    return "held"

async def _api_expenses_diagnose(request):
    """Diagnosis-first runner (read-only; sends nothing). ?id=<expense> → one full diagnosis;
    no id → an overview + the most-stuck sample. ?format=csv → a diagnostics CSV download."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    eid = (request.query.get("id") or "").strip()
    if eid:
        e = _expenses.get(eid)
        if not e:
            return _json({"error": "not found"}, 404)
        return _json({"ok": True, "diagnosis": await asyncio.to_thread(_exp_diagnose, e)})
    overview = await asyncio.to_thread(_exp_diag_overview)
    sample = await asyncio.to_thread(_exp_diagnose_sample, 12)
    if request.query.get("format") == "csv":
        cols = ["ref", "apartment", "amount", "date", "canonical_status", "diagnosis_code",
                "hostaway_called", "dry_run_only", "real_hostaway_ref", "hostaway_verified",
                "error_class", "diagnosis_en", "recommended_en"]
        lines = [",".join(cols)]
        for d in sample:
            row = []
            for c in cols:
                v = str(d.get(c, "") if d.get(c) is not None else "")
                if any(ch in v for ch in [",", '"', "\n"]):
                    v = '"' + v.replace('"', '""') + '"'
                row.append(v)
            lines.append(",".join(row))
        body = ("﻿" + "\n".join(lines)).encode("utf-8")
        return web.Response(body=body, content_type="text/csv",
                            headers={"Content-Disposition": "attachment; filename=ouja-expense-diagnostics.csv"})
    return _json({"ok": True, "overview": overview, "sample": sample, "dryrun_on": EXPENSE_POST_DRYRUN})

# ============================================================================
#  EXPENSES V4 — API for the Expense Approval Center
#  Overview is LEDGER-ONLY (no Hostaway on page load). Hostaway is touched only on
#  explicit actions: Export, View Hostaway Match, Reconcile, Check-then-re-export.
# ============================================================================
def _exp4_actor(request, body=None):
    token = request.query.get("token") or request.headers.get("X-Token", "")
    if DASHBOARD_TOKEN and token and hmac.compare_digest(token, DASHBOARD_TOKEN):
        return "owner"
    sess = _sessions.get(token) or {}
    u = _users.get(sess.get("user_id")) or {}
    return str(u.get("name") or u.get("username") or (body or {}).get("by") or "dashboard")[:60]

def _exp4_field_options():
    """Dropdown (MCQ) options for the expense editor: apartment names from the listings store
    (+ any already used on expenses), and categories from the settings category_map (+ any
    already used). Lets bank/sheet expenses be completed with a picker, not free text."""
    apts = []
    try:
        for rec in (_ls_get().get("listings") or {}).values():
            nm = (rec.get("internal_name") or "").strip()
            if nm and nm not in apts:
                apts.append(nm)
    except Exception:
        pass
    for e in _expenses.values():
        nm = (e.get("apartment") or "").strip()
        if nm and nm not in apts:
            apts.append(nm)
    cats = []
    for k in (_exp_settings().get("category_map") or {}).keys():
        if k and k not in cats:
            cats.append(k)
    for e in _expenses.values():
        c = (e.get("category") or "").strip()
        if c and c not in cats:
            cats.append(c)
    return {"apartments": sorted(apts), "categories": cats}

def _exp4_tab_counts():
    """Single source of truth for the 5 lifecycle tab badges: {tab: {count, sar}}.
    Used by the overview AND returned on every action response so the chips stay live."""
    tabs = {k: {"count": 0, "sar": 0.0} for k in ("pending", "approved", "exported", "verified", "needs_action")}
    for e in _expenses.values():
        v = _exp4_view(e)
        t = v["tab"]
        if t in tabs:
            tabs[t]["count"] += 1
            tabs[t]["sar"] = round(tabs[t]["sar"] + v["amount_sar"], 2)
    return tabs

def _exp4_overview_data(tab="pending", q="", limit=120, offset=0):
    tabs = _exp4_tab_counts()
    ql = (q or "").strip().lower()
    rows = []
    for e in _expenses.values():
        v = _exp4_view(e)
        t = v["tab"]
        if t == "archived":
            continue
        if t == tab:
            if ql and ql not in (" ".join([str(v.get(k) or "") for k in
                                           ("ouja_reference", "apartment", "submitter", "category", "concept")])).lower():
                continue
            rows.append(v)
    rows.sort(key=lambda r: (r.get("created_at") or ""), reverse=True)
    return {"ok": True, "tab": tab, "tabs": tabs, "total": len(rows),
            "rows": rows[offset:offset + limit], "dryrun_on": EXPENSE_POST_DRYRUN,
            "options": _exp4_field_options()}

async def _api_exp4_bank_import(request):
    """Upload a bank statement (Al Rajhi .xlsx) → every money-out (debit) row becomes a pending
    expense tagged source=bank. Same multipart contract as the bank-register import."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    try:
        data, fname, _fields = await _fb_read_upload(request)
    except ValueError as e:
        return _json({"error": str(e)}, 400)
    if not data:
        return _json({"error": "empty_file"}, 400)
    by = _req_actor(request)
    try:
        res = await asyncio.to_thread(_exp_bank_ingest_debits, data, fname, by)
    except Exception as e:
        return _json({"error": "parse_failed", "message": str(e)[:300]}, 400)
    return _json(res)

async def _api_exp4_overview(request):
    """Ledger-only Approval Center data (fast; no Hostaway calls). ?tab=&q=&limit=&offset="""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    tab = (request.query.get("tab") or "pending").strip()
    if tab not in ("pending", "approved", "exported", "verified", "needs_action"):
        tab = "pending"
    try:
        limit = max(1, min(400, int(request.query.get("limit") or 120)))
        offset = max(0, int(request.query.get("offset") or 0))
    except (TypeError, ValueError):
        limit, offset = 120, 0
    data = await asyncio.to_thread(_exp4_overview_data, tab, request.query.get("q") or "", limit, offset)
    return _json(data)

