async def _api_fb_daftra_bankmap(request):
    """Map an imported bank statement (e.g. alrajhi_1039) to its Daftra account. GET list / POST upsert/delete."""
    if request.method == "GET":
        if not _dash_auth(request):
            return _json({"error": "unauthorized"}, 401)
        ccs = [{"source_id": r.get("source_id"), "display_name": r.get("display_name"), "code": r.get("code")}
               for r in _fb_external.values() if r.get("source_type") in ("accounts", "treasuries")][:400]
        return _json({"ok": True, "maps": list(_fb_bankmap.values()), "daftra_accounts": ccs})
    if not _fb_can_finance(request):
        return _json({"error": "forbidden"}, 403)
    b = await _read_body(request)
    src = (b.get("source") or "").strip()
    if not src:
        return _json({"error": "source_required"}, 400)
    if b.get("delete"):
        _fb_bankmap.pop(src, None)
        _fb_save("finance_bank_account_map.json", _fb_bankmap)
        return _json({"ok": True, "deleted": src})
    _fb_bankmap[src] = {"source": src, "display": (b.get("display") or src),
                        "daftra_account_id": str(b.get("daftra_account_id") or ""),
                        "daftra_account_name": (b.get("daftra_account_name") or ""),
                        "daftra_account_code": str(b.get("daftra_account_code") or ""),
                        "active": (b.get("active") is not False), "notes": (b.get("notes") or "")[:300],
                        "updated_at": datetime.now(TZ).isoformat(timespec="seconds")}
    _fb_save("finance_bank_account_map.json", _fb_bankmap)
    _fb_audit_add(_req_actor(request), "bank_account_map", "daftra", src, after={"account": _fb_bankmap[src].get("daftra_account_code")})
    return _json({"ok": True, "map": _fb_bankmap[src]})

async def _api_fb_daftra_dup(request):
    """Duplicate shield. GET: suggestions for a txn / manual search. POST: check / link / not_duplicate / ignore."""
    if not _fb_can_finance(request):
        return _json({"error": "forbidden"}, 403)
    if request.method == "GET":
        q = request.query
        tid = q.get("txn")
        if tid:
            txn = _fb_bank.get(tid)
            if not txn:
                return _json({"error": "bank_txn_not_found"}, 404)
            return _json({"ok": True, "txn": txn, "suggestions": _fb_dup_suggest(txn),
                          "bank_mapping": bool(_fb_mapped_bank_accounts()), "journals": len(_fb_djournals)})
        if q.get("ready"):
            return _json({"ok": True, "ready": _fb_dup_ready(), "summary": _fb_dup_summary(),
                          "distributed": _fb_distributed_summary(), "custody": _fb_custody_balances(),
                          "flows": _fb_flow_summary()})
        jid = q.get("journal")
        if jid:                                  # full journal lines (with consumption) for manual selection
            ent = _fb_djournals.get(str(jid))
            if not ent:
                return _json({"error": "journal_not_found"}, 404)
            return _json({"ok": True, "entry_id": ent.get("entry_id"), "number": ent.get("number"),
                          "date": ent.get("date"), "description": ent.get("description"),
                          "lines": _fb_journal_lines_view(ent)})
        bid = q.get("batch")
        if bid:                                  # batch suggestion: many bank txns → one journal bank line
            return _json(_fb_batch_suggest(bid) or {"error": "journal_not_found"})
        return _json({"ok": True, "results": _fb_search_daftra(q.get("q"), q.get("amount"))})
    b = await _read_body(request)
    action = (b.get("action") or "").strip()
    actor = _req_actor(request)
    if action == "check":
        res = await asyncio.to_thread(_fb_dup_check, b.get("start"), b.get("end"), actor, b.get("ids"))
        return _json(res)
    if action == "bulk_link":                    # one-click link all CONFIRMED (Tier-A) matches
        return _json(_fb_dup_bulk_link(actor, b.get("ids")))
    if action == "fix_statuses":                 # recompute/normalize display states (no re-import)
        return _json(_fb_fix_statuses(actor))
    if action == "batch_link":                   # many bank txns → one journal bank line
        res = _fb_batch_link(b.get("journal_id"), b.get("ids") or [], actor)
        return _json(res, (200 if res.get("ok") else 400))
    if action in ("link", "link_distributed", "not_duplicate", "ignore"):
        res = _fb_dup_resolve(b.get("id"), action, actor, daftra=b.get("daftra"), reason=b.get("reason", ""))
        return _json(res, (200 if res.get("ok") else 400))
    return _json({"error": "bad_action"}, 400)

# ---- Stage 4-5: shared Excel reader + multipart helper ----
def _fb_read_xlsx(file_bytes):
    """(headers, rows[]) from the first worksheet. Header row = first non-empty row."""
    import io as _io, openpyxl
    wb = openpyxl.load_workbook(_io.BytesIO(file_bytes), data_only=True, read_only=True)
    ws = wb[wb.sheetnames[0]]
    rows = []
    for r in ws.iter_rows(values_only=True):
        rows.append(list(r))
    wb.close()
    # find header row (first row with >=2 non-empty cells)
    hi = 0
    for i, r in enumerate(rows[:15]):
        if sum(1 for c in r if c not in (None, "")) >= 2:
            hi = i
            break
    headers = [str(c).strip() if c is not None else "" for c in (rows[hi] if rows else [])]
    body = [r for r in rows[hi + 1:] if any(c not in (None, "") for c in r)]
    return headers, body, hi

async def _fb_read_upload(request):
    """Read a single uploaded file (multipart) → (bytes, filename, fields)."""
    reader = await request.multipart()
    data, fname, fields = b"", "", {}
    async for part in reader:
        if part.name == "file":
            fname = part.filename or "upload.xlsx"
            chunks, total = [], 0
            while True:
                ch = await part.read_chunk()
                if not ch:
                    break
                total += len(ch)
                if total > 15 * 1024 * 1024:
                    raise ValueError("file_too_large")
                chunks.append(ch)
            data = b"".join(chunks)
        else:
            fields[part.name] = (await part.text()).strip()
    return data, fname, fields

# ---- Stage 4: Contract Profiles importer ----
_FB_CONTRACT_HINTS = {
    "apartment_name": ("apartment", "unit name", "الشقة", "اسم الشقة", "الوحدة", "name", "اسم"),
    "apartment_code": ("code", "كود", "رمز", "id", "معرف"),
    "owner_name": ("owner", "investor", "مالك", "المالك", "مستثمر", "المستثمر"),
    "ouja_percentage": ("percent", "%", "نسبة", "عمولة", "عوجا", "ouja"),
    "cleaning": ("clean", "نظافة", "تنظيف"),
    "maintenance": ("maint", "صيانة"),
    "refund": ("refund", "استرجاع", "استرداد", "ريفند"),
    "hostaway_listing_id": ("hostaway", "listing", "هوست"),
    "status": ("status", "الحالة", "حالة"),
    "contract_type": ("contract", "عقد", "نوع العقد", "type"),
    "notes": ("note", "ملاحظ", "تعليق"),
}

def _fb_detect_cols(headers):
    cmap = {}
    low = [(h or "").strip().lower() for h in headers]
    for field, hints in _FB_CONTRACT_HINTS.items():
        for i, h in enumerate(low):
            if h and any(hint in h for hint in hints) and field not in cmap:
                cmap[field] = i
                break
    return cmap

def _fb_norm_cleaning(val):
    """Normalize the messy cleaning column → (rule, monthly_amount). Never guesses an amount."""
    s = str(val or "").strip().lower()
    if not s:
        return "unknown", None
    if any(w in s for w in ("علينا", "عوجا", "ouja", "on us", "our")):
        return "ouja_pays", None
    if any(w in s for w in ("owner", "مالك", "المالك")):
        # owner pays — maybe a monthly figure too
        amt = _fb_money(s)
        return ("owner_monthly_charge", str(amt.quantize(Decimal("0.01")))) if amt >= 200 else ("owner_pays", None)
    amt = _fb_money(s)
    if amt >= 200:                      # a bare SAR figure → owner monthly charge
        return "owner_monthly_charge", str(amt.quantize(Decimal("0.01")))
    if "%" in s:                        # a percentage in the cleaning column is ambiguous
        return "unknown", None
    return "unknown", None

def _fb_norm_pct(val):
    s = str(val or "").strip().replace("%", "").replace("٪", "").strip()
    if not s:
        return None
    try:
        p = float(s)
        return round(p * 100, 2) if p <= 1 else round(p, 2)   # 0.25 or 25 → 25.0
    except ValueError:
        return None

def _fb_contract_key(name, code):
    base = (str(code or "").strip() or str(name or "").strip()).lower()
    return "".join(ch for ch in base if ch.isalnum()) or None

def _fb_contract_validate(p):
    """Return (validation_status, issues[]). Owner-managed active needs the full set."""
    issues = []
    ut = p.get("unit_type")
    if not p.get("apartment_name"):
        issues.append(("بدون اسم شقة", "missing apartment name"))
    if not p.get("apartment_code"):
        issues.append(("بدون كود", "missing code"))
    if ut == "company_operated":
        if not p.get("daftra_cost_center_id"):
            issues.append(("ناقص مركز تكلفة", "missing cost center"))
    else:  # owner_managed (or unknown defaults to owner-managed expectations)
        if not p.get("owner_name"):
            issues.append(("بدون مالك", "missing owner"))
        if p.get("ouja_percentage") is None:
            issues.append(("بدون نسبة عوجا", "missing Ouja %"))
        if (p.get("cleaning_rule") or "unknown") == "unknown":
            issues.append(("قاعدة النظافة غير واضحة", "unknown cleaning rule"))
        if not p.get("daftra_cost_center_id"):
            issues.append(("ناقص مركز تكلفة", "missing cost center"))
    if not p.get("hostaway_listing_id"):
        issues.append(("ناقص Hostaway ID", "missing Hostaway ID"))
    status = "complete" if not issues else ("needs_review" if len(issues) <= 2 else "incomplete")
    return status, issues

def _fb_contract_row_to_profile(headers, row, cmap):
    g = lambda f: (row[cmap[f]] if f in cmap and cmap[f] < len(row) else None)
    name = str(g("apartment_name") or "").strip()
    code = str(g("apartment_code") or "").strip()
    crule, camt = _fb_norm_cleaning(g("cleaning"))
    owner = str(g("owner_name") or "").strip()
    # unit type: only company_operated when explicitly Ouja-owned; never guessed
    owner_low = owner.lower()
    unit_type = "company_operated" if any(w in owner_low for w in ("ouja", "عوجا", "company", "الشركة")) else ("owner_managed" if owner else "unknown")
    p = {"apartment_name": name, "apartment_code": code, "owner_name": owner,
         "unit_type": unit_type, "status": (str(g("status") or "").strip().lower() or "unknown"),
         "contract_type": str(g("contract_type") or "").strip(),
         "ouja_percentage": _fb_norm_pct(g("ouja_percentage")),
         "platform_fee_rule": "before_ouja_percentage",
         "cleaning_rule": crule, "cleaning_monthly_amount": camt, "cleaning_provider": "",
         "maintenance_rule": "owner_pays", "refund_rule": "owner_pays",
         "owner_expense_deduction_rule": "after_ouja_fee",
         "hostaway_listing_id": str(g("hostaway_listing_id") or "").strip(),
         "daftra_cost_center_id": "", "owner_daftra_id": "",
         "notes": str(g("notes") or "").strip()}
    p["validation_status"], p["validation_issues"] = _fb_contract_validate(p)
    return p

def _fb_contracts_preview(file_bytes, colmap=None):
    headers, body, hi = _fb_read_xlsx(file_bytes)
    cmap = colmap if colmap else _fb_detect_cols(headers)
    rows = []
    for i, r in enumerate(body):
        p = _fb_contract_row_to_profile(headers, r, cmap)
        if not (p["apartment_name"] or p["apartment_code"]):
            continue
        rows.append({"row": hi + 2 + i, "profile": p})
    return {"headers": headers, "detected": cmap, "rows": rows, "count": len(rows),
            "fields": list(_FB_CONTRACT_HINTS.keys())}

def _fb_contracts_save(rows, actor=""):
    saved = updated = 0
    for item in rows:
        p = item.get("profile") or item
        key = _fb_contract_key(p.get("apartment_name"), p.get("apartment_code"))
        if not key:
            continue
        p["validation_status"], p["validation_issues"] = _fb_contract_validate(p)
        p["updated_at"] = datetime.now(TZ).isoformat(timespec="seconds")
        p["updated_by"] = actor
        if key in _fb_contracts:
            # preserve accountant-set mappings on re-import
            for keep in ("daftra_cost_center_id", "owner_daftra_id", "hostaway_listing_id", "cleaning_provider", "notes"):
                if _fb_contracts[key].get(keep) and not p.get(keep):
                    p[keep] = _fb_contracts[key][keep]
            _fb_contracts[key] = {**_fb_contracts[key], **p}
            updated += 1
        else:
            p["id"] = key
            _fb_contracts[key] = p
            saved += 1
    _fb_save("finance_contract_profiles.json", _fb_contracts)
    _fb_audit_add(actor, "contracts_import", "import_run", "contracts", after={"saved": saved, "updated": updated})
    return {"saved": saved, "updated": updated, "total": len(_fb_contracts)}

def _fb_contracts_summary():
    rows = list(_fb_contracts.values())
    health = {"complete": 0, "needs_review": 0, "incomplete": 0}
    flags = {"missing_hostaway": 0, "missing_cost_center": 0, "missing_pct": 0, "unknown_cleaning": 0, "unknown_status": 0}
    for p in rows:
        health[p.get("validation_status", "incomplete")] = health.get(p.get("validation_status", "incomplete"), 0) + 1
        if not p.get("hostaway_listing_id"):
            flags["missing_hostaway"] += 1
        if not p.get("daftra_cost_center_id"):
            flags["missing_cost_center"] += 1
        if p.get("ouja_percentage") is None and p.get("unit_type") != "company_operated":
            flags["missing_pct"] += 1
        if (p.get("cleaning_rule") or "unknown") == "unknown":
            flags["unknown_cleaning"] += 1
        if (p.get("status") or "unknown") == "unknown":
            flags["unknown_status"] += 1
    return {"count": len(rows), "health": health, "flags": flags, "last_run": _fb_last_run("contracts")}

# ---- Stage 5: Al Rajhi bank Excel parser (Decimal · dedup · mask · classify) ----
def _fb_bank_classify(desc, debit, credit):
    s = str(desc or "").lower()
    if "رسوم" in s or "fee" in s or "عمولة" in s:                     # fees first (e.g. رسوم حوالة سريع/فورية)
        return "bank_fee"
    if any(w in s for w in ("airbnb", "hostaway", "booking", "agoda", "payout")):
        return "channel_payout"
    if any(w in s for w in ("نظافة", "cleaning")):
        return "cleaning_provider"
    if any(w in s for w in ("صيانة", "maintenance")):
        return "maintenance"
    if any(w in s for w in ("wifi", "wi-fi", "اتصالات", "stc", "internet")):
        return "wifi"
    if any(w in s for w in ("اشتراك", "subscription", "saas", "software")):
        return "software_subscription"
    if any(w in s for w in ("مدى", "mada", "نقطة بيع", "pos")) or "بطاقة" in s:
        return "employee_card_settlement"
    # Generic transfers (وارد/صادر/حوالة/تحويل) are NOT auto-guessed: an incoming transfer
    # might be a channel payout OR founder funding, an outgoing one a supplier/owner/founder —
    # leave them 'unknown' so the accountant classifies (never fake revenue).
    return "unknown"

def _fb_similar_key(desc):
    """Group bank rows by their transaction TYPE (the part before ' · ', which is the
    counterparty/reference) so 'apply to similar' can classify repeats in one click."""
    s = str(desc or "").split(" · ")[0].strip().lower()
    return re.sub(r"[^0-9a-z؀-ۿ ]+", "", s).strip()[:40]

def _fb_card_last4(desc):
    import re as _re
    m = _re.search(r"(\d{4})\D*$", str(desc or "")) or _re.search(r"\b(\d{4})\b", str(desc or ""))
    return m.group(1) if m else None

def _fb_xlsx_rows(file_bytes):
    """All rows of the first worksheet as lists (Al Rajhi has metadata rows before the table)."""
    import io as _io, openpyxl
    wb = openpyxl.load_workbook(_io.BytesIO(file_bytes), data_only=True, read_only=True)
    ws = wb[wb.sheetnames[0]]
    rows = [list(r) for r in ws.iter_rows(values_only=True)]
    wb.close()
    return rows

def _fb_redact(s):
    """Mask long digit runs (account/IBAN/long refs) in free text — keep it readable."""
    return re.sub(r"\d{10,}", lambda m: "••••" + m.group()[-4:], str(s or ""))

_FB_BANK_HEAD = ("تاريخ", "date", "مدين", "debit", "دائن", "credit", "رصيد", "balance", "تفاصيل", "بيان", "وصف", "narration")

def _fb_bank_preview(file_bytes, fname="", colmap=None):
    rows = _fb_xlsx_rows(file_bytes)
    # Find the TRANSACTION header row: Al Rajhi stacks metadata rows on top, so pick the row
    # richest in transaction-header keywords that ALSO has a date column + a debit/credit column.
    hi, best = 0, -1
    for i, r in enumerate(rows[:40]):
        cells = [str(c).strip().lower() for c in r if c not in (None, "")]
        score = sum(1 for c in cells for k in _FB_BANK_HEAD if k in c)
        has_date = any(("تاريخ" in c or "date" in c) for c in cells)
        has_amt = any(("مدين" in c or "دائن" in c or "debit" in c or "credit" in c) for c in cells)
        if has_date and has_amt and score > best:
            best, hi = score, i
    headers = [str(c).strip() if c is not None else "" for c in (rows[hi] if rows else [])]
    body = rows[hi + 1:]
    low = [(h or "").strip().lower() for h in headers]
    def find(hints, start=0):
        for i in range(start, len(low)):
            if low[i] and any(x in low[i] for x in hints):
                return i
        return None
    if colmap:
        cm = colmap
    else:
        d1 = find(["desc", "بيان", "وصف", "تفاصيل", "نوع العملية", "narration"])
        d2 = find(["desc", "بيان", "وصف", "تفاصيل", "narration"], (d1 + 1) if d1 is not None else 0)
        cm = {"date": find(["date", "تاريخ"]), "desc": d1, "desc2": d2,
              "debit": find(["debit", "مدين", "سحب", "withdraw"]), "credit": find(["credit", "دائن", "إيداع", "deposit"]),
              "balance": find(["balance", "رصيد"]), "ref": find(["ref", "مرجع", "reference"])}
    out = []
    for i, r in enumerate(body):
        def cell(k):
            idx = cm.get(k)
            return r[idx] if (idx is not None and idx < len(r)) else None
        debit = abs(_fb_money(cell("debit")))          # Al Rajhi shows debit as negative → magnitude
        credit = _fb_money(cell("credit"))
        date = str(cell("date") or "").strip()
        if debit == 0 and credit == 0:
            continue
        if not date and not (cell("desc") or cell("desc2")):
            continue                                   # skip footer / total rows
        parts = [str(cell("desc") or "").strip(), str(cell("desc2") or "").strip()]
        desc = _fb_redact(" · ".join([p for p in parts if p]))
        bal = (_fb_money_str(cell("balance")) if cell("balance") is not None else "")
        # include running balance so two genuinely-separate identical rows (same day/amount/desc)
        # stay distinct, while a true re-import of the same file still de-dupes cleanly.
        h = hashlib.sha1(("|".join([fname, date, desc, _fb_money_str(debit), _fb_money_str(credit), bal])).encode("utf-8")).hexdigest()
        out.append({"row": hi + 2 + i, "date": date, "desc": desc,
                    "debit": _fb_money_str(debit), "credit": _fb_money_str(credit),
                    "balance": (_fb_money_str(cell("balance")) if cell("balance") is not None else None),
                    "ref": str(cell("ref") or "").strip(), "card_last4": _fb_card_last4(parts[1] or parts[0]),
                    "category": _fb_bank_classify(desc, debit, credit), "hash": h,
                    "duplicate": h in _fb_bank})
    return {"headers": headers, "detected": cm, "header_row": hi, "rows": out, "count": len(out),
            "new": sum(1 for x in out if not x["duplicate"]), "dups": sum(1 for x in out if x["duplicate"]),
            "filename": fname}

def _fb_bank_save(rows, fname="", actor=""):
    saved = dup = 0
    now = datetime.now(TZ).isoformat(timespec="seconds")
    for x in rows:
        h = x.get("hash")
        if not h or h in _fb_bank:
            dup += 1
            continue
        _fb_bank[h] = {"id": h, "source_file": fname, "row": x.get("row"), "date": x.get("date"),
                       "description": x.get("desc"), "debit": x.get("debit"), "credit": x.get("credit"),
                       "balance": x.get("balance"), "ref": x.get("ref"), "card_last4": x.get("card_last4"),
                       "category": x.get("category"), "status": "auto_classified" if x.get("category") != "unknown" else "needs_review",
                       "match_status": "unmatched", "daftra_status": "not_imported",
                       "imported_at": now, "imported_by": actor}
        saved += 1
    _fb_save("finance_bank_transactions.json", _fb_bank)
    _fb_audit_add(actor, "bank_import", "import_run", fname, after={"saved": saved, "duplicates": dup})
    return {"saved": saved, "duplicates": dup, "total": len(_fb_bank)}

def _fb_bank_summary():
    rows = list(_fb_bank.values())
    by_cat, by_status = {}, {}
    for x in rows:
        by_cat[x.get("category", "unknown")] = by_cat.get(x.get("category", "unknown"), 0) + 1
        by_status[x.get("status", "needs_review")] = by_status.get(x.get("status", "needs_review"), 0) + 1
    return {"count": len(rows), "by_category": by_cat, "by_status": by_status,
            "needs_review": by_status.get("needs_review", 0), "unmatched": sum(1 for x in rows if x.get("match_status") == "unmatched"),
            "last_run": _fb_last_run("bank")}

# ---- contract + bank + card endpoints ----
def _fb_contract_template_bytes():
    """Ready contract template (.xlsx) with DROPDOWNS on the fixed-option columns so filling is
    easy and typo-free. Headers match the importer's auto-detect. Dropdowns are SUGGESTIONS
    (custom values still allowed, e.g. a custom monthly cleaning amount). Examples live on a
    SEPARATE 'أمثلة' sheet so they're never imported by mistake (the importer reads sheet 1 only)."""
    import io as _io, openpyxl
    from openpyxl.utils import get_column_letter
    from openpyxl.worksheet.datavalidation import DataValidation
    headers = ["اسم الشقة", "كود الشقة", "المالك", "نسبة عوجا %", "النظافة",
               "الصيانة", "الاسترجاع", "Hostaway ID", "الحالة", "نوع العقد", "ملاحظات"]
    wb = openpyxl.Workbook(); ws = wb.active; ws.title = "العقود"
    ws.append(headers)
    # dropdowns (suggestions; custom values still allowed) on the fixed-option columns
    drops = {
        "D": ["15", "18", "20", "25", "30"],                                 # نسبة عوجا %
        "E": ["علينا", "المالك", "1000", "1050", "1100"],                    # النظافة (or type a custom amount)
        "F": ["المالك", "عوجا"],                                             # الصيانة
        "G": ["المالك", "عوجا"],                                             # الاسترجاع
        "I": ["active", "inactive", "onboarding", "ending"],                 # الحالة
        "J": ["إدارة بنسبة", "نسبة + نظافة شهرية", "مخصّص", "تشغيل عوجا"],     # نوع العقد
    }
    for col, opts in drops.items():
        dv = DataValidation(type="list", formula1='"' + ",".join(opts) + '"', allow_blank=True)
        dv.showErrorMessage = False    # suggestion dropdown — typing a custom value is allowed
        ws.add_data_validation(dv)
        dv.add("%s2:%s300" % (col, col))
    try:
        ws.freeze_panes = "A2"; ws.sheet_view.rightToLeft = True
        for i in range(1, len(headers) + 1):
            ws.column_dimensions[get_column_letter(i)].width = 20
    except Exception:
        pass
    # examples on a SECOND sheet (reference only — NOT imported)
    ex = wb.create_sheet("أمثلة")
    ex.append(headers)
    ex.append(["Ouja | T08", "T08", "عبدالله السالم", 25, "علينا", "المالك", "المالك", "", "active", "إدارة بنسبة", "25% — تشغيل ونظافة على عوجا"])
    ex.append(["Ouja | A11", "A11", "سارة محمد", 18, "1050", "المالك", "المالك", "", "active", "نسبة + نظافة شهرية", "النظافة 1050 شهريًا على المالك"])
    ex.append(["Ouja | B02", "B02", "مستثمر", 20, "1100", "المالك", "المالك", "", "active", "مخصّص", ""])
    ex.append(["Ouja | E15", "E15", "عوجا", "", "علينا", "عوجا", "عوجا", "", "active", "تشغيل عوجا", "وحدة تشغيل عوجا — الربح كله لعوجا"])
    try:
        ex.sheet_view.rightToLeft = True
        for i in range(1, len(headers) + 1):
            ex.column_dimensions[get_column_letter(i)].width = 20
    except Exception:
        pass
    buf = _io.BytesIO(); wb.save(buf); return buf.getvalue()

async def _api_fb_contract_template(request):
    if not _fb_can_finance(request):
        return _json({"error": "forbidden"}, 403)
    data = await asyncio.to_thread(_fb_contract_template_bytes)
    return web.Response(body=data,
                        content_type="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
                        headers={"Content-Disposition": "attachment; filename=ouja-contracts-template.xlsx"})

def _fb_cc_suggest(profile, ccs):
    """Suggest a Daftra cost center for a contract by name/code token overlap. Conservative:
    score against the apartment's OWN tokens (so 'MLQ1' never matches 'MLQ 11'); an exact
    normalized-name/code equality boosts to 0.97 (NOT substring — that's the trap). Returns
    {id,name,confidence,reason_ar,reason_en} or None. Never auto-applies on its own."""
    ntoks = set(_fb_tokens(profile.get("apartment_name"))); ntoks.discard("ouja")
    ctoks = set(_fb_tokens(profile.get("apartment_code")))
    base = ntoks or ctoks
    if not base:
        return None
    pname = _fb_listing_norm(profile.get("apartment_name"))
    pcode = _fb_norm_match(profile.get("apartment_code"))
    best, bestscore, why = None, 0.0, ""
    for cc in ccs:
        nm = cc.get("display_name") or ""
        cctoks = set(_fb_tokens(nm)) | set(_fb_tokens(cc.get("code")))
        inter = base & cctoks
        if not inter:
            continue
        score = len(inter) / float(len(base))
        ccnorm = _fb_norm_match(nm)
        if (pname and pname == ccnorm) or (pcode and pcode == ccnorm):
            score = max(score, 0.97)
        score = min(score, 1.0)
        if score > bestscore:
            best, bestscore, why = cc, score, " ".join(sorted(inter))
    if not best:
        return None
    return {"id": best.get("source_id"), "name": best.get("display_name"),
            "confidence": round(bestscore, 2), "reason_ar": "الاسم يحتوي: " + why, "reason_en": "name contains: " + why}

async def _api_fb_contracts(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    ccs = [r for r in _fb_external.values() if r.get("source_type") == "cost_centers"]
    profs = []
    for key, p in _fb_contracts.items():
        pv = dict(p); pv["key"] = key
        if not p.get("daftra_cost_center_id"):
            sg = _fb_cc_suggest(p, ccs)
            if sg:
                pv["cc_suggestion"] = sg
        profs.append(pv)
    return _json({"ok": True, "summary": _fb_contracts_summary(),
                  "cost_centers": [{"source_id": c.get("source_id"), "display_name": c.get("display_name")} for c in ccs][:300],
                  "profiles": profs})

async def _api_fb_contract(request):
    """Update one (or bulk) contract profile + recompute validation. Audited. action options:
    'update' (default, by key) · 'bulk' (keys[] + patch) · 'apply_cc_suggestions' (auto-link
    high-confidence cost-center matches). Never guesses missing values — only what's sent."""
    if not _fb_can_finance(request):
        return _json({"error": "forbidden"}, 403)
    b = await _read_body(request)
    actor = _req_actor(request)
    ccs = [r for r in _fb_external.values() if r.get("source_type") == "cost_centers"]
    action = (b.get("action") or "update").strip()
    FIELDS = ("daftra_cost_center_id", "daftra_cost_center_name", "hostaway_listing_id",
              "ouja_percentage", "cleaning_rule", "cleaning_monthly_amount", "maintenance_rule",
              "refund_rule", "unit_type", "owner_name", "contract_type", "notes", "status")
    def _apply(p, patch):
        for k in FIELDS:
            if k not in patch:
                continue
            v = patch.get(k)
            if k == "ouja_percentage":
                p[k] = (None if v in (None, "") else _fb_norm_pct(v))
            elif k == "cleaning_monthly_amount":
                try:
                    p[k] = (None if v in (None, "") else float(v))
                except (TypeError, ValueError):
                    p[k] = None
            else:
                p[k] = v
        p["validation_status"], p["validation_issues"] = _fb_contract_validate(p)
    if action == "apply_cc_suggestions":
        thr = float(b.get("min_confidence") or 0.9)
        n = 0
        for p in _fb_contracts.values():
            if p.get("daftra_cost_center_id"):
                continue
            s = _fb_cc_suggest(p, ccs)
            if s and s["id"] and s["confidence"] >= thr:
                p["daftra_cost_center_id"] = str(s["id"]); p["daftra_cost_center_name"] = s["name"]
                p["validation_status"], p["validation_issues"] = _fb_contract_validate(p)
                n += 1
        _fb_save("finance_contract_profiles.json", _fb_contracts)
        _fb_audit_add(actor, "contract_cc_autolink", "contracts", "bulk", after={"linked": n, "min_conf": thr})
        return _json({"ok": True, "linked": n, "summary": _fb_contracts_summary()})
    if action == "bulk":
        patch = {k: b.get(k) for k in FIELDS if k in b}
        n = 0
        for key in (b.get("keys") or []):
            p = _fb_contracts.get(key)
            if p:
                _apply(p, patch); n += 1
        _fb_save("finance_contract_profiles.json", _fb_contracts)
        _fb_audit_add(actor, "contract_bulk_update", "contracts", "bulk", after={"count": n, "fields": list(patch.keys())})
        return _json({"ok": True, "updated": n, "summary": _fb_contracts_summary()})
    key = (b.get("key") or "").strip()
    p = _fb_contracts.get(key)
    if not p:
        return _json({"error": "contract_not_found"}, 404)
    before = {"cost_center": p.get("daftra_cost_center_id"), "status": p.get("validation_status")}
    _apply(p, b)
    _fb_save("finance_contract_profiles.json", _fb_contracts)
    _fb_audit_add(actor, "contract_update", "contracts", key, before=before,
                  after={"cost_center": p.get("daftra_cost_center_id"), "status": p.get("validation_status")})
    return _json({"ok": True, "profile": dict(p, key=key), "summary": _fb_contracts_summary()})

async def _api_fb_contracts_import(request):
    if not _fb_can_finance(request):
        return _json({"error": "forbidden"}, 403)
    try:
        data, fname, fields = await _fb_read_upload(request)
    except ValueError as e:
        return _json({"error": str(e)}, 400)
    if not data:
        return _json({"error": "empty_file"}, 400)
    save = (fields.get("save") == "1")
    colmap = None
    if fields.get("colmap"):
        try:
            colmap = {k: int(v) for k, v in json.loads(fields["colmap"]).items() if v not in (None, "")}
        except Exception:
            colmap = None
    try:
        prev = await asyncio.to_thread(_fb_contracts_preview, data, colmap)
    except Exception as e:
        return _json({"error": "parse_failed", "detail": str(e)[:200]}, 400)
    if not save:
        return _json({"ok": True, "preview": prev})
    run = _fb_run_start("contracts", fname, _req_actor(request))
    res = await asyncio.to_thread(_fb_contracts_save, prev["rows"], _req_actor(request))
    _fb_run_finish(run, "done", imported=res["saved"], updated=res["updated"])
    return _json({"ok": True, "saved": res, "summary": _fb_contracts_summary()})

async def _api_fb_bank(request):
    if not _fb_can_finance(request):
        return _json({"error": "forbidden"}, 403)
    status = (request.query.get("status") or "").strip()
    txns = list(_fb_bank.values())
    if status:
        txns = [x for x in txns if (x.get("status") or "needs_review") == status]
    return _json({"ok": True, "summary": _fb_bank_summary(),
                  "transactions": txns[-400:], "shown": min(len(txns), 400), "matched": len(txns)})

async def _api_fb_bank_import(request):
    if not _fb_can_finance(request):
        return _json({"error": "forbidden"}, 403)
    try:
        data, fname, fields = await _fb_read_upload(request)
    except ValueError as e:
        return _json({"error": str(e)}, 400)
    if not data:
        return _json({"error": "empty_file"}, 400)
    try:
        prev = await asyncio.to_thread(_fb_bank_preview, data, fname)
    except Exception as e:
        return _json({"error": "parse_failed", "detail": str(e)[:200]}, 400)
