async def _api_fb_cards(request):
    if not _fb_can_finance(request):
        return _json({"error": "forbidden"}, 403)
    if request.method == "GET":
        return _json({"ok": True, "cards": _fb_cards})
    b = await _read_body(request)
    last4 = "".join(ch for ch in str(b.get("last4") or "") if ch.isdigit())[-4:]
    if not last4:
        return _json({"error": "bad_last4"}, 400)
    if b.get("delete"):
        _fb_cards.pop(last4, None)
    else:
        _fb_cards[last4] = {"last4": last4, "employee": (b.get("employee") or "").strip()[:80],
                            "active": bool(b.get("active", True)), "notes": (b.get("notes") or "")[:200],
                            "default_category": (b.get("default_category") or "").strip()}
    _fb_save("finance_card_mappings.json", _fb_cards)
    _fb_audit_add(_req_actor(request), "card_mapping", "card", last4)
    return _json({"ok": True, "cards": _fb_cards})

# ---- Stage 6: canonical ledger + Financial Inbox + approval workflow ----
def _fb_ledger_create(source, amount, direction, category, apartment="", description="",
                      date="", source_id="", owner="", submitter="", cost_center=""):
    import uuid
    eid = "led-" + uuid.uuid4().hex[:12]
    amt = _fb_money_str(amount)
    _fb_ledger[eid] = {"id": eid, "source": source, "source_id": str(source_id or ""),
                       "amount": amt, "currency": "SAR", "direction": direction,  # debit|credit|expense|income
                       "category": category or "unknown", "apartment": apartment, "owner": owner,
                       "cost_center": cost_center, "description": (description or "")[:500],
                       "date": date, "submitter": submitter, "status": "draft",
                       "match_status": "unmatched", "daftra_status": "not_imported",
                       "verification_status": "none", "created_at": datetime.now(TZ).isoformat(timespec="seconds")}
    return _fb_ledger[eid]

async def _fb_notify_large(entry, actor):
    """Discord alert for an expense >= threshold (reuses _post_system_escalation; no bank/secret data)."""
    try:
        amt = _fb_money(entry.get("amount"))
        if amt < FB_APPROVAL_THRESHOLD:
            return
        await _post_system_escalation(
            "💰 مصروف يحتاج اعتماد فيصل (≥ %s ر.س)" % str(FB_APPROVAL_THRESHOLD),
            "المبلغ: %s ر.س · التصنيف: %s · الشقة: %s · المقدّم: %s · الوصف: %s" % (
                entry.get("amount"), entry.get("category") or "—", entry.get("apartment") or "—",
                actor or "—", (entry.get("description") or "—")[:120]),
            severity="high")
    except Exception as e:
        print("fb notify error:", e)

def _fb_next_action(e):
    st = e.get("status")
    if st == "draft":
        return ("submit", "أرسل للمراجعة", "submit for review")
    if st in ("submitted", "accountant_review"):
        return ("review", "راجع وصنّف", "review & classify")
    if st == "needs_faisal":
        return ("faisal", "بانتظار اعتماد فيصل", "awaiting Faisal approval")
    if st == "approved":
        return ("draft_journal", "جهّز قيد دافترة", "prepare Daftra journal")
    if st == "ready_to_post":
        return ("post", "ترحيل (يحتاج تفعيل)", "post (needs enable)")
    if st in ("posted", "verification_pending"):
        return ("verify", "تحقق من دافترة", "verify in Daftra")
    if st == "failed":
        return ("retry", "فشل — افتح السبب", "failed — open reason")
    return ("none", "—", "—")

_FB_LANES = ("ready_to_link", "linked_existing", "needs_decision", "missing_setup",
             "needs_faisal_approval", "ready_for_journal", "journal_draft",
             "needs_classify", "needs_dup_check", "needs_review", "rejected", "completed")

def _fb_resolve_status(item):
    """THE single authoritative finance-workflow resolver. Daftra duplicate state WINS over raw
    category/status, so a confirmed-in-Daftra row never sits in plain 'needs review'. Strict
    priority. Returns lane + bilingual labels + next action + reason + can_* capability flags."""
    dq = item.get("daftra_duplicate_status")
    amt = _fb_money(item.get("amount"))
    has_cat = item.get("category") not in (None, "", "unknown")
    fa_status = item.get("faisal_approval_status")
    outgoing = item.get("direction") in ("expense", "debit")
    # Faisal high-value approval is for OUTGOING spend only — incoming owner funding never needs it (spec Part 9 Test 8)
    needs_faisal = (amt >= FB_APPROVAL_THRESHOLD) and outgoing and (fa_status != "approved")
    kind, st = item.get("kind"), item.get("status")
    num = item.get("matched_daftra_number")
    mt = item.get("daftra_match_type")
    nlines = item.get("distributed_num_lines")
    rar = item.get("daftra_duplicate_reason_ar") or ""
    ren = item.get("daftra_duplicate_reason_en") or ""

    def R(state, lane, s_ar, s_en, na, na_ar, na_en, r_ar, r_en, **flags):
        d = {"primary_state": state, "lane": lane, "primary_state_label_ar": s_ar, "primary_state_label_en": s_en,
             "next_action": na, "next_action_label_ar": na_ar, "next_action_label_en": na_en,
             "reason_chip_ar": r_ar, "reason_chip_en": r_en, "requires_faisal_approval": needs_faisal,
             "matched_number": num, "can_classify": True, "can_promote_to_ledger": False,
             "can_prepare_daftra_post": False, "can_link_existing_daftra": False, "can_bulk_link": False,
             "is_completed": False, "blocking_reason": ""}
        d.update(flags)
        return d

    if dq == "linked_existing" or item.get("daftra_status") == "linked_existing":
        if mt == "distributed_subset_match":
            return R("linked_to_daftra", "linked_existing", "مربوط بتوزيع في دافترة", "Linked as distribution",
                     "open_daftra", "فتح التفاصيل", "Open details",
                     "مرتبط بأسطر محددة داخل قيد دافترة" + ((" · قيد #" + str(num)) if num else ""),
                     "Linked to specific lines inside a Daftra journal", can_classify=False, is_completed=True)
        if mt == "batch_bank_line_match":
            return R("linked_to_daftra", "linked_existing", "مربوط بحوالة مجمعة", "Linked (batch)",
                     "open_daftra", "فتح التفاصيل", "Open details",
                     "ضمن مجموعة حوالات تساوي سطر البنك" + ((" · قيد #" + str(num)) if num else ""),
                     "Part of a batch equalling the bank line", can_classify=False, is_completed=True)
        return R("linked_to_daftra", "linked_existing", "مربوط بدافترة", "Linked to Daftra",
                 "open_daftra", "فتح التفاصيل", "Open details",
                 ("قيد #" + str(num)) if num else "تم ربطها بسجل موجود في دافترة",
                 ("Journal #" + str(num)) if num else "Linked to existing Daftra record",
                 can_classify=False, is_completed=True)
    if dq == "already_in_daftra_verified":
        if mt == "distributed_subset_match":
            return R("existing_in_daftra_ready_to_link", "ready_to_link", "موجود كتوزيع في دافترة", "In Daftra as distribution",
                     "open_compare", "ربط كتوزيع", "Link as distribution",
                     rar or (("مجموع " + str(nlines) + " أسطر داخل قيد دافترة يطابق العملية") if nlines else "مجموع أسطر داخل قيد دافترة يطابق العملية"),
                     ren or "matches a subset of journal lines",
                     can_classify=False, can_link_existing_daftra=True, can_bulk_link=True, blocking_reason="exists_in_daftra")
        return R("existing_in_daftra_ready_to_link", "ready_to_link", "موجود في دافترة", "Existing in Daftra",
                 "link_confirm", "ربط واعتماد", "Link & confirm",
                 rar or "نفس المبلغ والتاريخ وسطر حساب البنك مطابق", ren or "amount/date/bank-line match",
                 can_classify=False, can_link_existing_daftra=True, can_bulk_link=True, blocking_reason="exists_in_daftra")
    if dq == "strong_possible_duplicate":
        if mt == "distributed_subset_match":
            return R("strong_possible", "needs_decision", "توزيع محتمل", "Possible distribution",
                     "open_compare", "راجع التوزيع", "Review distribution", rar, ren,
                     can_link_existing_daftra=True, blocking_reason="possible_duplicate")
        return R("strong_possible", "needs_decision", "احتمال تكرار قوي", "Strong possible duplicate",
                 "open_compare", "فتح المطابقة", "Open comparison", rar, ren,
                 can_link_existing_daftra=True, blocking_reason="possible_duplicate")
    if dq == "possible_duplicate":
        if mt == "distributed_subset_match":
            return R("possible", "needs_decision", "توزيع محتمل", "Possible distribution",
                     "open_compare", "راجع التوزيع", "Review distribution", rar, ren,
                     can_link_existing_daftra=True, blocking_reason="possible_duplicate")
        return R("possible", "needs_decision", "احتمال مكرر", "Possible duplicate",
                 "open_compare", "راجع المطابقة", "Review comparison", rar, ren,
                 can_link_existing_daftra=True, blocking_reason="possible_duplicate")
    if dq == "needs_manual_review":                  # medium-confidence (50-69) — a DECISION, not a dead 'needs review'
        if mt == "distributed_subset_match":
            return R("possible", "needs_decision", "توزيع محتمل — يحتاج قرار", "Possible distribution — decide",
                     "open_compare", "راجع التوزيع", "Review distribution", rar, ren,
                     can_link_existing_daftra=True, blocking_reason="possible_duplicate")
        return R("manual_review", "needs_decision", "يحتاج قرار يدوي", "Needs manual decision",
                 "open_compare", "راجع المطابقة", "Review comparison",
                 rar or "تطابق متوسط — راجع المرشحات أو علّمها «مو مكرر»",
                 ren or "medium-confidence match — review candidates or mark not-a-duplicate",
                 can_link_existing_daftra=True, blocking_reason="possible_duplicate")
    if dq == "missing_bank_account_mapping":
        return R("missing_setup", "missing_setup", "ناقص إعداد", "Missing setup",
                 "complete_setup", "أكمل ربط حساب البنك", "Complete bank mapping",
                 "ناقص ربط حساب البنك في دافترة", "Daftra bank account mapping missing",
                 blocking_reason="missing_bank_account_mapping")
    if dq == "check_failed":
        return R("check_failed", "needs_decision", "فشل التحقق", "Check failed",
                 "dup_check", "أعد الفحص", "Retry check", "فشل فحص التكرار مع دافترة", "Daftra check failed",
                 blocking_reason="check_failed")
    if kind == "bank" and dq in (None, "", "not_checked"):
        return R("needs_dup_check", "needs_dup_check", "يحتاج مطابقة دافترة", "Needs Daftra check",
                 "dup_check", "تأكد من التكرار", "Check duplicates",
                 "شغّل فحص التكرار مع دافترة قبل أي ترحيل", "run the Daftra duplicate check first",
                 blocking_reason="not_checked")
    if fa_status == "rejected":
        return R("rejected", "rejected", "مرفوض — يحتاج تصحيح", "Rejected — needs correction",
                 "classify", "صحّح وأعد الإرسال", "Correct & resubmit",
                 "اعتماد فيصل: مرفوض" + ((" — " + str(item.get("approval_reason"))) if item.get("approval_reason") else ""),
                 "Faisal approval: rejected")
    if fa_status == "needs_clarification":
        return R("needs_clarification", "needs_review", "يحتاج توضيح لفيصل", "Needs clarification",
                 "classify", "وضّح وأعد", "Clarify & resubmit",
                 "اعتماد فيصل: طلب توضيح" + ((" — " + str(item.get("approval_reason"))) if item.get("approval_reason") else ""),
                 "Faisal: needs clarification")
    if needs_faisal and st not in ("approved", "ready_to_post", "posted", "verified"):
        return R("needs_faisal", "needs_faisal_approval", "يحتاج اعتماد فيصل", "Needs Faisal approval",
                 "faisal", "إرسال لاعتماد فيصل", "Send for Faisal approval",
                 "المبلغ ٣٠٠٠ أو أكثر", "amount ≥ 3,000", can_approve_high_value=True)
    if item.get("daftra_flow_type") == "cash_in_owner_fitout_funding" and not (_fb_mappings.get("owner_fitout_funding") or {}).get("daftra_account_id"):
        return R("fitout_unmapped", "missing_setup", "ناقص ربط حساب التمويل", "Funding account unmapped",
                 "map_fitout", "اربط حساب تمويل تجهيز الشقق", "Map fit-out funding account",
                 "حساب تمويل تجهيز الشقق من الملاك غير مربوط في دافترة", "owner fit-out funding account not mapped",
                 blocking_reason="fitout_funding_account_unmapped")
    # A ledger entry is ALREADY in the internal ledger — it must NEVER loop back to ready_for_journal
    # or generic needs_review. The whole post-promote lifecycle lives in the journal_draft lane.
    if kind == "ledger":
        if st in ("posted", "verified") or item.get("verification_status") == "verified":
            return R("completed", "completed", "مكتمل", "Completed", "none", "—", "—",
                     "تم الترحيل/التحقق في دافترة", "posted/verified", can_classify=False, is_completed=True)
        if st == "rejected":
            return R("rejected", "rejected", "مرفوض — يحتاج تصحيح", "Rejected", "classify", "صحّح وأعد", "Correct & resubmit",
                     "مرفوض من الاعتماد", "rejected")
        if not has_cat:                          # in the ledger but missing category → setup, NOT a generic review
            return R("ledger_needs_class", "missing_setup", "في السجل — ناقص تصنيف", "In ledger — needs category",
                     "classify", "صنّف", "Classify", "موجودة في السجل المالي وتحتاج تصنيف قبل تجهيز القيد",
                     "in the ledger, classify before drafting", blocking_reason="missing_category")
        if st == "ready_to_post" or item.get("journal_draft_status") == "ready_to_post":
            return R("ready_to_post", "journal_draft", "مسودة جاهزة للترحيل", "Ready to post",
                     "post", "ترحيل لدافترة", "Post to Daftra", "مسودة القيد جاهزة للترحيل", "journal draft ready to post",
                     can_prepare_daftra_post=True, can_classify=False)
        if item.get("journal_draft_id") or item.get("journal_draft_status") == "draft_ready":
            return R("journal_draft_ready", "journal_draft", "مسودة قيد جاهزة", "Journal draft ready",
                     "review_draft", "راجع مسودة القيد", "Review journal draft", "في السجل المالي — راجع المسودة",
                     "in the ledger — review the draft", can_prepare_daftra_post=True, can_classify=False)
        return R("ledger_created", "journal_draft", "في السجل المالي", "In the ledger",
                 "draft_journal", "جهّز قيد دافترة", "Prepare Daftra journal",
                 "موجودة في السجل المالي — جهّز قيد دافترة", "in the ledger — prepare a Daftra journal",
                 can_prepare_daftra_post=True)
    if kind != "ledger" and dq in ("not_found_after_full_check", "not_duplicate"):
        if not has_cat:
            return R("needs_classify", "needs_classify", "يحتاج تصنيف", "Needs classification",
                     "classify", "صنّف", "Classify", "عملية جديدة تحتاج تصنيف", "new — classify it")
        return R("ready_for_journal", "ready_for_journal", "جاهز للسجل المالي", "Ready for ledger",
                 "promote", "حوّل للسجل المالي", "Move to ledger",
                 "جديدة وغير موجودة في دافترة — حوّلها للسجل المالي", "new, not in Daftra — move to ledger",
                 can_promote_to_ledger=True)
    if kind == "bank" and dq in (None, "", "not_checked"):     # safety net — should be caught above
        return R("needs_dup_check", "needs_dup_check", "يحتاج مطابقة دافترة", "Needs Daftra check",
                 "dup_check", "تأكد من التكرار", "Check duplicates",
                 "شغّل فحص التكرار مع دافترة قبل أي ترحيل", "run the Daftra duplicate check first",
                 blocking_reason="not_checked")
    if not has_cat:
        return R("needs_classify", "needs_classify", "يحتاج تصنيف", "Needs classification",
                 "classify", "صنّف", "Classify", "يحتاج تصنيف", "needs classification")
    # classified + dup-checked-clean = genuinely ready. Never park an actionable item in a dead 'needs_review'.
    return R("ready_for_journal", "ready_for_journal", "جاهز للسجل المالي", "Ready for ledger",
             "promote", "حوّل للسجل المالي", "Move to ledger",
             "مصنّفة ومفحوصة وما هي بدافترة — حوّلها للسجل المالي", "classified & checked, not in Daftra — move to ledger",
             can_promote_to_ledger=True)

