async def _api_cleaning_log(request):
    """Unified cleaning activity log: cleaner status actions + manager photo-report decisions +
    manual task adds, newest first. ?lid= scopes to one apartment."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    lmap = (await get_listings_map_async()) or {}
    want = (request.query.get("lid") or "").strip()
    rows = []
    for e in _oujact_status[-500:]:
        rows.append({"ts": e.get("ts"), "lid": e.get("lid"),
                     "name": lmap.get(e.get("lid"), str(e.get("lid"))),
                     "kind": "status", "action": e.get("action"),
                     "by": e.get("by") or "", "note": e.get("note") or ""})
    for a in _cleaning_report_audit[-500:]:
        act = a.get("action") or ""
        if not (act.startswith("manager_") or act == "report_submitted"):
            continue
        rep = _cleaning_reports.get(a.get("report_id")) or {}
        rows.append({"ts": a.get("timestamp"), "lid": rep.get("apartment_id"),
                     "name": a.get("apartment") or rep.get("apartment_name") or "",
                     "kind": "report", "action": act, "by": a.get("actor") or "",
                     "note": a.get("detail") or "", "report_id": a.get("report_id")})
    for tk in _clean_tasks.values():
        rows.append({"ts": tk.get("created_at"), "lid": tk.get("lid"),
                     "name": lmap.get(tk.get("lid"), str(tk.get("lid"))),
                     "kind": "task",
                     "action": "manual_task_canceled" if tk.get("canceled") else "manual_task_added",
                     "by": tk.get("by") or "", "note": _clean_type_label(tk.get("ctype"), "ar")})
    if want:
        rows = [r for r in rows if str(r.get("lid")) == want]
    rows.sort(key=lambda r: r.get("ts") or "", reverse=True)
    return _json({"ok": True, "log": rows[:250]})

async def _api_oujact_route(request):
    """PUBLIC, token-gated route data for the cleaning team (Oujact only · today · cleaning
    actions only — never the full dashboard). Optional ?start= computes ETA when possible."""
    token = request.query.get("token", "")
    team = _ct_team_by_token(token)
    if not team and OUJACT_ROUTE_TOKEN and hmac.compare_digest(str(OUJACT_ROUTE_TOKEN), str(token)):
        # DEPRECATED legacy unscoped link: never expose the full dispatch plan —
        # scope it to team-1 (the migrated team). External crews see only their units.
        team = _cleaning_teams.get("team-1")
        print("WARNING: legacy OUJACT_ROUTE_TOKEN link used — scoped to team-1; move crews to per-team links")
    if not team:
        return _json({"error": "unauthorized"}, 401)
    assigned = _ct_team_lids(team["id"])                       # scope to THIS team's apartments
    plan = await asyncio.to_thread(_oujact_dispatch_plan, True, assigned)
    start = (request.query.get("start") or "").strip()
    eta = {"available": False, "reason": "no_start", "legs": [], "total_drive_min": None}
    if start:
        eta = await asyncio.to_thread(_oujact_route_eta, start, plan)
        legs = eta.get("legs") or []
        for i, p in enumerate(plan):
            p["eta_min"] = legs[i] if i < len(legs) else None
    return _json({"ok": True, "date": datetime.now(TZ).date().isoformat(),
                  "team": {"id": team["id"], "name": team.get("name", "")} if team else None,
                  "plan": plan, "eta": eta, "totals": _oujact_plan_totals(plan, eta),
                  "have_start": bool(start), "maps_key": bool(GOOGLE_MAPS_API_KEY)})

async def _api_oujact_route_link(request):
    """Dashboard: generate + audit the shareable Oujact route link (token-scoped to today)."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    if not OUJACT_ROUTE_TOKEN:
        return _json({"error": "no_token",
                      "note": "ضع OUJACT_ROUTE_TOKEN أو CLEANING_TOKEN في متغيرات Railway أول"}, 400)
    plan = await asyncio.to_thread(_oujact_dispatch_plan)
    url = "/oujact-route?token=" + OUJACT_ROUTE_TOKEN
    audit = {"ts": datetime.now(TZ).isoformat(timespec="seconds"),
             "by": _req_actor(request), "date": datetime.now(TZ).date().isoformat(),
             "count": len(plan), "apartments": [p["name"] for p in plan]}
    _oujact_route_audit.append(audit)
    if len(_oujact_route_audit) > 1000:
        del _oujact_route_audit[:len(_oujact_route_audit) - 1000]
    _save_json("oujact_route_audit.json", _oujact_route_audit)
    log_event("ops", f"Oujact · أُنشئ رابط المسار · {len(plan)} شقة")
    return _json({"ok": True, "url": url, "count": len(plan),
                  "audit": _oujact_route_audit[-10:][::-1]})

async def _api_oujact_dispatch(request):
    """Dashboard summary of today's Oujact dispatch plan."""
