async def _api_cleaning_template_save(request):
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    scope = (b.get("scope") or "default").strip()
    if scope not in ("default", "apartment_type", "apartment"):
        return _json({"error": "bad scope"}, 400)
    value = b.get("apartment_id") if scope == "apartment" else (b.get("apartment_type") if scope == "apartment_type" else "default")
    tid = "cpt-default" if scope == "default" else _cleanproof_template_id(scope, value)
    slots = b.get("slots") or []
    clean_slots = []
    for i, s in enumerate(slots):
        sid = re.sub(r"[^A-Za-z0-9_-]+", "_", (s.get("slot_id") or f"slot_{i+1}").strip())[:40]
        if not sid:
            continue
        clean_slots.append({
            "slot_id": sid, "label_ar": (s.get("label_ar") or sid)[:80],
            "label_en": (s.get("label_en") or sid)[:80],
            "instructions_ar": (s.get("instructions_ar") or "")[:240],
            "instructions_en": (s.get("instructions_en") or "")[:240],
            "required": bool(s.get("required", True)),
            "allow_multiple": bool(s.get("allow_multiple", False)),
            "display_order": int(s.get("display_order") or (i + 1)),
            "active": bool(s.get("active", True)),
        })
    if not clean_slots:
        return _json({"error": "at least one slot required"}, 400)
    now = _cleanproof_now()
    old = _cleaning_photo_templates.get(tid) or {}
    tpl = {
        "template_id": tid, "scope": scope,
        "apartment_id": str(value or "") if scope == "apartment" else "",
        "apartment_type": str(value or "") if scope == "apartment_type" else "",
        "template_name": (b.get("template_name") or old.get("template_name") or "Cleaning photo checklist")[:120],
        "active": bool(b.get("active", True)),
        "slots": sorted(clean_slots, key=lambda x: x["display_order"]),
        "created_at": old.get("created_at") or now,
        "updated_at": now, "updated_by": _req_actor(request),
    }
    _cleaning_photo_templates[tid] = tpl
    _save_json("cleaning_photo_templates.json", _cleaning_photo_templates)
    _cleanproof_audit("", "template_edited", _req_actor(request), "", "", tid)
    return _json({"ok": True, "template": tpl})

async def _api_cleaning_photo_file(request):
    dash_ok = _dash_auth(request)
    route_ok = _oujact_route_auth(request)
    if not (route_ok or dash_ok):
        return _json({"error": "unauthorized"}, 401)
    pid = (request.query.get("photo_id") or "").strip()
    photo = _cleaning_report_photos.get(pid)
    if not photo or photo.get("status") == "removed":
        return _json({"error": "not found"}, 404)
    if route_ok and not dash_ok:
        # Team tokens only see photos of THEIR OWN apartments.
        team = _ct_team_by_token(request.query.get("token", ""))
        try:
            owns = team is not None and int(photo.get("apartment_id")) in _ct_team_lids(team["id"])
        except (TypeError, ValueError):
            owns = False
        if not owns:
            return _json({"error": "forbidden"}, 403)
    path = photo.get("local_path") or ""
    if path and os.path.exists(path):
        return web.FileResponse(path, headers={"Content-Type": photo.get("mime_type") or "application/octet-stream"})
    if photo.get("drive_file_id") and _cleanproof_drive_configured():
        try:
            from googleapiclient.http import MediaIoBaseDownload
            service = _cleanproof_get_drive_service()
            req = service.files().get_media(fileId=photo["drive_file_id"], supportsAllDrives=True)
            fh = io.BytesIO()
            dl = MediaIoBaseDownload(fh, req)
            done = False
            while not done:
                _, done = dl.next_chunk()
            return web.Response(body=fh.getvalue(), content_type=photo.get("mime_type") or "application/octet-stream")
        except Exception as e:
            return _json({"error": "drive file unavailable", "message": str(e)[:200]}, 404)
    if not path or not os.path.exists(path):
        return _json({"error": "file missing"}, 404)
    return web.FileResponse(path, headers={"Content-Type": photo.get("mime_type") or "application/octet-stream"})

async def _api_cleaning_photos_find(request):
    """Dashboard photo locator: find submitted cleaning photos by apartment + date.
    Always returns the `apartments` facet (every apartment that has at least one photo,
    with a count) so the dropdown can populate; the optional `apt` (listing id),
    `from` and `to` (YYYY-MM-DD) query params narrow the returned reports."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    apt = (request.query.get("apt") or "").strip()
    d_from = (request.query.get("from") or "").strip()
    d_to = (request.query.get("to") or "").strip()

    apt_counts = {}   # lid -> {"id","name","count"}
    rows = []
    for pid, ph in list(_cleaning_report_photos.items()):
        if (ph.get("status") or "") == "removed":
            continue
        rep = _cleaning_reports.get(ph.get("report_id")) or {}
        lid = str(ph.get("apartment_id") or rep.get("apartment_id") or "")
        name = rep.get("apartment_name") or ("شقة " + lid if lid else "—")
        date = rep.get("date") or (ph.get("uploaded_at") or "")[:10]
        a = apt_counts.setdefault(lid, {"id": lid, "name": name, "count": 0})
        a["count"] += 1
        if a["name"] in ("", "—") and name not in ("", "—"):
            a["name"] = name
        rows.append((pid, ph, rep, lid, name, date))

    apartments = sorted(apt_counts.values(), key=lambda x: x["name"])

    groups = {}
    for pid, ph, rep, lid, name, date in rows:
        if apt and lid != apt:
            continue
        if d_from and (date or "") < d_from:
            continue
        if d_to and (date or "") > d_to:
            continue
        rid = ph.get("report_id") or ("_" + pid)
        g = groups.get(rid)
        if not g:
            g = groups[rid] = {
                "report_id": rid,
                "date": date,
                "apartment_id": lid,
                "apartment_name": name,
                "status": rep.get("status") or "",
                "approved_by": rep.get("approved_by") or "",
                "drive_folder_url": rep.get("drive_folder_url") or "",
                "photos": [],
            }
        g["photos"].append({
            "photo_id": pid,
            "slot_id": ph.get("slot_id") or "",
            "uploaded_at": ph.get("uploaded_at") or "",
            "mime_type": ph.get("mime_type") or "",
        })

    reports = sorted(groups.values(), key=lambda g: (g["date"] or "", g["report_id"]), reverse=True)
    for g in reports:
        g["photos"].sort(key=lambda p: p.get("uploaded_at") or "")
    total = sum(len(g["photos"]) for g in reports)
    return _json({"apartments": apartments, "reports": reports, "total": total})

