async def _api_metrics_daily(request):
    """Return up to N days of daily counters + derived rates so the dashboard can
    chart the assistant's improvement over time. ?days=30 by default."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    try:
        days = int(request.query.get("days", "30"))
    except Exception:
        days = 30
    days = max(1, min(120, days))
    today = datetime.now(TZ).date()
    out = []
    for i in range(days - 1, -1, -1):
        d = today - timedelta(days=i)
        k = d.isoformat()
        row = _daily_metrics.get(k, _new_day_row())
        total = row.get("replies_total", 0)
        manual_or_edit = row.get("replies_manual", 0) + row.get("replies_edited", 0) + row.get("replies_dashboard", 0)
        auto_rate = round((row.get("replies_auto", 0) / total) * 100) if total else 0
        edit_rate = round((row.get("replies_edited", 0) / manual_or_edit) * 100) if manual_or_edit else 0
        drafts = row.get("drafts_made", 0)
        esc_rate = round((row.get("escalations_created", 0) / drafts) * 100) if drafts else 0
        avg_conf = round((row["confidence_sum"] / row["confidence_count"]) * 100) if row.get("confidence_count") else 0
        out.append({
            "date": k,
            "replies_total": total,
            "replies_auto": row.get("replies_auto", 0),
            "replies_manual": row.get("replies_manual", 0),
            "replies_edited": row.get("replies_edited", 0),
            "replies_dashboard": row.get("replies_dashboard", 0),
            "drafts_made": drafts,
            "escalations_created": row.get("escalations_created", 0),
            "escalations_resolved": row.get("escalations_resolved", 0),
            "auto_rate": auto_rate,         # % of replies that auto-sent
            "edit_rate": edit_rate,         # % of human-touched replies that needed editing
            "escalation_rate": esc_rate,    # % of drafts that escalated
            "avg_confidence": avg_conf,     # avg confidence across drafts that day
            "apartments_touched": len(row.get("apartments_touched", [])),
            "topics": row.get("topics", {}),
        })
    return _json({"days": out})

async def _api_learning_today(request):
    """Return today's learning events grouped by apartment so the page can show
    'what changed today' instead of just the static summary text."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    try:
        window_days = int(request.query.get("days", "1"))
    except Exception:
        window_days = 1
    window_days = max(1, min(30, window_days))
    cutoff = datetime.now(TZ) - timedelta(days=window_days)
    cutoff_iso = cutoff.isoformat(timespec="seconds")
    by_apt = defaultdict(list)
    for e in reversed(_learning_log):
        ts = e.get("ts", "")
        if ts < cutoff_iso:
            break
        unit = e.get("unit") or "—"
        by_apt[unit].append({
            "ts": ts, "via": e.get("via", ""),
            "guest_question": (e.get("guest_question") or "")[:240],
            "final_reply": (e.get("final_reply") or "")[:240],
            "was_edited": e.get("was_edited", False),
            "diff_ratio": e.get("diff_ratio", 0),
        })
    items = sorted([{"unit": u, "count": len(es), "events": es} for u, es in by_apt.items()],
                   key=lambda x: -x["count"])
    return _json({"window_days": window_days, "apartments": items,
                  "total_events": sum(x["count"] for x in items)})

async def _api_learning_edit(request):
    """POST {scope:'apartment'|'general', lid?, summary} — directly overwrite
    a distilled summary. Useful when the owner wants to add a fact the bot
    hasn't learned yet, or fix something the distiller got wrong. The edited
    summary sticks until the next distill — which only fires when there are
    new examples — so an edit is effectively permanent unless real new traffic
    overwrites it."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    scope = (b.get("scope") or "").strip()
    summary = (b.get("summary") or "").strip()
    if scope == "general":
        _general_learnings["summary"] = summary
        _general_learnings["last_distilled"] = time.time()
        if not _general_learnings.get("examples_count"):
            _general_learnings["examples_count"] = 1   # mark as set
        log_event("guest", "تعديل يدوي للملخص العام")
        await asyncio.to_thread(persist_state)
        return _json({"ok": True})
    if scope == "apartment":
        try:
            lid = int(b.get("lid"))
        except Exception:
            return _json({"error": "bad lid"}, 400)
        existing = _apartment_learnings.get(lid) or {}
        unit_name = existing.get("unit") or next(
            (u["name"] for u in _catalog_units if u.get("id") == lid), str(lid))
        _apartment_learnings[lid] = {
            "summary": summary,
            "last_distilled": time.time(),
            "examples_count": existing.get("examples_count") or 1,
            "unit": unit_name,
        }
        log_event("guest", f"تعديل يدوي لملخص {unit_name}")
        await asyncio.to_thread(persist_state)
        return _json({"ok": True})
    return _json({"error": "scope must be apartment|general"}, 400)

# ============== MUSAED SHOWCASE (أفضل محادثات مساعد) ==============
# Pulls recent Hostaway conversations, finds the messages MUSAED actually authored
# (he signs every guest-facing message), then surfaces the best real example of three
# kinds: (1) he suggested other apartments, (2) a long thread with no escalation,
# (3) a thread he correctly escalated. Rendered as a standalone, screenshot-friendly
# page so the owner can show real proof in an ad. Read-only; touches no bot logic.
_showcase_cache = {"ts": 0, "data": None}

# Markers that prove an OUTBOUND message came from Musaed (he always signs).
_MSC_SIG = ["مساعد", "Musaid", "الدعم الفني", "Technical Support"]
_MSC_ESC_PHRASE = "رفعنا موضوعك للقسم المختص"
# Verbs/phrases that signal "I'm recommending another unit / option".
_MSC_SUGGEST = ["أرشح", "ارشح", "نرشح", "نرشّح", "أرشّح", "ترشيح", "نقترح", "أقترح",
                "اقترح", "ننقلك", "بديل", "خيار ثاني", "خيار آخر", "وحدة ثانية",
                "شقة ثانية", "شقة أخرى", "وحدة أخرى", "أنسب لك", "متوفر لدينا",
                "عندنا وحدة", "عندنا شقة", "نوفر لك"]
_MSC_THANKS = ["شكرا", "شكراً", "تسلم", "يعطيك العافية", "مشكور", "الله يعطيك",
               "ممتاز", "كفو", "🙏", "🤍", "thank", "thanks", "appreciate"]

def _msc_is_musaed(body):
    b = body or ""
    return any(s in b for s in _MSC_SIG)

def _analyze_musaed_showcase(limit_conversations=120):
    """Walk recent conversations, classify each, and return the best example per bucket."""
    listings = get_listings_map()
    esc_cids = {str(e.get("conversation_id")) for e in _escalations.values()
                if e.get("conversation_id")}
    # --- pull recent conversations (paginated) ---
    convos, offset, page = [], 0, 100
    while len(convos) < limit_conversations:
        try:
            data = api_get("/conversations",
                           params={"limit": page, "offset": offset, "includeResources": 1})
        except Exception as e:
            print(f"showcase: /conversations error at {offset}: {e}")
            break
        batch = data.get("result", []) or []
        if not batch:
            break
        convos.extend(batch)
        if len(batch) < page:
            break
        offset += page
    convos = convos[:limit_conversations]

    # other-unit name tokens (distinctive part after the "|")
    name_tokens = {}
    for lid, nm in listings.items():
        tail = (nm or "").split("|")[-1].strip()
        toks = [t for t in tail.replace("-", " ").split() if len(t) >= 4]
        name_tokens[lid] = toks

    records = []
    for c in convos:
        cid = c.get("id")
        lid = c.get("listingMapId")
        if not cid:
            continue
        try:
            md = api_get(f"/conversations/{cid}/messages")
            msgs = sorted(md.get("result", []) or [], key=_msg_sort_key)
        except Exception:
            continue
        if len(msgs) < 3:
            continue
        thread, musaed_answers, escalated, suggests = [], 0, False, 0
        for m in msgs:
            body = (m.get("body") or "").strip()
            if not body:
                continue
            inb = _msg_is_inbound(m)
            is_m = (not inb) and _msc_is_musaed(body)
            if (not inb) and (not _looks_automated(body)) and is_m:
                musaed_answers += 1
            if (not inb) and (_MSC_ESC_PHRASE in body):
                escalated = True
            if (not inb):
                if any(k in body for k in _MSC_SUGGEST):
                    suggests += 2
                for olid, toks in name_tokens.items():
                    if olid == lid:
                        continue
                    if any(t in body for t in toks):
                        suggests += 1
                        break
            thread.append({"inb": inb, "musaed": is_m, "body": body[:1200],
                           "auto": _looks_automated(body),
                           "t": _msg_time(m)[:16].replace("T", " ")})
        if str(cid) in esc_cids:
            escalated = True
        if musaed_answers == 0:                       # only showcase genuine Musaed work
            continue
        tail = " ".join(x["body"] for x in thread[-3:])
        gratitude = any(k in tail.lower() for k in _MSC_THANKS)
        records.append({
            "cid": cid, "guest": c.get("recipientName") or c.get("guestName") or "ضيف",
            "unit": listings.get(lid) or c.get("listingName") or "—",
            "n": len(thread), "musaed_answers": musaed_answers,
            "escalated": escalated, "suggests": suggests, "gratitude": gratitude,
            "thread": thread,
        })

    def best(cands, keyfn):
        cands = list(cands)
        return max(cands, key=keyfn) if cands else None

    pick_suggest = best((r for r in records if r["suggests"] > 0),
                        lambda r: (r["suggests"], r["musaed_answers"], r["gratitude"], r["n"]))
    pick_long = best((r for r in records if not r["escalated"] and r["musaed_answers"] >= 2),
                     lambda r: (r["n"], r["musaed_answers"], r["gratitude"]))
    pick_esc = best((r for r in records if r["escalated"] and r["musaed_answers"] >= 1),
                    lambda r: (r["musaed_answers"], r["n"]))
    # avoid showing the same conversation twice
    used = set()
    out = []
    for tag, title, sub, rec in [
        ("suggest", "🏘️ يرشّح شقق ثانية", "بدل ما يصعّد — يقترح وحدة مناسبة للضيف", pick_suggest),
        ("long", "💬 محادثة طويلة بدون تصعيد", "جاوب على كل شي بنفسه من البداية للنهاية", pick_long),
        ("escalate", "🚨 محادثة بتصعيد", "تعامل بأدب ثم رفعها للفريق بالوقت الصح", pick_esc),
    ]:
        if rec and rec["cid"] not in used:
            used.add(rec["cid"])
            out.append({"tag": tag, "title": title, "sub": sub, "rec": rec})
    return {"scanned": len(convos), "candidates": len(records), "buckets": out}

def _msc_esc(s):
    return _html.escape(str(s or ""))

