# WhatsApp concierge number for /elite (digits, intl e.g. 9665XXXXXXXX). Falls back to
# STAY_WHATSAPP; if BOTH empty the booking button renders a graceful disabled state (no dead link).
ELITE_WHATSAPP = re.sub(r"\D", "", os.environ.get("ELITE_WHATSAPP", "") or "") or STAY_WHATSAPP

# WebP image proxy for /elite — re-encodes Hostaway photos on the fly (+ disk cache).
# FAIL-SAFE by design: any error or unknown host -> 302 redirect to the original URL,
# so images NEVER break. Disabled automatically if Pillow is missing.
try:
    from PIL import Image as _PILImage
    _ELITE_PIL = True
except Exception:
    _ELITE_PIL = False
ELITE_IMG_PROXY = (os.environ.get("ELITE_IMG_PROXY", "1") != "0") and _ELITE_PIL
_ELITE_IMG_HOSTS = ("hostaway", "amazonaws", "cloudfront", "googleusercontent", "akamaized", "cloudinary", "imgix")

def _elite_render(route="home", listing=None, base=""):
    title = "عوجا إيليت · إقامات مختارة في الرياض"
    desc = "عضوية عوجا إيليت — إقامات منتقاة في الرياض، كونسيرج خاص، وحجز مباشر عبر واتساب."
    og = ""
    path = {"home": "/elite", "search": "/elite/search", "listing": "/elite"}.get(route, "/elite")
    if listing:
        title = (listing.get("name_ar") or title) + " · عوجا إيليت"
        desc = (listing.get("short_ar") or listing.get("desc_ar") or desc)[:160]
        og = listing.get("cover") or ""
        path = "/elite/" + (listing.get("slug") or str(listing.get("id")))
    vis = _gw_visible_snaps()
    hcfg = _gw_hero_resolve()
    if not listing and hcfg.get("url"):
        og = og or hcfg["url"]
    data = {"route": route, "listing": listing,
            "config": {"noo": _gw_noo_options(), "count": len(vis),
                       "hero": (hcfg.get("url") or ""), "video": (os.environ.get("ELITE_HERO_VIDEO", "") or ""), "imgproxy": ELITE_IMG_PROXY, "whatsapp": ELITE_WHATSAPP,
                       "neighborhoods": _gw_neighborhoods_with_counts()}}
    blob = json.dumps(data, ensure_ascii=False).replace("</", "<\\/")
    # SEO/share JSON-LD — Apartment per unit, LodgingBusiness on the landing.
    if listing:
        ld = {"@context": "https://schema.org", "@type": "Apartment",
              "name": listing.get("name_ar") or listing.get("name_en") or "",
              "description": desc, "url": (base or "") + path,
              "numberOfRooms": listing.get("beds"),
              "occupancy": {"@type": "QuantitativeValue", "maxValue": listing.get("capacity")},
              "address": {"@type": "PostalAddress", "addressLocality": "Riyadh",
                          "addressRegion": (listing.get("area") or "Riyadh"), "addressCountry": "SA"}}
        if listing.get("cover"):
            ld["image"] = listing["cover"]
        ld = {k: v for k, v in ld.items() if v not in (None, "", {})}
    else:
        ld = {"@context": "https://schema.org", "@type": "LodgingBusiness",
              "name": "Ouja Elite · عوجا إيليت",
              "description": desc, "url": (base or "") + "/elite",
              "address": {"@type": "PostalAddress", "addressLocality": "Riyadh", "addressCountry": "SA"}}
        if hcfg.get("url"):
            ld["image"] = hcfg["url"]
    ld_blob = json.dumps(ld, ensure_ascii=False).replace("</", "<\\/")
    return (ELITE_HTML
            .replace("/*__ELITE_DATA__*/null", blob)
            .replace("/*__ELITE_JSONLD__*/null", ld_blob)
            .replace("__ELITE_TITLE__", _gw_he(title))
            .replace("__ELITE_DESC__", _gw_he(desc))
            .replace("__ELITE_OG__", _gw_he(og))
            .replace("__ELITE_URL__", _gw_he((base or "") + path)))

# ---- Ouja Elite public routes (NO dashboard token); reuse /api/stay/* endpoints ----
async def _handle_elite(request):
    return web.Response(text=_elite_render("home", base=str(request.url.origin())), content_type="text/html")

async def _handle_elite_search(request):
    return web.Response(text=_elite_render("search", base=str(request.url.origin())), content_type="text/html")

async def _handle_elite_id(request):
    lid = request.match_info.get("lid", "")
    snap, ov = _gw_find_by_slug_or_id(lid)
    if snap:
        slug = _gw_slug(snap, ov)
        q = ("?" + request.query_string) if request.query_string else ""
        raise web.HTTPFound("/elite/" + slug + q)
    return web.Response(text=_elite_render("listing", base=str(request.url.origin())), content_type="text/html")

async def _handle_elite_detail(request):
    token = request.match_info.get("slug", "")
    snap, ov = _gw_find_by_slug_or_id(token)
    listing = _gw_listing_public(snap, ov, with_airbnb=False) if snap else None   # with_airbnb=False — Elite never shows Airbnb
    return web.Response(text=_elite_render("listing", listing, base=str(request.url.origin())), content_type="text/html")


async def _handle_elite_img(request):
    """On-the-fly WebP proxy for /elite photos. Fail-safe: any problem -> 302 to the original URL."""
    u = request.query.get("u", "") or ""
    try:
        w = int(request.query.get("w", "0") or 0)
    except Exception:
        w = 0
    if not u.lower().startswith(("http://", "https://")):
        raise web.HTTPNotFound()
    if (not ELITE_IMG_PROXY) or (not any(h in u.lower() for h in _ELITE_IMG_HOSTS)):
        raise web.HTTPFound(u)                                  # disabled / unknown host -> original
    headers = {"Cache-Control": "public, max-age=31536000, immutable"}
    key = hashlib.sha1((u + "|" + str(w)).encode("utf-8")).hexdigest() + ".webp"
    cpath = None
    try:
        base = _state_path("elite_imgcache"); os.makedirs(base, exist_ok=True)
        cpath = os.path.join(base, key)
        if os.path.isfile(cpath) and os.path.getsize(cpath) > 0:
            with open(cpath, "rb") as f:
                return web.Response(body=f.read(), content_type="image/webp", headers=headers)
    except Exception:
        cpath = None
    def _work():
        r = requests.get(u, timeout=12)
        r.raise_for_status()
        im = _PILImage.open(io.BytesIO(r.content)).convert("RGB")
        if w and im.width > w:
            im = im.resize((w, max(1, int(im.height * (w / float(im.width))))), _PILImage.LANCZOS)
        out = io.BytesIO()
        im.save(out, format="WEBP", quality=82, method=5)
        return out.getvalue()
    try:
        data = await asyncio.get_event_loop().run_in_executor(None, _work)
    except Exception:
        raise web.HTTPFound(u)                                  # transcode/fetch failed -> original
    if cpath:
        try:
            with open(cpath, "wb") as f:
                f.write(data)
        except Exception:
            pass
    return web.Response(body=data, content_type="image/webp", headers=headers)


_ELITE_GEO_URL = "https://oujaguide.netlify.app/data.json"
_elite_geo_cache = {"map": None, "ts": 0.0}

def _elite_geo_norm(s):
    return re.sub(r"[^a-z0-9]+", " ", (s or "").lower()).strip()

def _elite_geo_fetch():
    """Fetch the oujaguide data.json -> {normalized listing_name: (lat,lng)} parsed from each
    record's map_link. Best-effort; {} on any failure. BLOCKING — call via run_in_executor."""
    out = {}
    try:
        r = requests.get(_ELITE_GEO_URL, timeout=12)
        r.raise_for_status()
        for d in (r.json() or []):
            m = re.search(r"(-?\d{2}\.\d+)[, ]+(-?\d{2}\.\d+)", str(d.get("map_link") or ""))
            if not m:
                continue
            lat, lng = float(m.group(1)), float(m.group(2))
            if not (24.0 <= lat <= 25.6 and 46.0 <= lng <= 47.6):
                continue
            nm = _elite_geo_norm(d.get("listing_name"))
            if nm:
                out[nm] = (lat, lng)
    except Exception as e:
        print("oujaguide data.json fetch error:", e)
    return out

def _elite_geo_refresh():
    """Refresh the cached name->coords map if stale (6h TTL). BLOCKING — executor only."""
    now = time.time()
    if _elite_geo_cache["map"] is None or (now - _elite_geo_cache["ts"]) > 21600:
        m = _elite_geo_fetch()
        if m or _elite_geo_cache["map"] is None:
            _elite_geo_cache["map"] = m
            _elite_geo_cache["ts"] = now

def _elite_geo_points():
    """{id: [approx_lat, approx_lng]} for visible Elite listings matched (by name) to the
    oujaguide guide coordinates. APPROXIMATE on purpose: a stable per-listing jitter (~330m)
    + rounding to ~110m, so the public map shows the general area, never the exact building.
    Cache-only (no network here). Returns (points, count, total)."""
    gmap = _elite_geo_cache.get("map") or {}
    pts, total = {}, 0
    for s, ov in _gw_visible_snaps():
        total += 1
        try:
            pub = _gw_listing_public(s, ov, with_airbnb=False)
        except Exception:
            continue
        lid = pub.get("id")
        if lid is None:
            continue
        ll = gmap.get(_elite_geo_norm(pub.get("name_en"))) or gmap.get(_elite_geo_norm(pub.get("name_ar")))
        if not ll:
            continue
        lat, lng = ll
        h = int(hashlib.sha1(str(lid).encode("utf-8")).hexdigest(), 16)
        dlat = ((h % 1000) / 1000.0 - 0.5) * 0.0060            # +/- ~0.003 deg (~330m)
        dlng = (((h // 1000) % 1000) / 1000.0 - 0.5) * 0.0060
        pts[str(lid)] = [round(lat + dlat, 3), round(lng + dlng, 3)]
    return pts, len(pts), total


async def _handle_elite_geo(request):
    """Public — APPROXIMATE per-listing coordinates for the Elite map (never exact)."""
    try:
        await asyncio.get_event_loop().run_in_executor(None, _elite_geo_refresh)
        pts, count, total = _elite_geo_points()
    except Exception as e:
        print("elite geo error:", e)
        pts, count, total = {}, 0, 0
    return web.json_response({"points": pts, "count": count, "total": total})


# ==================== Ouja Monthly (عوجا بالشهر) — /monthly ====================
# A public lead site for MONTHLY apartment stays. Sibling of /stay + /elite: same SPA
# architecture, reuses _gw_cache listings + _gw_overrides (no new Hostaway sync). Guest picks a
# move-in date + number of months; we sum the real Hostaway calendar nightly prices = the "before",
# apply the visible default discount = the "after" (always shown), and tease "up to 30%". The real
# max discount is unlocked only by contacting the team on WhatsApp. WhatsApp-only conversion.
MONTHLY_ENABLED = os.environ.get("MONTHLY_ENABLED", "1") != "0"
# Own WhatsApp number for monthly leads; falls back to the shared STAY_WHATSAPP until set.
MONTHLY_WHATSAPP = re.sub(r"\D", "", os.environ.get("MONTHLY_WHATSAPP", "") or "") or STAY_WHATSAPP
MONTHLY_IMG_PROXY = ELITE_IMG_PROXY                       # reuse the proven /elite WebP proxy machinery

def _monthly_default_cfg():
    """Seed config. Owner-editable later via the admin endpoint / dashboard tab (v2)."""
    try:
        _d = float(os.environ.get("MONTHLY_DISCOUNT_DEFAULT", "0.20"))
    except ValueError:
        _d = 0.20
    try:
        _c = float(os.environ.get("MONTHLY_DISCOUNT_MAX", "0.30"))
    except ValueError:
        _c = 0.30
    return {
        "default_pct": _d, "ceiling_pct": _c,
        "promo": {"on": False, "pct": 0.0, "label_ar": "", "label_en": ""},
        "hidden": [],
        "addons": [
            {"key": "parking", "ar": "موقف خاص", "en": "Private parking",
             "match": ["parking", "garage", "carport", "موقف", "مواقف", "كراج", "كراچ"]},
            {"key": "entry", "ar": "دخول خاص / مستقل", "en": "Private entry",
             "match": ["self check-in", "self check in", "private entrance", "self entry",
                       "separate entrance", "دخول ذاتي", "مدخل خاص", "دخول مستقل", "مدخل مستقل"]},
        ],
    }

def _monthly_cfg_load():
    base = _monthly_default_cfg()
    saved = _load_json("monthly_config.json", None)
    if isinstance(saved, dict):
        for k in ("default_pct", "ceiling_pct"):
            if isinstance(saved.get(k), (int, float)):
                base[k] = float(saved[k])
        if isinstance(saved.get("promo"), dict):
            p = saved["promo"]
            base["promo"] = {"on": bool(p.get("on")),
                             "pct": float(p.get("pct") or 0.0),
                             "label_ar": str(p.get("label_ar") or ""),
                             "label_en": str(p.get("label_en") or "")}
        if isinstance(saved.get("hidden"), list):
            base["hidden"] = [str(x) for x in saved["hidden"]]
        if isinstance(saved.get("addons"), list) and saved["addons"]:
            base["addons"] = saved["addons"]
    return base

_monthly_cfg = _monthly_cfg_load()

def _monthly_cfg_save():
    _save_json("monthly_config.json", _monthly_cfg)

# ---- pure pricing math (unit-tested in tests/test_monthly_pricing.py; no network) ----
def _add_months(d, n):
    """Add n calendar months to date d, clamping the day to the target month's length."""
    import calendar as _cal
    m = d.month - 1 + int(n)
    y = d.year + m // 12
    m = m % 12 + 1
    last = _cal.monthrange(y, m)[1]
    return date(y, m, min(d.day, last))

def monthly_pricing(before_total, months, cfg):
    """Before/after for a whole stay. The VISIBLE discount = max(default, promo-if-on), capped at
    the ceiling. The ceiling itself is only advertised ('up to 30%'), never used as the price."""
    before = int(round(float(before_total or 0)))
    months = max(1, int(months or 1))
    default = float(cfg.get("default_pct") or 0.0)
    ceiling = float(cfg.get("ceiling_pct") or 0.0)
    promo = cfg.get("promo") or {}
    promo_on = bool(promo.get("on"))
    pct = default
    if promo_on:
        pct = max(pct, float(promo.get("pct") or 0.0))
    pct = max(0.0, min(pct, ceiling))
    after = int(round(before * (1.0 - pct)))
    return {
        "before": before, "after": after, "saved": before - after,
        "pct": round(pct, 4), "ceiling": round(ceiling, 4),
        "per_month_before": int(round(before / months)),
        "per_month_after": int(round(after / months)),
        "promo": promo_on and pct >= default and float(promo.get("pct") or 0.0) > default,
        "promo_label": (promo.get("label_ar") or "") if promo_on else "",
    }

def _monthly_hidden_set():
    return set(str(x) for x in (_monthly_cfg.get("hidden") or []))

def _monthly_visible_snaps():
    hid = _monthly_hidden_set()
    return [(s, ov) for (s, ov) in _gw_visible_snaps() if str(s.get("id")) not in hid]

def monthly_quote(listing_id, move_in, months, snap=None):
    """Price a monthly stay. Prefers the real Hostaway calendar sum (the 'before'); falls back to
    price_base * nights (flagged estimated) so before/after ALWAYS render. Returns None on bad
    input or when no price is knowable at all."""
    mi = _parse_date(move_in)
    try:
        months = int(months)
    except (TypeError, ValueError):
        return None
    if not mi or months < 1 or months > 12:
        return None
    mo = _add_months(mi, months)
    nights = (mo - mi).days
    if nights < 1:
        return None
    before, available, estimated = None, None, False
    av = unit_availability_price(listing_id, mi.isoformat(), mo.isoformat())
    if av and av.get("total"):
        before = av["total"]
        available = bool(av.get("available"))
    else:
        pb = (snap or {}).get("price_base")
        try:
            pbf = float(pb) if pb is not None else 0.0
        except (TypeError, ValueError):
            pbf = 0.0
        if pbf > 0:
            before = round(pbf * nights)
            estimated = True
            available = (av.get("available") if av else None)
    if before is None:
        return None
    out = monthly_pricing(before, months, _monthly_cfg)
    out.update({"months": months, "nights": nights,
                "move_in": mi.isoformat(), "move_out": mo.isoformat(),
                "available": available, "estimated": estimated})
    return out

def _monthly_addons_for(snap):
    """Per-listing add-on availability + the matching Hostaway amenity text (the 'text from
    Hostaway' the owner wanted). Every add-on is always selectable as a request; in_listing just
    surfaces that the unit already advertises it."""
    amen = [str(a) for a in (snap.get("amenities") or []) if a]
    hay = (" ".join(amen) + " " + str(snap.get("desc") or "") + " "
           + str(snap.get("public_desc") or "")).lower()
    out = []
    for a in (_monthly_cfg.get("addons") or []):
        keys = [str(k).lower() for k in (a.get("match") or [])]
        note = ""
        for am in amen:
            al = am.lower()
            if any(k and k in al for k in keys):
                note = am
                break
        in_listing = bool(note) or any(k and k in hay for k in keys)
        out.append({"key": a.get("key"), "ar": a.get("ar"), "en": a.get("en"),
                    "in_listing": in_listing, "note": note})
    return out

def _monthly_card(snap, ov, move_in=None, months=None):
    """Public listing JSON for /monthly cards + detail, with before/after attached. Without dates
    we show a per-month 'from' before/after off price_base; with dates we attach the full quote."""
    pub = _gw_listing_public(snap, ov, with_airbnb=False)     # WhatsApp-only, like /elite
    pub["addons"] = _monthly_addons_for(snap)
    # always-present per-month estimate (so before/after show even before a date is picked)
    pb = pub.get("price_base")
    try:
        pbf = float(pb) if pb is not None else 0.0
    except (TypeError, ValueError):
        pbf = 0.0
    if pbf > 0:
        est = monthly_pricing(round(pbf * 30), 1, _monthly_cfg)
        pub["m_before"] = est["per_month_before"]
        pub["m_after"] = est["per_month_after"]
        pub["m_pct"] = est["pct"]
    else:
        pub["m_before"] = pub["m_after"] = None
        pub["m_pct"] = monthly_pricing(0, 1, _monthly_cfg)["pct"]
    pub["ceiling"] = monthly_pricing(0, 1, _monthly_cfg)["ceiling"]
    if move_in and months:
        q = monthly_quote(snap.get("id"), move_in, months, snap)
        if q:
            pub["quote"] = q
    return pub

def _monthly_beds_match(snap, beds):
    """beds filter: 'studio'=0, '1','2' exact, '3' = 3 or more. Empty/all = pass."""
    if not beds or beds in ("all", ""):
        return True
    try:
        b = int(snap.get("beds")) if snap.get("beds") is not None else None
    except (TypeError, ValueError):
        b = None
    if b is None:
        return False
    if beds == "studio":
        return b == 0
    try:
        want = int(beds)
    except ValueError:
        return True
    return b >= 3 if want >= 3 else b == want

def _monthly_filter(beds=None, typ=None, area=None, neighborhood=None, tags=None, guests=None):
    """Non-availability filters (no network) — runs before the concurrent calendar pulls."""
    try:
        g = int(guests) if guests else None
    except (TypeError, ValueError):
        g = None
    tag_list = [t for t in ((tags or "").split(",")) if t and t not in ("all",)]
    out = []
    for s, ov in _monthly_visible_snaps():
        if g and s.get("capacity") and int(s["capacity"]) < g:
            continue
        if not _monthly_beds_match(s, beds):
            continue
        if typ and typ not in ("all", "") and typ not in (s.get("tag_keys") or []):
            continue
        if area and area not in ("all", "") and area not in (s.get("tag_keys") or []):
            continue
        if neighborhood and neighborhood not in ("all", "") and ov.get("neighborhood") != neighborhood:
            continue
        if tag_list and not all(t in (s.get("tag_keys") or []) for t in tag_list):
            continue
        out.append((s, ov))
    return out

def _monthly_sort_cards(rows):
    """rows: [(card, ov)] -> [card] in the site's default order."""
    rows.sort(key=lambda t: (-((t[1].get("sort") or 0)),
                             0 if t[0].get("images") else 1, (t[0].get("name_ar") or "")))
    return [r[0] for r in rows]

async def _monthly_search_async(move_in=None, months=None, beds=None, typ=None, area=None,
                                neighborhood=None, tags=None, guests=None):
    """Monthly results. The slow part — one Hostaway calendar pull per unit — now runs CONCURRENTLY
    (semaphore-bounded) instead of serially, and unit_availability_price caches for ~15m, so the
    search returns fast and repeat searches are instant. Browse mode (no dates) does zero network."""
    snaps = await asyncio.to_thread(_monthly_filter, beds, typ, area, neighborhood, tags, guests)
    if not (move_in and months):
        rows = [(_monthly_card(s, ov), ov) for s, ov in snaps]
        return {"browse": True, "avail_error": False, "results": _monthly_sort_cards(rows)}
    sem = asyncio.Semaphore(8)
    async def one(s, ov):
        async with sem:
            q = await asyncio.to_thread(monthly_quote, s.get("id"), move_in, months, s)
        return (s, ov, q)
    got = await asyncio.gather(*[one(s, ov) for s, ov in snaps])
    rows, avail_error = [], False
    for s, ov, q in got:
        if not q:
            avail_error = True
            continue
        if q.get("available") is False:
            continue
        card = _monthly_card(s, ov)          # cheap: quote already computed, no extra network
        card["quote"] = q
        rows.append((card, ov))
    return {"browse": False, "avail_error": avail_error, "results": _monthly_sort_cards(rows)}

def _monthly_rating_of(snap):
    """(rating, reviews_count) for a snap, (0.0, 0) when unknown."""
    try:
        rt = _gw_ratings_map().get(int(snap.get("id")))
    except (TypeError, ValueError):
        rt = None
    if rt:
        try:
            return (float(rt.get("rating") or 0), int(rt.get("count") or 0))
        except (TypeError, ValueError):
            return (0.0, 0)
    return (0.0, 0)

def _monthly_hero_url():
    """Landing cover photo. Owner pick: the '101 QUR' apartment's photo; falls back to the shared
    /stay hero, then any visible cover, so the hero is never blank."""
    snaps = _monthly_visible_snaps()
    for s, ov in snaps:
        nm = ((s.get("name") or "") + " " + (s.get("internal") or "")).lower()
        if "101" in nm and "qur" in nm:
            c = (ov.get("hero_image") or s.get("cover") or "")
            if c:
                return c
    h = _gw_hero_resolve()
    if h.get("url"):
        return h["url"]
    for s, ov in snaps:
        c = (ov.get("hero_image") or s.get("cover") or "")
        if c:
            return c
    return ""

def _monthly_featured(limit=6):
    """Featured strip = the highest-rated apartments we have (owner request)."""
    rows = []
    for s, ov in _monthly_visible_snaps():
        r, n = _monthly_rating_of(s)
        rows.append((-r, -n, 0 if ov.get("featured") else 1, (s.get("name") or ""), s, ov))
    rows.sort(key=lambda x: x[:4])
    return {"results": [_monthly_card(s, ov) for (_a, _b, _c, _d, s, ov) in rows[:limit]], "auto": True}

# ---- underperformer "deals" engine: apartments with moderate occupancy that have room to fill ----
_monthly_deals_cache = {"data": None, "ts": 0.0}

def _monthly_booked_nights(listing_id, start, end):
    """Reserved nights in [start,end) from the Hostaway calendar. A night counts as booked ONLY if
    it carries a reservationId — so Airbnb/manual BLOCKS (unavailable, no reservation) are NOT
    counted as bookings. Returns (booked, blocked, days) or None on error."""
    try:
        data = api_get("/listings/%s/calendar" % listing_id,
                       params={"startDate": start, "endDate": end})
        days = data.get("result", []) or []
    except Exception:
        return None
    booked = blocked = 0
    for d in days:
        if int(d.get("isAvailable", 1) or 0) == 1:
            continue
        if d.get("reservationId") or d.get("reservation_id"):
            booked += 1
        else:
            blocked += 1
    return (booked, blocked, len(days))

async def _monthly_deals_async(limit=6, ttl=10800):
    """Apartments with 5-15 reserved nights in the next ~30 days = underperforming but in demand:
    proven bookings, yet half-empty, so a monthly tenant is the best fill. Excludes dead/blocked
    units (<5 reserved, which is where Airbnb-blocked + no-booking units land) and healthy units
    (>15). Concurrent calendar pulls (semaphore-bounded) + 3h cache so it never slows the page."""
    c = _monthly_deals_cache
    if c["data"] is not None and (time.time() - c["ts"]) < ttl:
        return c["data"]
    today = datetime.now(TZ).date()
    start, end = today.isoformat(), _add_months(today, 1).isoformat()
    snaps = _monthly_visible_snaps()
    sem = asyncio.Semaphore(8)
    async def one(s, ov):
        async with sem:
            r = await asyncio.to_thread(_monthly_booked_nights, s.get("id"), start, end)
        if not r:
            return None
        booked, _blocked, _days = r
        if 5 <= booked <= 15:
            return (s, ov, booked)
        return None
    rows = [x for x in await asyncio.gather(*[one(s, ov) for s, ov in snaps]) if x]
    rows.sort(key=lambda t: (-_monthly_rating_of(t[0])[0], -_monthly_rating_of(t[0])[1]))
    out = []
    for s, ov, booked in rows[:limit]:
        card = _monthly_card(s, ov)
        card["deal"] = True
        card["deal_booked"] = booked
        out.append(card)
    res = {"results": out}
    c["data"], c["ts"] = res, time.time()
    return res

def _monthly_cfg_public():
    c = _monthly_cfg
    return {"default_pct": c.get("default_pct"), "ceiling_pct": c.get("ceiling_pct"),
            "promo": {"on": bool((c.get("promo") or {}).get("on")),
                      "pct": (c.get("promo") or {}).get("pct") or 0.0,
                      "label_ar": (c.get("promo") or {}).get("label_ar") or "",
                      "label_en": (c.get("promo") or {}).get("label_en") or ""},
            "addons": [{"key": a.get("key"), "ar": a.get("ar"), "en": a.get("en")}
                       for a in (c.get("addons") or [])],
            "count": len(_monthly_visible_snaps())}


