async def _api_monthly_admin(request):
    """Token-gated config control (dashboard Manage tab is v2; this is the API behind it)."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    if request.method == "GET":
        listings = [{"id": s.get("id"), "name": s.get("name"),
                     "hidden": str(s.get("id")) in _monthly_hidden_set()}
                    for s in (_gw_cache.get("listings") or [])]
        listings.sort(key=lambda x: (x["name"] or ""))
        return _json({"ok": True, "config": _monthly_cfg, "listings": listings})
    b = await _read_body(request)
    if isinstance(b.get("default_pct"), (int, float)):
        _monthly_cfg["default_pct"] = max(0.0, min(float(b["default_pct"]), 0.95))
    if isinstance(b.get("ceiling_pct"), (int, float)):
        _monthly_cfg["ceiling_pct"] = max(0.0, min(float(b["ceiling_pct"]), 0.95))
    if isinstance(b.get("promo"), dict):
        p = b["promo"]
        _monthly_cfg["promo"] = {"on": bool(p.get("on")), "pct": max(0.0, min(float(p.get("pct") or 0.0), 0.95)),
                                 "label_ar": str(p.get("label_ar") or "")[:80],
                                 "label_en": str(p.get("label_en") or "")[:80]}
    if isinstance(b.get("hidden"), list):
        _monthly_cfg["hidden"] = [str(x) for x in b["hidden"]]
    if isinstance(b.get("addons"), list) and b["addons"]:
        _monthly_cfg["addons"] = b["addons"]
    _monthly_cfg_save()
    return _json({"ok": True, "config": _monthly_cfg})


async def _api_gw_hero(request):
    """Dashboard hero control. GET → config + resolved + listings-with-images for the chooser. POST → save/reset."""
    if request.method == "GET":
        if not _dash_auth(request):
            return _json({"error": "unauthorized"}, 401)
        ls = []
        for s in (_gw_cache.get("listings") or []):
            imgs = [im["url"] for im in (s.get("images") or []) if im.get("url")]
            if imgs:
                ls.append({"id": s.get("id"), "name": s.get("name"), "images": imgs[:24]})
        return _json({"ok": True, "hero": _gw_hero, "resolved": _gw_hero_resolve(), "listings": ls})
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    b = await _read_body(request)
    if b.get("reset"):
        _gw_hero.clear(); _gw_save_hero()
        return _json({"ok": True, "hero": _gw_hero, "resolved": _gw_hero_resolve()})
    mode = (b.get("mode") or "").strip()
    if mode in ("listing_image", "uploaded_image", "auto_default"):
        _gw_hero["mode"] = mode
    if "listing_id" in b:
        _gw_hero["listing_id"] = str(b.get("listing_id") or "")
    if "image_url" in b:
        _gw_hero["image_url"] = (b.get("image_url") or "").strip()
    if "focal" in b:
        _gw_hero["focal"] = (b.get("focal") if b.get("focal") in _GW_FOCALS else "center")
    for k in ("title", "subtitle", "trust"):
        if k in b:
            _gw_hero[k] = (b.get(k) or "").strip()[:160]
    if "overlay" in b:
        try:
            _gw_hero["overlay"] = max(20, min(95, int(b.get("overlay"))))
        except (TypeError, ValueError):
            pass
    _gw_hero["updated_at"] = datetime.now(TZ).isoformat(timespec="seconds")
    _gw_save_hero()
    return _json({"ok": True, "hero": _gw_hero, "resolved": _gw_hero_resolve()})

async def _api_gw_hero_upload(request):
    """Upload a custom hero image (JPG/PNG/WebP ≤6MB) → STATE_DIR, served by /stay/hero-image. Local only."""
    if not _dash_auth(request):
        return _json({"error": "unauthorized"}, 401)
    try:
        data, fname, _fields = await _fb_read_upload(request)
    except ValueError as e:
        return _json({"error": str(e)}, 400)
    except Exception:
        return _json({"error": "upload_failed"}, 400)
    if not data:
        return _json({"error": "no_file"}, 400)
    if len(data) > 6 * 1024 * 1024:
        return _json({"error": "too_large", "error_ar": "الصورة كبيرة (الحد ٦MB)"}, 400)
    fl = (fname or "").lower()
    ext, ct = None, None
    if data[:3] == b"\xff\xd8\xff" or fl.endswith((".jpg", ".jpeg")):
        ext, ct = "jpg", "image/jpeg"
    elif data[:8].startswith(b"\x89PNG") or fl.endswith(".png"):
        ext, ct = "png", "image/png"
    elif (data[:4] == b"RIFF" and data[8:12] == b"WEBP") or fl.endswith(".webp"):
        ext, ct = "webp", "image/webp"
    if not ext:
        return _json({"error": "bad_type", "error_ar": "نوع غير مدعوم (JPG/PNG/WebP)"}, 400)
    try:
        with open(_state_path("gw_hero." + ext), "wb") as f:
            f.write(data)
    except Exception:
        return _json({"error": "write_failed"}, 500)
    _gw_hero["mode"] = "uploaded_image"; _gw_hero["upload_path"] = "gw_hero." + ext
    _gw_hero["upload_ct"] = ct; _gw_hero["updated_at"] = datetime.now(TZ).isoformat(timespec="seconds")
    _gw_save_hero()
    return _json({"ok": True, "hero": _gw_hero, "resolved": _gw_hero_resolve()})

