@tasks.loop(hours=24)
async def reviews_refresh_loop():
    """Pull new Airbnb/Booking reviews from Hostaway once a day and merge them in,
    so the Reviews page keeps growing automatically without anyone clicking."""
    try:
        n = await asyncio.to_thread(refresh_reviews)
        await asyncio.to_thread(persist_state)
        print(f"reviews: daily refresh pulled {n} from Hostaway — total {len(_reviews)}")
    except Exception as e:
        print("reviews_refresh_loop error:", e)
    try:
        _oujact_prune_done()    # daily safety net even when Discord sweeps don't run
        _oujact_prune_opened()
    except Exception as e:
        print("oujact done-prune error:", e)
    # Reclaim old local cleaning photos so the volume can't slowly fill (the 2026-06-23 bug).
    try:
        await asyncio.to_thread(_cleanproof_purge_local_photos)
    except Exception as e:
        print("cleaning-photo purge error:", e)
    # C-2: daily DP-drift count → Discord (evidence for the DP cutover decision).
    try:
        day_ago = (datetime.now(TZ) - timedelta(hours=24)).isoformat(timespec="seconds")
        todays = [h for h in _dp_drift_hits if (h.get("detected_at") or "") >= day_ago]
        if todays:
            names = (await get_listings_map_async()) or {}
            lines = "، ".join(f"{names.get(h['lid'], h['lid'])} {h['date']} ({h['ours']}→{h['live']})"
                              for h in todays[:6])
            await _post_system_escalation(
                f"📊 Hostaway DP عدّل {len(todays)} ليلة طبّقناها",
                f"خلال ٢٤ ساعة، أسعار كتبناها وتأكدنا منها تغيّرت بدون حجز وبدون كتابة منا: {lines}"
                + (" …" if len(todays) > 6 else ""), severity="med")
            log_event("pricing", f"DP drift · {len(todays)} ليلة تعدّلت من Hostaway DP خلال ٢٤ ساعة")
    except Exception as e:
        print("dp drift daily error:", e)
    # C-1: nightly Price DNA rebuild — background, never page-load.
    try:
        await asyncio.to_thread(_dna_get, True)
    except Exception as e:
        print("dna nightly error:", e)
    # B.3: nightly inquiry-mining refresh (like Price DNA) — background, never page-load.
    try:
        gen = _parse_date(str(_inquiry_mining.get("generated_at") or "")[:10])
        stale = (gen is None) or ((datetime.now(TZ).date() - gen).days >= 1)
        if stale and not _inquiry_state["running"]:
            _inquiry_state.update({"running": True, "started": time.time(),
                                   "finished": 0, "error": "", "result": None})
            try:
                _inquiry_state["result"] = await asyncio.to_thread(_inquiry_mine_run, 400)
            except Exception as e:
                _inquiry_state["error"] = str(e)
            finally:
                _inquiry_state["running"] = False
                _inquiry_state["finished"] = time.time()
    except Exception as e:
        print("inquiry nightly error:", e)

@tasks.loop(minutes=REVIEW_AUTOANALYZE_MIN)
async def reviews_autoanalyze_loop():
    """Quietly analyze a small batch of any not-yet-analyzed reviews each cycle
    (negatives first), so new reviews get their removability + AAA reply ready
    automatically. Skips while a manual 'analyze everything' job is running."""
    if not REVIEW_AUTOANALYZE_ENABLED or not ANTHROPIC_API_KEY:
        return
    if _review_bulk_job.get("running"):
        return
    try:
        targets = await asyncio.to_thread(_review_analyze_targets)
        if not targets:
            return
        batch = targets[:max(1, REVIEW_AUTOANALYZE_BATCH)]

        def _work():
            n = 0
            for rid, rev in batch:
                try:
                    out = claude_analyze_review(rev)
                    if out:
                        _review_ai_cache[rid] = out
                        n += 1
                except Exception as e:
                    print(f"autoanalyze {rid} error:", e)
            if n:
                try:
                    persist_state()
                except Exception:
                    pass
            return n

        n = await asyncio.to_thread(_work)
        if n:
            print(f"reviews: auto-analyzed {n} (remaining ~{len(targets) - n})")
    except Exception as e:
        print("reviews_autoanalyze_loop error:", e)

