        _paused_units.clear()
        _paused_units.update(int(x) for x in _load_json("paused_units.json", []) if str(x).strip())
        _dc_anchor_date = _load_json("dc_anchor.json", None) or None
        _tickets.clear()
        for t in (_load_json("tickets.json", []) or []):
            if isinstance(t, dict) and t.get("id"):
                _tickets.append(t)
        _reviews.clear()
        for k, v in (_load_json("reviews.json", {}) or {}).items():
            if isinstance(v, dict):
                _reviews[str(k)] = v
        try:
            _seeded = merge_reviews_seed()
            if _seeded:
                print(f"reviews: merged {_seeded} seed reviews (Airbnb history) — total {len(_reviews)}")
        except Exception as e:
            print("merge_reviews_seed error:", e)
        _review_ai_cache.clear()
        for k, v in (_load_json("review_ai.json", {}) or {}).items():
            if isinstance(v, dict):
                _review_ai_cache[str(k)] = v
        _review_states.clear()
        for k, v in (_load_json("review_states.json", {}) or {}).items():
            if isinstance(v, dict):
                _review_states[str(k)] = v
        _review_translations.clear()
        for k, v in (_load_json("review_translations.json", {}) or {}).items():
            if isinstance(v, dict):
                _review_translations[str(k)] = v
        _users.clear()
        for k, v in (_load_json("users.json", {}) or {}).items():
            if isinstance(v, dict) and v.get("id"):
                _users[str(k)] = v
        # Sessions survive a redeploy (pruned by TTL on load + on every save).
        _sessions.clear()
