# ---- nudge loop: ping the current holder every N hours inside the windows ----
async def _proc_run_reminders():
    now = datetime.now(TZ)
    if not _proc_in_window(now):
        return
    guild = bot.get_guild(GUILD_ID)
    if guild is None:
        return
    every = timedelta(hours=PROC_PING_EVERY_HOURS)
    for cid, rec in list(_dtk["tickets"].items()):
        if not isinstance(rec, dict) or rec.get("kind") != "proc":
            continue
        status = rec.get("status")
        if status in (None, "closed"):
            continue
        ref = rec.get("last_nudge_at") or rec.get("stage_at") or rec.get("created_at")
        try:
            ref_dt = datetime.fromisoformat(ref) if ref else None
        except Exception:
            ref_dt = None
        if ref_dt is not None:
            if ref_dt.tzinfo is None:
                ref_dt = ref_dt.replace(tzinfo=TZ)
            if (now - ref_dt) < every:
                continue
        ch = guild.get_channel(int(cid))
        if ch is None:
            continue
        try:
            n = int(rec.get("nudges") or 0)
            holder = _proc_holder_mention(rec, status)
            slbl = _proc_status_meta(status)[0]
            seq = int(rec.get("seq") or 0)
            if n >= PROC_REMINDER_MAX:
                esc = f"<@&{PROC_ESCALATE_ROLE_ID}> " if PROC_ESCALATE_ROLE_ID else ""
                if not rec.get("escalated"):
                    rec["escalated"] = True
                    _dtk_save()
                    try:
                        if rec.get("card_msg_id"):
                            m = await ch.fetch_message(rec["card_msg_id"])
                            await m.edit(embed=_proc_card(rec))
                    except Exception as e:
                        print("proc escalate card error:", e)
                await ch.send(
                    f"🚨 {esc}**تذكرة مشتريات متأخرة #{seq:03d}** — {holder} تجاوزت عدد التنبيهات. الحالة: {slbl}",
                    allowed_mentions=discord.AllowedMentions(users=True, roles=True))
            else:
                await ch.send(
                    f"⏰ {holder} — تذكير: {_PROC_NUDGE_MSG.get(status, 'التذكرة بانتظار إجراء')} "
                    f"(تذكير {n + 1}/{PROC_REMINDER_MAX})",
                    allowed_mentions=discord.AllowedMentions(users=True, roles=True))
            rec["nudges"] = n + 1
            rec["last_nudge_at"] = now.isoformat(timespec="seconds")
            _dtk_save()
        except Exception as e:
            print(f"proc nudge error ({cid}):", e)

@tasks.loop(minutes=PROC_REMINDER_POLL_MIN)
async def proc_reminder_loop():
    """Every ~20 min: nudge whoever holds each open purchase ticket, but only inside
    PROC_PING_WINDOWS and at most once per PROC_PING_EVERY_HOURS per ticket."""
    try:
        await _proc_run_reminders()
    except Exception as e:
        print("proc_reminder_loop error:", e)

@bot.command(name="مشتريات-بحث", aliases=["proc-search", "مشتريات-البحث"])
async def proc_search_cmd(ctx, *, query: str = ""):
    """Search the purchase-ticket archive by last-4 / amount / vendor (admins only).
       !ouja مشتريات-بحث 4827        → by quote last-4
       !ouja مشتريات-بحث الركن        → by vendor name
       !ouja مشتريات-بحث 4500         → by amount
    Answers "did we already receive/pay this invoice?" in one command."""
    if not _tk_is_admin(ctx.author):
        await ctx.reply("هذا الأمر للإدارة فقط 🙏")
        return
    q = (query or "").strip()
    if not q:
        await ctx.reply("اكتب وش تبي تدوّر: آخر 4 من عرض السعر، أو المبلغ، أو اسم المورّد.\n"
                        "مثال: `!ouja مشتريات-بحث 4827`")
        return
    qn = q.lower()
    qdigits = re.sub(r"\D", "", q.translate(_AR_DIGIT_MAP))
    qnum = _tk_num(q)
    hits = []
    for cid, rec in _dtk["tickets"].items():
        if not isinstance(rec, dict) or rec.get("kind") != "proc":
            continue
        last4 = str(rec.get("last4") or "")
        vendor = (rec.get("vendor") or "").lower()
        items = (rec.get("items") or "").lower()
        amt = _tk_num(rec.get("amount_raw"))
        match = ((qn and (qn in vendor or qn in items))
                 or (qdigits and qdigits in last4)
                 or (qnum is not None and amt is not None and abs(amt - qnum) < 0.01))
        if match:
            hits.append((cid, rec))
    if not hits:
        await ctx.reply(f"ما لقيت تذاكر مشتريات تطابق «{q}».")
        return
    hits.sort(key=lambda x: int(x[1].get("seq") or 0), reverse=True)
    lines = [f"🔎 **نتائج البحث عن «{q}»** — {len(hits)} تذكرة:"]
    for cid, rec in hits[:20]:
        slbl = _proc_status_meta(rec.get("status") or "open")[0]
        lines.append(f"• #{int(rec.get('seq') or 0):03d} — {rec.get('vendor') or '—'} · "
                     f"عرض …{rec.get('last4') or '—'} · {_proc_amt_txt(rec)} · {slbl} → <#{cid}>")
    if len(hits) > 20:
        lines.append(f"… و{len(hits) - 20} تذكرة ثانية (ضيّق البحث أكثر).")
    out = "\n".join(lines)
    for i in range(0, len(out), 1900):
        await ctx.send(out[i:i + 1900])

# ---------------- panels + admin commands ----------------
async def ensure_ticket_panels(guild):
    """The two «افتح تذكرة» rooms exist under their categories, each holding ONE
    live panel message with the button (re-posted automatically if deleted)."""
    defs = [
        ("maint", MAINT_PANEL_CHANNEL, MaintPanelView(), "🛠️ تذاكر الصيانة",
         "عندك مشكلة بشقة؟ اضغط الزر تحت 👇\n\n"
         "1️⃣ اختر الشقة + الأولوية + التصنيف\n"
         "2️⃣ اكتب ملخص المشكلة وتفاصيلها\n"
         "3️⃣ ينفتح روم خاص بالتذكرة ويتنبّه المسؤول تلقائياً\n\n"
         "وداخل كل تذكرة زر **🔍 فحص الإشغال** يعطيك حالة الشقة لحظتها:\n"
         "ساكنها أحد؟ فيه دخول اليوم أو بكرة؟ منو آخر ضيف طلع؟ ومتى أقرب نافذة شغل آمنة."),
        ("rr", RR_PANEL_CHANNEL, RRPanelView(), "🧾 طلبات التعويض — RR",
         "تلفيات؟ مفقودات؟ نظافة غير طبيعية؟ افتح طلب RR من الزر 👇\n\n"
         "1️⃣ اختر نوع المشكلة والأدلة المتوفرة\n"
         "2️⃣ عبّي التفاصيل **بالعربي** براحتك\n"
         "3️⃣ البوت يجهّز النسخة الإنجليزية الرسمية كاملة لفريق المطالبات،\n"
         "ويجيب بيانات الحجز من Hostaway، ويحسب مهلة الـ 14 يوم حقت AirCover ⏳\n\n"
         "بعد فتح التذكرة ارفعوا الصور والفواتير داخل الروم 📎"),
        ("proc", PROC_PANEL_CHANNEL, ProcPanelView(), "🧾 تذاكر المشتريات",
         "شريت من مورّد؟ سجّل الفاتورة هنا عشان ما تضيع 👇\n\n"
         "1️⃣ اختر الشقة/الشقق وسبب الطلب\n"
         "2️⃣ اكتب آخر 4 من عرض السعر + اسم المورّد + الأصناف + المبلغ\n"
         "3️⃣ ينفتح روم للتذكرة وتمشي بسلسلة الاعتماد:\n"
         "📸 صورة الفاتورة (العمليات) ← ✅ تأكيد قادة العمليات ← 💰 تحويل المحاسبة ← 🔒 إغلاق الإدارة\n\n"
         "وكل تذكرة يذكّر صاحب الدور تلقائياً لين يخلّص — "
         "والبحث `!ouja مشتريات-بحث` يلقّط أي فاتورة قديمة لو وصلت متأخرة."),
    ]
    for kind, ch_name, view, title, desc in defs:
        try:
            cat = await _tk_category(guild, kind)
            meta = _dtk["panels"].get(kind) or {}
            # stored channel id first — survives the panel room being RENAMED
            ch = guild.get_channel(meta.get("channel_id") or 0)
            if ch is None:
                ch = await ensure_channel(guild, ch_name, cat)
            if ch is None:
                continue
            msg = None
            if meta.get("message_id") and meta.get("channel_id") == ch.id:
                try:
                    msg = await ch.fetch_message(meta["message_id"])
                except Exception:
                    msg = None
            if msg is None:
                emb = discord.Embed(title=title, description=desc, color=GOLD)
                msg = await ch.send(embed=emb, view=view)
                try:
                    await msg.pin()
                except Exception:
                    pass
                _dtk["panels"][kind] = {"channel_id": ch.id, "message_id": msg.id}
                _dtk_save()
        except Exception as e:
            print(f"ticket panel setup error ({kind}):", e)

def _tk_is_admin(user):
    p = getattr(user, "guild_permissions", None)
    return bool(p and (p.administrator or p.manage_guild))

async def _tk_resolve_member(guild, raw):
    """(display_name, discord_id) from a mention / raw ID / name. Name lookup uses
    query_members — works WITHOUT the privileged members intent (flipping that
    intent blind would take the live bot down, so we never require it)."""
    raw = str(raw or "").strip()
    m = re.search(r"<@!?(\d+)>", raw) or re.fullmatch(r"(\d{15,21})", raw)
    if m:
        uid = int(m.group(1))
        member = guild.get_member(uid)
        if member is None:
            try:
                member = await guild.fetch_member(uid)
            except Exception:
                member = None
        if member:
            return member.display_name, member.id
        return raw, None
    try:
        found = await guild.query_members(query=raw, limit=5)
    except Exception:
        found = []
    low = raw.lower()
    best = (next((x for x in found
                  if x.display_name.lower() == low or x.name.lower() == low), None)
            or (found[0] if len(found) == 1 else None))
    if best:
        return best.display_name, best.id
    return raw, None

async def _maint_import_assignments(guild, attachment):
    """Excel/CSV bulk import: column A = apartment, column B = employee
    (mention, Discord ID, or display name). Returns the Arabic report text."""
    import io as _io
    try:
        raw = await attachment.read()
    except Exception as e:
        return f"⚠️ ما قدرت أقرأ الملف: {e}"
    fname = (attachment.filename or "").lower()
    rows = []
    try:
        if fname.endswith((".xlsx", ".xlsm")):
            import openpyxl
            wb = openpyxl.load_workbook(_io.BytesIO(raw), data_only=True)
            ws = wb.worksheets[0]
            for r in ws.iter_rows(values_only=True):
                if r and len(r) >= 2 and (r[0] is not None or r[1] is not None):
                    rows.append((str(r[0] or "").strip(), str(r[1] or "").strip()))
        else:
            text = raw.decode("utf-8-sig", errors="replace")
            sample = [l for l in text.splitlines() if l.strip()][:5]
            delim = max([",", ";", "\t"],
                        key=lambda d: sum(len(l.split(d)) >= 2 for l in sample)) if sample else ","
            for line in text.splitlines():
                parts = [p.strip().strip('"') for p in line.split(delim)]
                if len(parts) >= 2:
                    rows.append((parts[0], parts[1]))
    except Exception as e:
        return f"⚠️ ما قدرت أفك الملف ({attachment.filename}): {e}"
    linked, unmatched_apt, unresolved_emp = 0, [], []
    header_words = ("الشقة", "شقة", "الوحدة", "apartment", "unit", "listing")
    for apt_raw, emp_raw in rows:
        if not apt_raw or not emp_raw:
            continue
        matches = _tk_find_listings(apt_raw)
        if len(matches) != 1:
            if _tk_norm_name(apt_raw) not in (_tk_norm_name(w) for w in header_words):
                unmatched_apt.append(apt_raw)
            continue
        lid, nm = matches[0]
        name, did = await _tk_resolve_member(guild, emp_raw)
        _maint_assign["by_lid"][str(lid)] = {"name": name or emp_raw, "discord_id": did}
        linked += 1
        if not did:
            unresolved_emp.append(f"{emp_raw} ({nm})")
    _maint_assign_save()
    out = [f"✅ ربطت **{linked}** شقة بمسؤوليها."]
    if unresolved_emp:
        out.append(f"⚠️ {len(unresolved_emp)} اسم ما لقيت حسابه بديسكورد "
                   "(انحفظ كاسم بس — بدون منشن تلقائي):\n"
                   + "\n".join("• " + x for x in unresolved_emp[:10]))
    if unmatched_apt:
        out.append(f"⚠️ {len(unmatched_apt)} سطر ما عرفت أي شقة يقصد:\n"
                   + "\n".join("• " + x for x in unmatched_apt[:10]))
    return "\n".join(out)

@bot.command(name="تذاكر-تجهيز", aliases=["tickets-setup"])
async def tickets_setup_cmd(ctx):
    """Re-create the two ticket panels (auto-runs on boot too)."""
    if not _tk_is_admin(ctx.author):
        await ctx.reply("هذا الأمر للإدارة فقط 🙏")
        return
    await ensure_ticket_panels(ctx.guild)
    await ctx.reply("✅ رومات فتح التذاكر جاهزة (صيانة + RR).")

@bot.command(name="صيانة-تعيينات", aliases=["maint-assign", "صيانه-تعيينات"])
async def maint_assign_cmd(ctx, *, args: str = ""):
    """apartment→responsible map: show / set one / set default / bulk Excel import.
      !ouja صيانة-تعيينات                      → show the map
      !ouja صيانة-تعيينات @user نخلة 23        → link one apartment
      !ouja صيانة-تعيينات @user افتراضي        → fallback assignee for unmapped units
      (attach the Excel/CSV with the command)  → bulk import
    """
    if not _tk_is_admin(ctx.author):
        await ctx.reply("هذا الأمر للإدارة فقط 🙏")
        return
    if ctx.message.attachments:
        report = await _maint_import_assignments(ctx.guild, ctx.message.attachments[0])
        await ctx.reply(report[:1900])
        return
    args = (args or "").strip()
    m = re.search(r"<@!?(\d+)>", args)
    if m:
        uid = int(m.group(1))
        member = ctx.guild.get_member(uid)
        if member is None:
            try:
                member = await ctx.guild.fetch_member(uid)
            except Exception:
                member = None
        if member is None:
            await ctx.reply("ما لقيت هذا العضو بالسيرفر.")
            return
        rest = re.sub(r"<@!?\d+>", "", args).strip()
        if not rest or rest in ("افتراضي", "default"):
            _maint_assign["default"] = {"name": member.display_name, "discord_id": member.id}
            _maint_assign_save()
            await ctx.reply(f"✅ **{member.display_name}** صار المسؤول الافتراضي "
                            "لكل الشقق اللي ما لها مسؤول مربوط.")
            return
        matches = _tk_find_listings(rest)
        if not matches:
            await ctx.reply(f"ما لقيت شقة تطابق «{rest}».")
            return
        if len(matches) > 1:
            names = "\n".join(f"• {nm}" for _l, nm in matches[:8])
            await ctx.reply(f"لقيت أكثر من شقة تطابق «{rest}» — حدد أكثر:\n{names}")
            return
        lid, nm = matches[0]
        _maint_assign["by_lid"][str(lid)] = {"name": member.display_name, "discord_id": member.id}
        _maint_assign_save()
        await ctx.reply(f"✅ ربطت **{nm}** ← **{member.display_name}**.")
        return
    lines = []
    for lid, nm in _tk_listings():
        a = _maint_assign["by_lid"].get(str(lid))
        lines.append(f"• {nm} ← {a['name'] if a else '⚠️ بدون مسؤول'}")
    d = _maint_assign.get("default")
    out = (f"**خريطة مسؤولي الصيانة** (الافتراضي: {d['name'] if d else 'ما فيه'})\n"
           + ("\n".join(lines) or "ما فيه شقق بالقائمة بعد."))
    for i in range(0, len(out), 1900):
        await ctx.send(out[i:i + 1900])

# ---- /deletethischannel : delete the channel the command is run in (admins only) ----
# Standalone utility, nothing to do with cleaning. Exposed BOTH as a slash command and an
# "!ouja deletethischannel" prefix command (the prefix one is a guaranteed fallback in case the
# bot wasn't invited with the applications.commands scope, so slash sync is unavailable). Deletes
# immediately, no confirm (owner's choice). Gated to admins / people with Manage-Channels so
# regular members (e.g. the cleaning team) can't delete rooms.
def _can_delete_channels(user):
    try:
        if _tk_is_admin(user):
            return True
    except Exception:
        pass
    p = getattr(user, "guild_permissions", None)
    return bool(p and (p.administrator or p.manage_channels))

@bot.tree.command(name="deletethischannel",
                  description="Delete the channel this command is used in (admins only)")
async def slash_delete_this_channel(interaction: discord.Interaction):
    if not _can_delete_channels(interaction.user):
        await interaction.response.send_message(
            "🚫 هذا الأمر للإدارة فقط (يحتاج صلاحية إدارة القنوات).", ephemeral=True)
        return
    ch = interaction.channel
    try:                               # ack first so the interaction doesn't show as failed
        await interaction.response.send_message("🗑️ يتم حذف الروم…", ephemeral=True)
    except Exception:
        pass
    try:
        await ch.delete(reason=f"deletethischannel by {interaction.user}")
    except Exception as e:
        print("deletethischannel error:", e)
        try:
            await interaction.followup.send(
                f"⚠️ ما قدرت أحذف الروم: {e}\n(غالباً البوت يحتاج صلاحية «Manage Channels» على هذا الروم.)",
                ephemeral=True)
        except Exception:
            pass

@bot.command(name="deletethischannel", aliases=["delete-this-channel", "احذف-الروم", "احذف-القناة"])
async def cmd_delete_this_channel(ctx):
    """!ouja deletethischannel — delete the current channel (admins only). Prefix fallback for
    the /deletethischannel slash command."""
    if not _can_delete_channels(ctx.author):
        await ctx.reply("🚫 هذا الأمر للإدارة فقط (يحتاج صلاحية إدارة القنوات).")
        return
    try:
        await ctx.channel.delete(reason=f"deletethischannel by {ctx.author}")
    except Exception as e:
        print("deletethischannel error:", e)
        try:
            await ctx.send(f"⚠️ ما قدرت أحذف الروم: {e}\n(غالباً البوت يحتاج صلاحية «Manage Channels».)")
        except Exception:
            pass

@bot.command(name="افتح-تنظيفات-اليوم",
             aliases=["build-today-cleanings", "افتح-تنظيفات", "build-cleanings", "افتح-التنظيفات"])
async def cmd_build_today_cleanings(ctx):
    """!ouja افتح-تنظيفات-اليوم — CREATE-ONLY recovery: re-open today's turnover cleaning
    channels that are missing. Never deletes an open channel. Admins only. Channels you've
    closed will come back here too (this is an explicit manual rebuild) — close them once and
    they stay closed for good."""
    if not _can_delete_channels(ctx.author):
        await ctx.reply("🚫 هذا الأمر للإدارة فقط.")
        return
    await ctx.reply("⏳ أفتح قنوات تنظيف اليوم الناقصة (ما أحذف أي قناة مفتوحة)…")
    try:
        changed = await sync_oujact_turnovers(day="today")   # force=True: explicit manual rebuild
    except Exception as e:
        await ctx.send(f"⚠️ صار خطأ: {e}")
        return
    created = sum(1 for c in changed if c.get("action") == "created")
    await ctx.send(f"✅ فتحت {created} قناة تنظيف لليوم. أي قناة تقفلها من الحين تنقفل نهائياً وما ترجع مع أي نشر.")

def _oujact_turnover_channels(category):
    """All open OujaCT turnover channels in the Turnovers category (topic has oujact:1)."""
    return [ch for ch in list(category.text_channels) if "oujact:1" in (ch.topic or "")]

def _oujact_channel_is_cleaned(ch):
    """True if the system has CONFIRMED this turnover's cleaning: a done-marker for its
    unit+day, or the cleaner submitted the photo report (cleaning-review flag on the topic)."""
    topic = ch.topic or ""
    key = parse_topic_oujact_key(topic)
    return bool((key and _oujact_is_done(key)) or "cleaning-review:1" in topic)

@bot.command(name="احذف-المؤكدة",
             aliases=["delete-cleaned", "احذف-المنجزة", "delete-confirmed-clean", "احذف-المكتملة"])
async def cmd_delete_confirmed_clean(ctx):
    """!ouja احذف-المؤكدة — delete ONLY the turnover channels the system has confirmed cleaned
    (cleaner submitted the cleaning report). NEVER touches a pending/not-yet-cleaned channel.
    Safe to run anytime. Admins only."""
    if not _can_delete_channels(ctx.author):
        await ctx.reply("🚫 هذا الأمر للإدارة فقط.")
        return
    try:
        category = await get_category(ctx.guild)
    except Exception as e:
        await ctx.reply(f"⚠️ ما قدرت أوصل لتصنيف Turnovers: {e}")
        return
    chans = _oujact_turnover_channels(category)
    targets = [ch for ch in chans if _oujact_channel_is_cleaned(ch)]
    pending = len(chans) - len(targets)
    if not targets:
        await ctx.reply(f"ما فيه قنوات تنظيف *مؤكدة* للحذف. (المفتوحة حالياً: {len(chans)}، كلها لسه تحت التنظيف)")
        return
    await ctx.reply(f"⏳ أحذف {len(targets)} قناة تنظيف **مؤكدة الإنجاز** فقط، وأخلي {pending} لسه تحت التنظيف…")
    done = 0
    for ch in targets:
        key = parse_topic_oujact_key(ch.topic or "")
        if key:
            _oujact_mark_opened(key)
        try:
            await ch.delete(reason=f"delete confirmed-clean by {ctx.author}")
            done += 1
        except Exception as e:
            print("delete-confirmed-clean error:", e)
    log_event("ops", f"حذف قنوات تنظيف مؤكدة · {done} · أبقى {pending} تحت التنظيف · بواسطة {ctx.author}")
    try:
        await ctx.send(f"✅ حذفت {done} قناة مؤكدة الإنجاز، وأبقيت {pending} قناة لسه تحت التنظيف. المحذوفة ما ترجع تنفتح.")
    except Exception:
        pass

@bot.command(name="احذف-كل-التنظيفات",
             aliases=["delete-all-cleanings", "احذف-الكل-تنظيفات", "nuke-cleanings", "احذف-كل-التنظيف"])
async def cmd_delete_all_cleanings(ctx):
    """!ouja احذف-كل-التنظيفات — delete ALL open turnover cleaning channels regardless of state
    (including ones still being cleaned). Use only when you're sure everything is handled.
    Each is locked so it won't auto-reopen. Admins only."""
    if not _can_delete_channels(ctx.author):
        await ctx.reply("🚫 هذا الأمر للإدارة فقط.")
        return
    try:
        category = await get_category(ctx.guild)
    except Exception as e:
        await ctx.reply(f"⚠️ ما قدرت أوصل لتصنيف Turnovers: {e}")
        return
    targets = _oujact_turnover_channels(category)
    if not targets:
        await ctx.reply("ما فيه قنوات تنظيف مفتوحة حالياً 👍")
        return
    await ctx.reply(f"⏳ أحذف **كل** قنوات التنظيف ({len(targets)}) بغض النظر عن حالتها…")
    done = 0
    for ch in targets:
        key = parse_topic_oujact_key(ch.topic or "")
        if key:
            _oujact_mark_opened(key)
        try:
            await ch.delete(reason=f"delete ALL cleanings by {ctx.author}")
            done += 1
        except Exception as e:
            print("delete-all-cleanings error:", e)
    log_event("ops", f"حذف كل قنوات التنظيف · {done} · بواسطة {ctx.author}")
    try:
        await ctx.send(f"✅ حذفت {done} قناة تنظيف. ولا وحدة ترجع تنفتح تلقائياً.")
    except Exception:
        pass

@bot.event
async def on_guild_channel_delete(channel):
    """When a turnover cleaning channel is closed/deleted by ANYONE (owner, team, or a bot
    sweep), permanently remember its unit+day so the automatic sync never re-opens it on the
    next deploy or poll. This makes 'close a channel' stick forever — the durable answer to
    cleaned channels popping back. (Explicit dashboard rebuild still overrides via force.)"""
    try:
        topic = getattr(channel, "topic", "") or ""
        if "oujact:1" not in topic:
            return
        key = parse_topic_oujact_key(topic)
        if key:
            _oujact_mark_opened(key)
            print(f"OujaCT: channel closed → locked {key} (won't auto-reopen)")
    except Exception as e:
        print("on_guild_channel_delete error:", e)

# ============================================================================
# Musaed Quality Scoreboard — ADDITIVE Discord surface for eval_musaed.py.
# Everything here is new and self-contained. eval_musaed is imported LAZILY inside
# try/except so any error in it can never break on_ready, the dashboard, or the bot.
# This NEVER messages a guest — it only drafts + scores via the eval engine.
# ============================================================================
def _eval_norm_cat(name):
    """Normalize a category name (lowercase, keep only letters/digits) so the configured
    EVAL_CATEGORY ('🛠️ Operations') reuses the EXISTING 'Operations' category instead of
    creating a near-duplicate."""
    return re.sub(r"[^0-9a-z؀-ۿ]+", "", (name or "").lower())

async def _eval_get_category(guild):
    want = _eval_norm_cat(EVAL_CATEGORY)
    for cat in guild.categories:
        if _eval_norm_cat(cat.name) == want:
            return cat                          # reuse existing (never rename it)
    try:
        return await guild.create_category(EVAL_CATEGORY)
    except Exception as e:
        print("eval category create error:", e)
        return None

async def _eval_ensure_channel(guild):
    """Get-or-create #musaed-quality under Operations and post the panel once (idempotent)."""
    cat = await _eval_get_category(guild)
    ch = await ensure_channel(guild, EVAL_CHANNEL, cat)
    if ch is None:
        return None
    try:                                   # ensure the bot can operate in its OWN scoreboard room
        me = guild.me                      # (the room may be restricted to specific people; the
        if me is not None:                 #  bot still needs to post the panel + results here)
            await ch.set_permissions(
                me, view_channel=True, send_messages=True, embed_links=True,
                attach_files=True, read_message_history=True)
    except Exception as e:
        print("eval channel self-perm error (delivery falls back to a private reply):", e)
    try:
        already = False
        async for m in ch.history(limit=30):
            if (m.author == guild.me and m.embeds
                    and (m.embeds[0].footer.text or "").startswith("eval-panel")):
                already = True
                break
        if not already:
            e = discord.Embed(
                title="🧪 لوحة جودة المساعد / Musaed Quality Scoreboard",
                description=(
                    "اضغط الزر تحت عشان تشغّل فحص جودة المساعد (فيصل). بيكتب مسودات على حالات "
                    "حقيقية، يقيّمها مقابل أفضل رد، ويوريك إذا التغيير حسّن أو خرّب. أي مسودة "
                    "خطيرة (كود باب، لهجة غير سعودية، تصعيد فايت) تُرصد كـ«خطأ حرج» ويمنع نشرها.\n\n"
                    "Tap the button to score Musaed against the golden set. A full run takes "
                    "~1–2 minutes. This is read-only — it never messages a guest."),
                color=GOLD)
            e.set_footer(text="eval-panel · musaed-quality")
            await ch.send(embed=e, view=MusaedEvalView())
    except Exception as e:
        print("eval panel post error:", e)
    return ch

async def _eval_run_and_post(channel, triggered_by, interaction=None):
    """Run the quality check and post a LIVE checklist + result card. Shared by the button
    and the weekly loop. Heavy work runs in a worker thread so the event loop (and every
    other bot loop) stays responsive. Delivery is PERMISSION-RESILIENT: if the bot can't
    post in `channel` (e.g. a locked-down room → 403 Missing Access) it falls back to a
    private reply to whoever pressed the button, so results are never lost. Never messages a guest."""
    # Resilient send/edit: try the channel; on failure fall back to an ephemeral reply to
    # the person who triggered it. Returns (message_or_None, posted_publicly_bool).
    async def _send(**kw):
        try:
            return await channel.send(**kw), True
        except Exception as ce:
            if interaction is not None:
                try:
                    return await interaction.followup.send(ephemeral=True, **kw), False
                except Exception as fe:
                    print("eval send failed (channel + followup):", ce, fe)
            else:
                print("eval send failed (channel, no interaction):", ce)
            return None, False

    async def _edit(message, **kw):
        if message is None:
            return
        try:
            await message.edit(**kw)
        except Exception:
            pass

    try:
        import eval_musaed                       # lazy import (guardrail G4)
    except Exception as e:
        await _send(content=f"⚠️ تعذّر تحميل أداة الجودة (eval_musaed): {e}")
        print("eval import failed:", e)
        return
    try:
        eval_musaed.seed_golden()              # best-effort: write the volume copy if missing
    except Exception as _se:
        print("eval seed (run path):", _se)
    if not eval_musaed.golden_exists():        # only true if even the built-in seed is gone
        await _send(content=("🧪 **لوحة الجودة** — ما فيه golden set بعد.\n"
            "ابنِ واحد من الطرفية: `python eval_musaed.py --build-golden --limit 200` "
            "ثم نظّفه واحفظه باسم `golden_set.jsonl` على نفس مجلّد البيانات."))
        return

    STEPS = [("drafting", "✍️ كتابة المسودات · Drafting replies"),
             ("scoring", "🧮 التقييم مقابل المعيار · Scoring vs golden"),
             ("aggregating", "📊 التجميع · Aggregating"),
             ("baseline", "📈 المقارنة بالأساس · Comparing to baseline")]
    state = {k: "pending" for k, _ in STEPS}
    _EM = {"pending": "⬜", "start": "⏳", "done": "✅", "skip": "➖"}

    def checklist_embed(note=""):
        e = discord.Embed(
            title="🧪 فحص جودة المساعد / Musaed quality check",
            description=(note or "يستغرق دقيقة–دقيقتين عادةً · usually 1–2 min"),
            color=GOLD)
        e.add_field(name="الخطوات / Steps",
                    value="\n".join(f"{_EM.get(state[k],'⬜')} {label}" for k, label in STEPS),
                    inline=False)
        return e

    msg, _public = await _send(embed=checklist_embed())

    def cb(step, status):                        # called from the worker thread (simple dict write)
        if step in state:
            state[step] = status

    task = asyncio.create_task(asyncio.to_thread(eval_musaed.run_quality_check, progress_cb=cb))
    last = None
    while not task.done():
        snap = tuple(state.values())
        if snap != last:
            last = snap
            await _edit(msg, embed=checklist_embed())
        await asyncio.sleep(1.5)
    await _edit(msg, embed=checklist_embed())

    try:
        summary, results, diff, html_path = await task
    except Exception as e:
        err = discord.Embed(title="🧪 فحص الجودة — خطأ",
                            description=f"تعذّر إكمال الفحص: {e}", color=0xB3261E)
        if msg is not None:
            await _edit(msg, embed=err)
        else:
            await _send(embed=err)
        print("eval run error:", e)
        log_event("eval", f"eval run error: {e}")
        return

    hf = summary["hard_fails"]
    errs = summary.get("errors", 0)
    inconclusive = errs >= max(1, summary["n"])     # every draft failed → run didn't measure anything
    safe = (not inconclusive) and (hf == 0) and \
        (not diff.get("has_baseline") or (diff.get("mean_delta") or 0) >= 0)
    res = discord.Embed(title="🧪 نتيجة جودة المساعد / Musaed quality result",
                        color=(0x9A6B00 if inconclusive else (0x1F7A4D if safe else 0xB3261E)))
    res.add_field(name="متوسط الجودة / Mean", value=f"**{summary['mean_overall']:.0f}**/100", inline=True)
    res.add_field(name="نسبة النجاح / Pass", value=f"{summary['pass_rate']*100:.0f}%", inline=True)
    res.add_field(name="دقة التوجيه / Routing", value=f"{summary['routing_accuracy']*100:.0f}%", inline=True)
    res.add_field(name="أخطاء حرجة / Hard fails",
                  value=("✅ 0 — آمن" if hf == 0 else f"🛑 {hf} — يمنع النشر"), inline=True)
    res.add_field(name="تحذيرات / Warnings", value=f"{summary['warnings']}", inline=True)
    res.add_field(name="حالات / Cases", value=f"{summary['n']}", inline=True)
    if errs:
        res.add_field(
            name="⚠️ أخطاء مسودة / Draft errors",
            value=(f"{errs} حالة تعذّر إنشاء مسودة لها — غالباً حدود استخدام Claude (rate limit) "
                   f"أو مفتاح API. النتيجة غير مكتملة. / couldn't draft (rate limit / API key)."),
            inline=False)
    if diff.get("has_baseline"):
        md, pd = (diff.get("mean_delta") or 0), (diff.get("pass_delta") or 0)
        line = f"Δ متوسط: **{md:+.1f}** · Δ نجاح: **{pd*100:+.0f}%**"
        regs = diff.get("regressions") or []
        if regs:
            line += "\n**تراجع / regressions:** " + "، ".join(
                f"{r['id']} ({r['from']}→{r['to']})" for r in regs[:8])
            if len(regs) > 8:
                line += f" +{len(regs) - 8}"
        else:
            line += "\nلا تراجع مقابل الأساس ✔"
        res.add_field(name="مقارنة بالأساس / vs baseline", value=line, inline=False)
    else:
        res.add_field(name="الأساس / Baseline", value=(diff.get("note") or "—"), inline=False)
    # name the actual hard-fail cases + reasons (the count alone isn't actionable)
    hard_cases = [r for r in results if r.get("hard_fails")]
    if hard_cases:
        hl = []
        for r in hard_cases[:6]:
            hl.append(f"• `{r.get('id','?')}` ({r.get('intent','')}): " + "؛ ".join(r["hard_fails"]))
        if len(hard_cases) > 6:
            hl.append(f"…+{len(hard_cases) - 6}")
        res.add_field(name="🛑 الأخطاء الحرجة / Hard fails", value=("\n".join(hl))[:1024], inline=False)
    by = summary.get("by_intent") or {}
    if by and not inconclusive:
        worst = sorted(by.items(), key=lambda kv: kv[1]["mean"])[:3]
        res.add_field(name="أضعف الأنواع / Weakest", inline=False,
                      value=("\n".join(f"• {k}: {v['mean']:.0f}/100 ({v['n']})" for k, v in worst))[:1024])
    if inconclusive:
        rule = "⚠️ فحص غير مكتمل · تعذّر إنشاء المسودات (تحقّق من المفتاح/حدود الاستخدام وأعد المحاولة)"
    elif safe:
        rule = "✅ آمن للنشر · 0 أخطاء حرجة والمتوسط ما نزل"
    else:
        rule = "🛑 لا تنشر · فيه خطأ حرج أو المتوسط نزل"
    fresh = summary.get("fresh")
    if fresh == 0:
        cost_note = " · ♻️ من الذاكرة · ٠ رصيد جديد / cached, $0"
    elif fresh:
        cost_note = f" · 🆕 {fresh} حالة جديدة فقط / fresh only"
    else:
        cost_note = ""
    res.set_footer(text=f"{rule} · شغّله: {triggered_by}{cost_note}")
    if msg is not None:
        await _edit(msg, embed=res)
    else:
        await _send(embed=res)
    if html_path and os.path.isfile(html_path):
        try:
            await channel.send(file=discord.File(html_path, filename="musaed_quality.html"))
        except Exception as ce:
            if interaction is not None:
                try:
                    await interaction.followup.send(
                        ephemeral=True, file=discord.File(html_path, filename="musaed_quality.html"))
                except Exception as fe:
                    print("eval report attach error:", ce, fe)
            else:
                print("eval report attach error:", ce)
    log_event("eval", f"جودة المساعد · متوسط {summary['mean_overall']:.0f} · "
                      f"نجاح {summary['pass_rate']*100:.0f}% · أخطاء حرجة {hf} · ({triggered_by})")

class MusaedEvalView(discord.ui.View):
    """Persistent panel button for the Musaed Quality Scoreboard. Admin/team only."""
    def __init__(self):
        super().__init__(timeout=None)         # persistent across restarts

    @discord.ui.button(label="🧪 Run quality check", style=discord.ButtonStyle.primary,
                       custom_id="ouja_eval_run")
    async def run_check(self, interaction: discord.Interaction, button: discord.ui.Button):
        try:
            if not _tk_is_admin(interaction.user):
                await interaction.response.send_message("هذا الأمر للإدارة فقط 🙏", ephemeral=True)
                return
            await interaction.response.send_message(
                "🧪 شغّلت فحص الجودة… النتيجة بتنزل تحت (ولو القناة مقفّلة على البوت بترجع لك هنا بشكل خاص).",
                ephemeral=True)
            await _eval_run_and_post(interaction.channel, f"@{interaction.user.display_name}", interaction)
        except Exception as e:
            print("eval button error:", e)
            try:
                await interaction.followup.send(f"⚠️ خطأ في فحص الجودة: {e}", ephemeral=True)
            except Exception:
                pass

@bot.command(name="جودة-المساعد", aliases=["musaed-quality", "eval-musaed"])
async def musaed_quality_cmd(ctx):
    """Run the Musaed quality check from any channel (admin only)."""
    if not _tk_is_admin(ctx.author):
        await ctx.reply("هذا الأمر للإدارة فقط 🙏")
        return
    await _eval_run_and_post(ctx.channel, f"@{ctx.author.display_name}")

@tasks.loop(time=dt_time(hour=EVAL_DAILY_HOUR, tzinfo=TZ))
async def eval_auto_score_loop():
    """Daily auto quality check (EVAL_AUTO_SCORE=1). Posts the scoreboard to #musaed-quality
    each morning so nobody has to tap the button. (Shows 'inconclusive' until the Claude key works.)"""
    try:
        guild = bot.get_guild(GUILD_ID)
        if guild is None:
            return
        try:
            import eval_musaed as _ev
        except Exception:
            return
        if not _ev.golden_exists():
            return
        # COST GUARD: if Musaed's rules + the golden set are unchanged since the last
        # auto-run, there's nothing new to measure — skip entirely (no API calls, $0).
        fp = ""
        try:
            fp = await asyncio.to_thread(_ev.world_fingerprint)
            if fp and fp == (_load_json("eval_auto_fp.json", {}) or {}).get("fp"):
                print("eval: daily auto-run skipped — nothing changed (0 credits)")
                return
        except Exception as _fe:
            print("eval auto fingerprint error:", _fe)
        ch = await _eval_ensure_channel(guild)
        if ch is None:
            return
        await _eval_run_and_post(ch, "الفحص اليومي التلقائي / daily auto-run")
        try:
            if fp:
                _save_json("eval_auto_fp.json",
                           {"fp": fp, "ts": now_riyadh().isoformat(timespec="seconds")})
        except Exception:
            pass
    except Exception as e:
        print("eval auto-score loop error:", e)

@tasks.loop(time=dt_time(hour=EVAL_EXPORT_HOUR, tzinfo=TZ))
async def eval_auto_export_loop():
    """Weekly fresh-chats export (EVAL_AUTO_EXPORT=1). Once a week posts a starter JSONL of
    recent real conversations to #musaed-quality so the team can curate + grow the golden set.
    Read-only Hostaway pull — needs no Claude key."""
    try:
        if now_riyadh().weekday() != EVAL_EXPORT_DOW:
            return
        guild = bot.get_guild(GUILD_ID)
        if guild is None:
            return
        try:
            import eval_musaed as _ev
            import io
        except Exception:
            return
        ch = await _eval_ensure_channel(guild)
        if ch is None:
            return
        text, n = await asyncio.to_thread(_ev.export_starter_jsonl, 150, False)
        if not n:
            return
        f = discord.File(io.BytesIO(text.encode("utf-8")), filename="musaed_fresh_chats.jsonl")
        await ch.send(
            content=(f"🗓️ تصدير أسبوعي / weekly export — **{n}** محادثة جديدة. نظّفها مع Claude "
                     f"وارفعها في صفحة /eval لتكبير قائمة الجودة. / curate in Claude, import on /eval."),
            file=f)
        log_event("eval", f"تصدير تلقائي · {n} محادثة → #{EVAL_CHANNEL}")
    except Exception as e:
        print("eval auto-export loop error:", e)

# ============================================================================
# Conversation Watchman «الرقيب» — re-reads FINISHED guest conversations and
#   (1) flags info the team answered that is MISSING from the apartment's guide
#       page  -> a "guide gaps" card, and
#   (2) catches concrete PROMISES a team member made (action / money / timing)
#       -> a card that @mentions the responder and chases it to completion
#       (deadline -> nudge -> manager escalation).
#
# Ships DORMANT: WATCHMAN_ENABLED=0 by default, so deploying this changes nothing
# and never messages a guest. When enabled it still starts in WATCHMAN_DRYRUN=1
# (watch-only): it analyzes + LOGS what it WOULD post and sends nothing. The first
# dry-run also doubles as the live verification of what Hostaway returns per
# message (it prints the outgoing-message field shape + the sender it detected).
# Flip WATCHMAN_DRYRUN=0 to go live. Everything reuses existing helpers (api_get,
# claude_json, directions_link, _load_json/_save_json, ensure_channel) — additive,
# no new dependencies. NOTE: this is ordinary Python (NOT inside DASHBOARD_HTML),
# so normal string escapes are fine here.
# ============================================================================
def _wm_flag(name, default="0"):
    return os.environ.get(name, default) in ("1", "true", "True", "yes")

WATCHMAN_ENABLED          = _wm_flag("WATCHMAN_ENABLED", "1")   # on by default (owner: go fully live)
WATCHMAN_DRYRUN           = _wm_flag("WATCHMAN_DRYRUN", "0")     # LIVE: posts cards + pings (set 1 for watch-only)
WATCHMAN_QUIET_MIN        = int(os.environ.get("WATCHMAN_QUIET_MIN", "45"))   # silence before we analyze
WATCHMAN_POLL_MIN         = float(os.environ.get("WATCHMAN_POLL_MIN", "10"))  # how often the loop runs
WATCHMAN_SCAN             = int(os.environ.get("WATCHMAN_SCAN", "30"))        # recent conversations to look at
WATCHMAN_MAX_PER_TICK     = int(os.environ.get("WATCHMAN_MAX_PER_TICK", "8")) # AI passes per tick (cost cap)
WATCHMAN_HISTORY_MSGS     = int(os.environ.get("WATCHMAN_HISTORY_MSGS", "30"))
WATCHMAN_ADMIN_CHANNEL    = os.environ.get("WATCHMAN_ADMIN_CHANNEL", "مطابقة-الأسماء")  # name↔Discord
# guide-gaps + promises now each open their OWN ticket channel under «صيانه» (no shared channel).
WATCHMAN_GAP_PREFIX       = os.environ.get("WATCHMAN_GAP_PREFIX", "نقص")
WATCHMAN_PROMISE_PREFIX   = os.environ.get("WATCHMAN_PROMISE_PREFIX", "وعد")
WATCHMAN_KNOWN_NAMES      = os.environ.get("WATCHMAN_KNOWN_NAMES", "Ohoud,nasser,Noura,Aseel,Mohammed,Maather,Faisal")
WATCHMAN_GUIDE_OWNER      = os.environ.get("WATCHMAN_GUIDE_OWNER", "").strip()   # who fixes guides (id / role:id)
WATCHMAN_MANAGER_ROLE     = os.environ.get("WATCHMAN_MANAGER_ROLE", "").strip()  # escalation target (id / role:id)
WATCHMAN_ACTION_DUE_H     = float(os.environ.get("WATCHMAN_ACTION_DUE_H", "6"))
WATCHMAN_MONEY_DUE_H      = float(os.environ.get("WATCHMAN_MONEY_DUE_H", "24"))
WATCHMAN_TIMING_FALLBACK_H = float(os.environ.get("WATCHMAN_TIMING_FALLBACK_H", "12"))
WATCHMAN_ESCALATE_AFTER_H = float(os.environ.get("WATCHMAN_ESCALATE_AFTER_H", "3"))
WATCHMAN_MIN_CONF         = float(os.environ.get("WATCHMAN_MIN_CONF", "0.6"))

def _wm_name_map():
    """Hostaway-responder-name -> Discord mention id. JSON in WATCHMAN_NAME_MAP, e.g.
    {"Ahmed":"123456789012345678","Sara":"role:9999"}. Keys are matched case-insensitively."""
    raw = os.environ.get("WATCHMAN_NAME_MAP", "").strip()
    if not raw:
        return {}
    try:
        d = json.loads(raw)
        return {str(k).strip().lower(): str(v).strip() for k, v in d.items()}
    except Exception as e:
        print("WATCHMAN_NAME_MAP parse error:", e)
        return {}

WATCHMAN_NAME_MAP = _wm_name_map()

# Promises only count from a MATCHED human or the owner — NEVER from the AI (Musaed). Our bot
# appends a Musaid/مساعد signature on every send, so a signed/automated outgoing message = AI.
_WM_AI_SIGS = tuple(s for s in
                    ([ASSISTANT_SIGNATURE_AR, ASSISTANT_SIGNATURE_EN] + SIGNATURES_AR + SIGNATURES_EN)
                    if s)
_WM_OWNER_NAMES = {s.strip().lower() for s in
                   os.environ.get("WATCHMAN_OWNER_NAMES", "Faisal,فيصل").split(",") if s.strip()}

def _wm_is_ai_message(m):
    """True if this OUTGOING message came from our bot/Musaed (carries a Musaid signature) or
    looks automated — i.e. NOT an accountable human promise."""
    body = m.get("body") or ""
    if not body.strip():
        return False
    for sig in _WM_AI_SIGS:
        if sig and sig in body:
            return True
    if "Musaid" in body:
        return True
    return _looks_automated(body)

def _wm_promise_allowed(responder):
    """Owner rule: only a promise from a MATCHED human (or the owner Faisal) opens a ticket.
    The AI ('AI-Assistant'), a generic 'Team', or an unmatched/anonymous sender → no ticket."""
    n = (responder or "").strip().lower()
    if not n or n in ("ai-assistant", "team", "musaid", "مساعد"):
        return False
    if n in _WM_OWNER_NAMES:
        return True
    return bool(_wm_resolve_id(responder))

# Entry/door/access code is intentionally sent ~1h before check-in — it is NOT a static guide
# gap, so never open a gap ticket about it. (Wifi password etc. are fine — they have no entry word.)
_WM_CODE_WORDS  = ("code", "passcode", "pincode", "pin code", "كود", "رمز", "الرقم السري", "رقم سري")
_WM_ENTRY_WORDS = ("entry", "door", "access", "lock", "gate", "check-in", "checkin", "self check",
                   "self-entry", "self entry", "دخول", "الباب", "باب", "قفل", "بوابة", "الدخول الذاتي")

def _wm_is_entry_code_gap(*parts):
    blob = " ".join(p for p in parts if p).lower()
    return any(w in blob for w in _WM_CODE_WORDS) and any(w in blob for w in _WM_ENTRY_WORDS)

# in-memory stores (mirrored to the STATE_DIR volume so tickets survive redeploys)
_wm_seen        = {}    # conversation_id(str) -> last-analyzed last-message timestamp
_wm_gaps        = {}    # gap_key -> record   (open guide-gap cards, for dedup / "+N guests")
_wm_promises    = {}    # promise_id -> record (lifecycle: open/nudged/escalated/done)
_wm_msg2promise = {}    # discord message id(str) -> promise_id  (for the Done button)
_wm_namemap     = {}    # lowercased Hostaway/Airbnb responder name -> Discord user id (admin-assigned)
_wm_meta        = {}    # small persisted flags, e.g. {"baselined": True, "names": [...], "carded": [...]}
_wm_loaded_flag = {"v": False}
_wm_diag_logged = {"v": False}   # print the outgoing-message shape once per process (Step-0 fold-in)
_wm_guide_cache = {}    # listing_id -> (flattened_text, ts)

def _wm_load():
    global _wm_seen, _wm_gaps, _wm_promises, _wm_msg2promise, _wm_meta, _wm_namemap
    _wm_seen        = _load_json("watchman_seen.json", {})
    _wm_gaps        = _load_json("watchman_gaps.json", {})
    _wm_promises    = _load_json("watchman_promises.json", {})
    _wm_msg2promise = _load_json("watchman_msg2promise.json", {})
    _wm_meta        = _load_json("watchman_meta.json", {})
    _wm_namemap     = _load_json("watchman_names.json", {})

def _wm_save():
    _save_json("watchman_seen.json", _wm_seen)
    _save_json("watchman_gaps.json", _wm_gaps)
    _save_json("watchman_promises.json", _wm_promises)
    _save_json("watchman_msg2promise.json", _wm_msg2promise)
    _save_json("watchman_meta.json", _wm_meta)
    _save_json("watchman_names.json", _wm_namemap)

def _wm_resolve_id(responder):
    """Discord id for a Hostaway/Airbnb responder name. Admin-assigned map (the
    «مطابقة-الأسماء» channel) wins, then the WATCHMAN_NAME_MAP env override. '' if neither."""
    n = (responder or "").strip().lower()
    if not n:
        return ""
    return _wm_namemap.get(n) or WATCHMAN_NAME_MAP.get(n) or ""

_WM_SENDER_KEYS = ("userName", "agentName", "sentBy", "fromName", "senderName", "authorName")

def _wm_sender_name(m):
    """Best-effort: which team member sent this OUTGOING Hostaway message. '' if unknown
    (e.g. a reply typed in the Airbnb app, which arrives without an individual sender)."""
    u = m.get("user")
    if isinstance(u, dict):
        nm = (u.get("name")
              or " ".join(str(x) for x in (u.get("firstName"), u.get("lastName")) if x)).strip()
        if nm:
            return nm
    for k in _WM_SENDER_KEYS:
        v = str(m.get(k) or "").strip()
        if v:
            return v
    return ""

def _wm_guide_text(listing_id):
    """Fetch + flatten the guide PAGE behind the apartment's directions link to plain text
    (cached 6h). '' when there is no link or it can't be read — the caller then falls back
    to the #knowledge facts for that apartment."""
    if not listing_id:
        return ""
    cached = _wm_guide_cache.get(listing_id)
    if cached and time.time() - cached[1] < 6 * 3600:
        return cached[0]
    text = ""
    try:
        url = directions_link(listing_id)
    except Exception:
        url = None
    if url:
        try:
            r = requests.get(url, timeout=20, headers={"User-Agent": "OujaWatchman/1.0"})
            if r.status_code == 200 and r.text:
                raw = r.text
                raw = re.sub(r"(?is)<(script|style)[^>]*>.*?</\1>", " ", raw)
                raw = re.sub(r"(?s)<[^>]+>", " ", raw)
                raw = re.sub(r"&[a-z#0-9]+;", " ", raw)
                text = re.sub(r"\s+", " ", raw).strip()[:6000]
        except Exception as e:
            print(f"watchman: guide fetch error listing {listing_id}: {e}")
    _wm_guide_cache[listing_id] = (text, time.time())
    return text

_WM_SYSTEM = (
    "You audit ONE finished guest conversation for a Riyadh short-term-rental company (Ouja). "
    "You receive the apartment name, the GUIDE TEXT the guest can already see (may be empty), and "
    "the full conversation with each line labeled by who sent it. Return STRICT JSON only — no prose, "
    "no markdown fences.\n\n"
    "Find TWO things:\n\n"
    "1) guide_gaps — a piece of practical info the TEAM gave the guest that is NOT already present in "
    "the GUIDE TEXT, and that FUTURE guests of THIS apartment would also need: wifi, parking, AC, the "
    "entry/door-code method, appliances, checkout steps, location/landmark, trash, water/electricity, "
    "etc. Include it ONLY if it is genuinely ABSENT from the GUIDE TEXT provided. If the GUIDE TEXT is "
    "empty, set used_fallback=true and be conservative (only clearly guide-type facts). Do NOT include "
    "one-off, guest-specific things (a personal refund, a late checkout granted just to them). Do NOT "
    "flag the apartment ENTRY / DOOR / ACCESS code, lock code or passcode as a gap — it is sent ~1 hour "
    "before check-in on purpose and is NOT part of the static guide (the wifi password, by contrast, IS "
    "fine to flag).\n\n"
    "2) promises — a CONCRETE commitment the TEAM (never the guest) made: ACTION we must do ('we'll send "
    "a technician', 'we'll bring towels', 'we'll replace it'), MONEY ('refund', 'discount', "
    "'compensation', 'no charge'), or TIMING ('early check-in at 12', 'late checkout till 2', 'we'll "
    "confirm by tonight'). IGNORE vague pleasantries ('we'll do our best', 'enjoy your stay', 'let us "
    "know if you need anything'). For each promise, copy the exact sender label of the line that made it "
    "into 'responder', and quote the promise text. CRITICAL: lines labeled 'AI-Assistant' are automated "
    "bot messages — NEVER extract a promise from an 'AI-Assistant' line; a promise only counts when a "
    "NAMED human team member made it. (For guide_gaps, information from ANY line still counts — a gap is "
    "a gap no matter who answered.)\n\n"
    "Return JSON exactly in this shape:\n"
    '{"guide_gaps":[{"topic":"...","guest_question":"...","our_answer":"...","suggested_guide_text":"...",'
    '"used_fallback":false,"confidence":0.0}],'
    '"promises":[{"type":"action|money|timing","summary":"...","quote":"...","responder":"...",'
    '"due_hint":"","confidence":0.0}]}\n'
    "Write topic / suggested_guide_text / summary in ARABIC (the Ouja team reads Arabic); keep 'quote' "
    "verbatim in its original language. confidence is 0.0-1.0. If nothing qualifies, return empty lists. "
    "Never invent facts."
)

def run_watchman_scan():
    """SYNC: scan recent conversations, analyze the quiet + not-yet-seen ones, update the
    stores, and RETURN a list of (kind, payload) intents for the async layer to POST. In
    dry-run it still analyzes (and marks conversations seen, so going live won't re-spend
    tokens on old chats) but emits only 'dry_*' intents and does NOT create ticket records."""
    if not WATCHMAN_ENABLED:
        return []
    import hashlib
    try:
        listings = get_listings_map()
    except Exception:
        listings = {}
    try:
        data = api_get("/conversations", params={"limit": WATCHMAN_SCAN, "includeResources": 1})
    except Exception as e:
        print("watchman fetch error:", e)
        return []
    convos = data.get("result", []) or []
    now = datetime.now(TZ)
    intents = []
    analyzed = 0
    # Safety baseline: the FIRST time we go live (not dry-run, never baselined) we mark the
    # whole existing backlog as already-seen WITHOUT analyzing — so flipping the switch can't
    # dump dozens of old-conversation tickets into the channels at once. Only genuinely NEW
    # conversations get tickets after this. (Dry-run never baselines — it analyzes backlog into
    # the LOG on purpose, so the owner can see what it would do.)
    baseline = (not WATCHMAN_DRYRUN) and (not _wm_meta.get("baselined"))
    for c in convos:
        if analyzed >= WATCHMAN_MAX_PER_TICK:
            break
        cid = c.get("id")
        if not cid:
            continue
        try:
            md = api_get(f"/conversations/{cid}/messages")
            msgs = [m for m in (md.get("result", []) or []) if (m.get("body") or "").strip()]
        except Exception:
            continue
        if len(msgs) < 2:
            continue
        if not any(not _msg_is_inbound(m) for m in msgs):
            continue                                  # no message sent by OUR team yet — nothing to audit
        msgs = sorted(msgs, key=_msg_sort_key)
        last_ts = _msg_time(msgs[-1])
        last_dt = _parse_msg_dt(last_ts)
        if last_dt is None:
            continue
        if (now - last_dt).total_seconds() < WATCHMAN_QUIET_MIN * 60:
            continue                                  # not quiet yet — wait
        if baseline:
            _wm_seen[str(cid)] = last_ts              # mark the existing backlog seen, don't analyze
            continue
        if _wm_seen.get(str(cid)) == last_ts:
            continue                                  # already analyzed up to this message
        if not _wm_diag_logged["v"]:                  # Step-0: learn the real sender shape, once
            out = next((m for m in msgs if not _msg_is_inbound(m)), None)
            if out is not None:
                print("watchman STEP0 outgoing-message keys:", sorted(out.keys()))
                print("watchman STEP0 sender detected:", repr(_wm_sender_name(out)))
                _wm_diag_logged["v"] = True
        lm = c.get("listingMapId")
        apt = listings.get(lm) or c.get("listingName") or f"unit-{lm}"
        guest = c.get("recipientName") or c.get("guestName") or "Guest"
        convo_lines = []
        for m in msgs[-WATCHMAN_HISTORY_MSGS:]:
            if _msg_is_inbound(m):
                who = "Guest"
            elif _wm_is_ai_message(m):
                who = "AI-Assistant"               # our bot/Musaed — never an accountable promise
            else:
                who = _wm_sender_name(m) or "Team"
            convo_lines.append(f"{who}: {(m.get('body') or '').strip()}")
        convo_text = "\n".join(convo_lines)
        guide_text = _wm_guide_text(lm)
        if not guide_text and lm:
            try:
                facts = _knowledge_apartment_facts.get(int(lm), [])
            except (TypeError, ValueError):
                facts = []
            guide_text = "[no readable guide page — fallback facts] " + (" ".join(facts) or _knowledge_text or "[none]")
            used_fallback_default = True
        else:
            used_fallback_default = not bool(guide_text)
            if not guide_text:
                guide_text = "[none]"
        user = (f"APARTMENT: {apt}\n\nGUIDE TEXT (what the guest can already see):\n{guide_text}\n\n"
                f"CONVERSATION:\n{convo_text}")
        result = claude_json(_WM_SYSTEM, user, max_tokens=1100, model=CLAUDE_MODEL_PREMIUM) or {}
        analyzed += 1
        _wm_seen[str(cid)] = last_ts                  # mark seen even in dry-run (no re-spend)

        for g in (result.get("guide_gaps") or []):
            if float(g.get("confidence") or 0) < WATCHMAN_MIN_CONF:
                continue
            topic = str(g.get("topic") or "").strip()
            if not topic:
                continue
            gq = str(g.get("guest_question") or "").strip()
            ga = str(g.get("our_answer") or "").strip()
            gs = str(g.get("suggested_guide_text") or "").strip()
            if _wm_is_entry_code_gap(topic, gq, ga, gs):
                continue                              # entry/door code → sent 1h before check-in, not a gap
            payload = {
                "listing_id": lm, "apartment": apt, "topic": topic,
                "guest_question": gq,
                "our_answer": ga,
                "suggested": gs,
                "fallback": bool(g.get("used_fallback")) or used_fallback_default,
                "confidence": float(g.get("confidence") or 0),
                "conversation_id": cid, "guest": guest,
            }
            if WATCHMAN_DRYRUN:
                intents.append(("dry_gap", payload))
                continue
            key = f"{lm}::" + hashlib.md5(topic.strip().lower().encode("utf-8")).hexdigest()[:10]
            existing = _wm_gaps.get(key)
            if existing:
                if not existing.get("resolved"):
                    existing["count"] = int(existing.get("count", 1)) + 1
                    existing["last_guest"] = guest
                    intents.append(("gap_bump", {"key": key, "count": existing["count"]}))
                continue                              # resolved gaps are not re-flagged
            payload.update({"key": key, "count": 1, "resolved": False, "msg_id": None,
                            "opened": now.isoformat(timespec="seconds")})
            _wm_gaps[key] = payload
            intents.append(("gap_new", payload))

        for p in (result.get("promises") or []):
            if float(p.get("confidence") or 0) < WATCHMAN_MIN_CONF:
                continue
            ptype = str(p.get("type") or "action").strip().lower()
            if ptype not in ("action", "money", "timing"):
                ptype = "action"
            summary = str(p.get("summary") or "").strip()
            if not summary:
                continue
            responder = str(p.get("responder") or "").strip()
            # remember real human-looking names so the «مطابقة-الأسماء» channel can map them
            if responder and responder.lower() not in ("ai-assistant", "team"):
                names = _wm_meta.setdefault("names", [])
                if responder.lower() not in [n.lower() for n in names]:
                    names.append(responder)
            # OWNER RULE: only open a promise ticket for a promise made by a MATCHED human
            # (or Faisal). Never for the AI assistant (Musaed) or an anonymous/unmatched sender.
            if not _wm_promise_allowed(responder):
                continue
            payload = {
                "conversation_id": cid, "listing_id": lm, "apartment": apt, "guest": guest,
                "type": ptype, "summary": summary, "quote": str(p.get("quote") or "").strip(),
                "responder": responder, "due_hint": str(p.get("due_hint") or "").strip(),
            }
            if WATCHMAN_DRYRUN:
                intents.append(("dry_promise", payload))
                continue
            pid = "wm-%s-%s" % (cid, hashlib.md5((ptype + "|" + summary).encode("utf-8")).hexdigest()[:10])
            if pid in _wm_promises:
                continue                              # already tracked (open or done)
            due_h = {"money": WATCHMAN_MONEY_DUE_H, "timing": WATCHMAN_TIMING_FALLBACK_H}.get(
                ptype, WATCHMAN_ACTION_DUE_H)
            payload.update({
                "id": pid, "discord_id": _wm_resolve_id(responder),
                "due": (now + timedelta(hours=due_h)).isoformat(timespec="seconds"),
                "opened": now.isoformat(timespec="seconds"),
                "state": "open", "msg_id": None, "nudged": 0, "escalated": False,
            })
            _wm_promises[pid] = payload
            intents.append(("promise_new", payload))
    if baseline:
        _wm_meta["baselined"] = True
        _wm_save()
        print(f"watchman: baselined {len(_wm_seen)} existing conversations (first live run) — "
              f"only NEW chats get tickets from now")
        return []
    if not WATCHMAN_DRYRUN:
        _wm_meta["baselined"] = True              # stays set once we've run live at least once
    _wm_save()
    return intents

def _wm_mention(raw):
    """Render a configured id as a Discord mention. Accepts an already-formatted '<@..>' /
    '<@&..>', a bare numeric user id, or 'role:<id>' for a role. '' stays ''."""
    raw = (raw or "").strip()
    if not raw:
        return ""
    if raw.startswith("<@"):
        return raw
    if raw.lower().startswith("role:"):
        return f"<@&{raw.split(':', 1)[1].strip()}>"
    if raw.isdigit():
        return f"<@{raw}>"
    return raw

def _wm_guild():
    return bot.get_guild(GUILD_ID)

def _wm_slug(apartment):
    return re.sub(r"^ouja-", "", channel_name(apartment or "unit"))[:34]

async def _wm_close_channel(ch, note):
    """Close a Watchman ticket room by DELETING the channel (owner: closed tickets are
    removed, not kept). The record stays in the JSON stores as the audit trail."""
    if ch is None:
        return
    try:
        await ch.send(f"✅ {note} — بيتحذف الروم خلال ثواني. 🗑️")
    except Exception:
        pass
    try:
        await asyncio.sleep(3)
        await ch.delete(reason="watchman: ticket closed")
    except Exception as e:
        print("watchman channel delete error:", e)

def _wm_member_mention(guild, name):
    """Best-effort: find a Discord member whose name matches the Hostaway responder name and
    return '<@id>'. '' if no confident match (then the promise stays unassigned). Only as good
    as the members the bot has cached — the explicit WATCHMAN_NAME_MAP always wins over this."""
    if guild is None or not name:
        return ""
    n = name.strip().lower()
    if not n:
        return ""
    members = list(getattr(guild, "members", []) or [])
    # 1) exact match on display name / username / global name
    for mem in members:
        cands = {(mem.display_name or "").lower(), (mem.name or "").lower(),
                 (getattr(mem, "global_name", None) or "").lower()}
        if n in cands:
            return f"<@{mem.id}>"
    # 2) first-name match (e.g. responder 'Ahmed' vs display 'Ahmed | Ops'), only if unambiguous
    first = n.split()[0]
    hits = [mem for mem in members
            if (mem.display_name or "").lower().split()[:1] == [first]
            or (mem.name or "").lower().split()[:1] == [first]]
    if len(hits) == 1:
        return f"<@{hits[0].id}>"
    return ""

# ---- admin name-matching channel «مطابقة-الأسماء»: Hostaway/Airbnb name -> Discord user ----
_WM_NAME_FOOT = "wm-name:"

def _wm_known_names():
    """Names to map: the env seed (WATCHMAN_KNOWN_NAMES) + every responder the watcher has
    actually seen (stored in _wm_meta['names']). De-duplicated, original casing kept."""
    seed = [s.strip() for s in (WATCHMAN_KNOWN_NAMES or "").split(",") if s.strip()]
    seen = _wm_meta.get("names", []) if isinstance(_wm_meta, dict) else []
    out, low = [], set()
    for nm in list(seed) + list(seen):
        k = (nm or "").strip().lower()
        if k and k not in low:
            low.add(k)
            out.append(nm.strip())
    return out

def _wm_name_card_embed(name):
    assigned = _wm_namemap.get(name.strip().lower())
    if assigned:
        body = (f"**{name}**  ←  <@{assigned}>\n✅ مربوط — أي وعد باسم «{name}» بيوسم هذا الحساب.\n"
                f"تبي تغيّره؟ اختر حساب ثاني من القائمة.")
        color = 0x4CAF50
    else:
        body = (f"**{name}**\n⚠️ غير مربوط بعد — اختر حساب الموظف في ديسكورد من القائمة تحت.")
        color = 0xC9A24B
    emb = discord.Embed(title=f"👤 مطابقة اسم · {name}", description=body, color=color)
    emb.set_footer(text=f"{_WM_NAME_FOOT}{name.strip().lower()}")
    return emb

class WatchmanNameSelect(discord.ui.UserSelect):
    def __init__(self):
        super().__init__(custom_id="wm_name_select", placeholder="اختر حساب الموظف في ديسكورد…",
                         min_values=1, max_values=1)

    async def callback(self, interaction: discord.Interaction):
        name = ""
        if interaction.message.embeds and interaction.message.embeds[0].footer:
            foot = interaction.message.embeds[0].footer.text or ""
            if foot.startswith(_WM_NAME_FOOT):
                name = foot[len(_WM_NAME_FOOT):]
        if not name:
            await interaction.response.send_message("⚠️ ما عرفت الاسم من البطاقة.", ephemeral=True)
            return
        if not _wm_namemap:                            # lazy-load if a restart cleared memory
            _wm_load()
        user = self.values[0]
        _wm_namemap[name.strip().lower()] = str(user.id)
        _wm_save()
        try:
            await interaction.message.edit(embed=_wm_name_card_embed(name), view=WatchmanNameView())
        except Exception:
            pass
        await interaction.response.send_message(f"✅ ربطت «{name}» بـ {user.mention}.", ephemeral=True)

class WatchmanNameView(discord.ui.View):
    def __init__(self):
        super().__init__(timeout=None)
        self.add_item(WatchmanNameSelect())

def _wm_is_watchman_ticket_channel(ch, closed_only=True):
    """True if `ch` is one of the watchman's own ticket rooms (نقص-/وعد- under صيانه),
    identified by its topic. closed_only → only the leftover «مغلقة-» ones."""
    topic = getattr(ch, "topic", "") or ""
    if not topic.startswith("ouja-watchman:"):
        return False
    if closed_only:
        return (ch.name or "").startswith("مغلقة-")
    return True

class WatchmanCleanupView(discord.ui.View):
    def __init__(self):
        super().__init__(timeout=None)

    @discord.ui.button(label="🗑️ احذف التذاكر المقفولة القديمة / Delete old closed tickets",
                       style=discord.ButtonStyle.danger, custom_id="wm_cleanup_closed")
    async def cleanup(self, interaction: discord.Interaction, button: discord.ui.Button):
        await interaction.response.defer(ephemeral=True, thinking=True)
        guild = interaction.guild
        deleted, failed = 0, 0
        for ch in list(guild.text_channels):
            if _wm_is_watchman_ticket_channel(ch, closed_only=True):
                try:
                    await ch.delete(reason="watchman: bulk cleanup of closed tickets")
                    deleted += 1
                except Exception as e:
                    failed += 1
                    print("watchman cleanup delete error:", e)
        msg = f"🗑️ حذفت **{deleted}** تذكرة مقفولة."
        if failed:
            msg += f" (تعذّر حذف {failed} — تأكد إن للبوت صلاحية إدارة القنوات.)"
        await interaction.followup.send(msg, ephemeral=True)

async def _wm_ensure_name_card(guild, name):
    """Post a mapping card for `name` in the admin channel if one isn't there yet (idempotent
    via the _wm_meta['carded'] list, so we don't re-scan history every promise)."""
    if guild is None or not name:
        return
    low = name.strip().lower()
    carded = _wm_meta.setdefault("carded", [])
    if low in [c.lower() for c in carded]:
        return
    ch = await ensure_channel(guild, WATCHMAN_ADMIN_CHANNEL, await _tk_category(guild, "maint"))
    if ch is None:
        return
    try:
        await ch.send(embed=_wm_name_card_embed(name), view=WatchmanNameView())
        carded.append(name.strip())
        _wm_save()
    except Exception as e:
        print("watchman name card error:", e)

async def ensure_watchman_admin(guild):
    """Create the «مطابقة-الأسماء» admin channel under «صيانه» and post one card per known
    name (intro once, cards idempotent by embed footer). Called on boot."""
    if not WATCHMAN_ENABLED or guild is None:
        return
    ch = await ensure_channel(guild, WATCHMAN_ADMIN_CHANNEL, await _tk_category(guild, "maint"))
    if ch is None:
        return
    have, intro_seen, cleanup_seen = set(), False, False
    try:
        async for msg in ch.history(limit=200):
            if msg.embeds and msg.embeds[0].footer:
                ft = msg.embeds[0].footer.text or ""
                if ft.startswith(_WM_NAME_FOOT):
                    have.add(ft[len(_WM_NAME_FOOT):])
                elif ft == "wm-name-intro":
                    intro_seen = True
                elif ft == "wm-cleanup":
                    cleanup_seen = True
    except Exception:
        pass
    if not cleanup_seen:
        cl = discord.Embed(
            title="🗑️ تنظيف التذاكر المقفولة",
            description=("التذاكر الجديدة تنحذف تلقائياً أول ما تُقفل. هذا الزر يحذف **التذاكر القديمة "
                         "المقفولة** (اللي اسمها يبدأ بـ «مغلقة-») دفعة وحدة — اضغطه وقت ما تبي تنظّف."),
            color=0xC0552B)
        cl.set_footer(text="wm-cleanup")
        try:
            await ch.send(embed=cl, view=WatchmanCleanupView())
        except Exception:
            pass
    if not intro_seen:
        intro = discord.Embed(
            title="🔗 مطابقة أسماء الموظفين  ·  Hostaway/Airbnb ← Discord",
            description=("اربط اسم كل موظف — زي ما يظهر في Hostaway/Airbnb — بحسابه في ديسكورد.\n"
                         "لما «الرقيب» يمسك وعد من موظف، بيوسم حسابه حسب الربط هنا.\n"
                         "اختر من القائمة تحت كل بطاقة. تقدر تغيّر الربط أي وقت."),
            color=0x4B89C9)
        intro.set_footer(text="wm-name-intro")
        try:
            await ch.send(embed=intro)
        except Exception:
            pass
    carded = _wm_meta.setdefault("carded", [])
    for name in _wm_known_names():
        low = name.strip().lower()
        if low in {h.lower() for h in have}:
            if name.strip() not in carded:
                carded.append(name.strip())
            continue
        try:
            await ch.send(embed=_wm_name_card_embed(name), view=WatchmanNameView())
            if name.strip() not in carded:
                carded.append(name.strip())
        except Exception as e:
            print("watchman admin seed card error:", e)
    _wm_save()

class WatchmanPromiseView(discord.ui.View):
    def __init__(self):
        super().__init__(timeout=None)            # persistent across restarts

    @discord.ui.button(label="✅ تم الوفاء بالوعد / Promise accomplished", style=discord.ButtonStyle.success,
                       custom_id="wm_promise_done")
    async def done(self, interaction: discord.Interaction, button: discord.ui.Button):
        pid = _wm_msg2promise.get(str(interaction.message.id))
        rec = _wm_promises.get(pid) if pid else None
        if not rec:
            await interaction.response.send_message("⚠️ ما لقيت هذا الوعد في السجل.", ephemeral=True)
            return
        rec["state"] = "done"
        rec["done_by"] = str(interaction.user)
        rec["done_at"] = datetime.now(TZ).isoformat(timespec="seconds")
        _wm_save()
        try:
            v = WatchmanPromiseView()
            for ch_ in v.children:
                ch_.disabled = True
            await interaction.message.edit(view=v)
        except Exception:
            pass
        await interaction.response.send_message(
            f"✅ تم — سجّلت إنك خلّصت الوعد، {interaction.user.mention}.")
        try:                                           # close the ticket room (delete it)
            await _wm_close_channel(interaction.channel,
                                    f"تم الوفاء بالوعد بواسطة {interaction.user.mention}")
        except Exception:
            pass

class WatchmanGapView(discord.ui.View):
    def __init__(self):
        super().__init__(timeout=None)

    @discord.ui.button(label="✅ أضفته للدليل / Added", style=discord.ButtonStyle.success,
                       custom_id="wm_gap_added")
    async def added(self, interaction: discord.Interaction, button: discord.ui.Button):
        key = None
        if interaction.message.embeds:
            foot = (interaction.message.embeds[0].footer.text or "") if interaction.message.embeds[0].footer else ""
            m = re.match(r"wm-gap:(.+)", foot)
            if m:
                key = m.group(1)
        rec = _wm_gaps.get(key) if key else None
        if rec:
            rec["resolved"] = True
            _wm_save()
        try:
            v = WatchmanGapView()
            for ch_ in v.children:
                ch_.disabled = True
            await interaction.message.edit(view=v)
        except Exception:
            pass
        await interaction.response.send_message("✅ تم — أزلته من قائمة النواقص.", ephemeral=True)
        try:                                           # close the ticket room (delete it)
            await _wm_close_channel(interaction.channel,
                                    f"أُضيف للدليل بواسطة {interaction.user.mention}")
        except Exception:
            pass

async def _wm_post_gap(rec):
    """Open a dedicated guide-gap TICKET ROOM (its own channel under «صيانه»)."""
    guild = _wm_guild()
    if guild is None:
        return
    cat = await _tk_category(guild, "maint")
    seq = _next_counter("watchman_gap")
    try:
        ch = await guild.create_text_channel(
            f"{WATCHMAN_GAP_PREFIX}-{seq:03d}-{_wm_slug(rec.get('apartment'))}", category=cat,
            topic=f"ouja-watchman:gap key:{rec['key']}")
    except Exception as e:
        print("watchman gap channel error:", e)
        return
    owner = _wm_mention(WATCHMAN_GUIDE_OWNER)
    warn = "\n\n⚠️ ثقة أقل — ما قدرت أقرأ صفحة الدليل (راجع يدوياً)." if rec.get("fallback") else ""
    emb = discord.Embed(
        title=f"🧭 نقص في الدليل #{seq:03d} · {rec['apartment']}",
        description=(f"**الموضوع:** {rec['topic']}\n"
                     f"**سؤال الضيف:** {rec.get('guest_question') or '—'}\n"
                     f"**ردّينا عليه بـ:** {rec.get('our_answer') or '—'}\n\n"
                     f"**أضِف للدليل:**\n> {rec.get('suggested') or rec.get('our_answer') or '—'}{warn}\n\n"
                     f"اضغط «أضفته للدليل» لما تحدّث صفحة الشقة — بيتقفل الروم."),
        color=0xC9A24B)
    emb.set_footer(text=f"wm-gap:{rec['key']}")
    msg = await ch.send(content=(owner or None), embed=emb, view=WatchmanGapView())
    try:
        await msg.pin()
    except Exception:
        pass
    rec["channel_id"] = str(ch.id)
    rec["msg_id"] = str(msg.id)
    _wm_save()

async def _wm_bump_gap(payload):
    rec = _wm_gaps.get(payload["key"])
    if not rec or not rec.get("channel_id"):
        return
    ch = bot.get_channel(int(rec["channel_id"]))
    if ch is None:
        return
    try:
        await ch.send(f"🔁 ضيف ثاني سأل نفس الشي — صاروا **{payload['count']}× ضيوف**. "
                      f"الدليل لسا ناقص هالمعلومة.")
    except Exception:
        pass

async def _wm_post_promise(rec):
    """Open a dedicated promise TICKET ROOM (its own channel under «صيانه»), @mention the
    employee who made it, and close it when they press Done."""
    guild = _wm_guild()
    if guild is None:
        return
    cat = await _tk_category(guild, "maint")
    # admin-assigned map (re-checked now, in case it was set after the scan) → env → name match
    who = _wm_mention(_wm_resolve_id(rec.get("responder", "")) or rec.get("discord_id", ""))
    if not who:
        who = _wm_member_mention(guild, rec.get("responder", ""))
    if not who and rec.get("responder"):              # unmapped → make sure a mapping card exists
        try:
            await _wm_ensure_name_card(guild, rec["responder"])
        except Exception:
            pass
    seq = _next_counter("watchman_promise")
    try:
        ch = await guild.create_text_channel(
            f"{WATCHMAN_PROMISE_PREFIX}-{seq:03d}-{_wm_slug(rec.get('apartment'))}", category=cat,
            topic=f"ouja-watchman:promise id:{rec['id']}")
    except Exception as e:
        print("watchman promise channel error:", e)
        return
    if who:
        wholine = f"**الموظف:** {who} ({rec.get('responder') or '—'})"
        content = who
    else:
        wholine = (f"**الموظف:** غير معروف ({rec.get('responder') or 'بدون اسم'}) — رد من تطبيق Airbnb. "
                   f"اربط الاسم في «{WATCHMAN_ADMIN_CHANNEL}».")
        content = _wm_mention(WATCHMAN_MANAGER_ROLE) or None
    label = {"action": "إجراء", "money": "مبلغ/تعويض", "timing": "وقت"}.get(rec["type"], rec["type"])
    emb = discord.Embed(
        title=f"🤝 وعد للضيف #{seq:03d} · {rec['apartment']}",
        description=(f"{wholine}\n"
                     f"**النوع:** {label}\n"
                     f"**الوعد:** {rec['summary']}\n"
                     f"**نصّه:** “{rec.get('quote') or '—'}”\n"
                     f"**الضيف:** {rec.get('guest')}\n"
                     f"**الموعد النهائي:** {rec['due'][:16].replace('T', ' ')}\n\n"
                     f"اضغط «تم التنفيذ» لما تخلّصه — بيتقفل الروم."),
        color=0x4B89C9)
    emb.set_footer(text=f"wm-promise:{rec['id']}")
    msg = await ch.send(content=content, embed=emb, view=WatchmanPromiseView(),
                        allowed_mentions=discord.AllowedMentions(users=True, roles=True))
    try:
        await msg.pin()
    except Exception:
        pass
    rec["channel_id"] = str(ch.id)
    rec["msg_id"] = str(msg.id)
    _wm_msg2promise[str(msg.id)] = rec["id"]
    _wm_save()

async def _wm_promise_followup(rec, escalate):
    ch = bot.get_channel(int(rec["channel_id"])) if rec.get("channel_id") else None
    if ch is None:
        return
    if escalate:
        who = _wm_mention(WATCHMAN_MANAGER_ROLE) or _wm_mention(rec.get("discord_id", ""))
        txt = (f"🚨 {who} وعد متأخّر ما تنفّذ: **{rec['summary']}** "
               f"({rec['apartment']} · الضيف {rec.get('guest')}). محتاج متابعة الحين.")
    else:
        who = _wm_mention(rec.get("discord_id", "")) or _wm_mention(WATCHMAN_MANAGER_ROLE)
        txt = (f"⏰ {who} تذكير: وعدت الضيف بـ **{rec['summary']}** "
               f"({rec['apartment']}). اضغط ✅ لما تخلّصه.")
    try:
        if rec.get("msg_id"):
            ref = await ch.fetch_message(int(rec["msg_id"]))
            await ref.reply(txt or "تذكير")
        else:
            await ch.send(txt or "تذكير")
    except Exception:
        try:
            await ch.send(txt or "تذكير")
        except Exception:
            pass

async def _wm_followups():
    """Nudge / escalate overdue promises. Skipped in dry-run."""
    if WATCHMAN_DRYRUN or not _wm_promises:
        return
    now = datetime.now(TZ)
    changed = False
    for rec in list(_wm_promises.values()):
        if rec.get("state") == "done":
            continue
        due = _parse_msg_dt(rec.get("due", ""))
        if due is None:
            continue
        overdue_h = (now - due).total_seconds() / 3600.0
        if overdue_h < 0:
            continue
        if overdue_h >= WATCHMAN_ESCALATE_AFTER_H and not rec.get("escalated"):
            await _wm_promise_followup(rec, escalate=True)
            rec["escalated"] = True
            rec["state"] = "escalated"
            changed = True
        elif rec.get("nudged", 0) == 0:
            await _wm_promise_followup(rec, escalate=False)
            rec["nudged"] = 1
            if rec.get("state") == "open":
                rec["state"] = "nudged"
            changed = True
    if changed:
        _wm_save()

@tasks.loop(minutes=WATCHMAN_POLL_MIN)
async def watchman_loop():
    if not WATCHMAN_ENABLED:
        return
    await bot.wait_until_ready()
    if not _wm_loaded_flag["v"]:
        _wm_load()
        _wm_loaded_flag["v"] = True
    try:
        intents = await asyncio.to_thread(run_watchman_scan)
    except Exception as e:
        print("watchman scan error:", e)
        return
    try:
        await _wm_followups()
    except Exception as e:
        print("watchman followup error:", e)
    for kind, payload in intents:
        try:
            if kind in ("dry_gap", "dry_promise"):
                what = payload.get("topic") or payload.get("summary") or ""
                print(f"watchman DRYRUN would open {kind[4:]}: {payload.get('apartment')} · {what}")
            elif kind == "gap_new":
                await _wm_post_gap(payload)
            elif kind == "gap_bump":
                await _wm_bump_gap(payload)
            elif kind == "promise_new":
                await _wm_post_promise(payload)
        except Exception as e:
            print("watchman post error:", e)

